// Database helper using LocalStorage (nextcare_v8_ ensures reset of data)
const DB = {
    get(key) {
        let data = localStorage.getItem(`nextcare_v8_${key}`);
        if (!data || data === 'undefined' || data === 'null') {
            const fallbackVal = SEED_DATA[key] || [];
            localStorage.setItem(`nextcare_v8_${key}`, JSON.stringify(fallbackVal));
            return fallbackVal;
        }
        let parsed = JSON.parse(data);
        if (key === 'lab_tests' && Array.isArray(parsed)) {
            let changed = false;
            let seedServices = [];
            try {
                seedServices = JSON.parse(localStorage.getItem('nextcare_v8_medical_services') || '[]');
            } catch(e){}
            parsed.forEach(t => {
                if (!t.service_id) {
                    if (t.test_name.startsWith('Emocromo (')) {
                        const s = seedServices.find(srv => srv.name.toLowerCase().includes('emocromo'));
                        t.service_id = s ? s.id : 4;
                        changed = true;
                    } else if (t.test_name.startsWith('Elettroforesi (')) {
                        const s = seedServices.find(srv => srv.name.toLowerCase().includes('elettroforesi'));
                        t.service_id = s ? s.id : 111;
                        changed = true;
                    } else if (t.test_name.startsWith('Esame Urine (')) {
                        const s = seedServices.find(srv => srv.name.toLowerCase().includes('urine'));
                        t.service_id = s ? s.id : 8;
                        changed = true;
                    } else {
                        const s = seedServices.find(srv => srv.name.toLowerCase().replace(/\s*\(lis\)\s*/g, '') === t.test_name.toLowerCase());
                        if (s) {
                            t.service_id = s.id;
                            changed = true;
                        } else if (t.test_name === 'Glucosio') {
                            t.service_id = 3;
                            changed = true;
                        } else if (t.test_name === 'Colesterolo Totale') {
                            t.service_id = 5;
                            changed = true;
                        } else if (t.test_name === 'Creatinina') {
                            t.service_id = 74;
                            changed = true;
                        }
                    }
                }
            });
            if (changed) {
                localStorage.setItem(`nextcare_v8_lab_tests`, JSON.stringify(parsed));
            }
        }
        if (key === 'email_templates' && Array.isArray(parsed)) {
            let changed = false;
            SEED_DATA.email_templates.forEach(seedTpl => {
                if (!parsed.some(t => t.event === seedTpl.event)) {
                    parsed.push(seedTpl);
                    changed = true;
                }
            });
            if (changed) {
                localStorage.setItem(`nextcare_v8_email_templates`, JSON.stringify(parsed));
            }
        }
        return parsed;
    },
    pendingSyncPromises: [],
    set(key, value) {
        if (Array.isArray(value)) {
            const seen = new Set();
            const deduped = [];
            for (let i = 0; i < value.length; i++) {
                const row = value[i];
                if (row && typeof row === 'object') {
                    let keyVal = null;
                    if ('id' in row) keyVal = row.id;
                    else if ('setting_key' in row) keyVal = row.setting_key;
                    else if ('price_list_id' in row && 'service_id' in row) keyVal = `${row.price_list_id}_${row.service_id}`;
                    else if ('appointment_id' in row && 'service_id' in row) keyVal = `${row.appointment_id}_${row.service_id}`;
                    else if ('agenda_id' in row && 'service_id' in row) keyVal = `${row.agenda_id}_${row.service_id}`;
                    
                    if (keyVal !== null && keyVal !== undefined) {
                        if (seen.has(keyVal)) continue;
                        seen.add(keyVal);
                    }
                }
                deduped.push(row);
            }
            value = deduped;
        }
        localStorage.setItem(`nextcare_v8_${key}`, JSON.stringify(value));
        
        // Asynchronously sync with MySQL in the background (except on port 8001 LocalStorage mode)
        if (window.location.port !== '8001') {
            const p = fetch('/api/db-sync-table', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    table_name: key,
                    rows: value
                })
            })
            .then(res => res.json())
            .then(res => {
                if (!res.success) {
                    console.error(`[MySQL Sync Error] Tabella ${key}:`, res.error);
                    throw new Error(res.error || "Errore di sincronizzazione MySQL");
                } else {
                    console.log(`[MySQL Sync] Tabella ${key} sincronizzata con successo.`);
                    return res;
                }
            })
            .catch(err => {
                console.error(`[MySQL Sync Network Error] Tabella ${key}:`, err);
                throw err;
            });
            
            DB.pendingSyncPromises.push(p);
            p.finally(() => {
                const idx = DB.pendingSyncPromises.indexOf(p);
                if (idx !== -1) DB.pendingSyncPromises.splice(idx, 1);
            });
            return p;
        } else {
            return Promise.resolve({ success: true });
        }
    },
    async waitForSync() {
        if (DB.pendingSyncPromises.length === 0) return Promise.resolve();
        // Wait for all current sync promises to complete
        await Promise.all(DB.pendingSyncPromises);
    },
    insert: (key, item) => {
        const data = DB.get(key);
        item.id = data.length > 0 ? Math.max(...data.map(i => i.id)) + 1 : 1;
        data.push(item);
        DB.set(key, data);
        return item;
    },
    update: (key, id, updatedFields) => {
        const data = DB.get(key);
        const index = data.findIndex(i => i.id === parseInt(id));
        if (index !== -1) {
            data[index] = { ...data[index], ...updatedFields };
            DB.set(key, data);
            return data[index];
        }
        return null;
    },
    delete: (key, id) => {
        const data = DB.get(key);
        const filtered = data.filter(i => i.id !== parseInt(id));
        DB.set(key, filtered);
        return true;
    },
    logAudit: (staffId, action, tableName, recordId, details) => {
        const log = {
            staff_id: staffId,
            action: action,
            table_name: tableName,
            record_id: recordId,
            details: details,
            created_at: new Date().toISOString()
        };
        DB.insert('audit_logs', log);
    }
};

