window.syncFromMySQL = function(callback) {
    if (window.location.port === '8001') {
        if (typeof callback === 'function') callback();
        return;
    }
    fetch('/api/db-get-all')
    .then(res => res.json())
    .then(res => {
        if (res && res.success && res.data) {
            for (const [table, rows] of Object.entries(res.data)) {
                localStorage.setItem(`nextcare_v8_${table}`, JSON.stringify(rows));
            }
            console.log("[MySQL Sync] Local cache aligned with database.");
        }
        if (typeof callback === 'function') callback();
    })
    .catch(err => {
        console.error("[MySQL Sync Error] Failed to align with database:", err);
        if (typeof callback === 'function') callback();
    });
};

// Auto-refresh silenzioso ogni 60 secondi: aggiorna i dati dal server e
// ri-renderizza il tab attivo per mostrare dati in tempo reale da tutti i punti prelievo
(function startAutoRefresh() {
    const REFRESH_INTERVAL_MS = 60000; // 60 secondi
    const TABS_TO_REFRESH = ['admission', 'dashboard', 'bi-dashboard', 'reporting-acceptances', 'reporting-services', 'accounting', 'lis', 'ris', 'rehab'];

    setInterval(() => {
        if (window.location.port === '8001') return;
        // Refresh silenzioso: non mostra spinner, non interrompe l'utente
        fetch('/api/db-get-all')
        .then(res => res.json())
        .then(res => {
            if (res && res.success && res.data) {
                for (const [table, rows] of Object.entries(res.data)) {
                    localStorage.setItem(`nextcare_v8_${table}`, JSON.stringify(rows));
                }
                // Re-renderizza solo se il tab corrente beneficia del refresh
                if (typeof currentTab !== 'undefined' && TABS_TO_REFRESH.includes(currentTab)) {
                    if (typeof loadActiveTab === 'function') {
                        loadActiveTab();
                    }
                }
                // Aggiorna l'indicatore di ultimo aggiornamento se presente
                const syncBadge = document.getElementById('last-sync-badge');
                if (syncBadge) {
                    const now = new Date().toLocaleTimeString('it-IT', {hour: '2-digit', minute: '2-digit'});
                    syncBadge.textContent = 'Aggiornato: ' + now;
                }
            }
        })
        .catch(() => {
            // Errore silenzioso — non mostrare avvisi all'utente
        });
    }, REFRESH_INTERVAL_MS);
})();


// Global API Helper with LocalStorage fallback for port 8001
function apiCall(url, data, callback) {
    if (window.location.port === '8001') {
        if (callback) callback({ success: true, active: false, logs: [] });
        return;
    }
    fetch(url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data)
    })
    .then(res => res.json())
    .then(res => {
        if (callback) {
            if (res && res.success && res.data) {
                let formattedData = res.data;
                if (data && data.table && res.data[data.table] !== undefined) {
                    formattedData = res.data[data.table];
                }
                callback({ success: true, data: formattedData, ...res.data });
            } else {
                callback(res);
            }
        }
    })
    .catch(err => {
        console.error(`API Call error for ${url}:`, err);
        if (callback) callback({ success: false, error: err });
    });
}

window.alert = function(msg) {
    const overlay = document.getElementById('letizia-modal-overlay');
    if (overlay) {
        const titleEl = document.getElementById('letizia-modal-title');
        const descEl = document.getElementById('letizia-modal-description');
        if (titleEl) titleEl.innerText = "Notifica di Sistema";
        if (descEl) descEl.innerHTML = String(msg).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/\n/g, '<br>');
        overlay.style.display = 'flex';

        const closeBtn = document.getElementById('letizia-btn-close');
        const okBtn = document.getElementById('letizia-btn-ok');
        
        if (closeBtn) {
            closeBtn.style.display = 'none';
        }
        if (okBtn) {
            okBtn.innerText = "OK";
            okBtn.style.display = 'inline-block';
            okBtn.focus();
            
            const handleClose = function() {
                overlay.style.display = 'none';
                document.removeEventListener('keydown', handleKey);
            };
            
            const handleKey = function(e) {
                if (e.key === 'Enter' || e.key === ' ' || e.key === 'Escape') {
                    e.preventDefault();
                    handleClose();
                }
            };
            
            okBtn.onclick = handleClose;
            document.addEventListener('keydown', handleKey);
        }
    } else {
        console.log("Alert fallback:", msg);
    }
};

