document.addEventListener('DOMContentLoaded', () => {
    const initSafe = (name, fn) => {
        try {
            fn();
        } catch (e) {
            console.error(`[NextCare Init Error] Failed to initialize ${name}:`, e);
        }
    };

    initSafe('Navigation', initNavigation);
    initSafe('Theme', initTheme);
    initSafe('GlobalSearch', initGlobalSearch);
    initSafe('EmailTemplatesSeed', window.ensureDefaultEmailTemplatesExist);
    initSafe('ActiveTab', loadActiveTab);
    initSafe('FormHandlers', initFormHandlers);
    initSafe('DicomControls', initDicomControls);
    initSafe('AiAssistant', initAiAssistant);
    initSafe('RichEditors', initRichEditors);
    initSafe('ServiceToggles', initServiceToggles);
    initSafe('LisSearchTags', initLisSearchTags);
    initSafe('CupSearchTags', () => {
        initCupSearchTags();
        if (typeof window.initWizardSearchTags === 'function') {
            window.initWizardSearchTags();
        }
    });
    initSafe('AgendaSearchTags', initAgendaSearchTags);
    initSafe('SqlSchema', loadSqlSchema);
    initSafe('EquipmentSetup', populateDropdownsEquipmentSetup);
    initSafe('DbSettingsForm', initDbSettingsForm);
    initSafe('LisSimulator', window.initLisSimulator);
    initSafe('SystemStatusCheck', checkSystemStatus);
    initSafe('TemplateSettingsForm', initTemplateSettingsForm);
    initSafe('ServiceFilters', initServiceFilters);
    initSafe('AccountingFilters', initAccountingFilters);
    initSafe('RequesterDatalist', window.populateRequesterDatalist);
    initSafe('PatientAutocompletes', () => {
        window.initPatientAutocomplete('app-patient-container', 'app-patient', 'app-patient-search', 'app-patient-suggestions');
        window.initPatientAutocomplete('sam-patient-container', 'sam-patient', 'sam-patient-search', 'sam-patient-suggestions');
        window.initPatientAutocomplete('ris-patient-container', 'ris-patient', 'ris-patient-search', 'ris-patient-suggestions');
        window.initPatientAutocomplete('adm-patient-container', 'adm-patient', 'adm-patient-search', 'adm-patient-suggestions');
        window.initPatientAutocomplete('wiz-patient-container', 'wiz-patient-id', 'wiz-patient-search', 'wiz-patient-search-results');

        const handlePatientChange = (patientSelectId, companySelectId, changeHandler) => {
            const patientEl = document.getElementById(patientSelectId);
            if (!patientEl) return;
            patientEl.addEventListener('change', () => {
                const patientId = parseInt(patientEl.value);
                const companyEl = document.getElementById(companySelectId);
                if (!companyEl) return;
                if (patientId) {
                    const patients = DB.get('patients') || [];
                    const pat = patients.find(p => p.id === patientId);
                    if (pat && pat.company_id) {
                        companyEl.value = pat.company_id;
                    } else {
                        companyEl.value = '';
                    }
                } else {
                    companyEl.value = '';
                }
                if (typeof changeHandler === 'function') {
                    changeHandler();
                }
            });
        };
        handlePatientChange('sam-patient', 'sam-company', window.handleSampleCompanyChange);
        handlePatientChange('ris-patient', 'ris-company', window.handleRisCompanyChange);
        handlePatientChange('adm-patient', 'adm-company', window.handleAdmissionCompanyChange);
    });
});

window.currentSidebarMenu = 'operational'; // 'operational' or 'settings'

window.toggleSidebarMenu = function() {
    const navOper = document.getElementById('sidebar-nav-operational');
    const navSett = document.getElementById('sidebar-nav-settings');
    const label = document.getElementById('menu-type-label');
    const btnText = document.getElementById('btn-toggle-menu-text');

    if (!navOper || !navSett) return;

    if (window.currentSidebarMenu === 'operational') {
        window.currentSidebarMenu = 'settings';
        navOper.style.display = 'none';
        navSett.style.display = 'flex';
        if (label) label.innerText = 'Menu Impostazioni';
        if (btnText) btnText.innerText = 'Menu Operativo';
    } else {
        window.currentSidebarMenu = 'operational';
        navOper.style.display = 'flex';
        navSett.style.display = 'none';
        if (label) label.innerText = 'Menu Operativo';
        if (btnText) btnText.innerText = 'Impostazioni';
    }
    if (window.lucide) window.lucide.createIcons();
};

window.currentDashboardSubTab = 'operative'; // 'operative' or 'bi'

window.switchDashboardSubTab = function(subTab) {
    window.currentDashboardSubTab = subTab;
    const btnOperative = document.getElementById('sub-tab-dashboard-operative');
    const btnBi = document.getElementById('sub-tab-dashboard-bi');
    const paneOperative = document.getElementById('dashboard-pane-operative');
    const paneBi = document.getElementById('dashboard-pane-bi');

    if (btnOperative && btnBi && paneOperative && paneBi) {
        if (subTab === 'operative') {
            btnOperative.classList.add('active');
            btnBi.classList.remove('active');
            paneOperative.style.display = 'block';
            paneBi.style.display = 'none';
            if (typeof renderDashboard === 'function') renderDashboard();
        } else {
            btnBi.classList.add('active');
            btnOperative.classList.remove('active');
            paneOperative.style.display = 'none';
            paneBi.style.display = 'block';
            if (typeof window.renderBiDashboard === 'function') window.renderBiDashboard();
        }
    }
};

function initNavigation() {
    const navItems = document.querySelectorAll('.nav-item');
    navItems.forEach(item => {
        item.addEventListener('click', (e) => {
            e.preventDefault();
            if (item.classList.contains('return-to-main')) return;
            
            navItems.forEach(n => n.classList.remove('active'));
            item.classList.add('active');
            
            const target = item.getAttribute('data-tab');
            switchTab(target);
        });
    });
}

function switchTab(tabId) {
    if (tabId === 'bi-dashboard') {
        window.switchDashboardSubTab('bi');
        tabId = 'dashboard';
    }

    currentTab = tabId;
    const sections = document.querySelectorAll('.tab-content');
    sections.forEach(sec => sec.classList.remove('active'));
    
    const targetSection = document.getElementById(`tab-${tabId}`);
    if (targetSection) {
        targetSection.classList.add('active');
    }
    
    // Highlight nav item in sidebar
    const navItems = document.querySelectorAll('.nav-item');
    navItems.forEach(n => n.classList.remove('active'));
    
    const matchingItem = document.querySelector(`.nav-item[data-tab="${tabId}"]`);
    if (matchingItem) {
        matchingItem.classList.add('active');
        
        // Auto-switch sidebar menu view if needed
        const parentNav = matchingItem.closest('nav');
        if (parentNav) {
            if (parentNav.id === 'sidebar-nav-settings' && window.currentSidebarMenu !== 'settings') {
                window.toggleSidebarMenu();
            } else if (parentNav.id === 'sidebar-nav-operational' && window.currentSidebarMenu !== 'operational') {
                window.toggleSidebarMenu();
            }
        }
    }
    
    // Sync cache from MySQL before rendering tab
    window.syncFromMySQL(() => {
        loadActiveTab();
    });
}

function initTheme() {
    const themeBtn = document.getElementById('theme-toggle-btn');
    const savedTheme = localStorage.getItem('nextcare_theme');
    if (savedTheme === 'dark') document.body.classList.add('dark-theme');
    
    themeBtn.addEventListener('click', () => {
        document.body.classList.toggle('dark-theme');
        localStorage.setItem('nextcare_theme', document.body.classList.contains('dark-theme') ? 'dark' : 'light');
    });
}

function initGlobalSearch() {
    const searchInput = document.getElementById('global-search');
    if (!searchInput) return;
    searchInput.addEventListener('input', (e) => {
        const query = e.target.value.toLowerCase();
        if (window.tablePaginationStates) {
            Object.keys(window.tablePaginationStates).forEach(tableId => {
                window.tablePaginationStates[tableId].currentPage = 1;
            });
        }
        if (currentTab === 'core') renderPatients(query);
        else if (currentTab === 'services') filterServicesRealtime();
        else if (currentTab === 'cup') renderAppointments(query);
        else if (currentTab === 'lis') renderSamples(query);
        else if (currentTab === 'ris') renderRisStudies(query);
        else if (currentTab === 'unified-reports') window.renderUnifiedReports(query);
    });
}

function loadActiveTab() {
    if (typeof window.autoDetectMicrobiologyServices === 'function') {
        window.autoDetectMicrobiologyServices();
    }
    if (window.lucide) window.lucide.createIcons();

    switch(currentTab) {
        case 'dashboard':
            renderDashboard();
            break;
        case 'core':
            renderPatients();
            break;
        case 'services':
            renderServices();
            populateDropdownsServiceSetup();
            break;
        case 'cup':
            renderAppointments();
            populateDropdownsCUP();
            break;
        case 'lis':
            if (typeof window.seedValidationHistory === 'function') {
                window.seedValidationHistory();
            }
            const activeLisSub = document.querySelector('#tab-lis .sub-tabs-container .sub-tab-btn.active');
            if (activeLisSub && activeLisSub.id === 'sub-tab-lis-samples') {
                renderSamples();
            } else if (activeLisSub && activeLisSub.id === 'sub-tab-lis-worksheets') {
                window.populateLisWorksheetsDropdown();
                window.renderLisWorksheetView();
            } else if (activeLisSub && activeLisSub.id === 'sub-tab-lis-validation') {
                window.renderLisValidationView();
            } else if (activeLisSub && activeLisSub.id === 'sub-tab-lis-reporting') {
                window.renderLisReportingView();
            } else if (activeLisSub && activeLisSub.id === 'sub-tab-lis-bulk-manage') {
                if (typeof window.renderLisBulkManageView === 'function') window.renderLisBulkManageView();
            } else {
                renderLisAcceptances();
            }
            populateDropdownsLIS();
            break;
        case 'lis-logs':
            if (typeof window.initLisSimulator === 'function') {
                window.initLisSimulator();
            }
            break;
        case 'ris':
            const activeRisSub = document.querySelector('#tab-ris .sub-tabs-container .sub-tab-btn.active');
            if (activeRisSub && activeRisSub.id === 'btn-sub-ris-tsrm') {
                window.renderRisTsrmView();
            } else if (activeRisSub && activeRisSub.id === 'btn-sub-ris-dose') {
                window.renderRisDoseReport();
            } else if (activeRisSub && activeRisSub.id === 'btn-sub-ris-templates') {
                if (typeof window.renderRisTemplatesTable === 'function') window.renderRisTemplatesTable();
            } else {
                renderRisStudies();
            }
            populateDropdownsRIS();
            break;
        case 'bi-dashboard':
            if (typeof window.renderBiDashboard === 'function') window.renderBiDashboard();
            break;
        case 'rehab':
            if (typeof window.renderRehab === 'function') window.renderRehab();
            break;
        case 'warehouse':
            if (typeof window.renderWarehouse === 'function') window.renderWarehouse();
            break;
        case 'clinics':
            renderClinicsAndEquipment();
            break;
        case 'admission':
            renderAdmissionsAndInvoices();
            populateDropdownsAdmission();
            break;
        case 'hris':
            {
                const activeHrisSub = document.querySelector('#tab-hris .sub-tabs-container .sub-tab-btn.active');
                if (activeHrisSub && activeHrisSub.id === 'sub-tab-hris-companies') {
                    if (typeof window.renderCompanies === 'function') window.renderCompanies();
                } else {
                    renderStaffAndShifts();
                    populateDropdownsHRIS();
                }
            }
            break;
        case 'accounting':
            renderAccountingDashboard();
            const activeSub = document.querySelector('#tab-accounting .sub-tabs-container .sub-tab-btn.active');
            if (activeSub && activeSub.id === 'sub-tab-profit-centers') {
                renderProfitCentersTable();
            }
            break;
        case 'reporting-services':
            renderReportingServices();
            break;
        case 'reporting-acceptances':
            renderReportingAcceptances();
            break;
        case 'notifications':
            renderSentEmails();
            loadSelectedEmailTemplate();
            break;
        case 'templates':
            loadTemplateSettings();
            break;
        case 'insurance-config':
            renderInsuranceConfig();
            break;
        case 'unified-reports':
            window.renderUnifiedReports();
            break;
    }
}

// --- 3. WYSIWYG EDITOR IMPLEMENTATION ---
function initRichEditors() {
    const toolbars = ['ris-editor-toolbar', 'lis-editor-toolbar'];
    
    toolbars.forEach(toolbarId => {
        const toolbar = document.getElementById(toolbarId);
        if (!toolbar) return;
        
        const buttons = toolbar.querySelectorAll('.editor-btn');
        buttons.forEach(btn => {
            btn.addEventListener('click', (e) => {
                e.preventDefault();
                const command = btn.getAttribute('data-command');
                document.execCommand(command, false, null);
                btn.classList.toggle('active');
                
                const editor = toolbar.nextElementSibling;
                if (editor) editor.focus();
            });
        });
    });

    const sizeSelect = document.getElementById('ris-font-size');
    if (sizeSelect) {
        sizeSelect.addEventListener('change', (e) => {
            document.execCommand('fontSize', false, e.target.value);
            sizeSelect.nextElementSibling ? sizeSelect.nextElementSibling.focus() : null;
        });
    }
}

// Conditionally show/hide form fields in Prestazioni Configurator
function initServiceToggles() {
    const typeSelect = document.getElementById('srv-type');
    if (typeSelect) {
        typeSelect.addEventListener('change', (e) => {
            toggleServiceFormFields(e.target.value);
            if (e.target.value === 'ris') {
                const guessed = window.guessDoseClassIdByName(document.getElementById('srv-name').value);
                if (guessed) {
                    document.getElementById('srv-dose-class').value = guessed;
                }
            }
        });
    }
    const nameInput = document.getElementById('srv-name');
    if (nameInput) {
        nameInput.addEventListener('input', () => {
            const type = document.getElementById('srv-type').value;
            if (type === 'ris') {
                const guessed = window.guessDoseClassIdByName(nameInput.value);
                if (guessed) {
                    document.getElementById('srv-dose-class').value = guessed;
                } else {
                    document.getElementById('srv-dose-class').value = '';
                }
            }
        });
    }
}

window.populatePackageItemsContainer = function(selectedItems = []) {
    const container = document.getElementById('srv-package-items-container');
    if (!container) return;
    container.innerHTML = '';

    const editId = document.getElementById('srv-edit-id').value;
    const services = DB.get('medical_services') || [];
    
    // Parse selectedItems safely if it is a string
    let parsedItems = selectedItems;
    if (typeof parsedItems === 'string') {
        try {
            parsedItems = JSON.parse(parsedItems);
        } catch (e) {
            parsedItems = [];
        }
    }
    if (!Array.isArray(parsedItems)) {
        parsedItems = [];
    }

    // If editing and selectedItems is empty, read from existing service
    let checkedIds = parsedItems;
    if (editId && checkedIds.length === 0) {
        const s = services.find(sv => sv.id === parseInt(editId));
        if (s && s.package_items) {
            let pItems = s.package_items;
            if (typeof pItems === 'string') {
                try {
                    pItems = JSON.parse(pItems);
                } catch (e) {
                    pItems = [];
                }
            }
            checkedIds = Array.isArray(pItems) ? pItems : [];
        }
    }

    // List only LIS, RIS and visitas (no packages inside packages to avoid loop dependencies)
    const validServices = services.filter(s => s.type !== 'pacchetto' && s.id !== parseInt(editId));
    
    if (validServices.length === 0) {
        container.innerHTML = '<span class="text-muted" style="font-size:0.8rem;">Nessun esame o visita configurata da poter aggiungere.</span>';
        return;
    }

    validServices.forEach(s => {
        const isChecked = checkedIds.includes(s.id);
        const div = document.createElement('div');
        div.style.display = 'flex';
        div.style.alignItems = 'center';
        div.style.gap = '8px';
        div.style.fontSize = '0.8rem';
        div.style.padding = '4px';
        div.style.background = 'var(--bg-surface)';
        div.style.border = '1px solid var(--border-color)';
        div.style.borderRadius = 'var(--radius-sm)';

        div.innerHTML = `
            <input type="checkbox" class="srv-package-item-checkbox" value="${s.id}" ${isChecked ? 'checked' : ''} style="cursor:pointer;">
            <span style="flex:1;"><strong>[${s.type.toUpperCase()}]</strong> ${s.code ? `[${s.code}] ` : ''}${s.name}</span>
        `;
        container.appendChild(div);
    });
};

window.expandServices = function(serviceIds) {
    const services = DB.get('medical_services') || [];
    let expanded = [];
    serviceIds.forEach(id => {
        const srv = services.find(s => s.id === parseInt(id));
        if (srv) {
            if (srv.type === 'pacchetto') {
                let pItems = srv.package_items || [];
                if (typeof pItems === 'string') {
                    try {
                        pItems = JSON.parse(pItems);
                    } catch (e) {
                        pItems = [];
                    }
                }
                if (Array.isArray(pItems) && pItems.length > 0) {
                    expanded = expanded.concat(pItems);
                } else {
                    expanded.push(srv.id);
                }
            } else {
                expanded.push(srv.id);
            }
        }
    });
    // Remove duplicates
    return [...new Set(expanded)];
};

window.toggleServiceFormFields = function(type) {
    const clinicGrp = document.getElementById('srv-clinic-group');
    const equipGrp = document.getElementById('srv-equip-group');
    const sampleGrp = document.getElementById('srv-sample-group');
    const sampleColGrp = document.getElementById('srv-sample-collection-type-group');
    const lisDetailsGrp = document.getElementById('srv-lis-details-group');
    const lisInstGrp = document.getElementById('srv-lis-instrument-group');
    const branchGrp = document.getElementById('srv-branch-group');
    const paramsSec = document.getElementById('srv-lis-parameters-section');
    const packageSec = document.getElementById('srv-package-items-section');
    const doseGrp = document.getElementById('srv-dose-class-group');
    const microFlagGrp = document.getElementById('srv-microbiology-flag-group');
    const modalBox = document.querySelector('#modal-add-service .modal-box');

    // Default states
    clinicGrp.classList.add('hidden');
    equipGrp.classList.add('hidden');
    sampleGrp.classList.add('hidden');
    if (sampleColGrp) sampleColGrp.classList.add('hidden');
    lisDetailsGrp.classList.add('hidden');
    if (lisInstGrp) lisInstGrp.classList.add('hidden');
    branchGrp.classList.add('hidden');
    if (paramsSec) paramsSec.classList.add('hidden');
    if (packageSec) packageSec.classList.add('hidden');
    if (doseGrp) doseGrp.classList.add('hidden');
    if (microFlagGrp) microFlagGrp.style.display = 'none';
    if (modalBox) modalBox.classList.remove('modal-lg');

    if (type === 'visita') {
        clinicGrp.classList.remove('hidden');
        branchGrp.classList.remove('hidden');
    } else if (type === 'ris') {
        clinicGrp.classList.remove('hidden');
        equipGrp.classList.remove('hidden');
        branchGrp.classList.remove('hidden');
        if (doseGrp) doseGrp.classList.remove('hidden');
    } else if (type === 'lis') {
        sampleGrp.classList.remove('hidden');
        if (sampleColGrp) {
            sampleColGrp.classList.remove('hidden');
            window.populateSampleCollectionTypesDropdown('srv-sample-collection-type');
        }
        lisDetailsGrp.classList.remove('hidden');
        if (lisInstGrp) {
            lisInstGrp.classList.remove('hidden');
            window.populateLisInstrumentsDropdown('srv-lis-instrument');
        }
        if (paramsSec) paramsSec.classList.remove('hidden');
        if (microFlagGrp) microFlagGrp.style.display = 'block';
        if (modalBox) modalBox.classList.add('modal-lg');
    } else if (type === 'pacchetto') {
        if (packageSec) {
            packageSec.classList.remove('hidden');
            window.populatePackageItemsContainer();
        }
        if (modalBox) modalBox.classList.add('modal-lg');
    }
};

window.populateLisInstrumentsDropdown = function(selectId, selectedId = null, emptyText = "-- Nessuno / Inserimento Manuale --") {
    const select = document.getElementById(selectId);
    if (!select) return;
    select.innerHTML = `<option value="">${emptyText}</option>`;
    const equipment = DB.get('equipment') || [];
    const activeLisInstruments = equipment.filter(e => e.type === 'LIS' && e.status === 'active');
    activeLisInstruments.forEach(ins => {
        const option = document.createElement('option');
        option.value = ins.id;
        option.innerText = ins.name;
        if (selectedId && ins.id === parseInt(selectedId)) {
            option.selected = true;
        }
        select.appendChild(option);
    });
};

window.populateDoseClassesDropdown = function(selectId, selectedId = null) {
    const select = document.getElementById(selectId);
    if (!select) return;
    select.innerHTML = '<option value="">-- Nessuna / Rileva Automaticamente --</option>';
    const doseClasses = DB.get('dose_classes') || [];
    doseClasses.forEach(dc => {
        const option = document.createElement('option');
        option.value = dc.id;
        option.innerText = `Classe ${dc.code} (${dc.range_msv}) - ${dc.description}`;
        if (selectedId && dc.id === parseInt(selectedId)) {
            option.selected = true;
        }
        select.appendChild(option);
    });
};

// --- 4. EXCEL IMPORTING LOGIC ---
window.importRisServices = function() {
    const btn = document.getElementById('btn-import-ris-excel');
    btn.innerHTML = '<i data-lucide="loader"></i> Importazione...';
    btn.disabled = true;
    
    fetch('ris_visite_services_seed.json')
        .then(response => {
            if (!response.ok) throw new Error("File ris_visite_services_seed.json non trovato sul server.");
            return response.json();
        })
        .then(data => {
            const currentServices = DB.get('medical_services');
            let addedCount = 0;
            
            data.forEach(importedSrv => {
                const exists = currentServices.some(s => 
                    (s.code && importedSrv.code && s.code.toLowerCase() === importedSrv.code.toLowerCase()) || 
                    (s.name.toLowerCase() === importedSrv.name.toLowerCase() && s.type === importedSrv.type)
                );
                if (!exists) {
                    importedSrv.id = currentServices.length > 0 ? Math.max(...currentServices.map(s => s.id)) + 1 : 1;
                    if (!importedSrv.profit_center) {
                        importedSrv.profit_center = (importedSrv.type === 'visita') ? 'SPECIALISTICA' : 'IMAGING';
                    }
                    if (importedSrv.type === 'ris') {
                        importedSrv.dose_class_id = window.guessDoseClassIdByName(importedSrv.name);
                    }
                    currentServices.push(importedSrv);
                    addedCount++;
                }
            });
            
            DB.set('medical_services', currentServices);
            DB.logAudit(6, "IMPORT_SERVICES_RIS_EXCEL", "medical_services", null, { count: addedCount });
            
            alert(`Importazione completata con successo!

Importate ${addedCount} nuove prestazioni RIS e Visite reali con codice nomenclatore CUR 2024 e branche mediche.`);
            renderServices();
            populateBranchFilter();
        })
        .catch(err => {
            alert("Errore nell'importazione:\n\n" + err.message);
        })
        .finally(() => {
            btn.innerHTML = '<i data-lucide="upload"></i> Importa RIS & Visite (Excel)';
            btn.disabled = false;
            if (window.lucide) window.lucide.createIcons();
        });
};

window.importLisServices = function() {
    const btn = document.getElementById('btn-import-lis-excel');
    btn.innerHTML = '<i data-lucide="loader"></i> Importazione...';
    btn.disabled = true;
    
    fetch('lis_services_seed.json')
        .then(response => {
            if (!response.ok) throw new Error("File lis_services_seed.json non trovato sul server.");
            return response.json();
        })
        .then(data => {
            const currentServices = DB.get('medical_services') || [];
            let addedCount = 0;
            let mergedCount = 0;
            
            const lisPrefix = "90.LIS.";
            let maxProgressive = 0;
            currentServices.forEach(s => {
                if (s.code && s.code.startsWith(lisPrefix)) {
                    const numPart = s.code.substring(lisPrefix.length);
                    const parsed = parseInt(numPart);
                    if (!isNaN(parsed) && parsed > maxProgressive) {
                        maxProgressive = parsed;
                    }
                }
            });
            
            data.forEach(importedSrv => {
                const existing = currentServices.find(s => 
                    (s.name.toLowerCase() === importedSrv.name.toLowerCase() && s.type === importedSrv.type)
                );
                if (!existing) {
                    importedSrv.id = currentServices.length > 0 ? Math.max(...currentServices.map(s => s.id)) + 1 : 1;
                    maxProgressive++;
                    importedSrv.code = importedSrv.code || (lisPrefix + String(maxProgressive).padStart(4, '0'));
                    importedSrv.branch = "Laboratorio";
                    importedSrv.profit_center = "LABORATORIO";
                    currentServices.push(importedSrv);
                    addedCount++;
                } else {
                    existing.code = importedSrv.code;
                    existing.sample_type = importedSrv.sample_type;
                    existing.biological_material = importedSrv.biological_material;
                    existing.parameters = importedSrv.parameters;
                    existing.branch = "Laboratorio";
                    existing.profit_center = "LABORATORIO";
                    mergedCount++;
                }
            });
            
            DB.set('medical_services', currentServices);
            window.ensureAllTubeTypesExist();
            DB.logAudit(6, "IMPORT_SERVICES_LIS_EXCEL", "medical_services", null, { count: addedCount, merged: mergedCount });
            
            alert(`Importazione completata con successo!

Importate ${addedCount} nuove prestazioni LIS e aggiornate/unite ${mergedCount} esistenti.`);
            renderServices();
        })
        .catch(err => {
            alert("Errore nell'importazione:\n\n" + err.message);
        })
        .finally(() => {
            btn.innerHTML = '<i data-lucide="upload"></i> Importa LIS (Excel)';
            btn.disabled = false;
            if (window.lucide) window.lucide.createIcons();
        });
};

// --- 5. SEARCHABLE SELECT & TAG SYSTEM (LIS COLLECTION) ---
function initLisSearchTags() {
    const searchInput = document.getElementById('sam-search-test');
    const resultsDropdown = document.getElementById('sam-search-results');
    
    if (!searchInput) return;

    searchInput.addEventListener('input', (e) => {
        const query = e.target.value.toLowerCase().trim();
        if (!query) {
            resultsDropdown.classList.add('hidden');
            return;
        }

        const services = DB.get('medical_services').filter(s => s.type === 'lis');
        const matches = services.filter(s => s.name.toLowerCase().includes(query) || (s.code && s.code.toLowerCase().includes(query)));

        resultsDropdown.innerHTML = '';
        if (matches.length === 0) {
            resultsDropdown.innerHTML = '<div class="search-result-item text-muted">Nessun esame corrispondente</div>';
        } else {
            matches.slice(0, 15).forEach(m => {
                const div = document.createElement('div');
                div.className = 'search-result-item';
                div.style.display = 'flex';
                div.style.alignItems = 'center';
                div.style.justifyContent = 'space-between';
                div.style.gap = '10px';
                
                div.innerHTML = `
                    <span style="flex: 1;">${m.code ? `<strong>[${m.code}]</strong> ` : ''}${m.name}</span>
                    ${window.getTubeBadgeHtml(m.sample_type)}
                `;
                div.addEventListener('click', () => {
                    addSelectedLisTest(m.id);
                    searchInput.value = '';
                    resultsDropdown.classList.add('hidden');
                });
                resultsDropdown.appendChild(div);
            });
        }
        resultsDropdown.classList.remove('hidden');
    });

    document.addEventListener('click', (e) => {
        if (e.target !== searchInput && e.target !== resultsDropdown) {
            resultsDropdown.classList.add('hidden');
        }
    });
}

function addSelectedLisTest(serviceId) {
    if (!selectedLisServiceIds.includes(serviceId)) {
        selectedLisServiceIds.push(serviceId);
        renderSelectedLisTags();

        // Show alert note if present
        const srv = DB.get('medical_services').find(s => s.id === serviceId);
        if (srv && srv.alert_note) {
            alert(`⚠️ AVVISO PRESTAZIONE LIS: [${srv.name}]



${srv.alert_note}`);
        }
    }
}

window.removeSelectedLisTest = function(serviceId) {
    selectedLisServiceIds = selectedLisServiceIds.filter(id => id !== serviceId);
    renderSelectedLisTags();
};

function renderSelectedLisTags() {
    const container = document.getElementById('sam-selected-tests');
    const services = DB.get('medical_services') || [];
    const priceListItems = DB.get('price_list_items') || [];
    const listinoId = parseInt(document.getElementById('sam-listino')?.value || 1);
    container.innerHTML = '';

    if (selectedLisServiceIds.length === 0) {
        container.innerHTML = '<span class="text-muted" style="font-size: 0.8rem; padding: 4px;">Nessun esame selezionato. Cerca sopra per aggiungere.</span>';
        if (typeof window.updateSampleCalculations === 'function') window.updateSampleCalculations();
        return;
    }

    selectedLisServiceIds.forEach(id => {
        const s = services.find(sv => sv.id === id);
        if (s) {
            const item = priceListItems.find(p => p && p.price_list_id === listinoId && p.service_id === s.id);
            const currentPrice = Number(item ? item.price : (s.price || 0)) || 0;
            container.innerHTML += `
                <div style="display:flex; justify-content:space-between; align-items:center; font-size:0.85rem; padding:4px 8px; background:var(--bg-base); border-radius:var(--radius-sm); margin-bottom:4px; border:1px solid var(--border-color); width:100%;">
                    <span><strong>[LIS]</strong> ${s.name} <span class="test-tag-remove" onclick="removeSelectedLisTest(${s.id})" style="color:var(--danger); cursor:pointer; font-weight:bold; margin-left:5px;">&times;</span></span>
                    <div style="display:flex; align-items:center; gap:5px;">
                        <span>€</span>
                        <input type="number" step="0.01" class="form-control sam-price-input" 
                               data-service-id="${s.id}" data-original-price="${currentPrice}" 
                               value="${currentPrice.toFixed(2)}" 
                               style="width: 80px; padding: 2px 6px; text-align: right; border: 1px solid var(--border-color); border-radius: var(--radius-sm);">
                    </div>
                </div>
            `;
        }
    });

    const inputs = container.querySelectorAll('.sam-price-input');
    inputs.forEach(input => {
        input.addEventListener('change', (e) => {
            const newVal = parseFloat(e.target.value) || 0;
            const origVal = parseFloat(e.target.dataset.originalPrice) || 0;
            if (newVal !== origVal) {
                alert(`La tariffa è cambiata!

Prezzo precedente: € ${origVal.toFixed(2)}

Nuovo prezzo: € ${newVal.toFixed(2)}`);
                e.target.dataset.originalPrice = newVal;
            }
            updateSampleCalculations();
        });
    });

    if (typeof window.updateSampleCalculations === 'function') {
        window.updateSampleCalculations();
    }
}

window.updateSampleCalculations = function() {
    const listinoEl = document.getElementById('sam-listino');
    const claimEl = document.getElementById('sam-claim');
    const discValEl = document.getElementById('sam-discount-val');
    const discTypeEl = document.getElementById('sam-discount-type');
    if (!listinoEl || !claimEl || !discValEl || !discTypeEl) return;

    const listinoId = parseInt(listinoEl.value || 1);
    const claimIdVal = claimEl.value;
    const discountVal = parseFloat(discValEl.value || 0);
    const discountType = discTypeEl.value;

    let subtotal = 0;
    const inputs = document.querySelectorAll('#sam-selected-tests .sam-price-input');
    inputs.forEach(input => {
        const price = parseFloat(input.value || 0) || 0;
        subtotal += price;
    });

    // Apply discount
    let discountAmt = 0;
    if (discountType === 'percentage') {
        discountAmt = subtotal * (discountVal / 100);
    } else {
        discountAmt = discountVal;
    }
    discountAmt = Math.min(discountAmt, subtotal);
    const discountedTotal = subtotal - discountAmt;

    // Apply insurance
    let insuranceCovered = 0;
    let patientTotal = discountedTotal;

    const insRow = document.getElementById('sam-calc-insurance-row');
    if (claimIdVal) {
        const claim = DB.get('patient_claims').find(c => c.id === parseInt(claimIdVal));
        if (claim) {
            if (claim.deductible_type === 'percentage') {
                patientTotal = discountedTotal * (claim.deductible_value / 100);
                insuranceCovered = discountedTotal - patientTotal;
            } else {
                patientTotal = Math.min(discountedTotal, claim.deductible_value);
                insuranceCovered = discountedTotal - patientTotal;
            }
            if (insRow) insRow.style.display = 'flex';
        }
    } else {
        if (insRow) insRow.style.display = 'none';
    }

    let stampDuty = 0.00;
    if (patientTotal > 77.47) {
        stampDuty = 2.00;
    }

    const stampRow = document.getElementById('sam-calc-stamp-duty-row');
    const stampEl = document.getElementById('sam-calc-stamp-duty');
    if (stampDuty > 0) {
        if (stampRow) stampRow.style.display = 'flex';
        if (stampEl) stampEl.innerText = `€ ${stampDuty.toFixed(2)}`;
        patientTotal += stampDuty;
    } else {
        if (stampRow) stampRow.style.display = 'none';
    }

    const subEl = document.getElementById('sam-calc-subtotal');
    const discEl = document.getElementById('sam-calc-discount');
    const insEl = document.getElementById('sam-calc-insurance');
    const totEl = document.getElementById('sam-calc-total');

    if (subEl) subEl.innerText = `€ ${subtotal.toFixed(2)}`;
    if (discEl) discEl.innerText = `€ ${discountAmt.toFixed(2)}`;
    if (insEl) insEl.innerText = `€ ${insuranceCovered.toFixed(2)}`;
    if (totEl) totEl.innerText = `€ ${patientTotal.toFixed(2)}`;
};

window.openAddSampleModal = function() {
    document.getElementById('form-add-sample').reset();
    selectedLisServiceIds = [];
    renderSelectedLisTags();
    
    // Load patients
    populateDropdownsLIS();
    
    // Load price lists
    populatePriceListsDropdown('sam-listino');
    document.getElementById('sam-listino').value = 1;

    // Reset patient claims
    const claimSelect = document.getElementById('sam-claim');
    if (claimSelect) {
        claimSelect.innerHTML = '<option value="">-- Nessuna Assicurazione (Privato) --</option>';
    }

    window.updateSampleCalculations();
    openModal('modal-add-sample');
};

