// --- 5B. SEARCHABLE SELECT & TAG SYSTEM (CUP MULTI-SERVICES) ---
function initCupSearchTags() {
    const searchInput = document.getElementById('app-search-service');
    const resultsDropdown = document.getElementById('app-search-services-results');
    const doctorSelect = document.getElementById('app-doctor');
    
    if (!searchInput) return;

    searchInput.addEventListener('input', (e) => {
        const query = e.target.value.toLowerCase().trim();
        if (!query) {
            resultsDropdown.classList.add('hidden');
            return;
        }

        const selectedDoctorId = doctorSelect.value;
        let services = DB.get('medical_services') || [];

        // Filter: if a doctor or generic agenda is selected, limit Visita/RIS to those managed in that agenda.
        // LIS services are always selectable since they are outpatient and done in the lab.
        if (selectedDoctorId) {
            const agendas = DB.get('doctor_agendas') || [];
            const agendaServices = DB.get('doctor_agenda_services') || [];
            const managedServiceIds = [];
            
            if (selectedDoctorId.startsWith('agenda_')) {
                const agendaId = parseInt(selectedDoctorId.split('_')[1]);
                const srvs = agendaServices.filter(as => as.agenda_id === agendaId).map(as => as.service_id);
                managedServiceIds.push(...srvs);
            } else {
                const docId = parseInt(selectedDoctorId);
                const docAgendas = agendas.filter(a => a.doctor_id === docId);
                docAgendas.forEach(ag => {
                    const srvs = agendaServices.filter(as => as.agenda_id === ag.id).map(as => as.service_id);
                    managedServiceIds.push(...srvs);
                });
            }

            services = services.filter(s => s.type === 'lis' || managedServiceIds.includes(s.id));
        }

        const matches = services.filter(s => s.name.toLowerCase().includes(query) || (s.code && s.code.toLowerCase().includes(query)));

        resultsDropdown.innerHTML = '';
        if (matches.length === 0) {
            resultsDropdown.innerHTML = '<div class="search-result-item text-muted">Nessun esame/visita corrispondente</div>';
        } else {
            matches.slice(0, 15).forEach(m => {
                const div = document.createElement('div');
                div.className = 'search-result-item';
                div.style.display = 'flex';
                div.style.alignItems = 'center';
                div.style.gap = '8px';
                
                const isSelected = selectedCupServiceIds.includes(m.id);
                let typeText = m.type.toUpperCase();
                const tubeBadge = m.type === 'lis' && m.sample_type ? ` ${window.getTubeBadgeHtml(m.sample_type)}` : '';
                
                div.innerHTML = `
                    <input type="checkbox" id="chk-cup-srv-${m.id}" ${isSelected ? 'checked' : ''} style="cursor: pointer; pointer-events: none;">
                    <span style="flex: 1; display: inline-flex; align-items: center; justify-content: space-between; gap: 8px;">
                        <span>[${typeText}] ${m.code ? `[${m.code}] ` : ''}${m.name} (€ ${m.price ? m.price.toFixed(2) : '0.00'})</span>
                        ${tubeBadge}
                    </span>
                `;
                
                div.addEventListener('click', (event) => {
                    event.stopPropagation();
                    const checkbox = div.querySelector('input');
                    const nextState = !checkbox.checked;
                    checkbox.checked = nextState;
                    if (nextState) {
                        addSelectedCupService(m.id);
                    } else {
                        removeSelectedCupService(m.id);
                    }
                });
                resultsDropdown.appendChild(div);
            });
        }
        resultsDropdown.classList.remove('hidden');
    });

    document.addEventListener('click', (e) => {
        if (e.target !== searchInput && e.target !== resultsDropdown) {
            resultsDropdown.classList.add('hidden');
        }
    });

    // When doctor select changes, filter or warn if current selected services are incompatible
    doctorSelect.addEventListener('change', () => {
        validateCupDoctorAgendaSelection();
        findAndRenderFreeSlots();
    });

    const datetimeInput = document.getElementById('app-datetime');
    if (datetimeInput) {
        datetimeInput.addEventListener('change', () => {
            validateCupDoctorAgendaSelection();
            syncActiveSlotBadge();
        });
    }
}

function addSelectedCupService(serviceId) {
    if (!selectedCupServiceIds.includes(serviceId)) {
        selectedCupServiceIds.push(serviceId);
        renderSelectedCupTags();
        findAndRenderFreeSlots();
    }
}

window.removeSelectedCupService = function(serviceId) {
    selectedCupServiceIds = selectedCupServiceIds.filter(id => id !== serviceId);
    renderSelectedCupTags();
    findAndRenderFreeSlots();
};

function renderSelectedCupTags() {
    const container = document.getElementById('app-selected-services');
    const prepPanel = document.getElementById('app-preparations-panel');
    const prepContent = document.getElementById('app-preparations-content');
    const services = DB.get('medical_services');
    container.innerHTML = '';

    if (selectedCupServiceIds.length === 0) {
        container.innerHTML = '<span class="text-muted" style="font-size: 0.8rem; padding: 4px;">Nessuna prestazione aggiunta. Cerca sopra per aggiungere.</span>';
        if (prepPanel) prepPanel.style.display = 'none';
        return;
    }

    const alerts = [];
    selectedCupServiceIds.forEach(id => {
        const s = services.find(sv => sv.id === id);
        if (s) {
            container.innerHTML += `
                <span class="test-tag" style="background-color: var(--primary-light); color: var(--primary);">
                    ${s.name}
                    <span class="test-tag-remove" onclick="removeSelectedCupService(${s.id})">&times;</span>
                </span>
            `;
            if (s.alert_note) {
                alerts.push({ name: s.name, note: s.alert_note });
            }
        }
    });

    if (prepPanel && prepContent) {
        if (alerts.length === 0) {
            prepPanel.style.display = 'none';
        } else {
            prepContent.innerHTML = alerts.map(a => `
                <div style="margin-bottom: 6px;">
                    <strong>${a.name}:</strong> ${a.note}
                </div>
            `).join('');
            prepPanel.style.display = 'block';
        }
    }
}

