window.getEasterDate = function(year) {
    const a = year % 19;
    const b = Math.floor(year / 100);
    const c = year % 100;
    const d = Math.floor(b / 4);
    const e = b % 4;
    const f = Math.floor((b + 8) / 25);
    const g = Math.floor((b - f + 1) / 3);
    const h = (19 * a + b - d - g + 15) % 30;
    const i = Math.floor(c / 4);
    const k = c % 4;
    const l = (32 + 2 * e + 2 * i - h - k) % 7;
    const m = Math.floor((a + 11 * h + 22 * l) / 451);
    const month = Math.floor((h + l - 7 * m + 114) / 31);
    const day = ((h + l - 7 * m + 114) % 31) + 1;
    return new Date(year, month - 1, day);
};

window.isItalianHoliday = function(dateStr) {
    if (!dateStr) return false;
    const parts = dateStr.split('-');
    if (parts.length < 3) return false;
    const year = parseInt(parts[0]);
    const monthDay = `${parts[1]}-${parts[2]}`; // MM-DD
    
    const fixedHolidays = [
        '01-01', // Capodanno
        '01-06', // Epifania
        '04-25', // Festa della Liberazione
        '05-01', // Festa del Lavoro
        '06-02', // Festa della Repubblica
        '08-15', // Ferragosto
        '11-01', // Tutti i Santi
        '12-08', // Immacolata Concezione
        '12-25', // Natale
        '12-26'  // Santo Stefano
    ];
    
    if (fixedHolidays.includes(monthDay)) return true;
    
    const easter = window.getEasterDate(year);
    const yyyy = easter.getFullYear();
    const mm = String(easter.getMonth() + 1).padStart(2, '0');
    const dd = String(easter.getDate()).padStart(2, '0');
    const easterStr = `${yyyy}-${mm}-${dd}`;
    
    const em = new Date(easter.getTime() + 24 * 60 * 60 * 1000);
    const emYyyy = em.getFullYear();
    const emMm = String(em.getMonth() + 1).padStart(2, '0');
    const emDd = String(em.getDate()).padStart(2, '0');
    const emStr = `${emYyyy}-${emMm}-${emDd}`;
    
    if (dateStr === easterStr || dateStr === emStr) return true;
    
    return false;
};

window.isDateTimeClosed = function(doctorId, datetimeStr) {
    if (!datetimeStr) return false;
    const dateStr = datetimeStr.split('T')[0];
    
    // 1. Italian National Holiday
    if (window.isItalianHoliday(dateStr)) return true;
    
    // Parse doctorId clean
    let cleanDocId = null;
    if (doctorId && typeof doctorId === 'string') {
        if (!doctorId.startsWith('agenda_')) {
            cleanDocId = parseInt(doctorId);
        }
    } else if (doctorId) {
        cleanDocId = parseInt(doctorId);
    }
    
    // 2. Database Closures (Ferie/Assenze)
    const closures = DB.get('doctor_closures') || [];
    for (let i = 0; i < closures.length; i++) {
        const c = closures[i];
        if (dateStr >= c.start_date && dateStr <= c.end_date) {
            // Check if there is an hourly constraint
            let matchTime = true;
            if (c.start_time && c.end_time) {
                const parts = datetimeStr.split('T');
                if (parts.length > 1) {
                    const timeStr = parts[1].substring(0, 5); // HH:MM
                    if (timeStr >= c.start_time && timeStr < c.end_time) {
                        matchTime = true;
                    } else {
                        matchTime = false;
                    }
                }
            }
            
            if (matchTime) {
                // Whole clinic closed
                if (c.doctor_id === null || c.doctor_id === undefined || c.doctor_id === 'null' || c.doctor_id === '') {
                    return true;
                }
                // Doctor-specific closure
                if (cleanDocId && c.doctor_id && parseInt(c.doctor_id) === cleanDocId) {
                    return true;
                }
            }
        }
    }
    return false;
};

function validateCupDoctorAgendaSelection() {
    const doctorId = document.getElementById('app-doctor').value;
    const datetimeVal = document.getElementById('app-datetime').value;
    
    if (!doctorId || !datetimeVal) return;

    if (window.isDateTimeClosed(doctorId, datetimeVal)) {
        alert("Attenzione: La data selezionata rientra in un periodo di chiusura (ferie del medico o festività del centro).");
        document.getElementById('app-datetime').value = '';
        return;
    }

    const agendas = DB.get('doctor_agendas') || [];
    const targetDate = new Date(datetimeVal);
    const dateStr = datetimeVal.split('T')[0];

    // Find agendas for the selected doctor/agenda
    let activeAgenda = null;
    if (doctorId.startsWith('agenda_')) {
        const agendaId = parseInt(doctorId.split('_')[1]);
        activeAgenda = agendas.find(a => a.id === agendaId && dateStr >= a.start_date && dateStr <= a.end_date);
    } else {
        const docId = parseInt(doctorId);
        const docAgendas = agendas.filter(a => a.doctor_id === docId);
        if (docAgendas.length === 0) {
            alert("Attenzione: Il medico selezionato non ha agende operative registrate in archivio.");
            return;
        }
        activeAgenda = docAgendas.find(a => dateStr >= a.start_date && dateStr <= a.end_date);
    }

    if (!activeAgenda) {
        alert("Attenzione: La data selezionata non rientra nel periodo di validità dell'agenda operativa selezionata.");
        return;
    }

    // Check weekdays
    const weekdays = ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];
    const selectedDayName = weekdays[targetDate.getDay()];
    const activeDaysList = activeAgenda.active_days.split(',');

    if (!activeDaysList.includes(selectedDayName)) {
        alert(`Attenzione: L'agenda selezionata non è operativa il giorno ${selectedDayName} (Giorni attivi: ${activeAgenda.active_days}).`);
        return;
    }

    // Show slot duration message
    console.log(`Slot duration for agenda is ${activeAgenda.slot_duration_minutes} minutes.`);
}

function findAndRenderFreeSlots() {
    const doctorIdVal = document.getElementById('app-doctor').value;
    const container = document.getElementById('app-free-slots-container');
    if (!container) return;

    if (!doctorIdVal) {
        container.innerHTML = '<span class="text-muted" style="font-size: 0.8rem;">Seleziona un medico o agenda per cercare automaticamente gli slot liberi.</span>';
        return;
    }

    const agendas = DB.get('doctor_agendas') || [];
    const appointments = DB.get('appointments') || [];
    
    // Find agendas for the doctor/agenda
    let docAgendas = [];
    let isGeneric = false;
    let agendaId = null;
    let doctorId = null;

    if (doctorIdVal.startsWith('agenda_')) {
        agendaId = parseInt(doctorIdVal.split('_')[1]);
        docAgendas = agendas.filter(a => a.id === agendaId);
        isGeneric = true;
    } else {
        doctorId = parseInt(doctorIdVal);
        docAgendas = agendas.filter(a => a.doctor_id === doctorId);
    }

    if (docAgendas.length === 0) {
        container.innerHTML = '<span class="text-danger" style="font-size: 0.8rem;">Nessuna agenda configurata per la selezione corrente.</span>';
        return;
    }

    // Generate slots for the next 14 days starting from today
    const freeSlots = [];
    const maxSlotsToShow = 10;
    const today = new Date();
    
    const weekdays = ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];
    const weekdaysIT = ["Dom", "Lun", "Mar", "Mer", "Gio", "Ven", "Sab"];

    // Scan next 14 days
    for (let dayOffset = 0; dayOffset < 14; dayOffset++) {
        if (freeSlots.length >= maxSlotsToShow) break;

        const checkDate = new Date(today.getTime());
        checkDate.setDate(today.getDate() + dayOffset);
        
        // Format date string as YYYY-MM-DD
        const yyyy = checkDate.getFullYear();
        const mm = String(checkDate.getMonth() + 1).padStart(2, '0');
        const dd = String(checkDate.getDate()).padStart(2, '0');
        const dateStr = `${yyyy}-${mm}-${dd}`;
        const dayName = weekdays[checkDate.getDay()];

        // Find active agenda for this date
        const activeAgenda = docAgendas.find(a => dateStr >= a.start_date && dateStr <= a.end_date && a.active_days.split(',').includes(dayName));
        if (!activeAgenda) continue;

        const slotDur = activeAgenda.slot_duration_minutes || 30;

        const ranges = activeAgenda.time_slots || [
            { start: activeAgenda.start_hour || '08:00', end: activeAgenda.end_hour || '14:00' }
        ];

        for (let ri = 0; ri < ranges.length; ri++) {
            const r = ranges[ri];
            const startParts = r.start.split(':');
            const endParts = r.end.split(':');
            const startMin = parseInt(startParts[0]) * 60 + parseInt(startParts[1] || 0);
            const endMin = parseInt(endParts[0]) * 60 + parseInt(endParts[1] || 0);

            for (let m = startMin; m < endMin; m += slotDur) {
                if (freeSlots.length >= maxSlotsToShow) break;

                const hour = Math.floor(m / 60);
                const minute = m % 60;
                const hourStr = String(hour).padStart(2, '0');
                const minStr = String(minute).padStart(2, '0');
                const timeStr = `${hourStr}:${minStr}`;
                const slotDatetime = `${dateStr}T${timeStr}`;

                // Check if slot datetime is in the past
                const slotDateObj = new Date(slotDatetime);
                if (slotDateObj <= today) continue;

                // Check if slot is already booked
                const isBooked = appointments.some(app => {
                    if (isGeneric) {
                        return app.agenda_id === agendaId && 
                               window.compareDatetimes(app.appointment_datetime, slotDatetime) && 
                               app.status === 'scheduled';
                    } else {
                        return app.doctor_id === doctorId && 
                               window.compareDatetimes(app.appointment_datetime, slotDatetime) && 
                               app.status === 'scheduled';
                    }
                });

                if (!isBooked && !window.isDateTimeClosed(doctorIdVal, slotDatetime)) {
                    const exists = freeSlots.some(fs => fs.datetime === slotDatetime);
                    if (!exists) {
                        freeSlots.push({
                            datetime: slotDatetime,
                            label: `${weekdaysIT[checkDate.getDay()]} ${dd}/${mm} ${timeStr}`,
                            dateStr: dateStr,
                            timeStr: timeStr
                        });
                    }
                }
            }
        }
    }

    if (freeSlots.length === 0) {
        container.innerHTML = '<span class="text-warning" style="font-size: 0.8rem;">Nessuno slot libero trovato nei prossimi 14 giorni.</span>';
        return;
    }

    container.innerHTML = '';
    const datetimeInput = document.getElementById('app-datetime');
    const currentVal = datetimeInput ? datetimeInput.value : '';

    freeSlots.forEach(slot => {
        const btn = document.createElement('button');
        btn.type = 'button';
        btn.className = 'free-slot-badge';
        btn.dataset.datetime = slot.datetime;
        if (currentVal === slot.datetime) {
            btn.classList.add('active');
        }
        btn.innerText = slot.label;
        btn.addEventListener('click', () => {
            // Remove active class from all slots
            container.querySelectorAll('.free-slot-badge').forEach(b => b.classList.remove('active'));
            btn.classList.add('active');
            
            if (datetimeInput) {
                datetimeInput.value = slot.datetime;
                validateCupDoctorAgendaSelection();
            }
        });
        container.appendChild(btn);
    });
}

function syncActiveSlotBadge() {
    const datetimeInput = document.getElementById('app-datetime');
    const container = document.getElementById('app-free-slots-container');
    if (!datetimeInput || !container) return;
    const currentVal = datetimeInput.value;
    container.querySelectorAll('.free-slot-badge').forEach(btn => {
        if (btn.dataset.datetime === currentVal) {
            btn.classList.add('active');
        } else {
            btn.classList.remove('active');
        }
    });
}

window.openAddAppointmentModal = function() {
    document.getElementById('form-add-appointment').reset();
    selectedCupServiceIds = [];
    renderSelectedCupTags();
    const searchInput = document.getElementById('app-search-service');
    if (searchInput) searchInput.value = '';
    
    // Repopulate patient and doctor dropdowns to make sure they are up-to-date
    populateDropdownsCUP();
    
    // Render free slots (default state)
    findAndRenderFreeSlots();
    
    openModal('modal-add-appointment');
};

// --- 5C. INLINE PATIENT CREATION SYSTEM ---
window.openAddPatientInline = function(targetSelectId) {
    inlinePatientTargetSelect = targetSelectId;
    openModal('modal-add-patient');
};

window.openEditPatientInline = function(targetSelectId) {
    const el = document.getElementById(targetSelectId);
    if (!el || !el.value) {
        alert("Selezionare prima un paziente da modificare.");
        return;
    }
    inlinePatientTargetSelect = targetSelectId;
    window.openEditPatientModal(parseInt(el.value));
};

window.setPatientSelectValue = function(id, val) {
    const el = document.getElementById(id);
    if (!el) return;
    el.value = val;
    el.dispatchEvent(new Event('change', { bubbles: true }));
};

window.initPatientAutocomplete = function(containerId, inputId, searchInputId, suggestionsId) {
    const searchInput = document.getElementById(searchInputId);
    const hiddenInput = document.getElementById(inputId);
    const suggestionsBox = document.getElementById(suggestionsId);
    if (!searchInput || !hiddenInput || !suggestionsBox) return;

    searchInput.addEventListener('input', () => {
        const query = searchInput.value.toLowerCase().trim();
        if (!query) {
            suggestionsBox.style.display = 'none';
            hiddenInput.value = '';
            hiddenInput.dispatchEvent(new Event('change', { bubbles: true }));
            return;
        }

        const patients = DB.get('patients') || [];
        const matches = patients.filter(p => {
            const fullName = `${p.first_name} ${p.last_name}`.toLowerCase();
            const revFullName = `${p.last_name} ${p.first_name}`.toLowerCase();
            const taxCode = (p.tax_code || '').toLowerCase();
            return fullName.includes(query) || revFullName.includes(query) || taxCode.includes(query);
        });

        if (matches.length === 0) {
            suggestionsBox.innerHTML = '<div style="padding: 12px; text-align: center; color: var(--text-secondary); font-size: 0.85rem;">Nessun paziente trovato. Premi + per aggiungerlo.</div>';
            suggestionsBox.style.display = 'block';
            hiddenInput.value = '';
            hiddenInput.dispatchEvent(new Event('change', { bubbles: true }));
            return;
        }

        suggestionsBox.innerHTML = '';
        matches.slice(0, 10).forEach(p => {
            const item = document.createElement('div');
            item.className = 'patient-suggestion-item';
            item.innerHTML = `<strong>${p.last_name} ${p.first_name}</strong><span class="tax-code">${p.tax_code || 'N/A'} - Nascita: ${new Date(p.birth_date).toLocaleDateString('it-IT')}</span>`;
            item.addEventListener('click', () => {
                searchInput.value = `${p.last_name} ${p.first_name} (${p.tax_code})`;
                hiddenInput.value = p.id;
                suggestionsBox.style.display = 'none';
                hiddenInput.dispatchEvent(new Event('change', { bubbles: true }));
            });
            suggestionsBox.appendChild(item);
        });
        suggestionsBox.style.display = 'block';
    });

    // Close suggestions box on clicking outside
    document.addEventListener('click', (e) => {
        if (!searchInput.contains(e.target) && !suggestionsBox.contains(e.target)) {
            suggestionsBox.style.display = 'none';
        }
    });

    // Sync with form resets
    const form = searchInput.closest('form');
    if (form) {
        form.addEventListener('reset', () => {
            searchInput.value = '';
            hiddenInput.value = '';
            suggestionsBox.style.display = 'none';
        });
    }

    // Listen for programmatically set values (e.g. edit or inline creation)
    hiddenInput.addEventListener('change', () => {
        const patientId = parseInt(hiddenInput.value);
        if (!patientId) {
            searchInput.value = '';
            return;
        }
        const patients = DB.get('patients') || [];
        const p = patients.find(pat => pat.id === patientId);
        if (p) {
            const expectedText = `${p.last_name} ${p.first_name} (${p.tax_code})`;
            if (searchInput.value !== expectedText) {
                searchInput.value = expectedText;
            }
        } else {
            searchInput.value = '';
        }
    });
};

// ==========================================================
// --- SMART CUP BOOKING WIZARD SYSTEM ---
// ==========================================
let wizardSelectedServices = [];
let wizardSelectedDoctors = [];
let wizardSelectedSlots = [];
let wizardCurrentStep = 1;
let wizardSearchRange = 7;
let wizardStartDate = new Date().toISOString().split('T')[0];
let wizardBookingMode = 'together';
let wizardSelectedSlotsSeparate = {};


window.initWizardSearchTags = function() {
    const searchInput = document.getElementById('wiz-search-service');
    const resultsDropdown = document.getElementById('wiz-search-results');
    
    if (!searchInput || !resultsDropdown) return;

    searchInput.addEventListener('input', (e) => {
        const query = e.target.value.toLowerCase().trim();
        if (!query) {
            resultsDropdown.style.display = 'none';
            return;
        }

        let services = DB.get('medical_services') || [];
        const matches = services.filter(s => 
            s.name.toLowerCase().includes(query) || 
            (s.code && s.code.toLowerCase().includes(query))
        );

        resultsDropdown.innerHTML = '';
        if (matches.length === 0) {
            resultsDropdown.innerHTML = '<div style="padding: 10px; text-align: center; color: var(--text-secondary); font-size: 0.85rem;">Nessun esame/visita corrispondente</div>';
        } else {
            matches.slice(0, 15).forEach(m => {
                const div = document.createElement('div');
                div.className = 'search-result-item';
                div.style.padding = '8px 12px';
                div.style.cursor = 'pointer';
                div.style.display = 'flex';
                div.style.alignItems = 'center';
                div.style.gap = '8px';
                div.style.borderBottom = '1px solid var(--border-color)';
                
                const isSelected = wizardSelectedServices.includes(m.id);
                let typeText = m.type.toUpperCase();
                const tubeBadge = m.type === 'lis' && m.sample_type ? ` ${window.getTubeBadgeHtml(m.sample_type)}` : '';
                
                div.innerHTML = `
                    <input type="checkbox" id="chk-wiz-srv-${m.id}" ${isSelected ? 'checked' : ''} style="cursor: pointer; pointer-events: none;">
                    <span style="flex: 1; display: inline-flex; align-items: center; justify-content: space-between; gap: 8px; font-size: 0.85rem;">
                        <span>[${typeText}] ${m.code ? `[${m.code}] ` : ''}${m.name} (€ ${m.price ? m.price.toFixed(2) : '0.00'})</span>
                        ${tubeBadge}
                    </span>
                `;
                
                div.addEventListener('click', (event) => {
                    event.stopPropagation();
                    const checkbox = div.querySelector('input');
                    const nextState = !checkbox.checked;
                    checkbox.checked = nextState;
                    if (nextState) {
                        window.addWizardSelectedService(m.id);
                    } else {
                        window.removeWizardSelectedService(m.id);
                    }
                });
                resultsDropdown.appendChild(div);
            });
        }
        resultsDropdown.style.display = 'block';
    });

    document.addEventListener('click', (e) => {
        if (e.target !== searchInput && !resultsDropdown.contains(e.target)) {
            resultsDropdown.style.display = 'none';
        }
    });

    const dateFilter = document.getElementById('wiz-filter-start-date');
    if (dateFilter) {
        dateFilter.addEventListener('change', () => {
            window.findAndRenderWizardSlots();
        });
    }

    const wizPatientIdInput = document.getElementById('wiz-patient-id');
    if (wizPatientIdInput) {
        wizPatientIdInput.addEventListener('change', () => {
            const patientId = parseInt(wizPatientIdInput.value);
            const summaryPatient = document.getElementById('wiz-summary-patient');
            if (summaryPatient) {
                if (patientId) {
                    const patients = DB.get('patients') || [];
                    const p = patients.find(pat => pat.id === patientId);
                    summaryPatient.innerText = p ? `${p.last_name} ${p.first_name} (${p.tax_code})` : '-- Seleziona un paziente --';
                } else {
                    summaryPatient.innerText = '-- Seleziona un paziente --';
                }
            }
        });
    }
};

window.addWizardSelectedService = function(serviceId) {
    if (!wizardSelectedServices.includes(serviceId)) {
        wizardSelectedServices.push(serviceId);
        window.renderWizardSelectedServices();
    }
};

window.removeWizardSelectedService = function(serviceId) {
    wizardSelectedServices = wizardSelectedServices.filter(id => id !== serviceId);
    window.renderWizardSelectedServices();
};

window.renderWizardSelectedServices = function() {
    const container = document.getElementById('wiz-selected-services-list');
    const emptyMsg = document.getElementById('wiz-empty-services-msg');
    const prepContent = document.getElementById('wiz-preparations-content');
    if (!container) return;
    
    // Clear list
    container.innerHTML = '';
    
    if (wizardSelectedServices.length === 0) {
        if (emptyMsg) emptyMsg.style.display = 'block';
        container.appendChild(emptyMsg || document.createTextNode('Nessuna prestazione ancora selezionata.'));
        if (prepContent) {
            prepContent.innerHTML = '<div class="text-muted" style="font-style: italic; text-align: center; padding-top: 20px;">Nessun avviso o preparazione richiesta per gli esami selezionati.</div>';
        }
        return;
    }
    
    if (emptyMsg) emptyMsg.style.display = 'none';
    
    const services = DB.get('medical_services') || [];
    const alerts = [];
    
    wizardSelectedServices.forEach(id => {
        const s = services.find(sv => sv.id === id);
        if (s) {
            const badge = document.createElement('span');
            badge.className = 'test-tag';
            badge.style.backgroundColor = 'var(--primary-light)';
            badge.style.color = 'var(--primary)';
            badge.style.display = 'inline-flex';
            badge.style.alignItems = 'center';
            badge.style.gap = '6px';
            badge.style.padding = '4px 8px';
            badge.style.borderRadius = 'var(--radius-sm)';
            badge.style.fontSize = '0.8rem';
            badge.style.fontWeight = '500';
            
            badge.innerHTML = `
                ${s.name}
                <span class="test-tag-remove" style="cursor: pointer; font-weight: bold;" onclick="window.removeWizardSelectedService(${s.id})">&times;</span>
            `;
            container.appendChild(badge);
            
            if (s.alert_note) {
                alerts.push({
                    name: s.name,
                    note: s.alert_note
                });
            }
        }
    });

    if (prepContent) {
        if (alerts.length === 0) {
            prepContent.innerHTML = '<div class="text-muted" style="font-style: italic; text-align: center; padding-top: 20px;">Nessun avviso o preparazione richiesta per gli esami selezionati.</div>';
        } else {
            prepContent.innerHTML = alerts.map(a => `
                <div style="background: rgba(245, 158, 11, 0.05); border-left: 3px solid #f59e0b; padding: 10px; margin-bottom: 10px; border-radius: 4px;">
                    <strong style="display: block; color: #b45309; font-size: 0.82rem; margin-bottom: 4px;">${a.name}</strong>
                    <span style="font-size: 0.78rem; color: #78350f;">${a.note}</span>
                </div>
            `).join('');
        }
    }
};

window.openCupWizardModal = function() {
    // Reset state
    wizardSelectedServices = [];
    wizardSelectedDoctors = [];
    wizardSelectedSlots = [];
    wizardCurrentStep = 1;
    wizardSearchRange = 7;
    wizardStartDate = new Date().toISOString().split('T')[0];
    wizardBookingMode = 'together';
    wizardSelectedSlotsSeparate = {};
    
    // Reset HTML fields
    const searchInput = document.getElementById('wiz-search-service');
    if (searchInput) searchInput.value = '';
    
    const patientSearch = document.getElementById('wiz-patient-search');
    if (patientSearch) patientSearch.value = '';
    
    const patientId = document.getElementById('wiz-patient-id');
    if (patientId) patientId.value = '';
    
    const startFilter = document.getElementById('wiz-filter-start-date');
    if (startFilter) startFilter.value = wizardStartDate;
    
    const timeOfDaySelect = document.getElementById('wiz-filter-time-of-day');
    if (timeOfDaySelect) timeOfDaySelect.value = 'all';
    
    const weekdaysSelect = document.getElementById('wiz-filter-weekdays');
    if (weekdaysSelect) weekdaysSelect.value = 'all';
    
    const togetherCard = document.getElementById('wiz-mode-together');
    const separateCard = document.getElementById('wiz-mode-separate');
    if (togetherCard) {
        togetherCard.classList.add('active');
        togetherCard.style.borderColor = 'var(--primary)';
        togetherCard.style.background = 'rgba(37,99,235,0.02)';
    }
    if (separateCard) {
        separateCard.classList.remove('active');
        separateCard.style.borderColor = 'var(--border-color)';
        separateCard.style.background = 'var(--bg-surface)';
    }
    
    // Update active ranges
    window.updateWizardRangeButtons();
    
    // Render selected services
    window.renderWizardSelectedServices();
    
    // Clear slots
    const slotsContainer = document.getElementById('wiz-slots-container');
    if (slotsContainer) slotsContainer.innerHTML = '';
    
    // Display Step 1
    window.updateWizardStepsUI();
    
    // Open Modal
    openModal('modal-cup-wizard');
};

window.updateWizardRangeButtons = function() {
    [7, 14, 30].forEach(r => {
        const btn = document.getElementById(`btn-wiz-range-${r}`);
        if (btn) {
            if (wizardSearchRange === r) {
                btn.classList.add('active');
            } else {
                btn.classList.remove('active');
            }
        }
    });
};

window.changeWizardRange = function(days) {
    wizardSearchRange = days;
    window.updateWizardRangeButtons();
    window.findAndRenderWizardSlots();
};

window.updateWizardStepsUI = function() {
    // Show correct panel
    for (let i = 1; i <= 4; i++) {
        const panel = document.getElementById(`wiz-step-panel-${i}`);
        if (panel) {
            panel.style.display = (i === wizardCurrentStep) ? 'block' : 'none';
        }
        
        // Progress bar indicator class
        const ind = document.getElementById(`wiz-step-ind-${i}`);
        if (ind) {
            if (i <= wizardCurrentStep) {
                ind.classList.add('active');
            } else {
                ind.classList.remove('active');
            }
        }
    }
    
    // Footer buttons
    const prevBtn = document.getElementById('btn-wiz-prev');
    const nextBtn = document.getElementById('btn-wiz-next');
    const submitBtn = document.getElementById('btn-wiz-submit');
    
    if (prevBtn) prevBtn.style.display = (wizardCurrentStep === 1) ? 'none' : 'inline-block';
    if (nextBtn) nextBtn.style.display = (wizardCurrentStep === 4) ? 'none' : 'inline-block';
    if (submitBtn) submitBtn.style.display = (wizardCurrentStep === 4) ? 'inline-block' : 'none';
};

window.navigateWizard = function(stepDirection) {
    const nextStep = wizardCurrentStep + stepDirection;
    if (nextStep < 1 || nextStep > 4) return;
    
    if (stepDirection === 1) {
        // Validation when going forward
        if (wizardCurrentStep === 1) {
            if (wizardSelectedServices.length === 0) {
                alert("Errore: Selezionare almeno una prestazione!");
                return;
            }
            
            // Populate step 2 (doctors list)
            const medicalServices = DB.get('medical_services') || [];
            const selectedServices = wizardSelectedServices.map(id => medicalServices.find(s => s.id === id)).filter(Boolean);
            const needsDoctor = selectedServices.some(s => s.type !== 'lis');
            
            const docNotReqMsg = document.getElementById('wiz-doctor-not-required-msg');
            const docSelectGroup = document.getElementById('wiz-doctor-select-group');
            const container = document.getElementById('wiz-doctors-checkboxes-container');
            
            if (!needsDoctor) {
                if (docNotReqMsg) docNotReqMsg.style.display = 'block';
                if (docSelectGroup) docSelectGroup.style.display = 'none';
                wizardSelectedDoctors = [];
            } else {
                if (docNotReqMsg) docNotReqMsg.style.display = 'none';
                if (docSelectGroup) docSelectGroup.style.display = 'block';
                
                // Find doctors qualified for these services
                const doctorAgendas = DB.get('doctor_agendas') || [];
                const doctorAgendaServices = DB.get('doctor_agenda_services') || [];
                const doctors = DB.get('doctors') || [];
                const staff = DB.get('staff') || [];
                
                const qualifiedDoctorIds = new Set();
                const nonLisServiceIds = selectedServices.filter(s => s.type !== 'lis').map(s => s.id);
                
                doctorAgendas.forEach(ag => {
                    const managedServices = doctorAgendaServices.filter(as => as.agenda_id === ag.id).map(as => as.service_id);
                    const canDoAny = nonLisServiceIds.some(id => managedServices.includes(id));
                    if (canDoAny) {
                        qualifiedDoctorIds.add(ag.doctor_id);
                    }
                });
                
                // Clear and keep previously selected doctors if still qualified
                wizardSelectedDoctors = wizardSelectedDoctors.filter(docId => qualifiedDoctorIds.has(docId));
                
                if (container) {
                    container.innerHTML = '';
                    
                    // Helper function to update check styles dynamically
                    const updateSelectionUI = () => {
                        const anyActive = wizardSelectedDoctors.length === 0;
                        
                        // anyCard
                        const anyCard = container.querySelector('.doctor-checkbox-card:first-child');
                        if (anyCard) {
                            const anyChk = document.getElementById('chk-doc-any');
                            if (anyChk) anyChk.checked = anyActive;
                            anyCard.style.border = anyActive ? '2px solid var(--primary)' : '1px solid var(--border-color)';
                            anyCard.style.background = anyActive ? 'rgba(37,99,235,0.04)' : 'var(--bg-surface)';
                            if (anyActive) anyCard.classList.add('active'); else anyCard.classList.remove('active');
                        }
                        
                        // doctor cards
                        qualifiedDoctorIds.forEach(dId => {
                            const docCard = document.getElementById(`chk-doc-${dId}`)?.closest('.doctor-checkbox-card');
                            if (docCard) {
                                const chk = document.getElementById(`chk-doc-${dId}`);
                                const isChecked = wizardSelectedDoctors.includes(dId) && !anyActive;
                                if (chk) chk.checked = isChecked;
                                docCard.style.border = isChecked ? '2px solid var(--primary)' : '1px solid var(--border-color)';
                                docCard.style.background = isChecked ? 'rgba(37,99,235,0.04)' : 'var(--bg-surface)';
                                if (isChecked) docCard.classList.add('active'); else docCard.classList.remove('active');
                            }
                        });
                    };
                    
                    // 1. "Qualsiasi Medico" Card
                    const anyActive = wizardSelectedDoctors.length === 0;
                    const anyCard = document.createElement('div');
                    anyCard.className = `doctor-checkbox-card ${anyActive ? 'active' : ''}`;
                    anyCard.style.border = anyActive ? '2px solid var(--primary)' : '1px solid var(--border-color)';
                    anyCard.style.background = anyActive ? 'rgba(37,99,235,0.04)' : 'var(--bg-surface)';
                    anyCard.style.borderRadius = 'var(--radius-md)';
                    anyCard.style.padding = '15px';
                    anyCard.style.cursor = 'pointer';
                    anyCard.style.transition = 'all 0.2s ease';
                    anyCard.style.display = 'flex';
                    anyCard.style.alignItems = 'center';
                    anyCard.style.gap = '12px';
                    
                    anyCard.innerHTML = `
                        <input type="checkbox" id="chk-doc-any" ${anyActive ? 'checked' : ''} style="width: 18px; height: 18px; cursor: pointer;">
                        <div style="flex: 1;">
                            <strong style="display: block; font-size: 0.9rem; color: var(--text-primary);">Qualsiasi Medico (Tutti)</strong>
                            <span style="font-size: 0.75rem; color: var(--text-secondary);">Cerca la prima disponibilità tra tutti i medici</span>
                        </div>
                    `;
                    
                    anyCard.onclick = function(e) {
                        if (e.target.type !== 'checkbox') {
                            const chk = document.getElementById('chk-doc-any');
                            if (chk) chk.checked = true;
                        }
                        wizardSelectedDoctors = [];
                        updateSelectionUI();
                    };
                    
                    const anyCheckbox = anyCard.querySelector('input');
                    anyCheckbox.onchange = function() {
                        wizardSelectedDoctors = [];
                        updateSelectionUI();
                    };
                    
                    container.appendChild(anyCard);
                    
                    // 2. Individual Doctor Cards
                    qualifiedDoctorIds.forEach(docId => {
                        const doc = doctors.find(d => d.id === docId);
                        if (doc) {
                            const st = staff.find(s => s.id === doc.staff_id);
                            if (st) {
                                const isChecked = wizardSelectedDoctors.includes(docId);
                                const docCard = document.createElement('div');
                                docCard.className = `doctor-checkbox-card ${isChecked ? 'active' : ''}`;
                                docCard.style.border = isChecked ? '2px solid var(--primary)' : '1px solid var(--border-color)';
                                docCard.style.background = isChecked ? 'rgba(37,99,235,0.04)' : 'var(--bg-surface)';
                                docCard.style.borderRadius = 'var(--radius-md)';
                                docCard.style.padding = '15px';
                                docCard.style.cursor = 'pointer';
                                docCard.style.transition = 'all 0.2s ease';
                                docCard.style.display = 'flex';
                                docCard.style.alignItems = 'center';
                                docCard.style.gap = '12px';
                                
                                const prefix = st.first_name.endsWith('a') ? "Dott.ssa" : "Dott.";
                                docCard.innerHTML = `
                                    <input type="checkbox" id="chk-doc-${docId}" ${isChecked ? 'checked' : ''} style="width: 18px; height: 18px; cursor: pointer;">
                                    <div style="flex: 1;">
                                        <strong style="display: block; font-size: 0.9rem; color: var(--text-primary);">${prefix} ${st.last_name} ${st.first_name}</strong>
                                        <span style="font-size: 0.75rem; color: var(--text-secondary);">${doc.specialization || 'Specialista'}</span>
                                    </div>
                                `;
                                
                                docCard.onclick = function(e) {
                                    if (e.target.type !== 'checkbox') {
                                        const chk = document.getElementById(`chk-doc-${docId}`);
                                        if (chk) chk.checked = !chk.checked;
                                    }
                                    
                                    const chkVal = document.getElementById(`chk-doc-${docId}`).checked;
                                    if (chkVal) {
                                        if (!wizardSelectedDoctors.includes(docId)) {
                                            wizardSelectedDoctors.push(docId);
                                        }
                                    } else {
                                        wizardSelectedDoctors = wizardSelectedDoctors.filter(id => id !== docId);
                                    }
                                    updateSelectionUI();
                                };
                                
                                const docCheckbox = docCard.querySelector('input');
                                docCheckbox.onchange = function() {
                                    const chkVal = docCheckbox.checked;
                                    if (chkVal) {
                                        if (!wizardSelectedDoctors.includes(docId)) {
                                            wizardSelectedDoctors.push(docId);
                                        }
                                    } else {
                                        wizardSelectedDoctors = wizardSelectedDoctors.filter(id => id !== docId);
                                    }
                                    updateSelectionUI();
                                };
                                
                                container.appendChild(docCard);
                            }
                        }
                    });
                }
            }
        } else if (wizardCurrentStep === 2) {
            // wizardSelectedDoctors is already updated dynamically! No need to read a select element.
            
            // Set date filter to today if empty
            const dateFilter = document.getElementById('wiz-filter-start-date');
            if (dateFilter && !dateFilter.value) {
                dateFilter.value = new Date().toISOString().split('T')[0];
            }
            wizardStartDate = dateFilter ? dateFilter.value : new Date().toISOString().split('T')[0];
            
            // Show/hide booking mode selector based on number of services
            const modeContainer = document.getElementById('wiz-booking-mode-container');
            if (modeContainer) {
                if (wizardSelectedServices.length > 1) {
                    modeContainer.style.display = 'flex';
                } else {
                    modeContainer.style.display = 'none';
                    wizardBookingMode = 'together';
                }
            }
            
            // Render Step 3 slots
            window.findAndRenderWizardSlots();
        } else if (wizardCurrentStep === 3) {
            if (wizardBookingMode === 'separate') {
                const allSelected = wizardSelectedServices.every(id => wizardSelectedSlotsSeparate[id]);
                if (!allSelected) {
                    alert("Errore: Selezionare un orario per ciascuna prestazione!");
                    return;
                }
                // Map and sort
                wizardSelectedSlots = wizardSelectedServices.map(id => wizardSelectedSlotsSeparate[id]);
                wizardSelectedSlots.sort((a, b) => a.datetime.localeCompare(b.datetime));
            } else {
                if (!wizardSelectedSlots || wizardSelectedSlots.length === 0) {
                    alert("Errore: Selezionare uno slot orario!");
                    return;
                }
            }
            
            // Populate Step 4 summary
            const patientIdVal = document.getElementById('wiz-patient-id').value;
            const summaryPatient = document.getElementById('wiz-summary-patient');
            if (summaryPatient) {
                if (patientIdVal) {
                    const patients = DB.get('patients') || [];
                    const p = patients.find(pat => pat.id === parseInt(patientIdVal));
                    summaryPatient.innerText = p ? `${p.last_name} ${p.first_name} (${p.tax_code})` : '-- Seleziona un paziente --';
                } else {
                    summaryPatient.innerText = '-- Seleziona un paziente --';
                }
            }
            
            const summaryServicesList = document.getElementById('wiz-summary-services-list');
            if (summaryServicesList) {
                summaryServicesList.innerHTML = '';
                wizardSelectedSlots.forEach(s => {
                    const li = document.createElement('li');
                    li.innerText = s.service_name;
                    summaryServicesList.appendChild(li);
                });
            }
            
            const summaryDoctor = document.getElementById('wiz-summary-doctor');
            if (summaryDoctor) {
                const uniqueDoctors = [...new Set(wizardSelectedSlots.map(s => s.doctor_name))];
                summaryDoctor.innerText = uniqueDoctors.join(', ');
            }
            
            const summaryDatetime = document.getElementById('wiz-summary-datetime');
            if (summaryDatetime) {
                const dateStr = new Date(wizardSelectedSlots[0].datetime).toLocaleDateString('it-IT');
                const times = wizardSelectedSlots.map(s => s.time).join(' e ');
                summaryDatetime.innerText = `${dateStr} alle ore ${times}`;
            }
        }
    }
    
    wizardCurrentStep = nextStep;
    window.updateWizardStepsUI();
};

window.findWizardAvailableSlots = function(startDateStr, daysRange) {
    const medicalServices = DB.get('medical_services') || [];
    const appointments = DB.get('appointments') || [];
    const doctorAgendas = DB.get('doctor_agendas') || [];
    const doctorAgendaServices = DB.get('doctor_agenda_services') || [];
    const doctors = DB.get('doctors') || [];
    const staff = DB.get('staff') || [];

    // Read filters from DOM
    const timeOfDayFilterSelect = document.getElementById('wiz-filter-time-of-day');
    const weekdaysFilterSelect = document.getElementById('wiz-filter-weekdays');
    const timeOfDayFilter = timeOfDayFilterSelect ? timeOfDayFilterSelect.value : 'all';
    const weekdaysFilter = weekdaysFilterSelect ? weekdaysFilterSelect.value : 'all';

    // Map our selected service IDs to service objects
    const selectedServices = wizardSelectedServices.map(id => medicalServices.find(s => s.id === id)).filter(Boolean);
    if (selectedServices.length === 0) return [];

    const start = new Date(startDateStr);
    const results = [];
    const weekdays = ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];
    const weekdaysIT = ["Dom", "Lun", "Mar", "Mer", "Gio", "Ven", "Sab"];

    // Scan day by day
    for (let d = 0; d < daysRange; d++) {
        const checkDate = new Date(start.getTime());
        checkDate.setDate(start.getDate() + d);

        const dayOfWeek = checkDate.getDay();
        
        // Filter by weekdays
        if (weekdaysFilter === 'weekday' && (dayOfWeek === 0 || dayOfWeek === 6)) {
            continue; // Skip Sunday and Saturday
        }
        if (weekdaysFilter === 'saturday' && dayOfWeek !== 6) {
            continue; // Skip all except Saturday
        }
        if (dayOfWeek === 0) {
            continue; // Always skip Sunday (closed)
        }

        const yyyy = checkDate.getFullYear();
        const mm = String(checkDate.getMonth() + 1).padStart(2, '0');
        const dd = String(checkDate.getDate()).padStart(2, '0');
        const dateStr = `${yyyy}-${mm}-${dd}`;
        const dayName = weekdays[dayOfWeek];
        const dayNameIT = weekdaysIT[dayOfWeek];

        // Gather booked appointments for this date (scheduled only)
        const dayAppointments = appointments.filter(app => 
            app.appointment_datetime.startsWith(dateStr) && 
            app.status === 'scheduled'
        );

        // Scan every 15 minutes from 08:00 to 19:00
        const startMin = 8 * 60; // 08:00
        const endMin = 19 * 60;  // 19:00
        const step = 15;

        for (let timeInMins = startMin; timeInMins < endMin; timeInMins += step) {
            // Filter by time of day
            if (timeOfDayFilter === 'morning' && timeInMins >= 13 * 60) {
                continue; // Skip afternoon
            }
            if (timeOfDayFilter === 'afternoon' && timeInMins < 13 * 60) {
                continue; // Skip morning
            }
            const comboH = Math.floor(timeInMins / 60);
            const comboM = timeInMins % 60;
            const comboTimeStr = `${String(comboH).padStart(2, '0')}:${String(comboM).padStart(2, '0')}`;
            const comboDatetime = `${dateStr}T${comboTimeStr}`;

            let currentTimeInMins = timeInMins;
            let currentSlots = [];
            let possibleCombo = true;

            for (let i = 0; i < selectedServices.length; i++) {
                const service = selectedServices[i];
                
                // Determine duration
                let duration = 30; // default
                if (service.type === 'lis') {
                    duration = 15;
                }

                // Format current slot start time
                const h = Math.floor(currentTimeInMins / 60);
                const m = currentTimeInMins % 60;
                const timeStr = `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}`;
                const slotDatetime = `${dateStr}T${timeStr}`;

                // Check past date/time
                if (new Date(slotDatetime) <= new Date()) {
                    possibleCombo = false;
                    break;
                }

                if (service.type === 'lis') {
                    if (window.isDateTimeClosed(null, slotDatetime)) {
                        possibleCombo = false;
                        break;
                    }
                    // Check if laboratory is open (Mon-Fri, 08:00 to 13:00)
                    const isLabDay = checkDate.getDay() >= 1 && checkDate.getDay() <= 5;
                    const isLabTime = currentTimeInMins >= 8 * 60 && (currentTimeInMins + duration) <= 13 * 60;
                    if (!isLabDay || !isLabTime) {
                        possibleCombo = false;
                        break;
                    }

                    // Check if LIS slot is already booked (no doctor)
                    const isBooked = dayAppointments.some(app => 
                        app.doctor_id === null && 
                        window.compareDatetimes(app.appointment_datetime, slotDatetime)
                    );
                    if (isBooked) {
                        possibleCombo = false;
                        break;
                    }

                    currentSlots.push({
                        service_id: service.id,
                        service_name: service.name,
                        datetime: slotDatetime,
                        time: timeStr,
                        doctor_id: null,
                        doctor_name: "Laboratorio LIS",
                        duration: duration
                    });
                } else {
                    // Requires doctor or generic agenda
                    const activeGenericAgendas = doctorAgendas.filter(a => 
                        (a.doctor_id === null || a.doctor_id === undefined || a.doctor_id === '' || a.doctor_id === 'null') &&
                        dateStr >= a.start_date && 
                        dateStr <= a.end_date && 
                        a.active_days.split(',').includes(dayName) &&
                        doctorAgendaServices.some(as => as.agenda_id === a.id && as.service_id === service.id)
                    );
                    
                    let matchingGenericAgendas = [];
                    for (const a of activeGenericAgendas) {
                        if (window.isDateTimeClosed(null, slotDatetime)) continue;

                        let ranges = a.time_slots;
                        if (typeof ranges === 'string') {
                            try { ranges = JSON.parse(ranges); } catch(e) { ranges = null; }
                        }
                        if (!ranges || !Array.isArray(ranges)) {
                            ranges = [{ start: a.start_hour || '08:00', end: a.end_hour || '14:00' }];
                        }

                        let inHours = false;
                        for (const r of ranges) {
                            const startParts = r.start.split(':');
                            const endParts = r.end.split(':');
                            const rStartMin = parseInt(startParts[0]) * 60 + parseInt(startParts[1] || 0);
                            const rEndMin = parseInt(endParts[0]) * 60 + parseInt(endParts[1] || 0);

                            if (currentTimeInMins >= rStartMin && (currentTimeInMins + duration) <= rEndMin) {
                                inHours = true;
                                break;
                            }
                        }
                        if (!inHours) continue;

                        const agendaBooked = dayAppointments.some(app => 
                            app.agenda_id === a.id && 
                            window.compareDatetimes(app.appointment_datetime, slotDatetime)
                        );
                        if (agendaBooked) continue;

                        matchingGenericAgendas.push(a);
                    }
                    
                    if (matchingGenericAgendas.length > 0) {
                        currentSlots.push({
                            service_id: service.id,
                            service_name: service.name,
                            datetime: slotDatetime,
                            time: timeStr,
                            duration: duration,
                            matchingGenericAgendas: matchingGenericAgendas
                        });
                        currentTimeInMins += duration;
                        continue;
                    }

                    // Requires doctor
                    let candidateDoctors = [];
                    if (wizardSelectedDoctors && wizardSelectedDoctors.length > 0) {
                        candidateDoctors = doctors.filter(doc => wizardSelectedDoctors.includes(doc.id));
                    } else {
                        candidateDoctors = doctors;
                    }

                    let matchingDoctors = [];
                    for (const doc of candidateDoctors) {
                        const docAgendas = doctorAgendas.filter(a => a.doctor_id === doc.id);
                        const activeAgenda = docAgendas.find(a => 
                            dateStr >= a.start_date && 
                            dateStr <= a.end_date && 
                            a.active_days.split(',').includes(dayName)
                        );
                        if (!activeAgenda) continue;
                        if (window.isDateTimeClosed(doc.id, slotDatetime)) continue;

                        // Check if agenda manages service
                        const managesService = doctorAgendaServices.some(as => 
                            as.agenda_id === activeAgenda.id && 
                            as.service_id === service.id
                        );
                        if (!managesService) continue;

                        // Check working hours
                        let ranges = activeAgenda.time_slots;
                        if (typeof ranges === 'string') {
                            try { ranges = JSON.parse(ranges); } catch(e) { ranges = null; }
                        }
                        if (!ranges || !Array.isArray(ranges)) {
                            ranges = [{ start: activeAgenda.start_hour || '08:00', end: activeAgenda.end_hour || '14:00' }];
                        }

                        let inHours = false;
                        for (const r of ranges) {
                            const startParts = r.start.split(':');
                            const endParts = r.end.split(':');
                            const rStartMin = parseInt(startParts[0]) * 60 + parseInt(startParts[1] || 0);
                            const rEndMin = parseInt(endParts[0]) * 60 + parseInt(endParts[1] || 0);

                            if (currentTimeInMins >= rStartMin && (currentTimeInMins + duration) <= rEndMin) {
                                inHours = true;
                                break;
                            }
                        }
                        if (!inHours) continue;

                        // Check if doctor is free
                        const docBooked = dayAppointments.some(app => 
                            app.doctor_id === doc.id && 
                            window.compareDatetimes(app.appointment_datetime, slotDatetime)
                        );
                        if (docBooked) continue;

                        // Find staff name
                        const st = staff.find(s => s.id === doc.staff_id);
                        const docName = st ? `Dott. ${st.last_name} ${st.first_name}` : `Dott. ID ${doc.id}`;

                        matchingDoctors.push({
                            id: doc.id,
                            name: docName
                        });
                    }

                    if (matchingDoctors.length === 0) {
                        possibleCombo = false;
                        break;
                    }

                    currentSlots.push({
                        service_id: service.id,
                        service_name: service.name,
                        datetime: slotDatetime,
                        time: timeStr,
                        duration: duration,
                        matchingDoctors: matchingDoctors
                    });
                }

                // Advance time for consecutive slots
                currentTimeInMins += duration;
            }

            if (possibleCombo) {
                const nonLisSlots = currentSlots.filter(s => s.matchingDoctors || s.matchingGenericAgendas);
                
                let resolvedSlots = null;
                let isSameDoctor = false;

                if (nonLisSlots.length === 0) {
                    // LIS only
                    resolvedSlots = currentSlots.map(s => ({
                        service_id: s.service_id,
                        service_name: s.service_name,
                        datetime: s.datetime,
                        time: s.time,
                        doctor_id: null,
                        doctor_name: s.doctor_name,
                        duration: s.duration,
                        agenda_id: null
                    }));
                    isSameDoctor = true;
                } else {
                    // Try to find common doctor among doctor slots
                    const doctorSlots = nonLisSlots.filter(s => s.matchingDoctors);
                    let commonDoctor = null;
                    
                    if (doctorSlots.length > 0) {
                        const firstDocIds = doctorSlots[0].matchingDoctors.map(d => d.id);
                        for (const docId of firstDocIds) {
                            const canDoAll = doctorSlots.every(s => s.matchingDoctors.some(d => d.id === docId));
                            if (canDoAll) {
                                commonDoctor = doctorSlots[0].matchingDoctors.find(d => d.id === docId);
                                break;
                            }
                        }
                    }

                    const activeAgendas = DB.get('doctor_agendas') || [];

                    resolvedSlots = currentSlots.map(s => {
                        if (s.matchingGenericAgendas) {
                            const ag = s.matchingGenericAgendas[0];
                            return {
                                service_id: s.service_id,
                                service_name: s.service_name,
                                datetime: s.datetime,
                                time: s.time,
                                doctor_id: null,
                                doctor_name: ag.name,
                                duration: s.duration,
                                agenda_id: ag.id
                            };
                        } else if (s.matchingDoctors) {
                            const doc = commonDoctor || s.matchingDoctors[0];
                            const docAgenda = activeAgendas.find(a => a.doctor_id === doc.id);
                            return {
                                service_id: s.service_id,
                                service_name: s.service_name,
                                datetime: s.datetime,
                                time: s.time,
                                doctor_id: doc.id,
                                doctor_name: doc.name,
                                duration: s.duration,
                                agenda_id: docAgenda ? docAgenda.id : null
                            };
                        } else {
                            return {
                                service_id: s.service_id,
                                service_name: s.service_name,
                                datetime: s.datetime,
                                time: s.time,
                                doctor_id: s.doctor_id,
                                doctor_name: s.doctor_name,
                                duration: s.duration,
                                agenda_id: null
                            };
                        }
                    });
                    
                    isSameDoctor = (doctorSlots.length > 0 && commonDoctor !== null);
                }

                if (resolvedSlots) {
                    const totalDuration = resolvedSlots.reduce((sum, s) => sum + s.duration, 0);
                    
                    let label = `${dayNameIT} ${dd}/${mm} - `;
                    if (resolvedSlots.length === 1) {
                        label += resolvedSlots[0].time;
                    } else {
                        label += `${resolvedSlots[0].time} a ${resolvedSlots[resolvedSlots.length - 1].time}`;
                    }

                    results.push({
                        date: dateStr,
                        startTime: comboTimeStr,
                        slots: resolvedSlots,
                        isSameDoctor: isSameDoctor,
                        totalDuration: totalDuration,
                        label: label,
                        earliestDatetime: comboDatetime
                    });
                }
            }
        }
    }

    // Sort results:
    // 1. Same doctor combinations first
    // 2. Earliest date and time first
    // 3. Shorter duration first
    results.sort((a, b) => {
        if (a.isSameDoctor !== b.isSameDoctor) {
            return a.isSameDoctor ? -1 : 1;
        }
        const dateCompare = a.earliestDatetime.localeCompare(b.earliestDatetime);
        if (dateCompare !== 0) return dateCompare;
        return a.totalDuration - b.totalDuration;
    });

    return results;
};

window.setWizardBookingMode = function(mode) {
    wizardBookingMode = mode;
    
    // Highlight the active mode card
    const togetherCard = document.getElementById('wiz-mode-together');
    const separateCard = document.getElementById('wiz-mode-separate');
    
    if (mode === 'together') {
        if (togetherCard) {
            togetherCard.classList.add('active');
            togetherCard.style.borderColor = 'var(--primary)';
            togetherCard.style.background = 'rgba(37,99,235,0.02)';
        }
        if (separateCard) {
            separateCard.classList.remove('active');
            separateCard.style.borderColor = 'var(--border-color)';
            separateCard.style.background = 'var(--bg-surface)';
        }
    } else {
        if (togetherCard) {
            togetherCard.classList.remove('active');
            togetherCard.style.borderColor = 'var(--border-color)';
            togetherCard.style.background = 'var(--bg-surface)';
        }
        if (separateCard) {
            separateCard.classList.add('active');
            separateCard.style.borderColor = 'var(--primary)';
            separateCard.style.background = 'rgba(37,99,235,0.02)';
        }
    }
    
    // Clear selections to avoid mixing states
    wizardSelectedSlots = [];
    wizardSelectedSlotsSeparate = {};
    
    // Render slots for the new mode
    window.findAndRenderWizardSlots();
};

window.findAndRenderWizardSlots = function() {
    const slotsContainer = document.getElementById('wiz-slots-container');
    if (!slotsContainer) return;
    
    const dateFilter = document.getElementById('wiz-filter-start-date');
    if (dateFilter) {
        wizardStartDate = dateFilter.value;
    }
    if (!wizardStartDate) {
        wizardStartDate = new Date().toISOString().split('T')[0];
    }
    
    slotsContainer.innerHTML = '<div style="grid-column: 1 / -1; text-align: center; padding: 20px; color: var(--text-secondary);"><i data-lucide="loader" class="animate-spin" style="margin: 0 auto 10px; width: 24px; height: 24px;"></i> Calcolo slot disponibli in corso...</div>';
    if (typeof lucide !== 'undefined' && lucide.createIcons) lucide.createIcons();
    
    setTimeout(() => {
        if (wizardBookingMode === 'separate') {
            slotsContainer.innerHTML = '';
            // Reset grid layout so sections stack nicely
            slotsContainer.style.display = 'flex';
            slotsContainer.style.flexDirection = 'column';
            slotsContainer.style.gap = '20px';
            
            const medicalServices = DB.get('medical_services') || [];
            
            wizardSelectedServices.forEach(srvId => {
                const srv = medicalServices.find(s => s.id === srvId);
                if (!srv) return;
                
                // Create section card
                const section = document.createElement('div');
                section.className = 'card';
                section.style.padding = '15px';
                section.style.background = 'var(--bg-base)';
                section.style.border = '1px solid var(--border-color)';
                section.style.borderRadius = 'var(--radius-md)';
                section.style.marginBottom = '10px';
                
                // Header
                const header = document.createElement('h5');
                header.style.margin = '0 0 12px 0';
                header.style.fontSize = '0.9rem';
                header.style.fontWeight = '700';
                header.style.color = 'var(--primary)';
                header.style.display = 'flex';
                header.style.alignItems = 'center';
                header.style.gap = '6px';
                header.innerHTML = `<i data-lucide="check-square" style="width: 14px; height: 14px; color: var(--primary);"></i> ${srv.name}`;
                section.appendChild(header);
                
                // Grid
                const grid = document.createElement('div');
                grid.style.display = 'grid';
                grid.style.gridTemplateColumns = 'repeat(auto-fill, minmax(200px, 1fr))';
                grid.style.gap = '8px';
                grid.style.maxHeight = '250px';
                grid.style.overflowY = 'auto';
                grid.style.padding = '4px';
                
                // Fetch slots for this single service
                const savedServices = [...wizardSelectedServices];
                wizardSelectedServices = [srvId];
                const combos = window.findWizardAvailableSlots(wizardStartDate, wizardSearchRange);
                wizardSelectedServices = savedServices;
                
                if (combos.length === 0) {
                    grid.innerHTML = '<span style="grid-column: 1 / -1; font-size: 0.8rem; color: var(--text-secondary); font-style: italic; padding: 10px; text-align: center;">Nessuno slot disponibile per questo esame nel range selezionato.</span>';
                } else {
                    combos.slice(0, 30).forEach(combo => {
                        const slotObj = combo.slots[0];
                        const slotBtn = document.createElement('div');
                        slotBtn.className = 'free-slot-badge-wiz';
                        
                        // Style
                        slotBtn.style.padding = '8px 10px';
                        slotBtn.style.border = '1px solid var(--border-color)';
                        slotBtn.style.borderRadius = 'var(--radius-sm)';
                        slotBtn.style.cursor = 'pointer';
                        slotBtn.style.textAlign = 'center';
                        slotBtn.style.background = 'var(--bg-surface)';
                        slotBtn.style.fontSize = '0.78rem';
                        slotBtn.style.fontWeight = '600';
                        slotBtn.style.transition = 'all 0.2s ease';
                        
                        // Check if selected
                        const isSelected = wizardSelectedSlotsSeparate[srvId] && 
                            wizardSelectedSlotsSeparate[srvId].datetime === slotObj.datetime;
                        
                        if (isSelected) {
                            slotBtn.classList.add('active');
                            slotBtn.style.backgroundColor = 'var(--primary)';
                            slotBtn.style.color = 'white';
                            slotBtn.style.borderColor = 'var(--primary)';
                        }
                        
                        // Content
                        slotBtn.innerHTML = `
                            <div>${combo.label.split(' - ')[0]} ore ${slotObj.time}</div>
                            <div style="font-size: 0.68rem; font-weight: normal; margin-top: 2px; color: ${isSelected ? 'rgba(255,255,255,0.8)' : 'var(--text-secondary)'};">
                                ${slotObj.doctor_name.replace('Dott. ', '')}
                            </div>
                        `;
                        
                        slotBtn.addEventListener('click', async () => {
                            const prevSlot = wizardSelectedSlotsSeparate[srvId];
                            const targetAgendaId = slotObj.agenda_id || 1;
                            const lockRes = await window.lockSlot(targetAgendaId, slotObj.datetime, true);
                            if (!lockRes.success) {
                                alert(lockRes.message);
                                return;
                            }
                            
                            if (prevSlot) {
                                await window.lockSlot(prevSlot.agenda_id || 1, prevSlot.datetime, false);
                            }
                            
                            grid.querySelectorAll('.free-slot-badge-wiz').forEach(b => {
                                b.classList.remove('active');
                                b.style.backgroundColor = 'var(--bg-surface)';
                                b.style.color = 'var(--text-primary)';
                                b.style.borderColor = 'var(--border-color)';
                                const dl = b.querySelector('div:nth-child(2)');
                                if (dl) dl.style.color = 'var(--text-secondary)';
                            });
                            
                            slotBtn.classList.add('active');
                            slotBtn.style.backgroundColor = 'var(--primary)';
                            slotBtn.style.color = 'white';
                            slotBtn.style.borderColor = 'var(--primary)';
                            const dl = slotBtn.querySelector('div:nth-child(2)');
                            if (dl) dl.style.color = 'rgba(255,255,255,0.8)';
                            
                            wizardSelectedSlotsSeparate[srvId] = slotObj;
                        });
                        
                        grid.appendChild(slotBtn);
                    });
                }
                
                section.appendChild(grid);
                slotsContainer.appendChild(section);
            });
            
            if (typeof lucide !== 'undefined' && lucide.createIcons) lucide.createIcons();
        } else {
            // Together mode
            slotsContainer.innerHTML = '';
            slotsContainer.style.display = 'grid';
            slotsContainer.style.gridTemplateColumns = 'repeat(auto-fill, minmax(220px, 1fr))';
            slotsContainer.style.gap = '10px';
            
            const combos = window.findWizardAvailableSlots(wizardStartDate, wizardSearchRange);
            
            if (combos.length === 0) {
                slotsContainer.innerHTML = '<div style="grid-column: 1 / -1; text-align: center; padding: 20px; color: var(--warning); font-size: 0.85rem;">Nessuno slot consecutivo disponibile rilevato per le prestazioni selezionate nell\'intervallo temporale impostato.</div>';
                return;
            }
            
            combos.slice(0, 50).forEach(combo => {
                const btn = document.createElement('div');
                btn.className = 'free-slot-badge-wiz';
                btn.style.display = 'flex';
                btn.style.flexDirection = 'column';
                btn.style.alignItems = 'center';
                btn.style.justifyContent = 'center';
                btn.style.padding = '12px 10px';
                btn.style.borderRadius = 'var(--radius-md)';
                btn.style.border = '1px solid var(--border-color)';
                btn.style.cursor = 'pointer';
                btn.style.background = 'var(--bg-surface)';
                btn.style.transition = 'all 0.2s ease';
                
                // Check if combo is selected
                const isSelected = wizardSelectedSlots.length > 0 && 
                    wizardSelectedSlots[0].datetime === combo.slots[0].datetime &&
                    wizardSelectedSlots[wizardSelectedSlots.length - 1].datetime === combo.slots[combo.slots.length - 1].datetime;
                
                if (isSelected) {
                    btn.classList.add('active');
                    btn.style.backgroundColor = 'var(--primary)';
                    btn.style.color = 'white';
                    btn.style.borderColor = 'var(--primary)';
                }
                
                const timeLabel = document.createElement('span');
                timeLabel.style.fontWeight = '700';
                timeLabel.style.fontSize = '0.9rem';
                timeLabel.innerText = combo.label;
                btn.appendChild(timeLabel);
                
                const docLabel = document.createElement('span');
                docLabel.style.fontSize = '0.72rem';
                docLabel.style.marginTop = '4px';
                
                if (isSelected) {
                    docLabel.style.color = 'rgba(255,255,255,0.8)';
                } else {
                    docLabel.style.color = 'var(--text-secondary)';
                }
                
                const docsList = combo.slots.map(s => {
                    if (s.doctor_name === 'Laboratorio LIS') return 'Lab';
                    return s.doctor_name.replace('Dott. ', '');
                });
                const uniqueDocs = [...new Set(docsList)];
                docLabel.innerText = uniqueDocs.join(' + ');
                btn.appendChild(docLabel);
                
                if (combo.isSameDoctor && combo.slots.length > 1) {
                    const sameDocBadge = document.createElement('span');
                    sameDocBadge.style.fontSize = '0.65rem';
                    sameDocBadge.style.padding = '2px 6px';
                    sameDocBadge.style.borderRadius = '20px';
                    sameDocBadge.style.marginTop = '6px';
                    sameDocBadge.style.fontWeight = '600';
                    
                    if (isSelected) {
                        sameDocBadge.style.background = 'rgba(255,255,255,0.2)';
                        sameDocBadge.style.color = 'white';
                    } else {
                        sameDocBadge.style.background = 'rgba(16, 185, 129, 0.1)';
                        sameDocBadge.style.color = '#10b981';
                    }
                    sameDocBadge.innerText = 'Stesso Medico';
                    btn.appendChild(sameDocBadge);
                }
                
                btn.addEventListener('click', async () => {
                    const prevSlots = wizardSelectedSlots;
                    let lockSuccess = true;
                    const lockedInThisClick = [];
                    for (const slot of combo.slots) {
                        const targetAgendaId = slot.agenda_id || 1;
                        const lockRes = await window.lockSlot(targetAgendaId, slot.datetime, true);
                        if (!lockRes.success) {
                            alert("Attenzione: Uno o più slot del percorso sono temporaneamente bloccati da un altro operatore.");
                            lockSuccess = false;
                            break;
                        }
                        lockedInThisClick.push(slot);
                    }
                    
                    if (!lockSuccess) {
                        for (const slot of lockedInThisClick) {
                            await window.lockSlot(slot.agenda_id || 1, slot.datetime, false);
                        }
                        return;
                    }
                    
                    if (prevSlots && prevSlots.length > 0) {
                        for (const slot of prevSlots) {
                            await window.lockSlot(slot.agenda_id || 1, slot.datetime, false);
                        }
                    }
                    
                    slotsContainer.querySelectorAll('.free-slot-badge-wiz').forEach(b => {
                        b.classList.remove('active');
                        b.style.backgroundColor = 'var(--bg-surface)';
                        b.style.color = 'var(--text-primary)';
                        b.style.borderColor = 'var(--border-color)';
                        const dl = b.querySelector('span:nth-child(2)');
                        if (dl) dl.style.color = 'var(--text-secondary)';
                        const sdb = b.querySelector('span:nth-child(3)');
                        if (sdb) {
                            sdb.style.background = 'rgba(16, 185, 129, 0.1)';
                            sdb.style.color = '#10b981';
                        }
                    });
                    
                    btn.classList.add('active');
                    btn.style.backgroundColor = 'var(--primary)';
                    btn.style.color = 'white';
                    btn.style.borderColor = 'var(--primary)';
                    docLabel.style.color = 'rgba(255,255,255,0.8)';
                    const sdb = btn.querySelector('span:nth-child(3)');
                    if (sdb) {
                        sdb.style.background = 'rgba(255,255,255,0.2)';
                        sdb.style.color = 'white';
                    }
                    
                    wizardSelectedSlots = combo.slots;
                });
                
                slotsContainer.appendChild(btn);
            });
        }
    }, 50);
};

window.submitWizardBooking = function() {
    const patientIdVal = document.getElementById('wiz-patient-id').value;
    if (!patientIdVal) {
        alert("Errore: Selezionare o creare un paziente!");
        return;
    }
    const patientId = parseInt(patientIdVal);

    if (!wizardSelectedSlots || wizardSelectedSlots.length === 0) {
        alert("Errore: Selezionare una data e orario per procedere!");
        return;
    }

    const savedAppIds = [];
    const loggedUser = JSON.parse(localStorage.getItem('nextcare_logged_in_user') || '{}');
    const staffId = loggedUser.id || 6;

    // Create appointments
    wizardSelectedSlots.forEach(slot => {
        const appointmentFields = {
            patient_id: patientId,
            doctor_id: slot.doctor_id,
            agenda_id: slot.agenda_id || null,
            appointment_datetime: slot.datetime,
            duration_minutes: slot.duration,
            notes: "Prenotato tramite Assistente Smart CUP",
            status: 'scheduled'
        };

        const newApp = DB.insert('appointments', appointmentFields);
        savedAppIds.push(newApp.id);

        DB.insert('appointment_services', {
            appointment_id: newApp.id,
            service_id: slot.service_id
        });

        DB.logAudit(staffId, "BOOK_APPOINTMENT", "appointments", newApp.id, {
            doctor_id: slot.doctor_id,
            services_count: 1,
            wizard: true
        });
    });

    // Send confirmation email
    const p = DB.get('patients').find(pat => pat.id === patientId);
    const pName = p ? `${p.first_name} ${p.last_name}` : 'Paziente';
    
    const serviceNames = wizardSelectedSlots.map(s => s.service_name).join(', ');
    const examSummaries = wizardSelectedSlots.map(slot => 
        `- ${slot.service_name}: ${new Date(slot.datetime).toLocaleString('it-IT')} con ${slot.doctor_name}`
    ).join('\n\n');

    const services = DB.get('medical_services') || [];
    const notesArray = [];
    wizardSelectedSlots.forEach(slot => {
        const srv = services.find(s => s.id === slot.service_id);
        if (srv && srv.alert_note) {
            notesArray.push(`- ${srv.name}: ${srv.alert_note}`);
        }
    });
    const preparationNotes = notesArray.length > 0 ? `



Note di preparazione:

${notesArray.join('\n\n')}` : '';

    window.sendSimulatedEmail(patientId, 'new_appointment', {
        paziente: pName,
        data: new Date(wizardSelectedSlots[0].datetime).toLocaleString('it-IT'),
        prestazione: serviceNames,
        dettaglio: `Prenotazione multipla CUP Smart:

${examSummaries}${preparationNotes}`
    });

    alert("Prenotazione wizard registrata con successo!");
    
    // Close modal
    closeModal('modal-cup-wizard');
    
    // Clear and reset wizard state
    wizardSelectedServices = [];
    wizardSelectedDoctors = [];
    wizardSelectedSlots = [];
    wizardCurrentStep = 1;
    
    // Clear wizard inputs
    document.getElementById('wiz-search-service').value = '';
    document.getElementById('wiz-patient-id').value = '';
    document.getElementById('wiz-patient-search').value = '';
    
    // Refresh list views
    if (typeof renderAppointments === 'function') {
        renderAppointments();
    }
};


// --- 6. RENDERERS ---

// MODULE 1: DASHBOARD
function renderDashboard() {
    const patients = DB.get('patients');
    const appointments = DB.get('appointments');
    const samples = DB.get('lab_samples');
    const admissions = DB.get('admissions');
    
    document.getElementById('kpi-patients').innerText = patients.length;
    
    const today = new Date().toISOString().split('T')[0];
    const todayApps = appointments.filter(a => a.appointment_datetime.startsWith(today) && a.status === 'scheduled');
    document.getElementById('kpi-appointments').innerText = todayApps.length;
    
    const pendingSamples = samples.filter(s => s.status !== 'completed' && s.status !== 'rejected');
    document.getElementById('kpi-lis').innerText = pendingSamples.length;
    
    const activeAdmissions = admissions.filter(a => a.status === 'active');
    document.getElementById('kpi-admissions').innerText = activeAdmissions.length;

    const rehabCycles = DB.get('rehab_cycles') || [];
    const activeRehabCycles = rehabCycles.filter(rc => rc.status === 'active' || rc.status === 'in_progress');
    const completedRehabCycles = rehabCycles.filter(rc => rc.status === 'completed');
    const kpiRehabEl = document.getElementById('kpi-rehab-cycles');
    if (kpiRehabEl) kpiRehabEl.innerText = activeRehabCycles.length;

    const ssnRecipes = DB.get('ssn_recipes') || [];
    const kpiSsnEl = document.getElementById('kpi-ssn-recipes');
    if (kpiSsnEl) kpiSsnEl.innerText = ssnRecipes.length;

    // Populate "Monitoraggio Nuove Funzioni" elements
    const dashSsnRecipesCountEl = document.getElementById('dash-ssn-recipes-count');
    if (dashSsnRecipesCountEl) dashSsnRecipesCountEl.innerText = ssnRecipes.length;

    const totalTicket = ssnRecipes.reduce((sum, r) => sum + (Number(r.ticket_amount) || 0), 0);
    const dashSsnTicketAmountEl = document.getElementById('dash-ssn-ticket-amount');
    if (dashSsnTicketAmountEl) {
        dashSsnTicketAmountEl.innerText = `€ ${totalTicket.toLocaleString('it-IT', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
    }

    const totalRefund = ssnRecipes.reduce((sum, r) => sum + (Number(r.refund_amount) || 0), 0);
    const dashSsnRefundAmountEl = document.getElementById('dash-ssn-refund-amount');
    if (dashSsnRefundAmountEl) {
        dashSsnRefundAmountEl.innerText = `€ ${totalRefund.toLocaleString('it-IT', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
    }

    const dashRehabActiveCountEl = document.getElementById('dash-rehab-active-count');
    if (dashRehabActiveCountEl) dashRehabActiveCountEl.innerText = activeRehabCycles.length;

    const rehabSessions = DB.get('rehab_sessions') || [];
    const completedSessions = rehabSessions.filter(s => s.status === 'completed');
    const dashRehabSessionsCountEl = document.getElementById('dash-rehab-sessions-count');
    if (dashRehabSessionsCountEl) dashRehabSessionsCountEl.innerText = completedSessions.length;

    const dashRehabCompletedCountEl = document.getElementById('dash-rehab-completed-count');
    if (dashRehabCompletedCountEl) dashRehabCompletedCountEl.innerText = completedRehabCycles.length;
    
    // Render department chart
    const departments = { 'Cardiologia': 0, 'Ortopedia': 0, 'Chirurgia': 0, 'Medicina Int.': 0 };
    activeAdmissions.forEach(adm => {
        if (adm.department === 'Cardiologia') departments['Cardiologia']++;
        else if (adm.department === 'Ortopedia') departments['Ortopedia']++;
        else if (adm.department.includes('Chirurgia')) departments['Chirurgia']++;
        else departments['Medicina Int.']++;
    });
    
    if (activeAdmissions.length === 0) {
        departments['Cardiologia'] = 3; departments['Ortopedia'] = 1; departments['Chirurgia'] = 2; departments['Medicina Int'] = 4;
    }
    
    const maxVal = Math.max(...Object.values(departments), 1);
    const chartDiv = document.getElementById('department-chart');
    chartDiv.innerHTML = '';
    
    Object.keys(departments).forEach(dept => {
        const val = departments[dept];
        const percentage = Math.round((val / maxVal) * 100);
        
        const wrapper = document.createElement('div');
        wrapper.className = 'chart-bar-wrapper';
        wrapper.innerHTML = `
            <div class="chart-bar-fill" style="height: ${percentage}%" data-value="${val}"></div>
            <div class="chart-bar-label">${dept}</div>
        `;
        chartDiv.appendChild(wrapper);
    });

    // --- Saturation Dashboard Elements ---
    const todayStr = new Date().toISOString().split('T')[0];
    const samplesToday = samples.filter(s => {
        const dt = s.collected_at || s.created_at;
        return dt && dt.startsWith(todayStr);
    });
    const labSaturation = Math.min(100, Math.round((samplesToday.length / 20) * 100));
    
    const satVal = document.getElementById('lab-saturation-value');
    if (satVal) satVal.innerText = `${labSaturation}%`;
    const satBar = document.getElementById('lab-saturation-bar');
    if (satBar) satBar.style.width = `${labSaturation}%`;
    
    const breakdownDiv = document.getElementById('lab-tubes-breakdown');
    if (breakdownDiv) {
        breakdownDiv.innerHTML = '';
        const counts = {};
        samplesToday.forEach(s => {
            counts[s.sample_type] = (counts[s.sample_type] || 0) + 1;
        });
        
        if (samplesToday.length === 0) {
            breakdownDiv.innerHTML = '<span class="text-muted" style="grid-column: span 2; text-align: center; font-size: 0.75rem;">Nessuna provetta raccolta oggi.</span>';
        } else {
            for (const [type, count] of Object.entries(counts)) {
                breakdownDiv.innerHTML += `
                    <div style="display:flex; justify-content:space-between; background:var(--bg-base); padding:6px; border-radius:4px; border:1px solid var(--border-color);">
                        <span style="overflow:hidden; text-overflow:ellipsis; white-space:nowrap;" title="${type}">${type}</span>
                        <strong>${count}</strong>
                    </div>
                `;
            }
        }
        const totTubes = document.getElementById('lab-tubes-total');
        if (totTubes) totTubes.innerText = samplesToday.length;
    }

    // Pie chart LIS
    const statusCounts = { collected: 0, processing: 0, to_validate: 0, validated: 0, completed: 0 };
    samples.forEach(s => {
        if (statusCounts[s.status] !== undefined) statusCounts[s.status]++;
    });
    
    const pieCanvas = document.getElementById('lis-pie-canvas');
    if (pieCanvas) {
        const ctx = pieCanvas.getContext('2d');
        ctx.clearRect(0, 0, pieCanvas.width, pieCanvas.height);
        
        const total = Object.values(statusCounts).reduce((a, b) => a + b, 0);
        const colors = {
            collected: '#3b82f6',
            processing: '#eab308',
            to_validate: '#f97316',
            validated: '#10b981',
            completed: '#8b5cf6'
        };
        
        const labels = {
            collected: 'Accettati',
            processing: 'In Corso',
            to_validate: 'Da Validare',
            validated: 'Validati',
            completed: 'Refertati'
        };
        
        let startAngle = 0;
        const centerX = pieCanvas.width / 2;
        const centerY = pieCanvas.height / 2;
        const radius = Math.min(centerX, centerY) - 5;
        
        if (total === 0) {
            ctx.fillStyle = '#e2e8f0';
            ctx.beginPath();
            ctx.arc(centerX, centerY, radius, 0, Math.PI * 2);
            ctx.fill();
            ctx.fillStyle = '#64748b';
            ctx.font = '10px sans-serif';
            ctx.textAlign = 'center';
            ctx.fillText('Nessun campione', centerX, centerY + 3);
        } else {
            for (const [status, count] of Object.entries(statusCounts)) {
                if (count === 0) continue;
                const sliceAngle = (count / total) * Math.PI * 2;
                
                ctx.fillStyle = colors[status];
                ctx.beginPath();
                ctx.moveTo(centerX, centerY);
                ctx.arc(centerX, centerY, radius, startAngle, startAngle + sliceAngle);
                ctx.closePath();
                ctx.fill();
                
                startAngle += sliceAngle;
            }
        }
        
        const legendDiv = document.getElementById('lis-pie-legend');
        if (legendDiv) {
            legendDiv.innerHTML = '';
            for (const [status, count] of Object.entries(statusCounts)) {
                legendDiv.innerHTML += `
                    <div style="display:flex; align-items:center; gap:6px;">
                        <span style="display:inline-block; width:10px; height:10px; background:${colors[status]}; border-radius:2px;"></span>
                        <span>${labels[status]}: <strong>${count}</strong></span>
                    </div>
                `;
            }
        }
    }

    // branch saturation
    const branchContainer = document.getElementById('branch-saturation-container');
    if (branchContainer) {
        branchContainer.innerHTML = '';
        const doctors = DB.get('doctors') || [];
        const appServices = DB.get('appointment_services') || [];
        const services = DB.get('medical_services') || [];
        
        const branchAppCounts = {};
        appointments.forEach(app => {
            if (app.status !== 'scheduled') return;
            const doc = doctors.find(d => d.id === app.doctor_id);
            const branch = doc ? doc.specialization : 'Laboratorio';
            branchAppCounts[branch] = (branchAppCounts[branch] || 0) + 1;
        });
        
        const branches = ['Cardiologia', 'Radiologia', 'Chirurgia Generale'];
        branches.forEach(b => {
            if (branchAppCounts[b] === undefined) branchAppCounts[b] = 0;
        });
        
        const maxCapacity = 10;
        for (const [branch, count] of Object.entries(branchAppCounts)) {
            const sat = Math.min(100, Math.round((count / maxCapacity) * 100));
            let barColor = 'var(--primary)';
            if (sat > 80) barColor = 'var(--danger)';
            else if (sat > 50) barColor = 'var(--warning)';
            
            branchContainer.innerHTML += `
                <div style="background: var(--bg-surface); padding:10px; border-radius:6px; border:1px solid var(--border-color);">
                    <div style="display:flex; justify-content:space-between; font-size:0.8rem; font-weight:600; margin-bottom:4px;">
                        <span>${branch}</span>
                        <span>${sat}% (${count}/${maxCapacity})</span>
                    </div>
                    <div style="background: var(--bg-base); height:6px; border-radius:3px; overflow:hidden;">
                        <div style="background:${barColor}; height:100%; width:${sat}%"></div>
                    </div>
                </div>
            `;
        }
    }

    // Render LIS instruments saturation grid
    const saturationGridDiv = document.getElementById('lis-instruments-saturation-grid');
    if (saturationGridDiv) {
        saturationGridDiv.innerHTML = '';
        const equipmentList = DB.get('equipment') || [];
        const activeInstruments = equipmentList.filter(e => e.type === 'LIS' && e.status === 'active');
        
        const tests = DB.get('lab_tests') || [];
        const services = DB.get('medical_services') || [];
        
        const activeSampleStatuses = ['collected', 'processing'];
        const activeSampleIds = new Set(
            samples.filter(s => activeSampleStatuses.includes(s.status)).map(s => s.id)
        );
        
        if (activeInstruments.length === 0) {
            saturationGridDiv.innerHTML = `
                <div style="grid-column: 1 / -1; text-align: center; color: var(--text-secondary); padding: 40px 0;">
                    <i data-lucide="info" style="width: 32px; height: 32px; display: block; margin: 0 auto 12px; opacity: 0.5; color: var(--text-secondary);"></i>
                    <p style="margin: 0; font-size: 0.9rem; font-weight: 500;">Nessun analizzatore LIS configurato o attivo nel sistema.</p>
                    <p style="margin: 4px 0 0; font-size: 0.8rem; opacity: 0.7;">Aggiungi o attiva gli strumenti nel modulo Cliniche & Asset.</p>
                </div>
            `;
        } else {
            activeInstruments.forEach(inst => {
                const pendingTests = tests.filter(t => {
                    if (!activeSampleIds.has(t.sample_id)) return false;
                    const isPending = t.result_value === null || t.result_value === undefined || String(t.result_value).trim() === '';
                    if (!isPending) return false;
                    
                    const srv = services.find(s => s.id === t.service_id);
                    return srv && srv.instrument_id === inst.id;
                });
                
                const capacity = 10;
                const load = pendingTests.length;
                const percentage = Math.min(100, Math.round((load / capacity) * 100));
                
                let barColor = '#10b981'; // Emerald
                let textColor = '#10b981';
                let bgTint = 'rgba(16, 185, 129, 0.1)';
                let glowColor = 'rgba(16, 185, 129, 0.15)';
                
                if (percentage >= 80) {
                    barColor = '#ef4444'; // Red
                    textColor = '#ef4444';
                    bgTint = 'rgba(239, 68, 68, 0.1)';
                    glowColor = 'rgba(239, 68, 68, 0.15)';
                } else if (percentage >= 50) {
                    barColor = '#f59e0b'; // Amber
                    textColor = '#f59e0b';
                    bgTint = 'rgba(245, 158, 11, 0.1)';
                    glowColor = 'rgba(245, 158, 11, 0.15)';
                }
                
                const instDiv = document.createElement('div');
                instDiv.style.background = 'var(--bg-surface)';
                instDiv.style.border = '1px solid var(--border-color)';
                instDiv.style.borderRadius = 'var(--radius-lg)';
                instDiv.style.padding = '20px';
                instDiv.style.display = 'flex';
                instDiv.style.flexDirection = 'column';
                instDiv.style.gap = '16px';
                instDiv.style.boxShadow = 'var(--shadow-sm)';
                instDiv.style.transition = 'transform 0.2s, box-shadow 0.2s';
                
                instDiv.onmouseover = () => {
                    instDiv.style.transform = 'translateY(-2px)';
                    instDiv.style.boxShadow = `0 6px 16px ${glowColor}`;
                };
                instDiv.onmouseout = () => {
                    instDiv.style.transform = 'translateY(0)';
                    instDiv.style.boxShadow = 'var(--shadow-sm)';
                };
                
                instDiv.innerHTML = `
                    <div style="display: flex; justify-content: space-between; align-items: flex-start;">
                        <div style="display: flex; align-items: center; gap: 12px;">
                            <div style="width: 44px; height: 44px; border-radius: var(--radius-md); background: rgba(14, 165, 233, 0.1); color: #0ea5e9; display: flex; align-items: center; justify-content: center; border: 1px solid rgba(14, 165, 233, 0.15);">
                                <i data-lucide="cpu" style="width: 22px; height: 22px;"></i>
                            </div>
                            <div>
                                <h3 style="font-size: 0.95rem; font-weight: 700; margin: 0; color: var(--text-primary);">${inst.name}</h3>
                                <span style="font-size: 0.75rem; color: var(--text-secondary); font-family: monospace;">Mod: ${inst.model || inst.code || 'N/A'}</span>
                            </div>
                        </div>
                        <span style="display: inline-flex; align-items: center; gap: 6px; font-size: 0.7rem; font-weight: 600; color: #10b981; background: rgba(16, 185, 129, 0.1); padding: 4px 10px; border-radius: 20px; border: 1px solid rgba(16, 185, 129, 0.15);">
                            <span style="width: 6px; height: 6px; border-radius: 50%; background: #10b981; display: inline-block; box-shadow: 0 0 8px #10b981;"></span>
                            Online
                        </span>
                    </div>
                    
                    <div>
                        <div style="display: flex; justify-content: space-between; font-size: 0.75rem; font-weight: 600; margin-bottom: 6px; color: var(--text-secondary);">
                            <span>Carico Elaborazione</span>
                            <span style="color: ${textColor}; font-weight: 700;">${load} / ${capacity} Esami (${percentage}%)</span>
                        </div>
                        <div style="background: var(--bg-base); height: 10px; border-radius: 5px; overflow: hidden; border: 1px solid var(--border-color); position: relative;">
                            <div style="background: ${barColor}; height: 100%; width: ${percentage}%; transition: width 0.6s cubic-bezier(0.4, 0, 0.2, 1); border-radius: 5px;"></div>
                        </div>
                    </div>
                    
                    <div style="display: grid; grid-template-columns: repeat(2, 1fr); gap: 12px; border-top: 1px solid var(--border-color); padding-top: 14px; font-size: 0.75rem;">
                        <div>
                            <div style="color: var(--text-secondary); margin-bottom: 2px;">Coda Lavoro</div>
                            <strong style="font-size: 0.95rem; color: var(--text-primary); font-family: monospace;">${load} test in attesa</strong>
                        </div>
                        <div>
                            <div style="color: var(--text-secondary); margin-bottom: 2px;">Tempo d'Attesa Est.</div>
                            <strong style="font-size: 0.95rem; color: var(--text-primary); font-family: monospace;">${load > 0 ? (load * 3) + ' min' : 'Tempo reale'}</strong>
                        </div>
                    </div>
                `;
                
                saturationGridDiv.appendChild(instDiv);
            });
        }
        if (window.lucide) window.lucide.createIcons();
    }
}

// MODULE 2: PATIENTS (CORE)
function renderPatients(query = '') {
    const patients = DB.get('patients');
    const consents = DB.get('patient_consents');
    const appointments = DB.get('appointments') || [];
    const studies = DB.get('radiology_studies') || [];
    const tbody = document.querySelector('#patients-table tbody');
    tbody.innerHTML = '';
    
    const roleSelect = document.getElementById('user-role-select');
    const currentRole = roleSelect ? roleSelect.value : 'admin';
    
    const filtered = patients.filter(p => {
        const matchesSearch = `${p.first_name} ${p.last_name}`.toLowerCase().includes(query) || p.tax_code.toLowerCase().includes(query);
        if (!matchesSearch) return false;
        
        if (currentRole === 'doctor_1') {
            const hasApp = appointments.some(app => app.patient_id === p.id && app.doctor_id === 1);
            const hasStudy = studies.some(st => st.patient_id === p.id && st.doctor_id === 1);
            return hasApp || hasStudy;
        } else if (currentRole === 'doctor_2') {
            const hasApp = appointments.some(app => app.patient_id === p.id && app.doctor_id === 2);
            const hasStudy = studies.some(st => st.patient_id === p.id && st.doctor_id === 2);
            return hasApp || hasStudy;
        }
        return true;
    });
    
    const paginated = window.setupTablePagination('patients-table', filtered, () => renderPatients(query));

    if (filtered.length === 0) {
        tbody.innerHTML = `<tr><td colspan="6" style="text-align: center;" class="text-muted">Nessun paziente trovato</td></tr>`;
        return;
    }
    
    paginated.forEach(p => {
        const consent = consents.find(c => c.patient_id === p.id) || { marketing_consent: 0, profiling_consent: 0 };
        const age = new Date().getFullYear() - new Date(p.birth_date).getFullYear();
        
        const tr = document.createElement('tr');
        tr.innerHTML = `
            <td>
                <div style="font-weight: 600;">${p.last_name} ${p.first_name}</div>
                <div style="font-size: 0.75rem; color: var(--text-secondary)">UUID: ${p.uuid.substring(0,8)}...</div>
            </td>
            <td><code style="font-size: 0.85rem; font-weight: 600;">${p.tax_code}</code></td>
            <td>${p.gender} / ${age} anni</td>
            <td>
                <div>${p.phone || '-'}</div>
                <div style="font-size: 0.8rem; color: var(--text-secondary)">${p.email || '-'}</div>
            </td>
            <td>
                <span class="badge badge-success">Clinico</span>
                ${consent.marketing_consent ? '<span class="badge badge-info">Marketing</span>' : ''}
                ${consent.profiling_consent ? '<span class="badge badge-purple">Profilazione</span>' : ''}
            </td>
            <td>
                <div class="row-actions">
                    <button class="btn btn-secondary btn-sm" onclick="openPatientDetail(${p.id})">
                        <i data-lucide="folder-open"></i> Cartella & Audit
                    </button>
                    <button class="btn btn-secondary btn-sm" onclick="window.openEditPatientModal(${p.id})">
                        <i data-lucide="edit"></i>
                    </button>
                    ${p.portal_active ? `
                    <button class="btn btn-success btn-sm" onclick="window.navigateToPatientPortal('${p.cf || p.tax_code}')" title="Apri Portale Paziente">
                        <i data-lucide="external-link"></i>
                    </button>
                    ` : ''}
                </div>
            </td>
        `;
        tbody.appendChild(tr);
    });
    if (window.lucide) window.lucide.createIcons();
}

// MODULE 3: SERVICES (CONFIGURA PRESTAZIONI) WITH FILTERS
function initServiceFilters() {
    const search = document.getElementById('filter-srv-search');
    const type = document.getElementById('filter-srv-type');
    const branch = document.getElementById('filter-srv-branch');
    const minPrice = document.getElementById('filter-srv-price-min');
    const maxPrice = document.getElementById('filter-srv-price-max');

    if (!search) return;

    const applyFilters = () => {
        window.srvCurrentPage = 1;
        filterServicesRealtime();
    };
    
    search.addEventListener('input', applyFilters);
    type.addEventListener('change', applyFilters);
    branch.addEventListener('change', applyFilters);
    minPrice.addEventListener('input', applyFilters);
    maxPrice.addEventListener('input', applyFilters);

    populateBranchFilter();
}

window.srvCurrentPage = 1;
window.srvPageLimit = 20;

window.changeServicePageLimit = function(limit) {
    if (limit === 'all') {
        window.srvPageLimit = 999999;
    } else {
        window.srvPageLimit = parseInt(limit);
    }
    window.srvCurrentPage = 1;
    filterServicesRealtime();
};

window.changeServicePage = function(pageNum) {
    window.srvCurrentPage = pageNum;
    filterServicesRealtime();
};

function populateBranchFilter() {
    const services = DB.get('medical_services');
    const branchSelect = document.getElementById('filter-srv-branch');
    if (!branchSelect) return;
    
    const branches = [...new Set(services.map(s => s.branch).filter(Boolean))];
    branchSelect.innerHTML = '<option value="">Tutte le branche</option>';
    branches.forEach(b => {
        branchSelect.innerHTML += `<option value="${b}">${b}</option>`;
    });
}

function filterServicesRealtime() {
    const searchVal = document.getElementById('filter-srv-search').value.toLowerCase().trim();
    const typeVal = document.getElementById('filter-srv-type').value;
    const branchVal = document.getElementById('filter-srv-branch').value;
    const minPriceVal = parseFloat(document.getElementById('filter-srv-price-min').value || 0);
    const maxPriceVal = parseFloat(document.getElementById('filter-srv-price-max').value || 999999);

    const services = DB.get('medical_services');
    const clinics = DB.get('clinics');
    const equipment = DB.get('equipment');
    const scTypes = DB.get('sample_collection_types') || [];
    const tbody = document.querySelector('#services-table tbody');
    tbody.innerHTML = '';

    const filtered = services.filter(s => {
        const matchesSearch = s.name.toLowerCase().includes(searchVal) || (s.code && s.code.toLowerCase().includes(searchVal));
        const matchesType = !typeVal || s.type === typeVal;
        const matchesBranch = !branchVal || s.branch === branchVal;
        const price = s.price || 0;
        const matchesPrice = price >= minPriceVal && price <= maxPriceVal;
        return matchesSearch && matchesType && matchesBranch && matchesPrice;
    });

    const totalPages = Math.ceil(filtered.length / window.srvPageLimit) || 1;
    if (window.srvCurrentPage > totalPages) {
        window.srvCurrentPage = totalPages;
    }
    const startIndex = (window.srvCurrentPage - 1) * window.srvPageLimit;
    const endIndex = Math.min(startIndex + window.srvPageLimit, filtered.length);
    const paginated = filtered.slice(startIndex, endIndex);

    if (filtered.length === 0) {
        tbody.innerHTML = `<tr><td colspan="9" style="text-align: center;" class="text-muted">Nessuna prestazione corrisponde ai filtri impostati</td></tr>`;
        const infoEl = document.getElementById('srv-pagination-info');
        if (infoEl) infoEl.innerText = 'Nessun elemento';
        const buttonsContainer = document.getElementById('srv-pagination-buttons');
        if (buttonsContainer) buttonsContainer.innerHTML = '';
        return;
    }

    paginated.forEach(s => {
        const c = clinics.find(cli => cli.id === s.clinic_id);
        const eq = equipment.find(e => e.id === s.equipment_id);
        
        let typeBadge = '';
        if (s.type === 'visita') typeBadge = '<span class="badge badge-info">Visita</span>';
        else if (s.type === 'lis') typeBadge = '<span class="badge badge-purple">LIS</span>';
        else if (s.type === 'ris') typeBadge = '<span class="badge badge-success">RIS</span>';
        else if (s.type === 'pacchetto') typeBadge = '<span class="badge badge-warning" style="background:#f59e0b; color:#fff;">Pacchetto</span>';

        let detailText = '';
        if (s.type === 'lis') {
            detailText = s.sample_type ? window.getTubeBadgeHtml(s.sample_type) : '';
            if (s.sample_collection_type_id) {
                const scType = scTypes.find(sc => sc.id === s.sample_collection_type_id);
                if (scType) {
                    detailText += ` <span class="badge badge-purple" style="margin-left: 4px; font-weight: normal;">${scType.name}</span>`;
                }
            }
            if (s.reference_range) detailText += ` <code>Rif: ${s.reference_range} ${s.unit}</code>`;
        } else if (s.type === 'pacchetto') {
            let packageItems = s.package_items || [];
            if (typeof packageItems === 'string') {
                try {
                    packageItems = JSON.parse(packageItems);
                } catch (e) {
                    packageItems = [];
                }
            }
            if (!Array.isArray(packageItems)) {
                packageItems = [];
            }
            const includedNames = packageItems.map(itemId => {
                const found = services.find(x => x.id === itemId);
                return found ? found.name : `Esame ${itemId}`;
            });
            detailText = `<span style="font-size: 0.75rem; color: var(--text-secondary); font-style: italic;">Comprende (${includedNames.length}): ${includedNames.join(', ')}</span>`;
        } else {
            detailText = c ? c.name : '';
            if (eq) detailText += ` / ${eq.name}`;
            if (s.type === 'ris') {
                if (s.dose_class_id) {
                    const dc = (DB.get('dose_classes') || []).find(d => d.id === s.dose_class_id);
                    if (dc) {
                        detailText += `<br><span class="badge badge-secondary" style="font-size: 0.72rem; margin-top: 4px; display: inline-block; background-color: var(--text-secondary); color: #fff;">Dose: Classe ${dc.code}</span>`;
                    }
                } else {
                    detailText += `<br><span class="badge badge-warning" style="font-size: 0.72rem; margin-top: 4px; display: inline-block; background-color: #f59e0b; color: #fff;">Dose: Non Classificato</span>`;
                }
            }
        }

        const tr = document.createElement('tr');
        tr.innerHTML = `
            <td style="text-align: center;"><input type="checkbox" class="service-select-checkbox" data-service-id="${s.id}" onclick="window.updateSelectAllServicesHeader()"></td>
            <td><code style="font-weight: 700;">${s.code || '-'}</code></td>
            <td><strong>${s.name}</strong></td>
            <td>${typeBadge}</td>
            <td>${s.branch || '<span class="text-muted">-</span>'}</td>
            <td><span class="badge badge-secondary" style="font-family: monospace; font-size: 0.75rem; padding: 4px 6px;">${s.profit_center || '--'}</span></td>
            <td><strong>€ ${(s.price || 0.0).toFixed(2)}</strong></td>
            <td>${detailText}</td>
            <td>
                <div class="row-actions">
                    <button class="btn btn-primary btn-sm" onclick="openEditServiceModal(${s.id})">Modifica</button>
                    <button class="btn btn-secondary btn-sm" onclick="deleteService(${s.id})">Rimuovi</button>
                </div>
            </td>
        `;
        tbody.appendChild(tr);
    });

    const master = document.getElementById('select-all-services');
    if (master) master.checked = false;

    if (window.lucide) window.lucide.createIcons();

    // Update pagination info text
    const infoEl = document.getElementById('srv-pagination-info');
    if (infoEl) {
        infoEl.innerText = `Mostrati ${startIndex + 1}-${endIndex} di ${filtered.length}`;
    }

    // Generate page buttons
    const buttonsContainer = document.getElementById('srv-pagination-buttons');
    if (buttonsContainer) {
        buttonsContainer.innerHTML = '';
        
        const createPageBtn = (pageNum, text, isActive, isDisabled) => {
            const btn = document.createElement('button');
            btn.className = `btn ${isActive ? 'btn-primary' : 'btn-secondary'}`;
            btn.style.padding = '4px 10px';
            btn.style.fontSize = '0.75rem';
            btn.style.minWidth = '30px';
            btn.style.margin = '0 2px';
            btn.disabled = isDisabled;
            btn.innerText = text;
            btn.onclick = () => window.changeServicePage(pageNum);
            return btn;
        };

        // First & Prev buttons
        buttonsContainer.appendChild(createPageBtn(1, '<<', false, window.srvCurrentPage === 1));
        buttonsContainer.appendChild(createPageBtn(window.srvCurrentPage - 1, '<', false, window.srvCurrentPage === 1));

        // Page numbers
        let startPage = Math.max(1, window.srvCurrentPage - 2);
        let endPage = Math.min(totalPages, startPage + 4);
        if (endPage - startPage < 4) {
            startPage = Math.max(1, endPage - 4);
        }

        for (let i = startPage; i <= endPage; i++) {
            buttonsContainer.appendChild(createPageBtn(i, i.toString(), i === window.srvCurrentPage, false));
        }

        // Next & Last buttons
        buttonsContainer.appendChild(createPageBtn(window.srvCurrentPage + 1, '>', false, window.srvCurrentPage === totalPages));
        buttonsContainer.appendChild(createPageBtn(totalPages, '>>', false, window.srvCurrentPage === totalPages));
    }
}

function renderServices(query = '') {
    filterServicesRealtime();
}

function deleteService(srvId) {
    if (!confirm("Sei sicuro di voler rimuovere questa prestazione configurata?")) return;
    const services = DB.get('medical_services');
    const filtered = services.filter(s => s.id !== srvId);
    DB.set('medical_services', filtered);
    DB.logAudit(6, "DELETE_SERVICE", "medical_services", srvId, {});
    renderServices();
    populateBranchFilter();
}

window.populateProfitCentersDropdown = function(selectId, addNoneOption = true, noneText = "-- Seleziona Profit Center --") {
    const select = document.getElementById(selectId);
    if (!select) return;
    select.innerHTML = '';
    
    if (addNoneOption) {
        const opt = document.createElement('option');
        opt.value = '';
        opt.innerText = noneText;
        select.appendChild(opt);
    }
    
    const pcs = DB.get('profit_centers') || [];
    pcs.forEach(pc => {
        const opt = document.createElement('option');
        opt.value = pc.name;
        opt.innerText = pc.name;
        select.appendChild(opt);
    });
};

window.openEditServiceModal = function(serviceId) {
    const services = DB.get('medical_services');
    const s = services.find(sv => sv.id === serviceId);
    if (!s) return;

    document.getElementById('srv-edit-id').value = s.id;
    document.getElementById('srv-code').value = s.code || '';
    document.getElementById('srv-price').value = s.price || '';
    document.getElementById('srv-name').value = s.name;
    document.getElementById('srv-type').value = s.type;
    
    window.populateProfitCentersDropdown('srv-profit-center');
    document.getElementById('srv-profit-center').value = s.profit_center || '';

    document.getElementById('srv-alert-note').value = s.alert_note || '';

    toggleServiceFormFields(s.type);
    
    if (s.type === 'visita' || s.type === 'ris') {
        document.getElementById('srv-branch').value = s.branch || '';
        document.getElementById('srv-clinic').value = s.clinic_id || '';
    }
    if (s.type === 'ris') {
        document.getElementById('srv-equip').value = s.equipment_id || '';
        window.populateDoseClassesDropdown('srv-dose-class', s.dose_class_id || window.guessDoseClassIdByName(s.name));
    }
    if (s.type === 'pacchetto') {
        window.populatePackageItemsContainer(s.package_items || []);
    }
    if (s.type === 'lis') {
        populateTubeTypesDropdown('srv-sample');
        const selectEl = document.getElementById('srv-sample');
        if (selectEl) {
            const val = (s.sample_type || '').trim().toLowerCase();
            let matchedValue = '';
            for (let option of selectEl.options) {
                if (option.value.trim().toLowerCase() === val) {
                    matchedValue = option.value;
                    break;
                }
            }
            selectEl.value = matchedValue;
        }
        window.populateSampleCollectionTypesDropdown('srv-sample-collection-type');
        document.getElementById('srv-sample-collection-type').value = s.sample_collection_type_id || '';
        window.populateLisInstrumentsDropdown('srv-lis-instrument');
        document.getElementById('srv-lis-instrument').value = s.instrument_id || '';
        document.getElementById('srv-ref-range').value = s.reference_range || '';
        document.getElementById('srv-unit').value = s.unit || '';
        document.getElementById('srv-is-microbiology').checked = !!s.is_microbiology;
        
        const container = document.getElementById('srv-lis-parameters-container');
        if (container) {
            container.innerHTML = '';
            if (s.parameters && s.parameters.length > 0) {
                s.parameters.forEach(p => {
                    window.addParameterRow(p.name, p.reference_range, p.unit, p.result_type || 'ALFABETICO');
                });
            }
        }
    }

    document.getElementById('service-modal-title').innerText = "Modifica Prestazione Configurata";
    document.getElementById('btn-service-submit').innerText = "Salva Modifiche";

    openModal('modal-add-service');
};

window.openCreateServiceModal = function() {
    document.getElementById('srv-edit-id').value = '';
    document.getElementById('form-add-service').reset();
    
    window.populateProfitCentersDropdown('srv-profit-center');
    document.getElementById('srv-profit-center').value = '';
    
    window.populateDoseClassesDropdown('srv-dose-class');

    toggleServiceFormFields('visita');

    const container = document.getElementById('srv-lis-parameters-container');
    if (container) container.innerHTML = '';

    document.getElementById('service-modal-title').innerText = "Configura Nuova Prestazione";
    document.getElementById('btn-service-submit').innerText = "Salva Prestazione";

    openModal('modal-add-service');
};

window.toggleSelectAllServices = function(master) {
    const checkboxes = document.querySelectorAll('.service-select-checkbox');
    checkboxes.forEach(cb => cb.checked = master.checked);
};

window.updateSelectAllServicesHeader = function() {
    const master = document.getElementById('select-all-services');
    if (!master) return;
    const checkboxes = document.querySelectorAll('.service-select-checkbox');
    const checked = document.querySelectorAll('.service-select-checkbox:checked');
    master.checked = checkboxes.length > 0 && checkboxes.length === checked.length;
};

window.openBulkServicesModal = function() {
    const checked = document.querySelectorAll('.service-select-checkbox:checked');
    if (checked.length === 0) {
        alert("Seleziona almeno una prestazione per eseguire l'operazione di gruppo.");
        return;
    }
    
    // Populate dropdowns
    const clinicSelect = document.getElementById('bulk-srv-clinic');
    if (clinicSelect) {
        clinicSelect.innerHTML = '<option value="">-- Nessuna modifica --</option>';
        const clinics = DB.get('clinics') || [];
        clinics.forEach(c => {
            clinicSelect.innerHTML += `<option value="${c.id}">${c.name}</option>`;
        });
    }
    
    const equipSelect = document.getElementById('bulk-srv-equip');
    if (equipSelect) {
        equipSelect.innerHTML = '<option value="">-- Nessuna modifica --</option>';
        const equipment = DB.get('equipment') || [];
        equipment.forEach(e => {
            equipSelect.innerHTML += `<option value="${e.id}">${e.name} (${e.type})</option>`;
        });
    }
    
    window.populateProfitCentersDropdown('bulk-srv-profit-center', true, "-- Nessuna modifica --");
    window.populateSampleCollectionTypesDropdown('bulk-srv-sample-collection-type', true, "-- Nessuna modifica --");
    if (document.getElementById('bulk-srv-lis-instrument')) {
        window.populateLisInstrumentsDropdown('bulk-srv-lis-instrument', null, "-- Nessuna modifica --");
    }
    
    const docSelect = document.getElementById('bulk-srv-doctor-agenda');
    if (docSelect) {
        docSelect.innerHTML = '<option value="">-- Non associare ad alcuna agenda --</option>';
        const doctors = DB.get('doctors') || [];
        const staff = DB.get('staff') || [];
        doctors.forEach(d => {
            const s = staff.find(st => st.id === d.staff_id);
            if (s && d.active) {
                docSelect.innerHTML += `<option value="${d.id}">Dott. ${s.last_name} ${s.first_name} (${d.specialization})</option>`;
            }
        });
    }
    
    // Reset fields
    document.getElementById('bulk-srv-branch').value = '';
    document.getElementById('bulk-srv-clinic').value = '';
    document.getElementById('bulk-srv-equip').value = '';
    document.getElementById('bulk-srv-profit-center').value = '';
    document.getElementById('bulk-srv-sample-collection-type').value = '';
    if (document.getElementById('bulk-srv-lis-instrument')) {
        document.getElementById('bulk-srv-lis-instrument').value = '';
    }
    document.getElementById('bulk-srv-doctor-agenda').value = '';
    
    document.getElementById('bulk-services-count').innerText = checked.length;
    openModal('modal-bulk-services');
};

window.handleBulkServicesSubmit = function(event) {
    event.preventDefault();
    const checked = document.querySelectorAll('.service-select-checkbox:checked');
    const selectedIds = Array.from(checked).map(cb => parseInt(cb.dataset.serviceId));
    if (selectedIds.length === 0) return;
    
    const branchVal = document.getElementById('bulk-srv-branch').value.trim();
    const clinicVal = document.getElementById('bulk-srv-clinic').value;
    const equipVal = document.getElementById('bulk-srv-equip').value;
    const profitCenterVal = document.getElementById('bulk-srv-profit-center').value;
    const sampleCollectionVal = document.getElementById('bulk-srv-sample-collection-type').value;
    const instrumentVal = document.getElementById('bulk-srv-lis-instrument') ? document.getElementById('bulk-srv-lis-instrument').value : '';
    const doctorIdVal = document.getElementById('bulk-srv-doctor-agenda').value;
    
    const services = DB.get('medical_services') || [];
    let updatedCount = 0;
    
    selectedIds.forEach(id => {
        const srv = services.find(s => s.id === id);
        if (!srv) return;
        
        const updated = {};
        if (branchVal) updated.branch = branchVal;
        if (clinicVal) updated.clinic_id = parseInt(clinicVal);
        if (equipVal) updated.equipment_id = parseInt(equipVal);
        if (profitCenterVal) updated.profit_center = profitCenterVal;
        if (sampleCollectionVal && srv.type === 'lis') updated.sample_collection_type_id = parseInt(sampleCollectionVal);
        if (instrumentVal && srv.type === 'lis') updated.instrument_id = parseInt(instrumentVal);
        
        if (Object.keys(updated).length > 0) {
            DB.update('medical_services', id, updated);
            updatedCount++;
        }
        
        // Handle doctor agenda auto-assignment
        if (doctorIdVal) {
            const docId = parseInt(doctorIdVal);
            const agendas = DB.get('doctor_agendas') || [];
            const doctorAgendas = agendas.filter(a => a.doctor_id === docId);
            
            if (doctorAgendas.length > 0) {
                const agendaServices = DB.get('doctor_agenda_services') || [];
                doctorAgendas.forEach(agenda => {
                    const exists = agendaServices.some(item => item.agenda_id === agenda.id && item.service_id === id);
                    if (!exists) {
                        agendaServices.push({ agenda_id: agenda.id, service_id: id });
                    }
                });
                DB.set('doctor_agenda_services', agendaServices);
            }
        }
    });
    
    DB.logAudit(6, "BULK_UPDATE_SERVICES", "medical_services", null, { 
        count: selectedIds.length,
        updated_fields_count: updatedCount,
        assigned_to_doctor_id: doctorIdVal || null
    });
    
    alert(`Operazione completata con successo! Aggiornate ${selectedIds.length} prestazioni.`);
    closeModal('modal-bulk-services');
    renderServices();
    populateBranchFilter();
    
    if (typeof renderAgendas === 'function') {
        renderAgendas();
    }
};

// MODULE 4: CUP PRENOTAZIONI
function renderAppointments(query = '') {
    const appointments = DB.get('appointments') || [];
    const patients = DB.get('patients') || [];
    const doctors = DB.get('doctors') || [];
    const staff = DB.get('staff') || [];
    const services = DB.get('medical_services') || [];
    const appServices = DB.get('appointment_services') || [];
    
    const tbody = document.querySelector('#appointments-table tbody');
    tbody.innerHTML = '';
    
    const roleSelect = document.getElementById('user-role-select');
    const currentRole = roleSelect ? roleSelect.value : 'admin';
    const isStaff = currentRole === 'staff';
    
    // Blinking stylesheet inject
    if (!document.getElementById('nextcare-blinking-style')) {
        const style = document.createElement('style');
        style.id = 'nextcare-blinking-style';
        style.innerHTML = `
            @keyframes nextcare-blink {
                50% { opacity: 0.2; }
            }
            .blinking-dot {
                animation: nextcare-blink 1.2s linear infinite;
            }
        `;
        document.head.appendChild(style);
    }

    const now = new Date();

    // Calculate no-shows count dynamically
    const noShowApps = appointments.filter(app => {
        if (app.status !== 'scheduled') return false;
        const appTime = new Date(app.appointment_datetime);
        const diffMs = now - appTime;
        const diffHours = diffMs / (1000 * 60 * 60);
        return diffHours > 1.0;
    });
    
    const noshowCountBadge = document.getElementById('cup-noshow-count');
    if (noshowCountBadge) {
        noshowCountBadge.innerText = noShowApps.length;
    }

    // Read filter inputs
    const aiSearchVal = document.getElementById('cup-ai-search')?.value || '';
    const startDateVal = document.getElementById('cup-filter-start-date')?.value || '';
    const endDateVal = document.getElementById('cup-filter-end-date')?.value || '';
    const doctorFilterVal = document.getElementById('cup-filter-doctor')?.value || '';
    const statusFilterVal = document.getElementById('cup-filter-status')?.value || '';

    // Parse AI natural query if active
    let aiFilter = null;
    if (aiSearchVal) {
        aiFilter = window.parseNaturalLanguageQuery(aiSearchVal, 'cup');
    }

    const filtered = appointments.filter(app => {
        const p = patients.find(pat => pat.id === app.patient_id);
        if (!p) return false;

        const doc = doctors.find(d => d.id === app.doctor_id);
        const s = doc ? staff.find(st => st.id === doc.staff_id) : null;
        const docName = s ? `${s.first_name} ${s.last_name}`.toLowerCase() : '';

        const srvIds = appServices.filter(as => as.appointment_id === app.id).map(as => as.service_id);
        const associatedServices = services.filter(sv => srvIds.includes(sv.id));
        const servicesText = associatedServices.map(sv => sv.name.toLowerCase()).join(' ');

        // Apply role filter
        if (currentRole === 'doctor_1' && app.doctor_id !== 1) return false;
        if (currentRole === 'doctor_2' && app.doctor_id !== 2) return false;

        // Apply start date filter
        const appDateStr = app.appointment_datetime.substring(0, 10);
        if (startDateVal && appDateStr < startDateVal) return false;
        if (aiFilter?.startDate && appDateStr < aiFilter.startDate) return false;

        // Apply end date filter
        if (endDateVal && appDateStr > endDateVal) return false;
        if (aiFilter?.endDate && appDateStr > aiFilter.endDate) return false;

        // Apply doctor filter
        if (doctorFilterVal && app.doctor_id !== parseInt(doctorFilterVal)) return false;
        if (aiFilter?.doctorName && !docName.includes(aiFilter.doctorName)) return false;

        // Apply status filter
        if (statusFilterVal && app.status !== statusFilterVal) return false;
        if (aiFilter?.status) {
            if (aiFilter.status === 'scheduled' && app.status !== 'scheduled') return false;
            if (aiFilter.status === 'completed' && app.status !== 'completed') return false;
            if (aiFilter.status === 'cancelled' && app.status !== 'cancelled') return false;
        }

        // Apply text query search (both standard global search or remaining AI text query)
        const searchQuery = (aiFilter ? aiFilter.textQuery : query).toLowerCase().trim();
        if (searchQuery) {
            const matchesPatient = `${p.first_name} ${p.last_name}`.toLowerCase().includes(searchQuery) || p.tax_code.toLowerCase().includes(searchQuery);
            const matchesDoctor = docName.includes(searchQuery);
            const matchesService = servicesText.includes(searchQuery);
            if (!matchesPatient && !matchesDoctor && !matchesService) return false;
        }

        return true;
    });

    let displayList = filtered;
    if (typeof cupFilterMode === 'undefined') {
        window.cupFilterMode = 'active';
    }
    
    if (cupFilterMode === 'active') {
        displayList = filtered.filter(app => {
            if (app.status !== 'scheduled') return false;
            const appTime = new Date(app.appointment_datetime);
            const diffHours = (now - appTime) / (1000 * 60 * 60);
            return diffHours <= 1.0;
        });
    } else if (cupFilterMode === 'noshow') {
        displayList = filtered.filter(app => {
            if (app.status === 'no_show') return true;
            if (app.status !== 'scheduled') return false;
            const appTime = new Date(app.appointment_datetime);
            const diffHours = (now - appTime) / (1000 * 60 * 60);
            return diffHours > 1.0;
        });
    } else if (cupFilterMode === 'past') {
        displayList = filtered.filter(app => {
            return app.status === 'completed' || app.status === 'cancelled' || app.status === 'no_show' || (app.status === 'scheduled' && new Date(app.appointment_datetime) < now);
        });
    }

    displayList.sort((a,b) => new Date(b.appointment_datetime) - new Date(a.appointment_datetime));
    
    const paginated = window.setupTablePagination('appointments-table', displayList, () => renderAppointments(query));

    if (displayList.length === 0) {
        tbody.innerHTML = `<tr><td colspan="6" style="text-align: center;" class="text-muted">Nessuna prenotazione trovata</td></tr>`;
        return;
    }
    
    paginated.forEach(app => {
        const p = patients.find(pat => pat.id === app.patient_id);
        const doc = doctors.find(d => d.id === app.doctor_id);
        const s = doc ? staff.find(st => st.id === doc.staff_id) : null;
        
        const srvIds = appServices.filter(as => as.appointment_id === app.id).map(as => as.service_id);
        const associatedServices = services.filter(sv => srvIds.includes(sv.id));
        
        let servicesBadges = associatedServices.map(srv => {
            let badgeType = srv.type === 'lis' ? 'badge-purple' : (srv.type === 'ris' ? 'badge-success' : 'badge-info');
            return `<span class="badge ${badgeType}" style="margin: 2px;">${srv.name}</span>`;
        }).join(' ');

        if (!servicesBadges) servicesBadges = '<span class="badge badge-secondary">Nessuna Prestazione</span>';
        
        let statusBadge = '';
        if (app.status === 'scheduled') statusBadge = '<span class="badge badge-info">Pianificato</span>';
        else if (app.status === 'completed') statusBadge = '<span class="badge badge-success">Accettato & Completato</span>';
        else if (app.status === 'no_show') statusBadge = '<span class="badge badge-danger" style="background: rgba(239, 68, 68, 0.15); color: #ef4444; border: 1px solid rgba(239, 68, 68, 0.2);">Assente (No-Show)</span>';
        else if (app.status === 'cancelled') {
            const reasonText = app.cancellation_reason ? ` (Causale: ${app.cancellation_reason})` : '';
            statusBadge = `<span class="badge badge-danger" title="${app.cancellation_notes || ''}">Annullato${reasonText}</span>`;
        }
        
        let dotIndicator = '';
        if (app.status === 'completed') {
            dotIndicator = '<span style="display:inline-block; width:10px; height:10px; border-radius:50%; background-color:#10b981; margin-right:6px;" title="Accettato/Check-in"></span>';
        } else if (app.status === 'no_show') {
            dotIndicator = '<span style="display:inline-block; width:10px; height:10px; border-radius:50%; background-color:#ef4444; margin-right:6px;" title="No-Show"></span>';
        } else if (app.status === 'scheduled') {
            const appTime = new Date(app.appointment_datetime);
            const diffMs = now - appTime;
            const diffMins = diffMs / (1000 * 60);
            
            if (diffMins > 60) {
                dotIndicator = '<span style="display:inline-block; width:10px; height:10px; border-radius:50%; background-color:#ef4444; margin-right:6px;" title="No-Show (>1h ritardo)"></span>';
            } else if (diffMs > 0 && diffMins < 5) {
                dotIndicator = '<span class="blinking-dot" style="display:inline-block; width:10px; height:10px; border-radius:50%; background-color:#f97316; margin-right:6px;" title="In ritardo (<5 min)"></span>';
            } else {
                dotIndicator = '<span style="display:inline-block; width:10px; height:10px; border-radius:50%; background-color:#3b82f6; margin-right:6px;" title="Pianificato in orario"></span>';
            }
        }
        
        let doctorText = '';
        if (doc && s) {
            doctorText = `
                <div style="font-weight: 500;">Dott. ${s.last_name}</div>
                <div style="font-size: 0.8rem; color: var(--text-secondary);">${doc.specialization}</div>
            `;
        } else {
            doctorText = '<span class="text-muted" style="font-size: 0.8rem;">Nessun Medico (Laboratorio LIS)</span>';
        }

        let actionButtons = '';
        if (app.status === 'scheduled') {
            actionButtons = `
                <button class="btn btn-success btn-sm" onclick="openCheckinModal(${app.id})"><i data-lucide="check"></i> Accetta & Avvia</button>
                <button class="btn btn-primary btn-sm" onclick="window.openEditAppointmentModal(${app.id})"><i data-lucide="edit"></i> Ripianifica</button>
                <button class="btn btn-secondary btn-sm" onclick="window.openCancelAppointmentModal(${app.id})">Annulla</button>
                <button class="btn btn-danger btn-sm" onclick="window.markAsNoShow(${app.id})">No Show</button>
            `;
        }
        
        const formattedDate = new Date(app.appointment_datetime).toLocaleString('it-IT', { day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' });
        
        const tr = document.createElement('tr');
        tr.innerHTML = `
            <td><div style="display:flex; align-items:center;">${dotIndicator}<strong>${formattedDate}</strong></div></td>
            <td>${p.last_name} ${p.first_name}</td>
            <td>${servicesBadges}</td>
            <td>${doctorText}</td>
            <td>${statusBadge}</td>
            <td><div class="row-actions">${actionButtons}</div></td>
        `;
        tbody.appendChild(tr);
    });
}

window.filterCupAppointments = function(mode) {
    window.cupFilterMode = mode;
    const btnActive = document.getElementById('btn-cup-filter-active');
    const btnNoShow = document.getElementById('btn-cup-filter-noshow');
    const btnPast = document.getElementById('btn-cup-filter-past');
    
    const setBtnActive = (btn, isActive) => {
        if (!btn) return;
        if (isActive) {
            btn.classList.remove('btn-secondary');
            btn.classList.add('btn-primary');
        } else {
            btn.classList.remove('btn-primary');
            btn.classList.add('btn-secondary');
        }
    };
    
    setBtnActive(btnActive, mode === 'active');
    setBtnActive(btnNoShow, mode === 'noshow');
    setBtnActive(btnPast, mode === 'past');
    
    renderAppointments();
};

window.updateAppointmentStatus = function(appId, newStatus) {
    DB.update('appointments', appId, { status: newStatus });
    DB.logAudit(6, "UPDATE_APPOINTMENT_STATUS", "appointments", appId, { status: newStatus });
    renderAppointments();
};

window.markAsNoShow = function(appId) {
    if (!confirm("Sei sicuro di voler contrassegnare questa prenotazione come No-Show (Assente)?")) return;
    
    DB.update('appointments', appId, { status: 'no_show' });
    DB.logAudit(6, "NO_SHOW_APPOINTMENT", "appointments", appId, {});
    
    // Send email notification
    const app = DB.get('appointments').find(a => a.id === appId);
    const patient = app ? DB.get('patients').find(p => p.id === app.patient_id) : null;
    const appServices = DB.get('appointment_services') || [];
    const services = DB.get('medical_services') || [];
    const linkedServices = appServices.filter(as => as.appointment_id === appId).map(as => services.find(s => s.id === as.service_id)).filter(Boolean);
    const serviceNames = linkedServices.map(s => s.name).join(', ') || 'Prestazione';
    const appDateStr = app ? new Date(app.appointment_datetime).toLocaleString('it-IT') : 'N/A';

    if (patient) {
        const pName = `${patient.first_name} ${patient.last_name}`;
        window.sendSimulatedEmail(patient.id, 'no_show', {
            paziente: pName,
            data: appDateStr,
            prestazione: serviceNames,
            dettaglio: "Il paziente non si è presentato all'appuntamento pianificato."
        });
    }
    
    renderAppointments();
};

// --- 6B. CUP ACCEPTANCE & AUTO-BILLING FLOW ---
window.acceptCupAppointment = function(appId) {
    const appointments = DB.get('appointments');
    const appServices = DB.get('appointment_services') || [];
    const services = DB.get('medical_services');
    const patients = DB.get('patients');
    
    const app = appointments.find(a => a.id === appId);
    if (!app) return;

    const patient = patients.find(p => p.id === app.patient_id);
    const serviceIds = appServices.filter(as => as.appointment_id === appId).map(as => as.service_id);
    const bookedServices = services.filter(sv => serviceIds.includes(sv.id));

    if (bookedServices.length === 0) {
        alert("Errore: Nessuna prestazione associata a questa prenotazione.");
        return;
    }

    // Split services into LIS, RIS and Visite
    const lisServices = bookedServices.filter(s => s.type === 'lis');
    const risServices = bookedServices.filter(s => s.type === 'ris');
    const visitServices = bookedServices.filter(s => s.type === 'visita');

    let invoiceAmount = 0.0;
    let createdSample = null;
    let createdStudyIds = [];

    // 1. Process LIS Services: create separate samples for each unique tube type
    if (lisServices.length > 0) {
        const servicesByTube = {};
        lisServices.forEach(srv => {
            const tube = srv.sample_type || "Sangue (Tappo Viola)";
            if (!servicesByTube[tube]) {
                servicesByTube[tube] = [];
            }
            servicesByTube[tube].push(srv);
        });

        const sessionUid = 'LIS-SESS-' + Date.now() + '-' + Math.floor(Math.random() * 1000);
        const tubeTypes = DB.get('tube_types') || [];

        for (const [tubeType, srvs] of Object.entries(servicesByTube)) {
            const matchedTube = tubeTypes.find(t => t.name === tubeType);
            const tubeSuffix = matchedTube ? matchedTube.suffix : '000';
            const barcodeNum = window.getNextBarcode(tubeSuffix);

            const sample = {
                patient_id: app.patient_id,
                barcode: barcodeNum,
                sample_type: tubeType,
                status: 'da prelevare',
                session_uid: sessionUid,
                collected_at: null,
                collected_by: null,
                report_notes: ""
            };
            const newSam = DB.insert('lab_samples', sample);
            if (!createdSample) {
                createdSample = newSam; // Use first sample for billing link
            }

            // Add tests for this sample
            srvs.forEach(srv => {
                invoiceAmount += (srv.price || 0.0);

                if (srv.parameters && srv.parameters.length > 0) {
                    srv.parameters.forEach(p => {
                        const test = {
                            sample_id: newSam.id,
                            service_id: srv.id,
                            test_name: p.name,
                            result_value: null,
                            reference_range: p.reference_range || '',
                            unit: p.unit || '',
                            result_type: p.result_type || 'ALFABETICO',
                            status: 'pending',
                            verified_by: null,
                            verified_at: null
                        };
                        DB.insert('lab_tests', test);
                    });
                } else {
                    const test = {
                        sample_id: newSam.id,
                        service_id: srv.id,
                        test_name: srv.name,
                        result_value: null,
                        reference_range: srv.reference_range || '',
                        unit: srv.unit || '',
                        result_type: 'ALFABETICO',
                        status: 'pending',
                        verified_by: null,
                        verified_at: null
                    };
                    DB.insert('lab_tests', test);
                }
            });

            DB.logAudit(4, "ACCEPT_LIS_BOOKING", "lab_samples", newSam.id, { barcode: barcodeNum, tests: srvs.length, session_uid: sessionUid });
        }
    }

    // 2. Process RIS Services: create radiology studies
    if (risServices.length > 0) {
        risServices.forEach(srv => {
            invoiceAmount += (srv.price || 0.0);
            
            let studyType = 'XRAY';
            if (srv.name.toLowerCase().includes('risonanza') || srv.name.toLowerCase().includes('mri')) studyType = 'MRI';
            else if (srv.name.toLowerCase().includes('tac') || srv.name.toLowerCase().includes('computerizzata')) studyType = 'CT';
            else if (srv.name.toLowerCase().includes('eco')) studyType = 'ULTRASOUND';

            const study = {
                patient_id: app.patient_id,
                doctor_id: app.doctor_id || 2, // Default to Dott.ssa Bianchi (Radiologia) if no doctor is assigned
                service_id: srv.id,
                study_type: studyType,
                scheduled_at: app.appointment_datetime,
                status: 'in_progress', // immediately start in progress
                dicom_series_uid: '1.2.840.113619.2.' + Math.floor(Math.random()*9000) + '.' + Math.floor(Math.random()*900),
                report_text: null,
                signed_by: null,
                signed_at: null
            };
            const newStudy = DB.insert('radiology_studies', study);
            createdStudyIds.push(newStudy.id);
            DB.logAudit(6, "ACCEPT_RIS_BOOKING", "radiology_studies", newStudy.id, { type: studyType });
        });
    }

    // 3. Process Visite Services
    if (visitServices.length > 0) {
        visitServices.forEach(srv => {
            invoiceAmount += (srv.price || 0.0);
            
            const study = {
                patient_id: app.patient_id,
                doctor_id: app.doctor_id || 2, // Default to doctor assigned or Dott.ssa Bianchi
                service_id: srv.id,
                study_type: 'VISIT',
                scheduled_at: app.appointment_datetime,
                status: 'in_progress', // immediately start in progress
                dicom_series_uid: '1.2.840.113619.2.' + Math.floor(Math.random()*9000) + '.' + Math.floor(Math.random()*900),
                report_text: null,
                signed_by: null,
                signed_at: null
            };
            const newStudy = DB.insert('radiology_studies', study);
            createdStudyIds.push(newStudy.id);
            DB.logAudit(6, "ACCEPT_VISIT_BOOKING", "radiology_studies", newStudy.id, { type: 'VISIT' });
        });
    }

    // 4. Update appointment status to completed
    DB.update('appointments', appId, { status: 'completed' });
    DB.logAudit(6, "CUP_ACCEPTANCE_CONVERTED", "appointments", appId, { sample_id: createdSample ? createdSample.id : null, studies_count: createdStudyIds.length });

    // 5. Automated Billing: Create invoice if price > 0
    if (invoiceAmount > 0) {
        const invoiceNum = getNextInvoiceNumber();
        let stampDuty = 0.00;
        let amountDue = invoiceAmount;
        if (invoiceAmount > 77.47) {
            stampDuty = 2.00;
            amountDue = invoiceAmount + 2.00;
        }
        const invoice = {
            admission_id: null, // Outpatient service
            appointment_id: appId,
            sample_id: createdSample ? createdSample.id : null,
            study_id: createdStudyIds.length > 0 ? createdStudyIds[0] : null,
            invoice_number: invoiceNum,
            issue_date: new Date().toISOString().split('T')[0],
            subtotal: invoiceAmount,
            stamp_duty: stampDuty,
            amount_due: amountDue,
            amount_paid: 0.0,
            payment_status: 'unpaid',
            payment_method: null,
            paid_at: null
        };
        const inserted = DB.insert('invoices', invoice);
        DB.logAudit(6, "AUTO_BILL_EMITTED", "invoices", null, { invoice_number: invoiceNum, amount: amountDue });
        
        alert(`Accettazione completata con successo!

- Prenotazione registrata come completata.

${createdSample ? `- Campione LIS creato con Barcode: ${createdSample.barcode}

` : ''}${createdStudyIds.length > 0 ? `- Generati ${createdStudyIds.length} studi RIS in elaborazione.

` : ''}- Emessa fattura non pagata di € ${amountDue.toFixed(2)} (incluso bollo se applicabile) per le prestazioni accettate.`);
        setTimeout(() => {
            window.promptDirectPaymentAndPrint(inserted.id);
        }, 150);
    }
    
    // Refresh tables
    renderAppointments();
    renderSamples();
    renderRisStudies();
    renderAdmissionsAndInvoices();
};

// MODULE 5: LIS LABORATORIO
// MODULE 5: LIS LABORATORIO
window.switchLisSubTab = function(tabName) {
    const buttons = document.querySelectorAll('#tab-lis .sub-tabs-container .sub-tab-btn');
    buttons.forEach(btn => {
        if (btn.id === `sub-tab-${tabName}`) {
            btn.classList.add('active');
        } else {
            btn.classList.remove('active');
        }
    });

    const contents = document.querySelectorAll('#tab-lis .sub-tab-content');
    contents.forEach(cnt => {
        if (cnt.id === `sub-content-${tabName}`) {
            cnt.style.display = 'block';
        } else {
            cnt.style.display = 'none';
        }
    });

    if (tabName === 'lis-acceptances') {
        window.renderLisAcceptances();
    } else if (tabName === 'lis-samples') {
        window.renderSamples();
        window.populateTubeTypesFilterDropdown();
    } else if (tabName === 'lis-worksheets') {
        window.populateLisWorksheetsDropdown();
        window.renderLisWorksheetView();
    } else if (tabName === 'lis-validation') {
        window.renderLisValidationView();
    } else if (tabName === 'lis-reporting') {
        window.renderLisReportingView();
    } else if (tabName === 'lis-instrument-entry') {
        window.populateLisInstrumentEntryDropdown();
        window.renderLisInstrumentEntryView();
    } else if (tabName === 'bulk-manage') {
        if (typeof window.renderLisBulkManageView === 'function') window.renderLisBulkManageView();
    } else if (tabName === 'lis-microbiology') {
        if (typeof window.renderLisMicrobiologyView === 'function') window.renderLisMicrobiologyView();
    } else if (tabName === 'lis-collection-points') {
        if (typeof window.renderLisCollectionPointsView === 'function') window.renderLisCollectionPointsView();
    } else if (tabName === 'lis-checkin') {
        if (typeof window.renderLisCheckinView === 'function') window.renderLisCheckinView();
    }
};

window.populateLisInstrumentEntryDropdown = function() {
    const select = document.getElementById('ins-entry-instrument-filter');
    if (!select) return;
    const savedVal = select.value;
    
    select.innerHTML = `
        <option value="all">Tutti gli Strumenti</option>
        <option value="unassigned">Non Assegnati / Manuale</option>
    `;
    
    const equipment = DB.get('equipment') || [];
    const activeLisInstruments = equipment.filter(e => e.type === 'LIS' && e.status === 'active');
    activeLisInstruments.forEach(inst => {
        const typeStr = inst.lis_interface_type ? inst.lis_interface_type.toUpperCase() : 'MANUALE';
        select.innerHTML += `<option value="${inst.id}">${inst.name} (S/N: ${inst.serial_number || 'N/D'} - ${typeStr})</option>`;
    });
    
    select.value = savedVal || 'all';
};

window.renderLisInstrumentEntryView = function() {
    const tbody = document.getElementById('lis-instrument-entry-tbody');
    const emptyDiv = document.getElementById('lis-instrument-entry-empty');
    if (!tbody) return;
    
    tbody.innerHTML = '';
    
    const instrumentFilterVal = document.getElementById('ins-entry-instrument-filter').value;
    const statusFilterVal = document.getElementById('ins-entry-status-filter').value;
    const searchFilterVal = document.getElementById('ins-entry-search-filter').value.toLowerCase().trim();
    
    const samples = DB.get('lab_samples') || [];
    const patients = DB.get('patients') || [];
    const tests = DB.get('lab_tests') || [];
    const services = DB.get('medical_services') || [];
    const equipment = DB.get('equipment') || [];
    const instruments = equipment.filter(e => e.type === 'LIS');
    
    const activeSampleStatuses = ['collected', 'processing', 'to_validate'];
    let filteredTests = [];
    
    tests.forEach(test => {
        const sam = samples.find(s => s.id === test.sample_id);
        if (!sam || !activeSampleStatuses.includes(sam.status)) return;
        
        const srv = services.find(s => s.id === test.service_id);
        const instrumentId = srv ? (srv.instrument_id || 0) : 0;
        
        if (instrumentFilterVal !== 'all') {
            if (instrumentFilterVal === 'unassigned') {
                if (instrumentId && instrumentId !== 0) return;
            } else {
                if (String(instrumentId) !== String(instrumentFilterVal)) return;
            }
        }
        
        const isPending = test.result_value === null || test.result_value === undefined || String(test.result_value).trim() === '';
        if (statusFilterVal === 'pending' && !isPending) return;
        
        const patient = patients.find(p => p.id === sam.patient_id);
        const patientName = patient ? `${patient.last_name} ${patient.first_name}`.toLowerCase() : '';
        const barcode = sam.barcode ? sam.barcode.toLowerCase() : '';
        
        if (searchFilterVal) {
            if (!patientName.includes(searchFilterVal) && !barcode.includes(searchFilterVal)) return;
        }
        
        filteredTests.push({
            test,
            sample: sam,
            patient,
            service: srv,
            instrumentId
        });
    });
    
    filteredTests.sort((a, b) => {
        const instA = a.instrumentId ? (instruments.find(i => i.id === a.instrumentId)?.name || 'ZZZZ') : 'ZZZZ';
        const instB = b.instrumentId ? (instruments.find(i => i.id === b.instrumentId)?.name || 'ZZZZ') : 'ZZZZ';
        const instCompare = instA.localeCompare(instB);
        if (instCompare !== 0) return instCompare;
        
        const dateA = new Date(a.sample.collected_at || a.sample.created_at);
        const dateB = new Date(b.sample.collected_at || b.sample.created_at);
        const dateCompare = dateB - dateA;
        if (dateCompare !== 0) return dateCompare;
        
        const nameA = a.patient ? `${a.patient.last_name} ${a.patient.first_name}` : '';
        const nameB = b.patient ? `${b.patient.last_name} ${b.patient.first_name}` : '';
        return nameA.localeCompare(nameB);
    });
    
    if (filteredTests.length === 0) {
        if (emptyDiv) emptyDiv.style.display = 'block';
        return;
    }
    
    if (emptyDiv) emptyDiv.style.display = 'none';
    
    filteredTests.forEach(item => {
        const t = item.test;
        const sam = item.sample;
        const pat = item.patient;
        const srv = item.service;
        const instId = item.instrumentId;
        
        const inst = instId ? instruments.find(i => i.id === instId) : null;
        const instBadge = inst 
            ? `<span class="badge" style="background: rgba(14, 165, 233, 0.1); color: #0ea5e9; font-size: 0.7rem; font-weight: 600; padding: 2px 6px; border-radius: var(--radius-sm); border: 1px solid rgba(14, 165, 233, 0.2);"><i data-lucide="cpu" style="width: 10px; height: 10px; display: inline-block; vertical-align: middle; margin-right: 3px;"></i>${inst.name}</span>`
            : `<span class="badge" style="background: rgba(156, 163, 175, 0.1); color: #9ca3af; font-size: 0.7rem; font-weight: 500; padding: 2px 6px; border-radius: var(--radius-sm); border: 1px solid rgba(156, 163, 175, 0.2);"><i data-lucide="keyboard" style="width: 10px; height: 10px; display: inline-block; vertical-align: middle; margin-right: 3px;"></i>Manuale</span>`;
            
        const patientName = pat ? `${pat.last_name} ${pat.first_name}` : "Sconosciuto";
        const dateStr = sam.collected_at ? new Date(sam.collected_at).toLocaleString('it-IT') : new Date(sam.created_at).toLocaleString('it-IT');
        
        const isPending = t.result_value === null || t.result_value === undefined || String(t.result_value).trim() === '';
        let badgeHTML = '';
        let inputBorderColor = 'var(--border-color)';
        let inputBgColor = 'var(--bg-surface)';
        
        if (isPending) {
            badgeHTML = `<span class="badge" style="background: rgba(156, 163, 175, 0.1); color: #9ca3af; padding: 3px 8px; border-radius: var(--radius-sm);">Pendente</span>`;
        } else {
            const isNormal = window.checkTestValueIsNormal(t.result_value, t.reference_range);
            if (isNormal === 'flagged') {
                badgeHTML = `<span class="badge" style="background: rgba(239, 68, 68, 0.1); color: #ef4444; font-weight: bold; padding: 3px 8px; border-radius: var(--radius-sm);"><i data-lucide="alert-triangle" style="width: 12px; height: 12px; display: inline-block; vertical-align: middle; margin-right: 2px;"></i> Fuori Range</span>`;
                inputBorderColor = 'var(--danger)';
                inputBgColor = 'rgba(239, 68, 68, 0.05)';
            } else {
                badgeHTML = `<span class="badge" style="background: rgba(34, 197, 94, 0.1); color: #22c55e; padding: 3px 8px; border-radius: var(--radius-sm);">Normale</span>`;
                inputBorderColor = 'var(--success)';
                inputBgColor = 'rgba(34, 197, 94, 0.05)';
            }
        }
        
        const tr = document.createElement('tr');
        tr.style.borderBottom = '1px solid var(--border-color)';
        tr.style.transition = 'background 0.2s';
        tr.onmouseover = () => tr.style.background = 'var(--bg-base)';
        tr.onmouseout = () => tr.style.background = 'transparent';
        
        tr.innerHTML = `
            <td style="padding: 12px;">
                <span class="badge badge-secondary" style="font-weight: 700; font-family: monospace; font-size: 0.8rem; background: var(--bg-base); color: var(--text-primary); border: 1px solid var(--border-color);">${sam.barcode}</span>
                <div style="font-size: 0.7rem; color: var(--text-secondary); margin-top: 4px;">Prelevato: ${dateStr}</div>
            </td>
            <td style="padding: 12px;">
                <div style="font-weight: 600; color: var(--text-primary); font-size: 0.85rem;">${patientName}</div>
                <div style="font-size: 0.7rem; color: var(--text-secondary);">ID Paziente: ${sam.patient_id}</div>
            </td>
            <td style="padding: 12px;">
                <div style="font-weight: 600; color: var(--primary); font-size: 0.85rem;">${t.test_name}</div>
                <div style="margin-top: 4px;">${instBadge}</div>
            </td>
            <td style="padding: 12px;">
                <input type="text" class="form-control inst-entry-value-input" data-test-id="${t.id}" value="${t.result_value !== null ? t.result_value : ''}" placeholder="Valore..." style="width: 100%; border: 1px solid ${inputBorderColor}; background: ${inputBgColor}; border-radius: var(--radius-sm); padding: 8px 12px; font-weight: 700; font-size: 0.85rem; box-sizing: border-box;" oninput="window.handleLisInstrumentEntryLiveValidation(this, '${t.reference_range || ''}')">
            </td>
            <td style="padding: 12px; font-size: 0.8rem;">
                <div style="font-weight: 600; color: var(--text-primary); font-family: monospace;">${t.unit || '-'}</div>
                <div style="font-size: 0.75rem; color: var(--text-secondary); margin-top: 2px;">Rif: ${t.reference_range || 'N/A'}</div>
            </td>
            <td style="padding: 12px; text-align: center;" id="inst-entry-status-badge-${t.id}">
                ${badgeHTML}
            </td>
        `;
        tbody.appendChild(tr);
    });
    
    if (window.lucide) window.lucide.createIcons();
};

window.handleLisInstrumentEntryLiveValidation = function(inputEl, referenceRange) {
    const val = inputEl.value.trim();
    const testId = inputEl.dataset.testId;
    const badgeEl = document.getElementById(`inst-entry-status-badge-${testId}`);
    
    if (val === '') {
        inputEl.style.borderColor = 'var(--border-color)';
        inputEl.style.backgroundColor = 'var(--bg-surface)';
        if (badgeEl) {
            badgeEl.innerHTML = `<span class="badge" style="background: rgba(156, 163, 175, 0.1); color: #9ca3af; padding: 3px 8px; border-radius: var(--radius-sm);">Pendente</span>`;
        }
        return;
    }
    
    const isNormal = window.checkTestValueIsNormal(val, referenceRange);
    
    if (isNormal === 'flagged') {
        inputEl.style.borderColor = 'var(--danger)';
        inputEl.style.backgroundColor = 'rgba(239, 68, 68, 0.05)';
        if (badgeEl) {
            badgeEl.innerHTML = `<span class="badge" style="background: rgba(239, 68, 68, 0.1); color: #ef4444; font-weight: bold; padding: 3px 8px; border-radius: var(--radius-sm);"><i data-lucide="alert-triangle" style="width: 12px; height: 12px; display: inline-block; vertical-align: middle; margin-right: 2px;"></i> Fuori Range</span>`;
            if (window.lucide) window.lucide.createIcons();
        }
    } else {
        inputEl.style.borderColor = 'var(--success)';
        inputEl.style.backgroundColor = 'rgba(34, 197, 94, 0.05)';
        if (badgeEl) {
            badgeEl.innerHTML = `<span class="badge" style="background: rgba(34, 197, 94, 0.1); color: #22c55e; padding: 3px 8px; border-radius: var(--radius-sm);">Normale</span>`;
        }
    }
};

window.saveLisInstrumentEntryResults = function() {
    const inputs = document.querySelectorAll('.inst-entry-value-input');
    if (inputs.length === 0) return;
    
    const tests = DB.get('lab_tests') || [];
    const samples = DB.get('lab_samples') || [];
    
    let updatedCount = 0;
    const affectedSampleIds = new Set();
    
    inputs.forEach(input => {
        const testId = parseInt(input.dataset.testId);
        const val = input.value.trim();
        
        const test = tests.find(t => t.id === testId);
        if (!test) return;
        
        const currentVal = test.result_value !== null ? String(test.result_value).trim() : '';
        if (val !== currentVal) {
            test.result_value = val === '' ? null : val;
            test.status = window.checkTestValueIsNormal(val, test.reference_range);
            test.verified_by = null;
            test.verified_at = null;
            updatedCount++;
            affectedSampleIds.add(test.sample_id);
        }
    });
    
    if (updatedCount > 0) {
        DB.set('lab_tests', tests);
        
        affectedSampleIds.forEach(sampleId => {
            const sam = samples.find(s => s.id === sampleId);
            if (!sam) return;
            
            const samTests = tests.filter(t => t.sample_id === sampleId);
            const allFilled = samTests.every(t => t.result_value !== null && t.result_value !== undefined && String(t.result_value).trim() !== '');
            
            let newStatus = sam.status;
            if (allFilled) {
                newStatus = 'to_validate';
            } else if (sam.status === 'collected') {
                newStatus = 'processing';
            }
            
            if (newStatus !== sam.status) {
                DB.update('lab_samples', sampleId, { status: newStatus });
            }
            
            DB.logAudit(5, "LAB_ENTER_RESULTS_INSTRUMENT", "lab_samples", sampleId, { updated_tests_count: samTests.length });
        });
        
        alert(`Risultati salvati con successo! Aggiornati ${updatedCount} parametri.`);
        window.renderLisInstrumentEntryView();
        
        if (typeof window.renderSamples === 'function') window.renderSamples();
    } else {
        alert("Nessuna modifica da salvare.");
    }
};

window.populateTubeTypesFilterDropdown = function() {
    const select = document.getElementById('filter-lis-tube-type');
    if (!select) return;
    const savedVal = select.value;
    select.innerHTML = '<option value="">Tutte le provette</option>';
    const tubes = DB.get('tube_types') || [];
    tubes.forEach(t => {
        select.innerHTML += `<option value="${t.name}">${t.name}</option>`;
    });
    select.value = savedVal;
};

window.getFilteredSamplesList = function() {
    const samples = DB.get('lab_samples') || [];
    const patients = DB.get('patients') || [];
    const appointments = DB.get('appointments') || [];
    const studies = DB.get('radiology_studies') || [];

    const roleSelect = document.getElementById('user-role-select');
    const currentRole = roleSelect ? roleSelect.value : 'admin';

    const filterBarcode = (document.getElementById('filter-lis-barcode')?.value || '').toLowerCase().trim();
    const filterPatient = (document.getElementById('filter-lis-patient')?.value || '').toLowerCase().trim();
    const filterStatus = document.getElementById('filter-lis-status')?.value || '';
    const filterTubeType = document.getElementById('filter-lis-tube-type')?.value || '';
    const filterStartDate = document.getElementById('filter-lis-start-date')?.value || '';
    const filterEndDate = document.getElementById('filter-lis-end-date')?.value || '';
    const filterCollectionPoint = document.getElementById('filter-lis-collection-point')?.value || '';

    return samples.filter(sam => {
        const p = patients.find(pat => pat.id === sam.patient_id);
        if (!p) return false;

        if (currentRole === 'doctor_1') {
            const hasApp = appointments.some(app => app.patient_id === p.id && app.doctor_id === 1);
            const hasStudy = studies.some(st => st.patient_id === p.id && st.doctor_id === 1);
            if (!hasApp && !hasStudy) return false;
        } else if (currentRole === 'doctor_2') {
            const hasApp = appointments.some(app => app.patient_id === p.id && app.doctor_id === 2);
            const hasStudy = studies.some(st => st.patient_id === p.id && st.doctor_id === 2);
            if (!hasApp && !hasStudy) return false;
        } else if (currentRole === 'infermiere') {
            if (sam.collected_at !== null) return false;
        }

        if (filterBarcode && !sam.barcode.toLowerCase().includes(filterBarcode)) return false;
        if (filterStatus && sam.status !== filterStatus) return false;
        if (filterTubeType && sam.sample_type !== filterTubeType) return false;

        if (filterCollectionPoint) {
            if (filterCollectionPoint === 'sede_centrale') {
                if (sam.collection_point_id && sam.collection_point_id !== null && sam.collection_point_id !== '0') return false;
            } else {
                if (parseInt(sam.collection_point_id) !== parseInt(filterCollectionPoint)) return false;
            }
        }

        if (filterPatient) {
            const nameMatch = `${p.first_name} ${p.last_name}`.toLowerCase().includes(filterPatient) ||
                             `${p.last_name} ${p.first_name}`.toLowerCase().includes(filterPatient) ||
                             p.tax_code.toLowerCase().includes(filterPatient);
            if (!nameMatch) return false;
        }

        if (filterStartDate) {
            const samDate = new Date(sam.collected_at || sam.created_at);
            const startDate = new Date(filterStartDate);
            startDate.setHours(0,0,0,0);
            if (samDate < startDate) return false;
        }

        if (filterEndDate) {
            const samDate = new Date(sam.collected_at || sam.created_at);
            const endDate = new Date(filterEndDate);
            endDate.setHours(23,59,59,999);
            if (samDate > endDate) return false;
        }

        return true;
    }).sort((a, b) => {
        const dateA = new Date(a.collected_at || a.created_at);
        const dateB = new Date(b.collected_at || b.created_at);
        return dateB - dateA;
    });
};

function renderSamples(query = '') {
    const tbody = document.querySelector('#samples-table tbody');
    if (!tbody) return;
    tbody.innerHTML = '';

    const patients = DB.get('patients');
    const tests = DB.get('lab_tests');
    const services = DB.get('medical_services');
    const collectionPoints = DB.get('lis_collection_points') || [];
    
    const roleSelect = document.getElementById('user-role-select');
    const currentRole = roleSelect ? roleSelect.value : 'admin';
    const isStaff = currentRole === 'staff';

    const filtered = window.getFilteredSamplesList();

    const paginated = window.setupTablePagination('samples-table', filtered, () => renderSamples(query));

    if (filtered.length === 0) {
        tbody.innerHTML = `<tr><td colspan="7" style="text-align: center;" class="text-muted">Nessun campione trovato</td></tr>`;
        return;
    }
    
    paginated.forEach(sam => {
        const p = patients.find(pat => pat.id === sam.patient_id);
        const samTests = tests.filter(t => t.sample_id === sam.id);
        const hasFlagged = samTests.some(t => t.status === 'flagged');
        
        let statusBadge = '';
        if (sam.status === 'da prelevare') {
            statusBadge = '<span class="badge" style="background-color: #64748b; color: #fff;">Da Prelevare</span>';
        } else if (sam.status === 'collected') {
            statusBadge = '<span class="badge badge-info">Prelievo Effettuato</span>';
        } else if (sam.status === 'processing') {
            statusBadge = '<span class="badge badge-warning" style="background-color: #f59e0b; color: #fff;">In Corso</span>';
        } else if (hasFlagged && sam.status !== 'completed') {
            statusBadge = '<span class="badge badge-danger" style="background-color: #ef4444; color: #fff;">Alert / Fuori Range</span>';
        } else if (sam.status === 'to_validate') {
            statusBadge = '<span class="badge" style="background-color: #f97316; color: #fff;">Da Validare</span>';
        } else if (sam.status === 'validated') {
            statusBadge = '<span class="badge badge-success" style="background-color: #10b981; color: #fff;">Validato</span>';
        } else if (sam.status === 'completed') {
            statusBadge = '<span class="badge badge-purple" style="background-color: #8b5cf6; color: #fff;">Refertato</span>';
        } else if (sam.status === 'suspended') {
            statusBadge = '<span class="badge badge-danger" style="background-color: #ef4444; color: #fff;">Sospeso</span>';
        } else if (sam.status === 'non_prelevato') {
            statusBadge = '<span class="badge badge-danger" style="background-color: #ef4444; color: #fff;">Non Prelevato</span>';
        } else if (sam.status === 'non_pervenuto') {
            statusBadge = '<span class="badge badge-warning" style="background-color: #f59e0b; color: #fff;">Non Pervenuto</span>';
        }
        
        const testsByService = {};
        samTests.forEach(t => {
            const srv = services.find(s => s.id === t.service_id);
            const srvName = srv ? srv.name : t.test_name;
            const srvId = srvName;
            if (!testsByService[srvId]) {
                testsByService[srvId] = {
                    name: srvName,
                    hasFlagged: false,
                    parameters: []
                };
            }
            if (t.status === 'flagged') {
                testsByService[srvId].hasFlagged = true;
            }
            if (t.result_value !== null && t.result_value !== undefined && String(t.result_value).trim() !== '') {
                testsByService[srvId].parameters.push({
                    name: t.test_name,
                    value: t.result_value,
                    unit: t.unit || '',
                    flagged: t.status === 'flagged'
                });
            } else {
                if (t.test_name !== srvName) {
                    testsByService[srvId].parameters.push({
                        name: t.test_name,
                        value: null
                    });
                }
            }
        });

        const testSpanList = Object.values(testsByService).map(item => {
            let valColor = item.hasFlagged ? 'color: var(--danger); font-weight: 700;' : '';
            let details = '';
            
            const results = item.parameters.filter(p => p.value !== null);
            if (results.length > 0) {
                const resultsStr = results.map(r => {
                    const rColor = r.flagged ? 'color: var(--danger); font-weight: 700;' : '';
                    const label = r.name === item.name ? '' : `${r.name}: `;
                    return `<span style="${rColor}">${label}${r.value} ${r.unit}</span>`;
                }).join(', ');
                details = ` <span style="font-size:0.75rem; color: var(--text-secondary); font-weight: 400;">(${resultsStr})</span>`;
            } else if (item.parameters.length > 0) {
                details = ` <span style="font-size:0.75rem; color: var(--text-secondary); font-weight: 400;">(${item.parameters.length} param)</span>`;
            }
            
            return `<span style="font-size: 0.8rem; ${valColor}"><strong>${item.name}</strong></span>${details}`;
        });
        
        let testString = testSpanList.join(', ');
        
        let actionBtn = '';
        const canPrelevare = ['admin', 'biologo', 'infermiere'].includes(currentRole);
        
        if (sam.status === 'da prelevare') {
            if (canPrelevare) {
                actionBtn = `<button class="btn btn-warning btn-sm" onclick="window.prelevaSample(${sam.id})" style="background-color: var(--warning); border-color: var(--warning); color: #000; font-weight: 600;"><i data-lucide="droplet" style="width: 12px; height: 12px; vertical-align: middle; margin-right: 4px;"></i> PRELEVA</button>`;
            } else {
                actionBtn = '<span class="text-muted" style="font-size:0.75rem;">Da prelevare</span>';
            }
        } else {
            if (sam.status === 'collected') {
                actionBtn = isStaff 
                    ? '<span class="text-muted" style="font-size:0.75rem;">In attesa invio</span>'
                    : `<button class="btn btn-primary btn-sm" onclick="startProcessingSample(${sam.id})">Invia a Strumento</button>`;
            } else if (sam.status === 'processing') {
                actionBtn = isStaff
                    ? '<span class="text-muted" style="font-size:0.75rem;">In elaborazione</span>'
                    : `<button class="btn btn-success btn-sm" onclick="openResultsModal(${sam.id})">Risultati</button>`;
            } else if (sam.status === 'to_validate') {
                actionBtn = `<button class="btn btn-warning btn-sm" onclick="openResultsModal(${sam.id})" style="background-color: #f97316; border-color: #f97316; color: white;">Valida</button>`;
            } else if (sam.status === 'validated') {
                actionBtn = `<button class="btn btn-success btn-sm" onclick="openResultsModal(${sam.id})">Referta</button>`;
            } else if (sam.status === 'completed') {
                actionBtn = `
                    <button class="btn btn-secondary btn-sm" onclick="openLisReportView(${sam.id})" style="margin-right: 5px;"><i data-lucide="file-text"></i> Referto LIS</button>
                `;
                if (!isStaff) {
                    actionBtn += `<button class="btn btn-primary btn-sm" onclick="openResultsModal(${sam.id}, true)"><i data-lucide="edit"></i> Modifica</button>`;
                }
            }
        }
        
        actionBtn += `
            <button class="btn btn-secondary btn-sm" onclick="window.printLisAcceptanceReceipt(${sam.id})" title="Stampa Ricevuta" style="margin-left: 2px;"><i data-lucide="printer"></i> Rec</button>
            <button class="btn btn-secondary btn-sm" onclick="window.printLisBarcodeLabel(${sam.id})" title="Stampa Barcode" style="margin-left: 2px;"><i data-lucide="barcode"></i> Bar</button>
        `;
        
        const formattedDate = new Date(sam.collected_at || sam.created_at).toLocaleString('it-IT', { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' });
        
        let genderIcon = '';
        if (p) {
            const g = (p.gender || '').toUpperCase();
            if (g === 'M' || g === 'MASCHIO') {
                genderIcon = ` <i data-lucide="mars" style="color: #2563eb; width: 14px; height: 14px; vertical-align: middle; margin-left: 4px;" title="Maschio"></i>`;
            } else if (g === 'F' || g === 'FEMMINA') {
                genderIcon = ` <i data-lucide="venus" style="color: #db2777; width: 14px; height: 14px; vertical-align: middle; margin-left: 4px;" title="Femmina"></i>`;
            } else {
                genderIcon = ` <i data-lucide="user" style="color: #64748b; width: 14px; height: 14px; vertical-align: middle; margin-left: 4px;" title="Altro"></i>`;
            }
        }

        // Find collection point name
        const cp = collectionPoints.find(point => point.id === parseInt(sam.collection_point_id));
        const cpName = cp ? cp.name : 'Sede Centrale';

        const tr = document.createElement('tr');
        tr.innerHTML = `
            <td>
                <div style="font-family: monospace; font-weight: 700;">${sam.barcode}</div>
                <div style="font-size: 0.75rem; color: var(--text-muted)">${formattedDate}</div>
            </td>
            <td><strong>${p.last_name} ${p.first_name}</strong>${genderIcon}</td>
            <td>${cpName}</td>
            <td>${window.getTubeBadgeHtml(sam.sample_type)}</td>
            <td>${statusBadge}</td>
            <td>
                <div>${testString}</div>
                ${sam.report_notes ? '<div style="font-size: 0.8rem; margin-top: 8px; border-left: 2px solid var(--purple); padding-left: 8px;" class="text-secondary">' + sam.report_notes + '</div>' : ''}
            </td>
            <td><div class="row-actions">${actionBtn}</div></td>
        `;
        tbody.appendChild(tr);
    });
    if (window.lucide) window.lucide.createIcons();
}

window.renderLisAcceptances = function() {
    const samples = DB.get('lab_samples') || [];
    const patients = DB.get('patients') || [];
    const tests = DB.get('lab_tests') || [];
    const services = DB.get('medical_services') || [];
    
    const tbody = document.querySelector('#lis-acceptances-table tbody');
    if (!tbody) return;
    tbody.innerHTML = '';

    const sessions = {};
    samples.forEach(sam => {
        let key = sam.session_uid;
        if (!key) {
            const dateStr = (sam.collected_at || sam.created_at || '').substring(0, 13);
            key = `LEGACY-${sam.patient_id}-${dateStr}`;
        }

        if (!sessions[key]) {
            sessions[key] = {
                session_uid: sam.session_uid || null,
                legacy_key: !sam.session_uid ? key : null,
                patient_id: sam.patient_id,
                collected_at: sam.collected_at || sam.created_at,
                samples: []
            };
        }
        sessions[key].samples.push(sam);
    });

    const sortedSessions = Object.values(sessions).sort((a, b) => new Date(b.collected_at) - new Date(a.collected_at));

    // Read filter inputs
    const aiSearchVal = document.getElementById('lis-acc-ai-search')?.value || '';
    const startDateVal = document.getElementById('lis-acc-filter-start')?.value || '';
    const endDateVal = document.getElementById('lis-acc-filter-end')?.value || '';
    const statusFilterVal = document.getElementById('lis-acc-filter-status')?.value || '';

    let aiFilter = null;
    if (aiSearchVal) {
        aiFilter = window.parseNaturalLanguageQuery(aiSearchVal, 'lis_acc');
    }

    const filteredSessions = sortedSessions.filter(session => {
        const p = patients.find(pat => pat.id === session.patient_id);
        if (!p) return false;

        const sessionDate = session.collected_at ? session.collected_at.substring(0, 10) : '';

        // Calculate session status
        const sessionSamples = session.samples;
        const sessionSampleIds = sessionSamples.map(s => s.id);
        const sessionTests = tests.filter(t => sessionSampleIds.includes(t.sample_id));
        
        let calculatedStatus = 'da prelevare';
        const allCompleted = sessionTests.length > 0 && sessionTests.every(t => t.status === 'completed');
        const hasProcessing = sessionSamples.some(s => s.status === 'received' || s.status === 'processing');
        if (allCompleted) calculatedStatus = 'completato';
        else if (hasProcessing || sessionSamples.some(s => s.status === 'collected')) calculatedStatus = 'in lavorazione';

        const testsText = sessionTests.map(t => {
            const srv = services.find(sv => sv.id === t.service_id);
            return srv ? srv.name.toLowerCase() : '';
        }).join(' ');

        // Apply start date filter
        if (startDateVal && sessionDate < startDateVal) return false;
        if (aiFilter?.startDate && sessionDate < aiFilter.startDate) return false;

        // Apply end date filter
        if (endDateVal && sessionDate > endDateVal) return false;
        if (aiFilter?.endDate && sessionDate > aiFilter.endDate) return false;

        // Apply status filter
        if (statusFilterVal && calculatedStatus !== statusFilterVal) return false;
        if (aiFilter?.status) {
            if (aiFilter.status === 'scheduled' && calculatedStatus !== 'da prelevare') return false;
            if (aiFilter.status === 'completed' && calculatedStatus !== 'completato') return false;
            if (aiFilter.status === 'in_progress' && calculatedStatus !== 'in lavorazione') return false;
        }

        // Apply text query search
        const searchQuery = (aiFilter ? aiFilter.textQuery : '').toLowerCase().trim();
        if (searchQuery) {
            const matchesPatient = `${p.first_name} ${p.last_name}`.toLowerCase().includes(searchQuery) || p.tax_code.toLowerCase().includes(searchQuery);
            const matchesTests = testsText.includes(searchQuery);
            if (!matchesPatient && !matchesTests) return false;
        }

        return true;
    });

    const paginated = window.setupTablePagination('lis-acceptances-table', filteredSessions, () => window.renderLisAcceptances());

    if (filteredSessions.length === 0) {
        tbody.innerHTML = `<tr><td colspan="6" style="text-align: center;" class="text-muted">Nessuna accettazione trovata</td></tr>`;
        return;
    }

    paginated.forEach(sess => {
        const patient = patients.find(p => p.id === sess.patient_id);
        const pName = patient ? `${patient.last_name} ${patient.first_name}` : 'Sconosciuto';
        
        let genderIcon = '';
        if (patient) {
            const g = (patient.gender || '').toUpperCase();
            if (g === 'M' || g === 'MASCHIO') {
                genderIcon = ` <i data-lucide="mars" style="color: #2563eb; width: 14px; height: 14px; vertical-align: middle; margin-left: 4px;" title="Maschio"></i>`;
            } else if (g === 'F' || g === 'FEMMINA') {
                genderIcon = ` <i data-lucide="venus" style="color: #db2777; width: 14px; height: 14px; vertical-align: middle; margin-left: 4px;" title="Femmina"></i>`;
            } else {
                genderIcon = ` <i data-lucide="user" style="color: #64748b; width: 14px; height: 14px; vertical-align: middle; margin-left: 4px;" title="Altro"></i>`;
            }
        }

        const formattedPName = `<strong>${pName}</strong>${genderIcon}`;
        
        let barcodesHtml = '';
        sess.samples.forEach(sam => {
            const colorHtml = window.getTubeBadgeHtml(sam.sample_type);
            const statusStyle = sam.status === 'suspended' ? 'text-decoration: line-through; opacity: 0.6;' : '';
            barcodesHtml += `
                <div style="display: inline-flex; align-items: center; margin-right: 8px; margin-bottom: 4px; padding: 4px 8px; border: 1px solid var(--border-color); border-radius: var(--radius-sm); background: var(--bg-surface);">
                    <span style="font-family: monospace; font-weight: 700; font-size: 0.8rem; margin-right: 6px; ${statusStyle}">${sam.barcode}</span>
                    ${colorHtml}
                    ${sam.status === 'suspended' ? '<span class="badge badge-danger" style="font-size:0.65rem; padding:2px 4px; margin-left:4px;">SOSPESO</span>' : ''}
                </div>
            `;
        });

        let overallStatus = 'In corso';
        let overallBadgeClass = 'badge-warning';
        
        const statuses = sess.samples.map(s => s.status);
        if (statuses.every(s => s === 'completed')) {
            overallStatus = 'Refertato';
            overallBadgeClass = 'badge-purple';
        } else if (statuses.every(s => s === 'validated')) {
            overallStatus = 'Validato';
            overallBadgeClass = 'badge-success';
        } else if (statuses.every(s => s === 'to_validate')) {
            overallStatus = 'Da Validare';
            overallBadgeClass = 'badge-info';
        } else if (statuses.every(s => s === 'suspended')) {
            overallStatus = 'Sospeso';
            overallBadgeClass = 'badge-danger';
        } else if (statuses.every(s => s === 'non_prelevato')) {
            overallStatus = 'Non Prelevato';
            overallBadgeClass = 'badge-danger';
        } else if (statuses.every(s => s === 'non_pervenuto')) {
            overallStatus = 'Non Pervenuto';
            overallBadgeClass = 'badge-warning';
        } else if (statuses.includes('suspended')) {
            overallStatus = 'Part. Sospeso';
            overallBadgeClass = 'badge-danger';
        }

        const statusBadge = `<span class="badge ${overallBadgeClass}">${overallStatus}</span>`;

        const linkedServices = [];
        sess.samples.forEach(sam => {
            const samTests = tests.filter(t => t.sample_id === sam.id);
            samTests.forEach(t => {
                const srv = services.find(s => s.id === t.service_id);
                const srvName = srv ? srv.name : t.test_name;
                if (!linkedServices.includes(srvName)) {
                    linkedServices.push(srvName);
                }
            });
        });
        const examsText = linkedServices.join(', ');

        const sessKey = sess.session_uid ? `'${sess.session_uid}'` : `'${sess.legacy_key}'`;
        const actionBtn = `
            <button class="btn btn-primary btn-sm" onclick="window.openEditLisAcceptanceModal(${sessKey})">
                <i data-lucide="edit" style="width: 12px; height: 12px; vertical-align: middle; margin-right: 4px;"></i> Gestisci
            </button>
        `;

        const firstSam = sess.samples[0];
        const collectionPoints = DB.get('lis_collection_points') || [];
        const cp = firstSam ? collectionPoints.find(point => point.id === parseInt(firstSam.collection_point_id)) : null;
        const cpName = cp ? cp.name : 'Sede Centrale';
        const formattedDate = window.safeFormatDate(sess.collected_at);

        const tr = document.createElement('tr');
        tr.innerHTML = `
            <td><strong>${formattedDate}</strong></td>
            <td>${formattedPName}</td>
            <td>${cpName}</td>
            <td><div style="display: flex; flex-wrap: wrap;">${barcodesHtml}</div></td>
            <td>${statusBadge}</td>
            <td><span style="font-size: 0.8rem;" class="text-secondary">${examsText || '-'}</span></td>
            <td><div class="row-actions">${actionBtn}</div></td>
        `;
        tbody.appendChild(tr);
    });

    if (window.lucide) window.lucide.createIcons();
};

window.openResultsFromAcceptance = function(sampleId) {
    const samples = DB.get('lab_samples') || [];
    const sam = samples.find(s => s.id === sampleId);
    if (sam && sam.status === 'collected') {
        DB.update('lab_samples', sampleId, { status: 'processing' });
    }
    closeModal('modal-edit-lis-acceptance');
    window.openResultsModal(sampleId, true);
};

window.openEditLisAcceptanceModal = function(sessionKey) {
    const samples = DB.get('lab_samples') || [];
    const patients = DB.get('patients') || [];
    const tests = DB.get('lab_tests') || [];
    const services = DB.get('medical_services') || [];

    let sessionSamples = [];
    if (sessionKey.startsWith('LEGACY-')) {
        const parts = sessionKey.split('-');
        const patId = parseInt(parts[1]);
        const dateStr = parts.slice(2).join('-');
        sessionSamples = samples.filter(sam => {
            if (sam.session_uid) return false;
            const samDateStr = (sam.collected_at || sam.created_at || '').substring(0, 13);
            return sam.patient_id === patId && samDateStr === dateStr;
        });
    } else {
        sessionSamples = samples.filter(sam => sam.session_uid === sessionKey);
    }

    if (sessionSamples.length === 0) return;

    const patient = patients.find(p => p.id === sessionSamples[0].patient_id);
    const pName = patient ? `${patient.last_name} ${patient.first_name}` : 'Sconosciuto';
    const pBirth = patient ? new Date(patient.birth_date).toLocaleDateString('it-IT') : '';
    
    document.getElementById('edit-lis-patient-name').innerText = `${pName} (n. ${pBirth})`;
    document.getElementById('edit-lis-session-date').innerText = window.safeFormatDate(sessionSamples[0].collected_at);
    document.getElementById('edit-lis-session-uid').innerText = sessionSamples[0].session_uid || 'N/A (Legacy)';

    // Dynamic buttons binding
    const firstSample = sessionSamples[0];
    const receiptBtn = document.getElementById('btn-edit-lis-receipt');
    const reportBtn = document.getElementById('btn-edit-lis-report');
    if (receiptBtn) {
        receiptBtn.onclick = () => window.printLisAcceptanceReceipt(firstSample.id);
    }
    if (reportBtn) {
        reportBtn.onclick = () => window.openLisReportView(firstSample.id);
    }
    const resultsBtn = document.getElementById('btn-edit-lis-results-all');
    if (resultsBtn) {
        const hasActiveSamples = sessionSamples.some(s => s.status !== 'suspended');
        if (hasActiveSamples) {
            resultsBtn.style.display = 'inline-flex';
            resultsBtn.onclick = () => {
                sessionSamples.forEach(sam => {
                    if (sam.status === 'collected') {
                        DB.update('lab_samples', sam.id, { status: 'processing' });
                    }
                });
                closeModal('modal-edit-lis-acceptance');
                window.openResultsModal(firstSample.id, true);
            };
        } else {
            resultsBtn.style.display = 'none';
        }
    }

    // Populate notes
    const notesTextarea = document.getElementById('edit-lis-session-notes');
    if (notesTextarea) {
        notesTextarea.value = firstSample.report_notes || '';
    }

    // Save notes button binding
    const saveNotesBtn = document.getElementById('btn-save-lis-session-notes');
    if (saveNotesBtn) {
        saveNotesBtn.onclick = () => {
            const updatedNotes = notesTextarea.value.trim();
            sessionSamples.forEach(sam => {
                DB.update('lab_samples', sam.id, { report_notes: updatedNotes });
            });
            alert("Note dell'accettazione salvate con successo!");
            window.renderLisAcceptances();
            window.renderSamples();
        };
    }

    const container = document.getElementById('edit-lis-tubes-container');
    if (!container) return;
    container.innerHTML = '';

    sessionSamples.forEach(sam => {
        const samTests = tests.filter(t => t.sample_id === sam.id);
        const samExamsNames = samTests.map(t => {
            const srv = services.find(s => s.id === t.service_id);
            return srv ? srv.name : t.test_name;
        });
        const examsUnique = [...new Set(samExamsNames)].join(', ');

        const typeLower = (sam.sample_type || '').toLowerCase();
        let capColor = '#94a3b8';
        let liquidColor = 'rgba(239, 68, 68, 0.25)';
        
        if (typeLower.includes('viola') || typeLower.includes('edta')) {
            capColor = '#7c3aed';
        } else if (typeLower.includes('rosso') || typeLower.includes('siero')) {
            capColor = '#dc2626';
        } else if (typeLower.includes('azzurro') || typeLower.includes('citrato')) {
            capColor = '#2563eb';
        } else if (typeLower.includes('verde') || typeLower.includes('eparina')) {
            capColor = '#059669';
        } else if (typeLower.includes('giallo') || typeLower.includes('urine')) {
            capColor = '#eab308';
            liquidColor = 'rgba(234, 179, 8, 0.2)';
        }

        let statusBadge = '';
        if (sam.status === 'collected') {
            statusBadge = '<span class="badge badge-info">Prelievo</span>';
        } else if (sam.status === 'processing') {
            statusBadge = '<span class="badge badge-warning" style="background-color: #f59e0b; color: #fff;">In Corso</span>';
        } else if (sam.status === 'to_validate') {
            statusBadge = '<span class="badge" style="background-color: #f97316; color: #fff;">Da Validare</span>';
        } else if (sam.status === 'validated') {
            statusBadge = '<span class="badge badge-success" style="background-color: #10b981; color: #fff;">Validato</span>';
        } else if (sam.status === 'completed') {
            statusBadge = '<span class="badge badge-purple" style="background-color: #8b5cf6; color: #fff;">Refertato</span>';
        } else if (sam.status === 'suspended') {
            statusBadge = '<span class="badge badge-danger" style="background-color: #ef4444; color: #fff;">Sospeso</span>';
        }

        const isSuspended = sam.status === 'suspended';
        const suspendBtnText = isSuspended ? 'Ripristina' : 'Sospendi';
        const suspendBtnIcon = isSuspended ? 'play' : 'pause';
        const suspendBtnClass = isSuspended ? 'btn-success' : 'btn-danger';
        const textStyle = isSuspended ? 'text-decoration: line-through; opacity: 0.5;' : '';

        const tubeCard = document.createElement('div');
        tubeCard.className = 'card';
        tubeCard.style.padding = '15px';
        tubeCard.style.display = 'flex';
        tubeCard.style.flexDirection = 'column';
        tubeCard.style.justifyContent = 'space-between';
        tubeCard.style.border = isSuspended ? '2px dashed var(--danger)' : '1px solid var(--border-color)';
        tubeCard.style.background = isSuspended ? 'var(--danger-light)' : 'var(--bg-surface)';

        tubeCard.innerHTML = `
            <div style="display: flex; gap: 15px; align-items: flex-start; margin-bottom: 12px;">
                <div style="width: 40px; height: 110px; display: flex; flex-direction: column; align-items: center; justify-content: flex-start;">
                    <div style="width: 20px; height: 25px; background: ${capColor}; border-radius: 4px 4px 0 0; box-shadow: inset 0 3px 5px rgba(255,255,255,0.4), 0 2px 4px rgba(0,0,0,0.15); border-bottom: 2px solid rgba(0,0,0,0.2);"></div>
                    <div style="width: 16px; height: 75px; border: 2px solid #cbd5e1; border-top: none; border-radius: 0 0 8px 8px; background: white; box-shadow: inset -2px 0 5px rgba(0,0,0,0.05); overflow: hidden; display: flex; flex-direction: column; justify-content: flex-end;">
                        <div style="width: 100%; height: 50px; background: ${isSuspended ? 'rgba(148,163,184,0.3)' : liquidColor}; border-radius: 0 0 6px 6px;"></div>
                    </div>
                </div>

                <div style="flex: 1;">
                    <div style="font-family: monospace; font-weight: 700; font-size: 1.05rem; ${textStyle}">${sam.barcode}</div>
                    <div style="font-size: 0.8rem; font-weight: 600; color: var(--text-secondary); margin-top: 2px;">${sam.sample_type}</div>
                    <div style="margin-top: 6px;">${statusBadge}</div>
                    <div style="margin-top: 10px; font-size: 0.8rem; font-weight: 700; color: var(--text-primary); ${textStyle}">Esami:</div>
                    <div style="font-size: 0.75rem; color: var(--text-secondary); ${textStyle}">${examsUnique || '-'}</div>
                </div>
            </div>

            <div style="display: flex; gap: 8px; justify-content: flex-end; border-top: 1px solid var(--border-color); padding-top: 10px; margin-top: auto;">
                <button class="btn btn-secondary btn-sm" onclick="window.printLisBarcodeLabel(${sam.id})" title="Ristampa Etichetta Barcode">
                    <i data-lucide="barcode" style="width: 12px; height: 12px; vertical-align: middle; margin-right: 4px;"></i> Ristampa
                </button>
                <button class="btn ${suspendBtnClass} btn-sm" onclick="window.toggleSuspendSample(${sam.id}, '${sessionKey}')">
                    <i data-lucide="${suspendBtnIcon}" style="width: 12px; height: 12px; vertical-align: middle; margin-right: 4px;"></i> ${suspendBtnText}
                </button>
            </div>
        `;
        container.appendChild(tubeCard);
    });

    openModal('modal-edit-lis-acceptance');
    if (window.lucide) window.lucide.createIcons();
};

window.toggleSuspendSample = function(sampleId, sessionKey) {
    const samples = DB.get('lab_samples') || [];
    const sam = samples.find(s => s.id === sampleId);
    if (!sam) return;

    const tests = DB.get('lab_tests') || [];
    const samTests = tests.filter(t => t.sample_id === sampleId);

    const isCurrentlySuspended = sam.status === 'suspended';

    if (isCurrentlySuspended) {
        const oldStatus = sam.original_status || 'collected';
        DB.update('lab_samples', sampleId, { status: oldStatus, original_status: null });
        
        samTests.forEach(t => {
            if (t.status === 'suspended') {
                DB.update('lab_tests', t.id, { status: 'pending' });
            }
        });

        DB.logAudit(4, "RESTORE_SAMPLE", "lab_samples", sampleId, { barcode: sam.barcode });
        alert(`Campione ${sam.barcode} ripristinato con successo.`);
    } else {
        const currentStatus = sam.status;
        DB.update('lab_samples', sampleId, { status: 'suspended', original_status: currentStatus });
        
        samTests.forEach(t => {
            DB.update('lab_tests', t.id, { status: 'suspended' });
        });

        DB.logAudit(4, "SUSPEND_SAMPLE", "lab_samples", sampleId, { barcode: sam.barcode });
        alert(`Campione ${sam.barcode} e tutti gli esami correlati sono stati sospesi.`);
    }

    window.openEditLisAcceptanceModal(sessionKey);
    window.renderLisAcceptances();
    window.renderSamples();
};

window.exportLisSamplesCsv = function() {
    const filteredSamples = window.getFilteredSamplesList();
    if (filteredSamples.length === 0) {
        alert("Nessun campione da esportare.");
        return;
    }

    let csv = 'Barcode;Data Prelievo;Paziente;Tipo Provetta;Stato;Esami\n\n';
    const patients = DB.get('patients') || [];
    const tests = DB.get('lab_tests') || [];
    const services = DB.get('medical_services') || [];

    filteredSamples.forEach(sam => {
        const p = patients.find(pat => pat.id === sam.patient_id);
        const pName = p ? `${p.last_name} ${p.first_name}` : 'Sconosciuto';
        const dateStr = window.safeFormatDate(sam.collected_at || sam.created_at);
        
        const samTests = tests.filter(t => t.sample_id === sam.id);
        const testNames = samTests.map(t => {
            const srv = services.find(s => s.id === t.service_id);
            return srv ? srv.name : t.test_name;
        });
        const examsStr = [...new Set(testNames)].join(', ');

        let statusLabel = sam.status;
        if (sam.status === 'collected') statusLabel = 'Prelievo Effettuato';
        else if (sam.status === 'processing') statusLabel = 'In Corso';
        else if (sam.status === 'to_validate') statusLabel = 'Da Validare';
        else if (sam.status === 'validated') statusLabel = 'Validato';
        else if (sam.status === 'completed') statusLabel = 'Refertato';
        else if (sam.status === 'suspended') statusLabel = 'Sospeso';

        csv += `"${sam.barcode}";"${dateStr}";"${pName}";"${sam.sample_type}";"${statusLabel}";"${examsStr}"

`;
    });

    const blob = new Blob([new Uint8Array([0xEF, 0xBB, 0xBF]), csv], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.setAttribute("download", `Elenco_Campioni_LIS_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
};

window.printLisSamplesReport = function() {
    const filteredSamples = window.getFilteredSamplesList();
    if (filteredSamples.length === 0) {
        alert("Nessun campione da stampare.");
        return;
    }

    const patients = DB.get('patients') || [];
    const tests = DB.get('lab_tests') || [];
    const services = DB.get('medical_services') || [];

    const printWindow = window.open('', '_blank');
    if (!printWindow) {
        alert("Consenti i pop-up per poter visualizzare la stampa del report.");
        return;
    }

    let rowsHtml = '';
    filteredSamples.forEach(sam => {
        const p = patients.find(pat => pat.id === sam.patient_id);
        const pName = p ? `${p.last_name} ${p.first_name}` : 'Sconosciuto';
        const dateStr = window.safeFormatDate(sam.collected_at || sam.created_at);
        
        const samTests = tests.filter(t => t.sample_id === sam.id);
        const testNames = samTests.map(t => {
            const srv = services.find(s => s.id === t.service_id);
            return srv ? srv.name : t.test_name;
        });
        const examsStr = [...new Set(testNames)].join(', ');

        let statusLabel = sam.status;
        let badgeColor = '#94a3b8';
        if (sam.status === 'collected') { statusLabel = 'Prelievo'; badgeColor = '#0ea5e9'; }
        else if (sam.status === 'processing') { statusLabel = 'In Corso'; badgeColor = '#f59e0b'; }
        else if (sam.status === 'to_validate') { statusLabel = 'Da Validare'; badgeColor = '#f97316'; }
        else if (sam.status === 'validated') { statusLabel = 'Validato'; badgeColor = '#10b981'; }
        else if (sam.status === 'completed') { statusLabel = 'Refertato'; badgeColor = '#8b5cf6'; }
        else if (sam.status === 'suspended') { statusLabel = 'Sospeso'; badgeColor = '#ef4444'; }

        rowsHtml += `
            <tr>
                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0; font-family: monospace; font-weight: 700;">${sam.barcode}</td>
                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;">${dateStr}</td>
                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0; font-weight: 600;">${pName}</td>
                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0; font-size: 0.85rem;">${sam.sample_type}</td>
                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;"><span style="display:inline-block; padding: 4px 8px; border-radius: 4px; color: white; background: ${badgeColor}; font-size: 0.75rem; font-weight: 700;">${statusLabel}</span></td>
                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0; font-size: 0.8rem; color: #475569;">${examsStr}</td>
            </tr>
        `;
    });

    printWindow.document.write(`
        <html>
        <head>
            <title>Report Campioni LIS</title>
            <style>
                body { font-family: -apple-system, sans-serif; padding: 30px; color: #1e293b; background: white; }
                table { width: 100%; border-collapse: collapse; margin-top: 20px; }
                th { text-align: left; padding: 12px 10px; background: #f8fafc; border-bottom: 2px solid #cbd5e1; font-size: 0.85rem; text-transform: uppercase; color: #64748b; }
                h1 { font-size: 1.5rem; margin-bottom: 4px; color: #0f172a; }
                p { font-size: 0.9rem; color: #64748b; margin-top: 0; }
            </style>
        </head>
        <body>
            <h1>Report Tracciabilità Campioni e Provette LIS</h1>
            <p>Estratto il ${new Date().toLocaleString('it-IT')}</p>
            <table>
                <thead>
                    <tr>
                        <th>Barcode</th>
                        <th>Data Prelievo</th>
                        <th>Paziente</th>
                        <th>Tipo Provetta</th>
                        <th>Stato</th>
                        <th>Esami Associati</th>
                    </tr>
                </thead>
                <tbody>
                    ${rowsHtml}
                </tbody>
            </table>
            <script>
                window.onload = function() {
                    window.print();
                    window.close();
                }
            </script>
        </body>
        </html>
    `);
    printWindow.document.close();
};

window.startProcessingSample = function(sampleId) {
    DB.update('lab_samples', sampleId, { status: 'processing' });
    renderSamples();
};

window.openResultsModal = function(sampleId, isEdit = false) {
    const samples = DB.get('lab_samples') || [];
    const patients = DB.get('patients') || [];
    const tests = DB.get('lab_tests') || [];
    const services = DB.get('medical_services') || [];
    
    const sam = samples.find(s => s.id === sampleId);
    if (!sam) return;

    const patient = patients.find(p => p.id === sam.patient_id);
    const patientName = patient ? `${patient.last_name} ${patient.first_name}` : "Sconosciuto";

    // Find all samples in the same session
    let sessionSamples = [];
    if (sam.session_uid) {
        sessionSamples = samples.filter(s => s.session_uid === sam.session_uid && s.status !== 'suspended');
    } else {
        const patId = sam.patient_id;
        const dateStr = (sam.collected_at || sam.created_at || '').substring(0, 10);
        sessionSamples = samples.filter(s => {
            const sDateStr = (s.collected_at || s.created_at || '').substring(0, 10);
            return s.patient_id === patId && sDateStr === dateStr && !s.session_uid && s.status !== 'suspended';
        });
    }

    if (sessionSamples.length === 0) {
        sessionSamples = [sam];
    }

    document.getElementById('res-sample-id').value = sam.id;
    document.getElementById('res-barcode-label').innerText = sessionSamples.map(s => s.barcode).join(', ');
    document.getElementById('res-patient-label').innerText = patientName;

    const container = document.getElementById('results-inputs-container');
    container.innerHTML = '';

    let containerHtml = '';
    let totalTestsRendered = 0;

    sessionSamples.forEach(currSam => {
        const currSamTests = tests.filter(t => t.sample_id === currSam.id);
        if (currSamTests.length === 0) return;

        totalTestsRendered += currSamTests.length;
        const isReadOnly = (currSam.status === 'to_validate' || currSam.status === 'validated' || currSam.status === 'completed') && !isEdit;

        let rowsHtml = '';
        currSamTests.forEach(t => {
            const val = t.result_value !== null ? t.result_value : '';
            const readOnlyAttr = isReadOnly ? 'readonly style="background:var(--bg-base); cursor:not-allowed;"' : '';
            const inputStyle = 'width: 100%; padding: 6px 10px; border-radius: var(--radius-sm); border: 1px solid var(--border-color); background: var(--bg-surface); color: var(--text-primary); font-size: 0.85rem; font-weight: 600; box-sizing: border-box;';
            
            if (typeof window.isMicrobiologyService === 'function' && window.isMicrobiologyService(t)) {
                rowsHtml += `
                    <tr style="border-bottom: 1px solid var(--border-color);">
                        <td style="padding: 10px 12px; font-weight: 600; font-size: 0.85rem; color: var(--text-primary);">
                            ${t.test_name} 
                            <span class="badge" style="background:#0284c7; color:white; font-size:0.7rem; padding:2px 6px; border-radius:4px; margin-left:6px; font-weight:bold;">MICROBIOLOGIA</span>
                        </td>
                        <td style="padding: 6px 12px;">
                            <button type="button" class="btn btn-sm" onclick="closeModal('modal-enter-results'); window.openMicrobiologyResultsModal(${t.id});" style="background-color: var(--primary); color: white; border: none; padding: 6px 12px; border-radius: 6px; font-weight: 500; display: inline-flex; align-items: center; gap: 6px; cursor: pointer;">
                                <i data-lucide="beaker" style="width:14px; height:14px; vertical-align:middle;"></i> Referta Microbiologia
                            </button>
                            ${val ? `<span style="margin-left: 10px; font-weight: 600; font-size: 0.8rem; color: var(--text-secondary);">Esito: <strong>${val}</strong></span>` : ''}
                        </td>
                        <td style="padding: 10px 12px; font-size: 0.85rem; font-family: monospace; color: var(--text-secondary);">${t.unit || '-'}</td>
                        <td style="padding: 10px 12px; font-size: 0.85rem; color: var(--text-secondary);">${t.reference_range || 'N/A'}</td>
                    </tr>
                `;
            } else {
                rowsHtml += `
                    <tr style="border-bottom: 1px solid var(--border-color);">
                        <td style="padding: 10px 12px; font-weight: 600; font-size: 0.85rem; color: var(--text-primary);">${t.test_name}</td>
                        <td style="padding: 6px 12px;">
                            <input type="text" id="test-input-${t.id}" class="form-control" value="${val}" required placeholder="Valore..." ${readOnlyAttr} style="${inputStyle}">
                        </td>
                        <td style="padding: 10px 12px; font-size: 0.85rem; font-family: monospace; color: var(--text-secondary);">${t.unit || '-'}</td>
                        <td style="padding: 10px 12px; font-size: 0.85rem; color: var(--text-secondary);">${t.reference_range || 'N/A'}</td>
                    </tr>
                `;
            }
        });

        containerHtml += `
            <div style="margin-bottom: 20px;">
                <div style="background: var(--bg-base); padding: 8px 12px; border-radius: var(--radius-sm); border: 1px solid var(--border-color); margin-bottom: 8px; font-size: 0.85rem; font-weight: 700; color: var(--text-primary); display: flex; justify-content: space-between; align-items: center;">
                    <span style="display: flex; align-items: center; gap: 6px;">
                        <i data-lucide="test-tube" style="width: 16px; height: 16px; color: var(--primary);"></i>
                        Campione: <strong>${currSam.sample_type}</strong>
                    </span>
                    <span style="font-family: monospace; font-size: 0.8rem; background: var(--bg-surface); padding: 2px 8px; border-radius: var(--radius-sm); border: 1px solid var(--border-color); color: var(--primary);">
                        Barcode: <strong>${currSam.barcode}</strong>
                    </span>
                </div>
                <div style="border: 1px solid var(--border-color); border-radius: var(--radius-md); background: var(--bg-surface); overflow-y: auto; box-shadow: inset 0 2px 4px rgba(0,0,0,0.02);">
                    <table style="width: 100%; border-collapse: collapse; text-align: left;">
                        <thead>
                            <tr style="background: var(--bg-base); border-bottom: 2px solid var(--border-color);">
                                <th style="padding: 10px 12px; font-weight: 600; font-size: 0.8rem; color: var(--text-secondary);">Analisi / Parametro</th>
                                <th style="padding: 10px 12px; font-weight: 600; font-size: 0.8rem; color: var(--text-secondary); width: 200px;">Valore Risultato</th>
                                <th style="padding: 10px 12px; font-weight: 600; font-size: 0.8rem; color: var(--text-secondary); width: 100px;">Unità</th>
                                <th style="padding: 10px 12px; font-weight: 600; font-size: 0.8rem; color: var(--text-secondary); width: 150px;">Riferimento</th>
                            </tr>
                        </thead>
                        <tbody>
                            ${rowsHtml}
                        </tbody>
                    </table>
                </div>
            </div>
        `;
    });

    if (totalTestsRendered === 0) {
        container.innerHTML = '<span class="text-muted" style="font-size: 0.8rem;">Nessun esame associato a questa accettazione.</span>';
    } else {
        container.innerHTML = containerHtml;
    }
    
    if (window.lucide) {
        window.lucide.createIcons();
    }

    const editor = document.getElementById('lis-report-editor');
    if (editor) {
        editor.innerHTML = sam.report_notes || '';
        const observationsEditable = (sam.status === 'validated' || sam.status === 'completed' || isEdit);
        editor.contentEditable = observationsEditable ? "true" : "false";
        
        const toolbar = document.getElementById('lis-editor-toolbar');
        if (toolbar) {
            toolbar.style.display = observationsEditable ? "flex" : "none";
        }
    }

    // Handle Doctor stamp selection group
    const signatureGroup = document.getElementById('lis-reporting-signature-group');
    const submitBtn = document.getElementById('btn-submit-results-form');
    
    if (signatureGroup) {
        const showSignature = (sam.status === 'validated' || sam.status === 'completed' || isEdit);
        signatureGroup.style.display = showSignature ? 'block' : 'none';
        
        const docSelect = document.getElementById('lis-signer-doctor');
        if (docSelect) {
            docSelect.innerHTML = '<option value="">-- Seleziona Medico Firmatario --</option>';
            const staff = DB.get('staff') || [];
            const doctors = DB.get('doctors') || [];
            doctors.filter(d => d.active === 1).forEach(d => {
                const s = staff.find(st => st.id === d.staff_id);
                if (s) {
                    docSelect.innerHTML += `<option value="${d.id}">Dott. ${s.last_name} (${d.specialization})</option>`;
                }
            });
            docSelect.value = sam.signed_by_doctor_id || '';
            docSelect.disabled = (sam.status === 'completed' && !isEdit);
        }
    }

    // Adjust modal footer buttons
    const footer = document.querySelector('#modal-enter-results .modal-footer');
    if (footer) {
        footer.innerHTML = '<button type="button" class="btn btn-secondary" onclick="closeModal(\'modal-enter-results\')">Annulla</button>';
        
        if (sam.status === 'processing') {
            footer.innerHTML += '<button type="submit" class="btn btn-primary" id="btn-submit-results-form">Invia a Validazione</button>';
        } else if (sam.status === 'to_validate') {
            if (isEdit) {
                footer.innerHTML += '<button type="submit" class="btn btn-primary" id="btn-submit-results-form">Salva Modifiche Risultati</button>';
            } else {
                const isAuth = window.isUserAuthorizedToValidate();
                const disabledAttr = isAuth ? '' : 'disabled style="opacity:0.6; cursor:not-allowed;" title="Non autorizzato alla validazione"';
                footer.innerHTML += `<button type="button" class="btn btn-warning" onclick="window.validateSample(${sam.id})" ${disabledAttr} style="background-color:#f97316; border-color:#f97316; color:#fff;">Valida Risultati</button>`;
                footer.innerHTML += `<button type="button" class="btn btn-danger" onclick="window.repeatSample(${sam.id})" ${disabledAttr} style="background-color:var(--danger); border-color:var(--danger); color:#fff; margin-left: 8px;"><i data-lucide="rotate-ccw" style="width: 14px; height: 14px; display: inline-block; vertical-align: middle; margin-right: 4px;"></i>Ripeti Esame</button>`;
            }
        } else if (sam.status === 'validated') {
            footer.innerHTML += '<button type="submit" class="btn btn-success" id="btn-submit-results-form">Finalizza & Firma Referto</button>';
            const isAuth = window.isUserAuthorizedToValidate();
            const disabledAttr = isAuth ? '' : 'disabled style="opacity:0.6; cursor:not-allowed;" title="Non autorizzato"';
            footer.innerHTML += `<button type="button" class="btn btn-warning" onclick="window.unvalidateSample(${sam.id})" ${disabledAttr} style="background-color:var(--warning); border-color:var(--warning); color:#fff; margin-left: 8px;"><i data-lucide="x-circle" style="width: 14px; height: 14px; display: inline-block; vertical-align: middle; margin-right: 4px;"></i>Svalida</button>`;
            footer.innerHTML += `<button type="button" class="btn btn-danger" onclick="window.repeatSample(${sam.id})" ${disabledAttr} style="background-color:var(--danger); border-color:var(--danger); color:#fff; margin-left: 8px;"><i data-lucide="rotate-ccw" style="width: 14px; height: 14px; display: inline-block; vertical-align: middle; margin-right: 4px;"></i>Ripeti Esame</button>`;
        } else if (sam.status === 'completed') {
            if (isEdit) {
                footer.innerHTML += '<button type="submit" class="btn btn-primary" id="btn-submit-results-form">Salva Modifiche Referto</button>';
            }
            const isAuth = window.isUserAuthorizedToValidate();
            const disabledAttr = isAuth ? '' : 'disabled style="opacity:0.6; cursor:not-allowed;" title="Non autorizzato"';
            footer.innerHTML += `<button type="button" class="btn btn-warning" onclick="window.unvalidateSample(${sam.id})" ${disabledAttr} style="background-color:var(--warning); border-color:var(--warning); color:#fff; margin-left: 8px;"><i data-lucide="x-circle" style="width: 14px; height: 14px; display: inline-block; vertical-align: middle; margin-right: 4px;"></i>Svalida</button>`;
            footer.innerHTML += `<button type="button" class="btn btn-danger" onclick="window.repeatSample(${sam.id})" ${disabledAttr} style="background-color:var(--danger); border-color:var(--danger); color:#fff; margin-left: 8px;"><i data-lucide="rotate-ccw" style="width: 14px; height: 14px; display: inline-block; vertical-align: middle; margin-right: 4px;"></i>Ripeti Esame</button>`;
        }
    }

    // Load patient LIS clinical history
    const lisHistoryContainer = document.getElementById('lis-history-container');
    const lisChartContainer = document.getElementById('lis-chart-container');
    
    if (lisHistoryContainer) {
        lisHistoryContainer.innerHTML = '';
        if (lisChartContainer) lisChartContainer.style.display = 'none';
        
        const patientSamples = (DB.get('lab_samples') || []).filter(s => s.patient_id === sam.patient_id && s.id !== sampleId && s.status === 'completed');
        const pastSampleIds = patientSamples.map(s => s.id);
        const pastTests = (DB.get('lab_tests') || []).filter(t => pastSampleIds.includes(t.sample_id));
        
        if (pastTests.length === 0) {
            lisHistoryContainer.innerHTML = '<span class="text-muted" style="font-size:0.75rem;">Nessuna analisi storica presente.</span>';
        } else {
            const grouped = {};
            pastTests.forEach(pt => {
                if (!grouped[pt.test_name]) grouped[pt.test_name] = [];
                grouped[pt.test_name].push(pt);
            });
            
            for (const [testName, list] of Object.entries(grouped)) {
                const unit = list[0].unit || '';
                const ref = list[0].reference_range || '';
                
                list.forEach(pt => {
                    const sampleObj = patientSamples.find(ps => ps.id === pt.sample_id);
                    pt.date = sampleObj ? new Date(sampleObj.collected_at || sampleObj.created_at) : new Date();
                });
                list.sort((a,b) => b.date - a.date);
                
                const div = document.createElement('div');
                div.style.background = 'var(--bg-surface)';
                div.style.border = '1px solid var(--border-color)';
                div.style.borderRadius = 'var(--radius-sm)';
                div.style.padding = '8px';
                div.style.fontSize = '0.8rem';
                div.style.marginBottom = '6px';
                
                let pastValsHTML = list.map(pt => {
                    const dateStr = pt.date.toLocaleDateString('it-IT');
                    const valColor = pt.status === 'flagged' ? 'color: var(--danger); font-weight:700;' : '';
                    return `<div style="display:flex; justify-content:space-between; font-size:0.75rem; margin-top:2px;">
                        <span>${dateStr}</span>
                        <strong style="${valColor}">${pt.result_value} ${unit}</strong>
                    </div>`;
                }).join('');
                
                const numericalVals = list.filter(pt => !isNaN(parseFloat(pt.result_value))).map(pt => ({
                    date: pt.date,
                    val: parseFloat(pt.result_value)
                })).sort((a,b) => a.date - b.date);
                
                let chartBtn = '';
                if (numericalVals.length >= 2) {
                    chartBtn = `<button type="button" class="btn btn-secondary btn-sm" onclick='window.drawLisTrendChart(${JSON.stringify(numericalVals)}, "${testName}", "${unit}")' style="padding:2px 6px; font-size:0.65rem; margin-top:4px;"><i data-lucide="line-chart" style="width:10px;height:10px;vertical-align:middle;margin-right:2px;"></i> Grafico</button>`;
                }
                
                div.innerHTML = `
                    <div style="font-weight:700; color:var(--text-primary); border-bottom:1px dashed var(--border-color); padding-bottom:3px; display:flex; justify-content:space-between; align-items:center;">
                        <span>${testName}</span>
                        <span style="font-size:0.7rem; font-weight:normal; color:var(--text-muted);">Rif: ${ref}</span>
                    </div>
                    ${pastValsHTML}
                    ${chartBtn}
                `;
                lisHistoryContainer.appendChild(div);
            }
            if (window.lucide) window.lucide.createIcons();
        }
    }

    openModal('modal-enter-results');
};

// MODULE 6: RIS RADIOLOGIA
window.renderRisStudies = function(query = '') {
    const studies = DB.get('radiology_studies');
    const patients = DB.get('patients');
    const doctors = DB.get('doctors');
    const staff = DB.get('staff');
    const services = DB.get('medical_services');
    const tbody = document.querySelector('#ris-table tbody');
    tbody.innerHTML = '';
    
    const roleSelect = document.getElementById('user-role-select');
    const currentRole = roleSelect ? roleSelect.value : 'admin';
    const isStaff = currentRole === 'staff';
    
    // Read filter inputs
    const aiSearchVal = document.getElementById('ris-ai-search')?.value || '';
    const startDateVal = document.getElementById('ris-filter-start')?.value || '';
    const endDateVal = document.getElementById('ris-filter-end')?.value || '';
    const statusFilterVal = document.getElementById('ris-filter-status')?.value || '';
    const doctorFilterVal = document.getElementById('ris-filter-doctor')?.value || '';
    const requestingDoctorFilterVal = document.getElementById('ris-filter-requesting-doctor')?.value || '';

    let aiFilter = null;
    if (aiSearchVal) {
        aiFilter = window.parseNaturalLanguageQuery(aiSearchVal, 'ris');
    }

    const filtered = studies.filter(st => {
        const p = patients.find(pat => pat.id === st.patient_id);
        if (!p) return false;

        const doc = doctors.find(d => d.id === st.doctor_id);
        const docStaff = doc ? staff.find(s => s.id === doc.staff_id) : null;
        const docName = docStaff ? `${docStaff.first_name} ${docStaff.last_name}`.toLowerCase() : '';

        const srv = services.find(sv => sv.id === st.service_id);
        const srvName = srv ? srv.name.toLowerCase() : '';

        const studyDate = st.scheduled_at ? st.scheduled_at.substring(0, 10) : '';

        // Apply doctor filter (Medico Refertante)
        if (doctorFilterVal && st.signed_by !== parseInt(doctorFilterVal)) return false;

        // Apply requesting doctor filter (Medico Richiedente)
        if (requestingDoctorFilterVal && st.doctor_id !== parseInt(requestingDoctorFilterVal)) return false;
        if (aiFilter?.doctorName && !docName.includes(aiFilter.doctorName)) return false;

        // Apply start date filter
        if (startDateVal && studyDate < startDateVal) return false;
        if (aiFilter?.startDate && studyDate < aiFilter.startDate) return false;

        // Apply end date filter
        if (endDateVal && studyDate > endDateVal) return false;
        if (aiFilter?.endDate && studyDate > aiFilter.endDate) return false;

        // Apply status filter
        if (statusFilterVal && st.status !== statusFilterVal) return false;
        if (aiFilter?.status) {
            if (aiFilter.status === 'scheduled' && st.status !== 'scheduled') return false;
            if (aiFilter.status === 'completed' && st.status !== 'completed') return false;
        }

        // Apply role filter
        if (currentRole === 'doctor_1' && st.doctor_id !== 1) return false;
        if (currentRole === 'doctor_2' && st.doctor_id !== 2) return false;

        // Apply text query search
        const searchQuery = (aiFilter ? aiFilter.textQuery : query).toLowerCase().trim();
        if (searchQuery) {
            const matchesPatient = `${p.first_name} ${p.last_name}`.toLowerCase().includes(searchQuery) || p.tax_code.toLowerCase().includes(searchQuery);
            const matchesSrv = srvName.includes(searchQuery);
            const matchesDoc = docName.includes(searchQuery);
            if (!matchesPatient && !matchesSrv && !matchesDoc) return false;
        }

        return true;
    });
    
    filtered.sort((a, b) => {
        const dateA = new Date(a.scheduled_at || a.created_at);
        const dateB = new Date(b.scheduled_at || b.created_at);
        return dateB - dateA;
    });
    
    const paginated = window.setupTablePagination('ris-table', filtered, () => window.renderRisStudies(query));

    if (filtered.length === 0) {
        tbody.innerHTML = `<tr><td colspan="7" style="text-align: center;" class="text-muted">Nessun esame radiologico in lista</td></tr>`;
        return;
    }
    
    paginated.forEach(st => {
        const p = patients.find(pat => pat.id === st.patient_id);
        const doc = doctors.find(d => d.id === st.doctor_id);
        const docStaff = doc ? staff.find(s => s.id === doc.staff_id) : null;
        const srv = services.find(s => s.id === st.service_id);
        const signerStaff = st.signed_by ? staff.find(s => s.id === st.signed_by) : null;
        const signerName = signerStaff ? `Dott. ${signerStaff.last_name}` : '--';
        
        const isVisit = st.study_type === 'VISIT';
        const startText = isVisit ? "Inizia Visita" : "Esegui Studio";
        const refertationText = isVisit ? "Scrivi Referto Visita" : "Apri DICOM & Referta";
        const reportBtnLabel = isVisit ? "Referto Visita" : "Referto RIS";

        let statusBadge = '';
        if (st.status === 'scheduled') {
            if (isVisit) {
                statusBadge = '<span class="badge badge-info">Pianificato</span>';
            } else {
                statusBadge = '<span class="badge badge-warning" style="background-color: #eab308; color: #fff;">Attesa Erogazione</span>';
            }
        } else if (st.status === 'executed') {
            statusBadge = '<span class="badge badge-info" style="background-color: #06b6d4; color: #fff;">Erogato (TSRM)</span>';
        } else if (st.status === 'in_progress') {
            statusBadge = '<span class="badge badge-warning">In Esecuzione</span>';
        } else if (st.status === 'completed') {
            statusBadge = '<span class="badge badge-success">Refertato</span>';
        }
        
        let reportLink = st.report_text ? `<button class="btn btn-secondary btn-sm" onclick="openRisReportView(${st.id})"><i data-lucide="file-text"></i> ${reportBtnLabel}</button>` : '<span class="text-muted">In attesa</span>';
        
        let actionBtn = '';
        if (st.status === 'scheduled') {
            if (isVisit) {
                actionBtn = isStaff 
                    ? '<span class="text-muted" style="font-size:0.75rem;">In attesa</span>' 
                    : `<button class="btn btn-primary btn-sm" onclick="startRisStudy(${st.id})">${startText}</button>`;
            } else {
                actionBtn = '<span class="text-muted" style="font-size:0.75rem; color: #a1a1aa; font-style: italic;">Attesa TSRM</span>';
            }
        } else if (st.status === 'executed') {
            actionBtn = isStaff 
                ? '<span class="text-muted" style="font-size:0.75rem;">Pronto</span>' 
                : `<button class="btn btn-success btn-sm" onclick="openDicomViewer(${st.id})">${refertationText}</button>`;
        } else if (st.status === 'in_progress') {
            actionBtn = isStaff 
                ? '<span class="text-muted" style="font-size:0.75rem;">In corso</span>' 
                : `<button class="btn btn-success btn-sm" onclick="openDicomViewer(${st.id})">${refertationText}</button>`;
        } else if (st.status === 'completed') {
            if (!isStaff) {
                actionBtn = `<button class="btn btn-primary btn-sm" onclick="openDicomViewer(${st.id}, true)"><i data-lucide="edit"></i> Modifica</button>`;
            }
        }
        
        actionBtn += ` <button class="btn btn-secondary btn-sm" onclick="window.printRisBarcodeLabel(${st.id})" title="Stampa Barcode Cartellina" style="margin-left: 2px;"><i data-lucide="barcode" style="width: 12px; height: 12px; vertical-align: middle; margin-right: 4px;"></i> Barcode</button>`;
        
        const formattedDate = new Date(st.scheduled_at).toLocaleString('it-IT', { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' });
        
        let dosePill = '';
        if (srv && srv.dose_class_id) {
            const dc = (DB.get('dose_classes') || []).find(c => c.id === srv.dose_class_id);
            if (dc) {
                dosePill = `<br><span class="badge badge-secondary" style="font-size: 0.72rem; margin-top: 4px; display: inline-block; background-color: var(--text-secondary); color: #fff;">Dose: ${dc.code}</span>`;
            }
        }

        const tr = document.createElement('tr');
        tr.innerHTML = `
            <td><strong>${p.last_name} ${p.first_name}</strong></td>
            <td><span class="badge badge-success">${srv ? srv.name : st.study_type}</span>${dosePill}</td>
            <td>Dott. ${docStaff ? docStaff.last_name : "Richiedente Esterno"}</td>
            <td>${signerName}</td>
            <td>${formattedDate}</td>
            <td>${statusBadge}</td>
            <td>${reportLink}</td>
            <td><div class="row-actions">${actionBtn}</div></td>
        `;
        tbody.appendChild(tr);
    });
    if (window.lucide) window.lucide.createIcons();
}

window.startRisStudy = function(studyId) {
    DB.update('radiology_studies', studyId, { status: 'in_progress' });
    renderRisStudies();
};

// MODULE 7: CLINICS & ASSETS
function renderClinicsAndEquipment() {
    const clinics = DB.get('clinics');
    const equipment = DB.get('equipment');
    
    // Render clinics
    const cTbody = document.querySelector('#clinics-table tbody');
    if (cTbody) {
        cTbody.innerHTML = '';
        clinics.forEach(c => {
            const tr = document.createElement('tr');
            tr.innerHTML = `
                <td><strong>${c.name}</strong></td>
                <td>${c.location}</td>
                <td>${c.capacity} paziente/ora</td>
                <td><span class="badge badge-success">Libero / Disponibile</span></td>
                <td>
                    <button class="btn btn-secondary btn-sm" onclick="window.openEditClinicModal(${c.id})"><i data-lucide="edit"></i> Modifica</button>
                    <button class="btn btn-danger btn-sm" onclick="window.deleteClinic(${c.id})" style="margin-left: 5px;"><i data-lucide="trash-2"></i> Elimina</button>
                </td>
            `;
            cTbody.appendChild(tr);
        });
    }
    
    // Render equipment (exclude LIS instruments)
    const eqTbody = document.querySelector('#equipment-table tbody');
    if (eqTbody) {
        eqTbody.innerHTML = '';
        const nonLisEquipment = equipment.filter(e => e.type !== 'LIS');
        if (nonLisEquipment.length === 0) {
            eqTbody.innerHTML = '<tr><td colspan="5" style="text-align: center;" class="text-muted">Nessuna apparecchiatura standard registrata</td></tr>';
        } else {
            nonLisEquipment.forEach(e => {
                let statusBadge = '';
                if (e.status === 'active') statusBadge = '<span class="badge badge-success">Operativo</span>';
                else if (e.status === 'maintenance') statusBadge = '<span class="badge badge-warning">Manutenzione</span>';
                else if (e.status === 'broken') statusBadge = '<span class="badge badge-danger">Fuori Servizio</span>';
                else statusBadge = '<span class="badge badge-secondary">Dismesso</span>';
                
                const tr = document.createElement('tr');
                tr.innerHTML = `
                    <td><strong>${e.name}</strong> (${e.type})</td>
                    <td><code>${e.serial_number}</code></td>
                    <td>${statusBadge}</td>
                    <td>
                        <select onchange="updateEquipmentStatus(${e.id}, this.value)" style="padding: 4px; font-size: 0.75rem; border-radius: 4px;">
                            <option value="active" ${e.status === 'active' ? 'selected' : ''}>Attivo</option>
                            <option value="maintenance" ${e.status === 'maintenance' ? 'selected' : ''}>Manutenzione</option>
                            <option value="broken" ${e.status === 'broken' ? 'selected' : ''}>Guasto</option>
                        </select>
                    </td>
                    <td>
                        <button class="btn btn-secondary btn-sm" onclick="window.openEditEquipmentModal(${e.id})"><i data-lucide="edit"></i> Modifica</button>
                        <button class="btn btn-danger btn-sm" onclick="window.deleteEquipment(${e.id})" style="margin-left: 5px;"><i data-lucide="trash-2"></i> Elimina</button>
                    </td>
                `;
                eqTbody.appendChild(tr);
            });
        }
    }

    // Render LIS Instruments Table
    const lisEqTbody = document.querySelector('#lis-instruments-management-table tbody');
    if (lisEqTbody) {
        lisEqTbody.innerHTML = '';
        const lisEquipment = equipment.filter(e => e.type === 'LIS');
        const services = DB.get('medical_services') || [];
        
        if (lisEquipment.length === 0) {
            lisEqTbody.innerHTML = '<tr><td colspan="6" style="text-align: center;" class="text-muted">Nessun analizzatore LIS registrato</td></tr>';
        } else {
            lisEquipment.forEach(e => {
                let statusBadge = '';
                if (e.status === 'active') statusBadge = '<span class="badge badge-success" style="background-color: #10b981; color: #fff;">Operativo</span>';
                else if (e.status === 'maintenance') statusBadge = '<span class="badge badge-warning" style="background-color: #f59e0b; color: #fff;">Manutenzione</span>';
                else if (e.status === 'broken') statusBadge = '<span class="badge badge-danger" style="background-color: #ef4444; color: #fff;">Guasto</span>';
                else statusBadge = '<span class="badge badge-secondary">Dismesso</span>';

                const associatedServices = services.filter(srv => srv.instrument_id === e.id);
                const servicesListText = associatedServices.map(srv => `<span class="badge badge-info" style="margin: 2px; font-size: 0.75rem;">${srv.name}</span>`).join(' ') || '<span class="text-muted" style="font-size: 0.75rem; font-style: italic;">Nessuno</span>';

                let portDisplay = '';
                if (e.lis_interface_type === 'socket' && e.lis_socket_port) {
                    portDisplay = `<br><small class="text-muted">Porta Socket: ${e.lis_socket_port}</small> <span class="socket-status-dot" data-port="${e.lis_socket_port}" style="display:inline-block; width:8px; height:8px; border-radius:50%; margin-left:4px; background-color:#94a3b8;" title="Inizializzazione..."></span>`;
                } else if (e.lis_interface_type === 'file') {
                    portDisplay = `<br><small class="text-muted">File: ${e.lis_file_name || ''}</small>`;
                }
                const tr = document.createElement('tr');
                tr.innerHTML = `
                    <td><strong>${e.name}</strong>${portDisplay}</td>
                    <td><code>${e.serial_number}</code></td>
                    <td>${statusBadge}</td>
                    <td>
                        <select onchange="updateEquipmentStatus(${e.id}, this.value)" style="padding: 4px; font-size: 0.75rem; border-radius: 4px;">
                            <option value="active" ${e.status === 'active' ? 'selected' : ''}>Attivo</option>
                            <option value="maintenance" ${e.status === 'maintenance' ? 'selected' : ''}>Manutenzione</option>
                            <option value="broken" ${e.status === 'broken' ? 'selected' : ''}>Guasto</option>
                        </select>
                    </td>
                    <td><div style="display: flex; flex-wrap: wrap; gap: 4px; max-height: 80px; overflow-y: auto;">${servicesListText}</div></td>
                    <td>
                        <button class="btn btn-secondary btn-sm" onclick="window.openEditEquipmentModal(${e.id})"><i data-lucide="edit"></i> Modifica</button>
                        <button class="btn btn-danger btn-sm" onclick="window.deleteEquipment(${e.id})" style="margin-left: 5px;"><i data-lucide="trash-2"></i> Elimina</button>
                    </td>
                `;
                lisEqTbody.appendChild(tr);
            });
        }
    }
    if (window.lucide) window.lucide.createIcons();
}

window.updateEquipmentStatus = function(eqId, newStatus) {
    DB.update('equipment', eqId, { status: newStatus });
    DB.logAudit(6, "EQUIPMENT_STATUS_CHANGE", "equipment", eqId, { status: newStatus });
    renderClinicsAndEquipment();
};

