window.toggleLisInterfacingFields = function() {
    const type = document.getElementById('eq-lis-interface-type').value;
    const fileParams = document.getElementById('eq-lis-file-params');
    const socketParams = document.getElementById('eq-lis-socket-params');
    
    if (type === 'file') {
        fileParams.style.display = 'block';
        socketParams.style.display = 'none';
        document.getElementById('eq-lis-import-path').required = true;
        document.getElementById('eq-lis-export-path').required = true;
        document.getElementById('eq-lis-file-name').required = true;
        document.getElementById('eq-lis-socket-port').required = false;
    } else if (type === 'socket') {
        fileParams.style.display = 'none';
        socketParams.style.display = 'block';
        document.getElementById('eq-lis-import-path').required = false;
        document.getElementById('eq-lis-export-path').required = false;
        document.getElementById('eq-lis-file-name').required = false;
        document.getElementById('eq-lis-socket-port').required = true;
    } else {
        fileParams.style.display = 'none';
        socketParams.style.display = 'none';
        document.getElementById('eq-lis-import-path').required = false;
        document.getElementById('eq-lis-export-path').required = false;
        document.getElementById('eq-lis-file-name').required = false;
        document.getElementById('eq-lis-socket-port').required = false;
    }
};

window.addLisTranscodingRow = function(data = null) {
    const tbody = document.getElementById('eq-lis-transcoding-tbody');
    if (!tbody) return;
    
    // Get unique parameter names and service list
    const services = DB.get('medical_services') || [];
    const lisServices = services.filter(srv => srv.type === 'lis');
    
    const rowId = 'transcode-row-' + Date.now() + '-' + Math.floor(Math.random() * 1000);
    const tr = document.createElement('tr');
    tr.id = rowId;
    
    const selectedType = data ? data.nc_type : 'service';
    const selectedNcValue = data ? (selectedType === 'service' ? data.nc_code : data.nc_name) : '';
    const instrumentCode = data ? data.instrument_code : '';
    
    tr.innerHTML = `
        <td style="padding: 4px;">
            <select class="form-control trans-type-select" style="padding: 2px 4px; font-size: 0.75rem;" onchange="window.updateLisTranscodingTargetSelect('${rowId}')">
                <option value="service" ${selectedType === 'service' ? 'selected' : ''}>Esame</option>
                <option value="parameter" ${selectedType === 'parameter' ? 'selected' : ''}>Parametro</option>
            </select>
        </td>
        <td style="padding: 4px;">
            <select class="form-control trans-target-select" style="padding: 2px 4px; font-size: 0.75rem; width: 100%;">
                <!-- Populated dynamically -->
            </select>
        </td>
        <td style="padding: 4px;">
            <input type="text" class="form-control trans-instrument-code" style="padding: 2px 4px; font-size: 0.75rem;" placeholder="Codice Strumento" value="${instrumentCode || ''}" required>
        </td>
        <td style="padding: 4px; text-align: center;">
            <button type="button" class="btn btn-danger btn-sm" style="padding: 2px 6px;" onclick="document.getElementById('${rowId}').remove()">
                <i data-lucide="trash-2" style="width: 12px; height: 12px;"></i>
            </button>
        </td>
    `;
    tbody.appendChild(tr);
    
    // Populate the target select
    window.updateLisTranscodingTargetSelect(rowId, selectedNcValue);
    if (window.lucide) window.lucide.createIcons();
};

window.updateLisTranscodingTargetSelect = function(rowId, selectedValue = '') {
    const tr = document.getElementById(rowId);
    if (!tr) return;
    const typeSelect = tr.querySelector('.trans-type-select');
    const targetSelect = tr.querySelector('.trans-target-select');
    if (!typeSelect || !targetSelect) return;
    
    targetSelect.innerHTML = '';
    const services = DB.get('medical_services') || [];
    const lisServices = services.filter(srv => srv.type === 'lis');
    
    if (typeSelect.value === 'service') {
        lisServices.forEach(srv => {
            const opt = document.createElement('option');
            opt.value = srv.code;
            opt.textContent = `${srv.name} (${srv.code})`;
            if (srv.code === selectedValue) opt.selected = true;
            targetSelect.appendChild(opt);
        });
    } else {
        const paramsSet = new Set();
        lisServices.forEach(srv => {
            let params = [];
            if (typeof srv.parameters === 'string') {
                try { params = JSON.parse(srv.parameters); } catch(e) {}
            } else if (Array.isArray(srv.parameters)) {
                params = srv.parameters;
            }
            params.forEach(p => {
                if (p && p.name) paramsSet.add(p.name);
            });
        });
        const uniqueParams = Array.from(paramsSet).sort();
        uniqueParams.forEach(p => {
            const opt = document.createElement('option');
            opt.value = p;
            opt.textContent = p;
            if (p === selectedValue) opt.selected = true;
            targetSelect.appendChild(opt);
        });
    }
};

