// MODULE 8: ADMISSIONS & BILLING
window.renderAdmissionsAndInvoices = function() {
    const admissions = DB.get('admissions');
    const invoices = DB.get('invoices');
    const patients = DB.get('patients');
    
    // Render admissions
    const admTbody = document.querySelector('#admissions-table tbody');
    admTbody.innerHTML = '';
    
    // Fetch filter values
    const aiSearchVal = document.getElementById('adm-ai-search')?.value || '';
    const startDateVal = document.getElementById('adm-filter-start')?.value || '';
    const endDateVal = document.getElementById('adm-filter-end')?.value || '';
    const clinicFilterVal = document.getElementById('adm-filter-clinic')?.value || '';

    let aiFilter = null;
    if (aiSearchVal) {
        aiFilter = window.parseNaturalLanguageQuery(aiSearchVal, 'adm');
    }

    const filteredAdmissions = admissions.filter(adm => {
        const p = patients.find(pat => pat.id === adm.patient_id);
        if (!p) return false;

        const admDate = adm.admission_date ? adm.admission_date.substring(0, 10) : '';

        // Apply department (clinic) filter
        if (clinicFilterVal) {
            const clinics = DB.get('clinics') || [];
            const selectedClinic = clinics.find(c => c.id === parseInt(clinicFilterVal));
            if (selectedClinic && adm.department.toLowerCase() !== selectedClinic.name.toLowerCase()) return false;
        }

        // Apply start date
        if (startDateVal && admDate < startDateVal) return false;
        if (aiFilter?.startDate && admDate < aiFilter.startDate) return false;

        // Apply end date
        if (endDateVal && admDate > endDateVal) return false;
        if (aiFilter?.endDate && admDate > aiFilter.endDate) return false;

        // Apply active vs discharged filter if specified, otherwise show all
        if (aiFilter?.status) {
            if (aiFilter.status === 'completed' && adm.status !== 'discharged') return false;
            if (aiFilter.status === 'in_progress' && adm.status !== 'active') return false;
        } else if (aiSearchVal.toLowerCase().includes('dimess') || aiSearchVal.toLowerCase().includes('storico')) {
            if (adm.status !== 'discharged') return false;
        } else if (aiSearchVal.toLowerCase().includes('attivo') || aiSearchVal.toLowerCase().includes('degente')) {
            if (adm.status !== 'active') return false;
        }

        // Apply text search
        const searchQuery = (aiFilter ? aiFilter.textQuery : '').toLowerCase().trim();
        if (searchQuery) {
            const matchesPatient = `${p.first_name} ${p.last_name}`.toLowerCase().includes(searchQuery) || p.tax_code.toLowerCase().includes(searchQuery);
            const matchesDept = adm.department.toLowerCase().includes(searchQuery);
            if (!matchesPatient && !matchesDept) return false;
        }

        return true;
    });

    filteredAdmissions.sort((a, b) => {
        const dateA = new Date(a.admission_date || a.created_at);
        const dateB = new Date(b.admission_date || b.created_at);
        return dateB - dateA;
    });

    const paginatedAdmissions = window.setupTablePagination('admissions-table', filteredAdmissions, () => window.renderAdmissionsAndInvoices());

    if (filteredAdmissions.length === 0) {
        admTbody.innerHTML = `<tr><td colspan="5" style="text-align: center;" class="text-muted">Nessun ricoverato trovato per i filtri selezionati</td></tr>`;
    } else {
        paginatedAdmissions.forEach(adm => {
            const p = patients.find(pat => pat.id === adm.patient_id);
            const formattedDate = new Date(adm.admission_date).toLocaleDateString('it-IT');
            const tr = document.createElement('tr');
            
            const badgeClass = adm.status === 'active' ? 'badge-warning' : 'badge-success';
            const statusLabel = adm.status === 'active' ? 'Degente' : 'Dimesso';
            const actionButton = adm.status === 'active' 
                ? `<button class="btn btn-secondary btn-sm" onclick="dischargePatient(${adm.id})">Dimetti</button>` 
                : `<span class="text-muted" style="font-size:0.8rem;">Completato</span>`;

            tr.innerHTML = `
                <td><strong>${p.last_name} ${p.first_name}</strong></td>
                <td>${adm.department}</td>
                <td>${formattedDate}</td>
                <td><span class="badge ${badgeClass}">${statusLabel}</span></td>
                <td>
                    ${actionButton}
                </td>
            `;
            admTbody.appendChild(tr);
        });
    }

    // Render outpatient acceptances
    const accTbody = document.querySelector('#outpatient-acceptances-table tbody');
    if (accTbody) {
        accTbody.innerHTML = '';
        
        const samples = DB.get('lab_samples') || [];
        const studies = DB.get('radiology_studies') || [];
        const tests = DB.get('lab_tests') || [];
        const services = DB.get('medical_services') || [];
        const collectionPoints = DB.get('lis_collection_points') || [];

        const acceptancesList = [];

        // 1. Group LIS samples by session_uid to avoid duplicates
        const lisGroups = {};
        samples.forEach(sam => {
            const sUid = sam.session_uid || ('LIS-FALLBACK-' + sam.patient_id + '-' + sam.collected_at);
            if (!lisGroups[sUid]) {
                lisGroups[sUid] = [];
            }
            lisGroups[sUid].push(sam);
        });

        Object.entries(lisGroups).forEach(([sessionUid, groupSamples]) => {
            const firstSam = groupSamples[0];
            const p = patients.find(pat => pat.id === firstSam.patient_id);
            if (!p) return;

            const groupSampleIds = groupSamples.map(s => s.id);
            const groupTests = tests.filter(t => groupSampleIds.includes(t.sample_id));

            // LIS is editable if there are NO result values entered
            const hasAnyResult = groupTests.some(t => t.result_value !== null && t.result_value !== undefined && String(t.result_value).trim() !== '');
            const isEditable = !hasAnyResult;

            let calculatedStatus = 'Da prelevare';
            let badgeColorClass = 'badge-warning'; // yellow/blue
            const allCompleted = groupTests.length > 0 && groupTests.every(t => t.status === 'completed');
            const hasProcessing = groupSamples.some(s => s.status === 'received' || s.status === 'processing');
            const hasCollected = groupSamples.some(s => s.status === 'collected');
            if (allCompleted) {
                calculatedStatus = 'Completato';
                badgeColorClass = 'badge-success';
            } else if (hasProcessing || hasCollected) {
                calculatedStatus = 'In lavorazione';
                badgeColorClass = 'badge-warning';
            }

            const examNames = groupTests.map(t => {
                const srv = services.find(sv => sv.id === t.service_id);
                return srv ? srv.name : t.test_name;
            });
            const examsStr = [...new Set(examNames)].join(', ') || 'Nessun esame';

            // Determina punto prelievo (se campione da fuori sede)
            const cpId = firstSam.collection_point_id;
            const cpObj = cpId ? collectionPoints.find(cp => cp.id === cpId) : null;
            const cpName = cpObj ? cpObj.name : (cpId ? 'Punto Prelievo #' + cpId : 'Sede');

            acceptancesList.push({
                patientName: `${p.last_name} ${p.first_name}`,
                patientTax: p.tax_code,
                type: 'LIS (Laboratorio)',
                dateRaw: firstSam.collected_at || firstSam.created_at || '',
                dateStr: window.safeFormatDate(firstSam.collected_at || firstSam.created_at),
                details: examsStr,
                status: calculatedStatus,
                badgeClass: badgeColorClass,
                isEditable: isEditable,
                dataType: 'LIS',
                paramId: sessionUid,
                collectionPoint: cpName
            });
        });

        // 2. Process RIS / Visite studies
        studies.forEach(st => {
            const p = patients.find(pat => pat.id === st.patient_id);
            if (!p) return;

            const srv = services.find(sv => sv.id === st.service_id);
            const examName = srv ? srv.name : 'Esame RIS';

            let statusLabel = 'Pianificato';
            let badgeColorClass = 'badge-warning';
            if (st.status === 'completed') {
                statusLabel = 'Refertato';
                badgeColorClass = 'badge-success';
            } else if (st.status === 'executed') {
                statusLabel = 'Erogato';
                badgeColorClass = 'badge-info';
            } else if (st.status === 'in_progress') {
                statusLabel = 'In Esecuzione';
                badgeColorClass = 'badge-warning';
            }

            // Criteri di Modificabilità:
            // RIS: Modificabile se lo studio non è ancora stato eseguito (stato diverso da executed e completed).
            // Visite: Modificabile se la visita non è ancora iniziata (nessun testo di referto e stato diverso da completed).
            let isEditable = false;
            const isVisit = st.study_type === 'VISIT';
            if (isVisit) {
                const hasReport = st.report_text !== null && st.report_text !== undefined && String(st.report_text).trim() !== '';
                isEditable = !hasReport && st.status !== 'completed';
            } else {
                isEditable = st.status !== 'executed' && st.status !== 'completed';
            }

            acceptancesList.push({
                patientName: `${p.last_name} ${p.first_name}`,
                patientTax: p.tax_code,
                type: isVisit ? 'Visita Specialistica' : 'RIS (Radiologia)',
                dateRaw: st.scheduled_at || '',
                dateStr: window.safeFormatDate(st.scheduled_at),
                details: examName,
                status: statusLabel,
                badgeClass: badgeColorClass,
                isEditable: isEditable,
                dataType: isVisit ? 'VISIT' : 'RIS',
                paramId: st.id,
                collectionPoint: 'Sede'
            });
        });

        // 3. Process Fisioterapia rehab cycles
        const rehabCycles = DB.get('rehab_cycles') || [];
        const rehabSessions = DB.get('rehab_sessions') || [];
        rehabCycles.forEach(rc => {
            const p = patients.find(pat => pat.id === rc.patient_id);
            if (!p) return;

            const cycleSessions = rehabSessions.filter(s => s.cycle_id === rc.id);
            const completedCount = cycleSessions.filter(s => s.status === 'completed').length;
            const detailsStr = `${rc.diagnosis || 'Trattamento'} (${completedCount}/${rc.total_sessions} sedute)`;

            let statusLabel = 'Attivo';
            let badgeColorClass = 'badge-info';
            if (rc.status === 'completed') {
                statusLabel = 'Completato';
                badgeColorClass = 'badge-success';
            } else if (rc.status === 'cancelled') {
                statusLabel = 'Annullato';
                badgeColorClass = 'badge-danger';
            }

            acceptancesList.push({
                patientName: `${p.last_name} ${p.first_name}`,
                patientTax: p.tax_code,
                type: 'Fisioterapia (Ciclo)',
                dateRaw: rc.created_at || '',
                dateStr: window.safeFormatDate(rc.created_at),
                details: detailsStr,
                status: statusLabel,
                badgeClass: badgeColorClass,
                isEditable: false,
                dataType: 'REHAB',
                paramId: rc.id,
                collectionPoint: 'Sede'
            });
        });

        // Sort by date (newest first)
        acceptancesList.sort((a, b) => new Date(b.dateRaw) - new Date(a.dateRaw));

        // Apply filters to outpatient acceptances
        const accAiSearchVal = document.getElementById('acc-ai-search')?.value || '';
        const accFilterType = document.getElementById('acc-filter-type')?.value || '';
        const accFilterStart = document.getElementById('acc-filter-start')?.value || '';
        const accFilterEnd = document.getElementById('acc-filter-end')?.value || '';

        let filteredAcceptances = acceptancesList;

        if (accFilterType) {
            filteredAcceptances = filteredAcceptances.filter(acc => {
                if (accFilterType === 'lis') return acc.type.includes('LIS');
                if (accFilterType === 'ris') return acc.type.includes('RIS');
                if (accFilterType === 'visit') return acc.type.includes('Visita');
                if (accFilterType === 'rehab') return acc.type.includes('Fisioterapia');
                return true;
            });
        }

        if (accFilterStart) {
            filteredAcceptances = filteredAcceptances.filter(acc => {
                const d = acc.dateRaw ? acc.dateRaw.substring(0, 10) : '';
                return d >= accFilterStart;
            });
        }

        if (accFilterEnd) {
            filteredAcceptances = filteredAcceptances.filter(acc => {
                const d = acc.dateRaw ? acc.dateRaw.substring(0, 10) : '';
                return d <= accFilterEnd;
            });
        }

        if (accAiSearchVal) {
            const query = accAiSearchVal.toLowerCase().trim();
            filteredAcceptances = filteredAcceptances.filter(acc => {
                return acc.patientName.toLowerCase().includes(query) || 
                       acc.patientTax.toLowerCase().includes(query) || 
                       acc.type.toLowerCase().includes(query) || 
                       acc.details.toLowerCase().includes(query) || 
                       acc.status.toLowerCase().includes(query);
            });
        }

        const paginatedAcceptances = window.setupTablePagination('outpatient-acceptances-table', filteredAcceptances, () => window.renderAdmissionsAndInvoices());

        if (filteredAcceptances.length === 0) {
            accTbody.innerHTML = `<tr><td colspan="6" style="text-align: center;" class="text-muted">Nessuna accettazione ambulatoriale in lista per i filtri selezionati</td></tr>`;
        } else {
            paginatedAcceptances.forEach(acc => {
                const tr = document.createElement('tr');
                
                let actionCell = '';
                if (acc.isEditable) {
                    const paramVal = typeof acc.paramId === 'string' ? `'${acc.paramId}'` : acc.paramId;
                    actionCell = `<button class="btn btn-secondary btn-sm" onclick="window.openEditAcceptanceModal('${acc.dataType}', ${paramVal})"><i data-lucide="edit"></i> Modifica</button>`;
                } else {
                    actionCell = `<span class="text-muted" style="font-size: 0.8rem;">Non modificabile</span>`;
                }

                tr.innerHTML = `
                    <td><strong>${acc.patientName}</strong><br><small style="color:var(--text-secondary);">${acc.patientTax}</small></td>
                    <td><span class="badge badge-info" style="font-size:0.75rem;">${acc.type}</span></td>
                    <td>${acc.dateStr}</td>
                    <td style="font-size: 0.8rem; color: var(--text-secondary);">${acc.details}</td>
                    <td><small style="color:var(--text-secondary);">${acc.collectionPoint || 'Sede'}</small></td>
                    <td><span class="badge ${acc.badgeClass}">${acc.status}</span></td>
                    <td>${actionCell}</td>
                `;
                accTbody.appendChild(tr);
            });
        }
    }
    
    // Render invoices
    const invTbody = document.querySelector('#invoices-table tbody');
    invTbody.innerHTML = '';

    // Fetch invoice filters
    const invAiSearchVal = document.getElementById('inv-ai-search')?.value || '';
    const invFilterStatus = document.getElementById('inv-filter-status')?.value || '';
    const invFilterStart = document.getElementById('inv-filter-start')?.value || '';
    const invFilterEnd = document.getElementById('inv-filter-end')?.value || '';

    const filteredInvoices = invoices.filter(inv => {
        // Apply status filter
        if (invFilterStatus && inv.payment_status !== invFilterStatus) return false;

        // Apply start date
        if (invFilterStart && inv.issue_date < invFilterStart) return false;

        // Apply end date
        if (invFilterEnd && inv.issue_date > invFilterEnd) return false;

        // Fetch patient for text search
        let p = null;
        if (inv.admission_id) {
            const adm = admissions.find(a => a.id === inv.admission_id);
            p = adm ? patients.find(pat => pat.id === adm.patient_id) : null;
        } else if (inv.appointment_id) {
            const app = DB.get('appointments').find(a => a.id === inv.appointment_id);
            p = app ? patients.find(pat => pat.id === app.patient_id) : null;
        } else if (inv.sample_id) {
            const sam = DB.get('lab_samples').find(s => s.id === inv.sample_id);
            p = sam ? patients.find(pat => pat.id === sam.patient_id) : null;
        } else if (inv.study_id) {
            const st = DB.get('radiology_studies').find(s => s.id === inv.study_id);
            p = st ? patients.find(pat => pat.id === st.patient_id) : null;
        } else if (inv.rehab_cycle_id) {
            const rc = (DB.get('rehab_cycles') || []).find(c => c.id === inv.rehab_cycle_id);
            p = rc ? patients.find(pat => pat.id === rc.patient_id) : null;
            if (!p && inv.patient_id) {
                p = patients.find(pat => pat.id === inv.patient_id);
            }
        } else if (inv.patient_id) {
            p = patients.find(pat => pat.id === inv.patient_id);
        }

        const patientName = p ? `${p.last_name} ${p.first_name}` : 'Paziente Esterno';
        const patientTax = p ? p.tax_code : '';

        if (invAiSearchVal) {
            const query = invAiSearchVal.toLowerCase().trim();
            const matchesInvoice = inv.invoice_number.toLowerCase().includes(query);
            const matchesPatient = patientName.toLowerCase().includes(query) || (patientTax && patientTax.toLowerCase().includes(query));
            if (!matchesInvoice && !matchesPatient) return false;
        }

        return true;
    });
    
    filteredInvoices.sort((a, b) => {
        const dateA = new Date(a.issue_date || a.created_at);
        const dateB = new Date(b.issue_date || b.created_at);
        return dateB - dateA;
    });

    const paginatedInvoices = window.setupTablePagination('invoices-table', filteredInvoices, () => window.renderAdmissionsAndInvoices());

    if (filteredInvoices.length === 0) {
        invTbody.innerHTML = `<tr><td colspan="5" style="text-align: center;" class="text-muted">Nessuna fattura trovata</td></tr>`;
        return;
    }

    paginatedInvoices.forEach(inv => {
        let p = null;
        let detailsLabel = '';

        if (inv.admission_id) {
            const adm = admissions.find(a => a.id === inv.admission_id);
            p = adm ? patients.find(pat => pat.id === adm.patient_id) : null;
            detailsLabel = 'Ricovero';
        } else if (inv.appointment_id) {
            const app = DB.get('appointments').find(a => a.id === inv.appointment_id);
            p = app ? patients.find(pat => pat.id === app.patient_id) : null;
            detailsLabel = 'CUP/Ambulatorio';
        } else if (inv.sample_id) {
            const sam = DB.get('lab_samples').find(s => s.id === inv.sample_id);
            p = sam ? patients.find(pat => pat.id === sam.patient_id) : null;
            detailsLabel = 'LIS Laboratorio';
        } else if (inv.study_id) {
            const st = DB.get('radiology_studies').find(s => s.id === inv.study_id);
            p = st ? patients.find(pat => pat.id === st.patient_id) : null;
            detailsLabel = st && st.study_type === 'VISIT' ? 'Visita Specialistica' : 'RIS Radiologia';
        } else if (inv.rehab_cycle_id) {
            const rc = (DB.get('rehab_cycles') || []).find(c => c.id === inv.rehab_cycle_id);
            p = rc ? patients.find(pat => pat.id === rc.patient_id) : null;
            if (!p && inv.patient_id) {
                p = patients.find(pat => pat.id === inv.patient_id);
            }
            detailsLabel = 'Fisioterapia (Ciclo)';
        } else if (inv.patient_id) {
            p = patients.find(pat => pat.id === inv.patient_id);
            detailsLabel = 'Fisioterapia / Altro';
        }

        const patientName = p ? `${p.last_name} ${p.first_name}` : 'Paziente Esterno';
        
        const isCreditNote = inv.is_credit_note || inv.invoice_number.startsWith('NDC-');

        let paymentBadge = '';
        if (isCreditNote) {
            paymentBadge = '<span class="badge badge-info">Nota di Credito</span>';
        } else if (inv.payment_status === 'paid') {
            paymentBadge = '<span class="badge badge-success">Pagata</span>';
        } else if (inv.payment_status === 'unpaid') {
            paymentBadge = '<span class="badge badge-danger">Non Pagata</span>';
        } else {
            paymentBadge = '<span class="badge badge-warning">Parziale</span>';
        }
        
        let amountStyle = '';
        let amountText = `€ ${inv.amount_due.toFixed(2)}`;
        if (isCreditNote) {
            amountStyle = 'style="color: #ef4444;"';
            amountText = `-€ ${Math.abs(inv.amount_due).toFixed(2)}`;
        }

        const roleSelect = document.getElementById('user-role-select');
        const currentRole = roleSelect ? roleSelect.value : 'admin';
        const isDoctor = currentRole.startsWith('doctor_');

        let actionBtn = '';
        if (isCreditNote) {
            actionBtn = '<span class="text-muted">Saldato</span>';
        } else if (inv.payment_status !== 'paid') {
            actionBtn = `<button class="btn btn-success btn-sm" onclick="openPayInvoiceModal(${inv.id})">Paga</button>`;
        } else {
            actionBtn = '<span class="text-muted">Saldato</span>';
        }
        
        // Add print invoice button
        actionBtn += ` <button class="btn btn-secondary btn-sm" style="margin-left: 5px;" onclick="openInvoiceReportView(${inv.id})"><i data-lucide="printer"></i> Stampa</button>`;
        
        if (!isDoctor && !isCreditNote) {
            actionBtn += ` <button class="btn btn-primary btn-sm" style="margin-left: 5px;" onclick="openEditInvoiceModal(${inv.id})"><i data-lucide="edit"></i> Rettifica</button>`;
        }
        
        let recipientName = patientName;
        if (inv.is_insurance_invoice && inv.claim_id) {
            const claim = DB.get('patient_claims').find(c => c.id === inv.claim_id);
            if (claim) {
                const ins = DB.get('insurances').find(i => i.id === claim.insurance_id);
                if (ins) {
                    recipientName = `${ins.name} (Paz: ${patientName})`;
                }
            }
        }

        const tr = document.createElement('tr');
        tr.innerHTML = `
            <td>
                <div style="font-family: monospace; font-weight: 700;">${inv.invoice_number}</div>
                <div style="font-size: 0.7rem; color: var(--text-secondary);">${detailsLabel} - ${inv.issue_date}</div>
            </td>
            <td>${recipientName}</td>
            <td ${amountStyle}><strong>${amountText}</strong></td>
            <td>${paymentBadge}</td>
            <td>${actionBtn}</td>
        `;
        invTbody.appendChild(tr);
    });
}

window.dischargePatient = function(admId) {
    if (!confirm("Confermi le dimissioni ospedaliere del paziente? Verrà emessa fattura ticket automatically.")) return;
    
    const admissions = DB.get('admissions') || [];
    const adm = admissions.find(a => a.id === admId);
    if (!adm) return;

    const dischargeDate = new Date().toISOString();
    DB.update('admissions', admId, { status: 'discharged', discharge_date: dischargeDate });
    
    // Auto emit hospital stay invoice
    const invoiceNum = getNextInvoiceNumber();
    
    // Base price from listino
    const listinoId = adm.price_list_id || 1;
    let basePrice = 680.00;
    if (listinoId === 2) basePrice = 500.00; // Unisalute
    else if (listinoId === 3) basePrice = 340.00; // Dipendenti

    // Calculate discount
    const discountVal = adm.discount_value || 0;
    const discountType = adm.discount_type || 'percentage';
    let discountAmt = 0;
    if (discountType === 'percentage') {
        discountAmt = basePrice * (discountVal / 100);
    } else {
        discountAmt = discountVal;
    }
    discountAmt = Math.min(discountAmt, basePrice);
    const discountedTotal = basePrice - discountAmt;

    // Calculate insurance claim copay/deductible
    let insuranceCovered = 0;
    let patientTotal = discountedTotal;
    if (adm.claim_id) {
        const claim = DB.get('patient_claims').find(c => c.id === adm.claim_id);
        if (claim) {
            if (claim.deductible_type === 'percentage') {
                patientTotal = discountedTotal * (claim.deductible_value / 100);
                insuranceCovered = discountedTotal - patientTotal;
            } else {
                patientTotal = Math.min(discountedTotal, claim.deductible_value);
                insuranceCovered = discountedTotal - patientTotal;
            }
        }
    }

    let billingMode = 'single';
    if (adm.claim_id) {
        const claim = DB.get('patient_claims').find(c => c.id === adm.claim_id);
        if (claim) {
            const ins = DB.get('insurances').find(i => i.id === claim.insurance_id);
            if (ins) {
                billingMode = ins.billing_mode || 'single';
            }
        }
    }

    if (billingMode === 'split' && insuranceCovered > 0) {
        // Patient invoice
        const invNumPat = getNextInvoiceNumber();
        let stampDuty = 0.00;
        let amountDue = patientTotal;
        if (patientTotal > 77.47) {
            stampDuty = 2.00;
            amountDue = patientTotal + 2.00;
        }
        const invPat = {
            admission_id: admId,
            appointment_id: null,
            sample_id: null,
            study_id: null,
            invoice_number: invNumPat,
            issue_date: dischargeDate.split('T')[0],
            subtotal: patientTotal,
            discount_value: 0,
            discount_type: 'flat',
            discount_amount: 0,
            price_list_id: listinoId,
            claim_id: adm.claim_id,
            insurance_covered_amount: 0,
            stamp_duty: stampDuty,
            amount_due: amountDue,
            amount_paid: 0.0,
            payment_status: 'unpaid',
            payment_method: null,
            paid_at: null,
            is_insurance_invoice: false
        };
        const insertedPat = DB.insert('invoices', invPat);
        const createdInvoiceId = insertedPat.id;
        DB.logAudit(6, "PATIENT_DISCHARGE_AUTO_BILL", "admissions", admId, { invoice_number: invNumPat, amount: amountDue, type: 'patient_split' });
 
        // Insurance invoice
        const invNumIns = getNextInvoiceNumber();
        const invIns = {
            admission_id: admId,
            appointment_id: null,
            sample_id: null,
            study_id: null,
            invoice_number: invNumIns,
            issue_date: dischargeDate.split('T')[0],
            subtotal: insuranceCovered,
            discount_value: 0,
            discount_type: 'flat',
            discount_amount: 0,
            price_list_id: listinoId,
            claim_id: adm.claim_id,
            insurance_covered_amount: 0,
            stamp_duty: 0.00,
            amount_due: insuranceCovered,
            amount_paid: 0.0,
            payment_status: 'unpaid',
            payment_method: null,
            paid_at: null,
            is_insurance_invoice: true
        };
        DB.insert('invoices', invIns);
        DB.logAudit(6, "PATIENT_DISCHARGE_AUTO_BILL", "admissions", admId, { invoice_number: invNumIns, amount: insuranceCovered, type: 'insurance_split' });
        
        renderAdmissionsAndInvoices();
        setTimeout(() => {
            window.promptDirectPaymentAndPrint(createdInvoiceId);
        }, 100);
    } else {
        const invoiceNum = getNextInvoiceNumber();
        let stampDuty = 0.00;
        let amountDue = patientTotal;
        if (patientTotal > 77.47) {
            stampDuty = 2.00;
            amountDue = patientTotal + 2.00;
        }
        const invoice = {
            admission_id: admId,
            invoice_number: invoiceNum,
            issue_date: dischargeDate.split('T')[0],
            subtotal: basePrice,
            discount_value: discountVal,
            discount_type: discountType,
            discount_amount: discountAmt,
            price_list_id: listinoId,
            claim_id: adm.claim_id || null,
            insurance_covered_amount: insuranceCovered,
            stamp_duty: stampDuty,
            amount_due: amountDue,
            amount_paid: 0.0,
            payment_status: 'unpaid',
            payment_method: null,
            paid_at: null,
            is_insurance_invoice: false
        };
        const insertedInv = DB.insert('invoices', invoice);
        DB.logAudit(6, "PATIENT_DISCHARGE_AUTO_BILL", "admissions", admId, { invoice_number: invoiceNum, amount: amountDue });
        
        renderAdmissionsAndInvoices();
        setTimeout(() => {
            window.promptDirectPaymentAndPrint(insertedInv.id);
        }, 100);
    }
};

window.promptDirectPaymentAndPrint = function(invoiceId) {
    if (!invoiceId) return;
    window.openPayInvoiceModal(invoiceId, true);
};

// --- Sequential Progress Invoice Numbering ---
function getNextInvoiceNumber(collectionPointId = null) {
    if (collectionPointId) {
        const collectionPoints = DB.get('lis_collection_points') || [];
        const cp = collectionPoints.find(p => p.id === parseInt(collectionPointId));
        if (cp && cp.invoice_separate == 1) {
            const prefix = cp.invoice_prefix || 'FAT-';
            const nextNum = parseInt(cp.invoice_next_num || 1, 10);
            const invoiceNum = `${prefix}${String(nextNum).padStart(4, '0')}`;
            
            // Increment and save next number in localstorage list
            cp.invoice_next_num = nextNum + 1;
            DB.set('lis_collection_points', collectionPoints);
            
            return invoiceNum;
        }
    }

    let nextNum = localStorage.getItem('nextcare_next_invoice_num');
    if (!nextNum) {
        nextNum = 1001; // default starting number
    } else {
        nextNum = parseInt(nextNum, 10);
    }
    const currentYear = new Date().getFullYear();
    const invoiceNum = `FAT-${currentYear}-${String(nextNum).padStart(4, '0')}`;
    
    // Increment and save next number
    localStorage.setItem('nextcare_next_invoice_num', nextNum + 1);
    
    // Update config input if present
    const configInput = document.getElementById('acc-next-invoice-num');
    if (configInput) {
        configInput.value = nextNum + 1;
    }
    
    return invoiceNum;
}
window.getNextInvoiceNumber = getNextInvoiceNumber;

// --- Sequential Progress Credit Note Numbering ---
window.getNextCreditNoteNumber = function() {
    let nextNum = localStorage.getItem('nextcare_next_credit_note_num');
    if (!nextNum) {
        nextNum = 1;
    } else {
        nextNum = parseInt(nextNum, 10);
    }
    const currentYear = new Date().getFullYear();
    const creditNoteNum = `NDC-${currentYear}-${String(nextNum).padStart(4, '0')}`;
    localStorage.setItem('nextcare_next_credit_note_num', nextNum + 1);
    return creditNoteNum;
};

window.openPayInvoiceModal = function(invoiceId, isDirect = false) {
    const invoices = DB.get('invoices') || [];
    const inv = invoices.find(i => i.id === invoiceId);
    if (!inv) return;
    
    window.payInvoiceIsDirect = isDirect;
    
    const idInput = document.getElementById('pay-invoice-id');
    idInput.value = invoiceId;
    idInput.dataset.amountDue = inv.amount_due;
    
    document.getElementById('pay-invoice-number-label').innerText = inv.invoice_number;
    document.getElementById('pay-invoice-amount-label').innerText = `€ ${inv.amount_due.toFixed(2)}`;
    
    const todayStr = new Date().toISOString().split('T')[0];
    document.getElementById('pay-invoice-date').value = todayStr;
    document.getElementById('pay-invoice-method').value = 'Contanti';
    
    // Reset calculator inputs
    const rec = document.getElementById('pay-invoice-received');
    if (rec) rec.value = '';
    const label = document.getElementById('pay-invoice-change-label');
    if (label) {
        label.innerText = '€ 0.00';
        label.style.color = '#10b981';
    }
    
    window.handlePayInvoiceMethodChange('Contanti');
    
    openModal('modal-pay-invoice');
};

window.handlePayInvoiceMethodChange = function(value) {
    const container = document.getElementById('pay-invoice-change-container');
    if (container) {
        container.style.display = (value === 'Contanti') ? 'block' : 'none';
        if (value === 'Contanti') {
            if (window.lucide) window.lucide.createIcons();
        }
    }
};

window.calculatePayInvoiceChange = function() {
    const amountDue = parseFloat(document.getElementById('pay-invoice-id').dataset.amountDue || 0);
    const received = parseFloat(document.getElementById('pay-invoice-received').value || 0);
    const change = Math.max(0, received - amountDue);
    const label = document.getElementById('pay-invoice-change-label');
    if (label) {
        label.innerText = `€ ${change.toFixed(2)}`;
        if (received >= amountDue) {
            label.style.color = '#10b981';
        } else {
            label.style.color = '#ef4444';
        }
    }
};

window.openEditInvoiceModal = function(invoiceId) {
    const invoices = DB.get('invoices') || [];
    const inv = invoices.find(i => i.id === invoiceId);
    if (!inv) return;
    
    document.getElementById('edit-invoice-id').value = invoiceId;
    document.getElementById('edit-invoice-number-label').innerText = inv.invoice_number;
    document.getElementById('edit-invoice-amount-label').innerText = `€ ${inv.amount_due.toFixed(2)}`;
    document.getElementById('edit-invoice-date').value = inv.issue_date;
    
    const statusSelect = document.getElementById('edit-invoice-status');
    if (statusSelect) statusSelect.value = inv.payment_status || 'unpaid';
    
    const methodSelect = document.getElementById('edit-invoice-method');
    if (methodSelect) methodSelect.value = inv.payment_method || 'Contanti';
    
    const paidDateInput = document.getElementById('edit-invoice-paid-date');
    if (paidDateInput) paidDateInput.value = inv.paid_at ? inv.paid_at.split('T')[0] : '';
    
    // Trigger display toggle
    const methodGrp = document.getElementById('edit-invoice-method-group');
    const paidDateGrp = document.getElementById('edit-invoice-paid-date-group');
    if (inv.payment_status === 'paid') {
        if (methodGrp) methodGrp.style.display = 'block';
        if (paidDateGrp) paidDateGrp.style.display = 'block';
    } else {
        if (methodGrp) methodGrp.style.display = 'none';
        if (paidDateGrp) paidDateGrp.style.display = 'none';
    }
    
    openModal('modal-edit-invoice');
};

window.handleEditInvoiceSubmit = function(e) {
    if (e) e.preventDefault();
    const invoiceId = parseInt(document.getElementById('edit-invoice-id').value);
    const issueDate = document.getElementById('edit-invoice-date').value;
    const paymentStatus = document.getElementById('edit-invoice-status').value;
    const paymentMethod = document.getElementById('edit-invoice-method').value;
    const paidAt = document.getElementById('edit-invoice-paid-date').value;
    
    const invoices = DB.get('invoices') || [];
    const inv = invoices.find(i => i.id === invoiceId);
    if (!inv) return;
    
    const updates = {
        issue_date: issueDate,
        payment_status: paymentStatus
    };
    
    if (paymentStatus === 'paid') {
        updates.amount_paid = inv.amount_due;
        updates.payment_method = paymentMethod;
        updates.paid_at = paidAt || new Date().toISOString().split('T')[0];
    } else {
        updates.amount_paid = 0.00;
        updates.payment_method = null;
        updates.paid_at = null;
    }
    
    DB.update('invoices', invoiceId, updates);
    DB.logAudit(6, "BILL_RECTIFIED", "invoices", invoiceId, updates);
    
    closeModal('modal-edit-invoice');
    
    // Refresh depending on where we are
    if (window.currentTab === 'admission') {
        if (typeof renderAdmissionsAndInvoices === 'function') renderAdmissionsAndInvoices();
    } else if (window.currentTab === 'accounting') {
        if (typeof renderAccountingDashboard === 'function') renderAccountingDashboard();
    }
    
    alert(`Fattura ${inv.invoice_number} modificata con successo.`);
};

function handleEditInvoiceSubmit(e) {
    window.handleEditInvoiceSubmit(e);
}

// --- Printable Invoice Generation ---
window.openInvoiceReportView = function(invoiceId) {
    const invoices = DB.get('invoices');
    const inv = invoices.find(i => i.id === invoiceId);
    if (!inv) return;
    
    const patients = DB.get('patients');
    const admissions = DB.get('admissions') || [];
    const appServices = DB.get('appointment_services') || [];
    const labTests = DB.get('lab_tests') || [];
    const services = DB.get('medical_services') || [];
    
    let p = null;
    let servicesList = [];
    
    if (inv.admission_id) {
        const adm = admissions.find(a => a.id === inv.admission_id);
        p = adm ? patients.find(pat => pat.id === adm.patient_id) : null;
        servicesList.push({
            code: 'RIC-HOSP',
            name: 'Degenza Ospedaliera Ordinaria (Ticket ricovero)',
            price: inv.amount_due
        });
    } else if (inv.appointment_id) {
        const app = DB.get('appointments').find(a => a.id === inv.appointment_id);
        p = app ? patients.find(pat => pat.id === app.patient_id) : null;
        const srvIds = appServices.filter(as => as.appointment_id === inv.appointment_id).map(as => as.service_id);
        const booked = services.filter(sv => srvIds.includes(sv.id));
        booked.forEach(srv => {
            let price = srv.price || 0.0;
            if (inv.custom_rates && inv.custom_rates[srv.id] !== undefined) {
                price = Number(inv.custom_rates[srv.id]) || 0.0;
            } else {
                const item = DB.get('price_list_items').find(pl => pl.price_list_id === inv.price_list_id && pl.service_id === srv.id);
                if (item) price = item.price;
            }
            servicesList.push({
                code: srv.code || 'N/A',
                name: srv.name,
                price: price
            });
        });
    } else if (inv.sample_id) {
        const sam = DB.get('lab_samples').find(s => s.id === inv.sample_id);
        p = sam ? patients.find(pat => pat.id === sam.patient_id) : null;
        const srvIds = labTests.filter(t => t.sample_id === inv.sample_id).map(t => t.service_id);
        const booked = services.filter(sv => srvIds.includes(sv.id));
        booked.forEach(srv => {
            let price = srv.price || 0.0;
            if (inv.custom_rates && inv.custom_rates[srv.id] !== undefined) {
                price = Number(inv.custom_rates[srv.id]) || 0.0;
            } else {
                const item = DB.get('price_list_items').find(pl => pl.price_list_id === inv.price_list_id && pl.service_id === srv.id);
                if (item) price = item.price;
            }
            servicesList.push({
                code: srv.code || 'N/A',
                name: srv.name,
                price: price
            });
        });
    }
    
    if (!p) p = { last_name: 'Paziente', first_name: 'Esterno', tax_code: 'N/A', gender: 'N/A', birth_date: new Date().toISOString(), address: 'N/A' };
    
    // Load dynamic template settings
    const tpl = DB.get('report_templates') || { header_title: 'NEXTCARE', contacts: 'Milano', director: 'Rossi', footer: 'NextCare' };
    
    document.getElementById('rep-inv-header-title').innerText = tpl.header_title;
    document.getElementById('rep-inv-header-contacts').innerText = tpl.contacts;
    document.getElementById('rep-inv-header-director').innerText = `Direttore Sanitario: ${tpl.director}`;
    document.getElementById('rep-inv-footer-disclaimer').innerText = tpl.footer;
    
    const logoContainer = document.getElementById('rep-inv-logo-container');
    const logoImg = document.getElementById('rep-inv-logo');
    if (tpl.logo_base64) {
        logoImg.src = tpl.logo_base64;
        logoContainer.style.display = 'block';
    } else {
        logoContainer.style.display = 'none';
    }
    
    document.getElementById('rep-inv-num').innerText = inv.invoice_number;
    document.getElementById('rep-inv-date').innerText = inv.issue_date;
    
    let recipientName = `${p.last_name.toUpperCase()} ${p.first_name.toUpperCase()}`;
    if (inv.company_id) {
        const companies = DB.get('companies') || [];
        const company = companies.find(c => c.id == inv.company_id);
        if (company) {
            recipientName = `${company.name.toUpperCase()} (Paziente: ${p.last_name.toUpperCase()} ${p.first_name.toUpperCase()})`;
        }
    } else if (inv.is_insurance_invoice && inv.claim_id) {
        const claim = DB.get('patient_claims').find(c => c.id === inv.claim_id);
        if (claim) {
            const ins = DB.get('insurances').find(i => i.id === claim.insurance_id);
            if (ins) {
                recipientName = `${ins.name.toUpperCase()} (Paziente: ${p.last_name.toUpperCase()} ${p.first_name.toUpperCase()})`;
            }
        }
    }
    document.getElementById('rep-inv-patient-name').innerText = recipientName;
    document.getElementById('rep-inv-patient-tax').innerText = p.tax_code;
    
    const age = new Date().getFullYear() - new Date(p.birth_date).getFullYear();
    document.getElementById('rep-inv-patient-meta').innerText = `${p.gender} / ${age} anni (Nascita: ${new Date(p.birth_date).toLocaleDateString('it-IT')})`;
    document.getElementById('rep-inv-patient-address').innerText = p.address || 'N/A';
    
    // Payment status labels
    const statusLabel = document.getElementById('rep-inv-status-label');
    if (inv.payment_status === 'paid') {
        statusLabel.innerHTML = '<span style="color: #16a34a; font-weight: 700; text-transform: uppercase;">Pagata / Saldata</span>';
        document.getElementById('rep-inv-method-label').innerText = inv.payment_method || 'Contanti';
        document.getElementById('rep-inv-paid-date-label').innerText = inv.paid_at || inv.issue_date;
    } else {
        statusLabel.innerHTML = '<span style="color: #dc2626; font-weight: 700; text-transform: uppercase;">Non Pagata</span>';
        document.getElementById('rep-inv-method-label').innerText = '--';
        document.getElementById('rep-inv-paid-date-label').innerText = '--';
    }
    
    // Services table body
    const tbody = document.getElementById('rep-inv-services-tbody');
    tbody.innerHTML = '';
    
    servicesList.forEach(srv => {
        const tr = document.createElement('tr');
        tr.style.borderBottom = '1px solid #e2e8f0';
        tr.innerHTML = `
            <td style="padding: 10px 5px; font-family: monospace;">${srv.code || ''}</td>
            <td style="padding: 10px 5px;">${srv.name}</td>
            <td style="padding: 10px 5px; text-align: right;">€ ${Number(srv.price || 0).toFixed(2)}</td>
        `;
        tbody.appendChild(tr);
    });
    
    const subtotalVal = inv.subtotal !== undefined ? Number(inv.subtotal) : Number(inv.amount_due || 0);
    const stampDutyVal = inv.stamp_duty !== undefined ? Number(inv.stamp_duty) : 0.00;
    
    document.getElementById('rep-inv-subtotal').innerText = `€ ${subtotalVal.toFixed(2)}`;
    
    const stampRow = document.getElementById('rep-inv-stamp-duty-row');
    if (stampDutyVal > 0) {
        if (stampRow) stampRow.style.display = 'table-row';
        const stampEl = document.getElementById('rep-inv-stamp-duty');
        if (stampEl) stampEl.innerText = `€ ${stampDutyVal.toFixed(2)}`;
    } else {
        if (stampRow) stampRow.style.display = 'none';
    }
    
    document.getElementById('rep-inv-total').innerText = `€ ${Number(inv.amount_due || 0).toFixed(2)}`;
    
    openModal('modal-invoice-report-view');
    if (window.lucide) window.lucide.createIcons();
};

// --- Accounting Dashboard Configuration and Rendering ---
window.saveAccountingConfig = function() {
    const input = document.getElementById('acc-next-invoice-num');
    if (input && input.value) {
        localStorage.setItem('nextcare_next_invoice_num', input.value);
        alert(`Prossimo numero progressivo salvato: ${input.value}`);
        renderAccountingDashboard();
    }
};

window.renderAccountingDashboard = function() {
    const invoices = DB.get('invoices') || [];
    const patients = DB.get('patients') || [];
    const admissions = DB.get('admissions') || [];
    const appServices = DB.get('appointment_services') || [];
    const labTests = DB.get('lab_tests') || [];
    const services = DB.get('medical_services') || [];

    // Set next invoice sequence input if empty
    const configInput = document.getElementById('acc-next-invoice-num');
    if (configInput && !configInput.value) {
        let nextNum = localStorage.getItem('nextcare_next_invoice_num');
        if (!nextNum) nextNum = 1001;
        configInput.value = nextNum;
    }

    // Read filters
    const startDateVal = document.getElementById('filter-acc-start-date').value;
    const endDateVal = document.getElementById('filter-acc-end-date').value;
    const paymentStatusVal = document.getElementById('filter-acc-payment-status').value;
    const aiSearchVal = document.getElementById('filter-acc-ai-search')?.value || '';

    let aiFilter = null;
    if (aiSearchVal) {
        aiFilter = window.parseNaturalLanguageQuery(aiSearchVal, 'accounting');
    }

    // Filter invoices
    const filteredInvoices = invoices.filter(inv => {
        let p = null;
        let servicesList = [];
        
        if (inv.admission_id) {
            const adm = admissions.find(a => a.id === inv.admission_id);
            p = adm ? patients.find(pat => pat.id === adm.patient_id) : null;
            servicesList.push("Ricovero Ospedaliero");
        } else if (inv.appointment_id) {
            const app = DB.get('appointments').find(a => a.id === inv.appointment_id);
            p = app ? patients.find(pat => pat.id === app.patient_id) : null;
            const srvIds = appServices.filter(as => as.appointment_id === inv.appointment_id).map(as => as.service_id);
            const booked = services.filter(sv => srvIds.includes(sv.id));
            booked.forEach(srv => servicesList.push(srv.name));
        } else if (inv.sample_id) {
            const sam = DB.get('lab_samples').find(s => s.id === inv.sample_id);
            p = sam ? patients.find(pat => pat.id === sam.patient_id) : null;
            const srvIds = labTests.filter(t => t.sample_id === inv.sample_id).map(t => t.service_id);
            const booked = services.filter(sv => srvIds.includes(sv.id));
            booked.forEach(srv => servicesList.push(srv.name));
        }

        const patientName = p ? `${p.last_name} ${p.first_name}`.toLowerCase() : '';
        const servicesText = servicesList.join(', ').toLowerCase();

        if (startDateVal && inv.issue_date < startDateVal) return false;
        if (aiFilter?.startDate && inv.issue_date < aiFilter.startDate) return false;

        if (endDateVal && inv.issue_date > endDateVal) return false;
        if (aiFilter?.endDate && inv.issue_date > aiFilter.endDate) return false;

        if (paymentStatusVal && inv.payment_status !== paymentStatusVal) return false;
        if (aiFilter?.status) {
            if (aiFilter.status === 'completed' && inv.payment_status !== 'paid') return false;
            if (aiFilter.status === 'unpaid' && inv.payment_status !== 'unpaid') return false;
        }

        const searchQuery = (aiFilter ? aiFilter.textQuery : '').toLowerCase().trim();
        if (searchQuery) {
            const matchesPatient = patientName.includes(searchQuery) || (p && p.tax_code.toLowerCase().includes(searchQuery));
            const matchesServices = servicesText.includes(searchQuery);
            const matchesInvoiceNum = String(inv.invoice_number).includes(searchQuery);
            if (!matchesPatient && !matchesServices && !matchesInvoiceNum) return false;
        }

        return true;
    });

    // Render table
    const tbody = document.querySelector('#accounting-invoices-table tbody');
    tbody.innerHTML = '';

    const paginatedInvoices = window.setupTablePagination('accounting-invoices-table', filteredInvoices, () => window.renderAccountingInvoices());

    if (filteredInvoices.length === 0) {
        tbody.innerHTML = `<tr><td colspan="8" style="text-align: center;" class="text-muted">Nessuna fattura trovata per i filtri selezionati</td></tr>`;
    } else {
        paginatedInvoices.forEach(inv => {
            let p = null;
            let servicesList = [];
            
            if (inv.admission_id) {
                const adm = admissions.find(a => a.id === inv.admission_id);
                p = adm ? patients.find(pat => pat.id === adm.patient_id) : null;
                servicesList.push("Ricovero Ospedaliero");
            } else if (inv.appointment_id) {
                const app = DB.get('appointments').find(a => a.id === inv.appointment_id);
                p = app ? patients.find(pat => pat.id === app.patient_id) : null;
                const srvIds = appServices.filter(as => as.appointment_id === inv.appointment_id).map(as => as.service_id);
                const booked = services.filter(sv => srvIds.includes(sv.id));
                booked.forEach(srv => servicesList.push(srv.name));
            } else if (inv.sample_id) {
                const sam = DB.get('lab_samples').find(s => s.id === inv.sample_id);
                p = sam ? patients.find(pat => pat.id === sam.patient_id) : null;
                const srvIds = labTests.filter(t => t.sample_id === inv.sample_id).map(t => t.service_id);
                const booked = services.filter(sv => srvIds.includes(sv.id));
                booked.forEach(srv => servicesList.push(srv.name));
            }

            const patientName = p ? `${p.last_name} ${p.first_name}` : 'Paziente Esterno';
            const servicesText = servicesList.join(', ') || 'Nessuna prestazione';

            const isCreditNote = inv.is_credit_note || inv.invoice_number.startsWith('NDC-');

            let paymentBadge = '';
            if (isCreditNote) {
                paymentBadge = '<span class="badge badge-info">Nota di Credito</span>';
            } else if (inv.payment_status === 'paid') {
                paymentBadge = '<span class="badge badge-success">Pagata</span>';
            } else if (inv.payment_status === 'unpaid') {
                paymentBadge = '<span class="badge badge-danger">Non Pagata</span>';
            } else {
                paymentBadge = '<span class="badge badge-warning">Parziale</span>';
            }

            const methodDateText = inv.payment_status === 'paid' 
                ? `${inv.payment_method || 'Contanti'} - ${inv.paid_at || inv.issue_date}` 
                : '--';

            // Pay action
            let actions = '';
            if (isCreditNote) {
                actions = '<span class="text-muted">Saldato</span>';
            } else if (inv.payment_status !== 'paid') {
                actions += `<button class="btn btn-success btn-sm" onclick="openPayInvoiceModal(${inv.id})"><i data-lucide="check"></i> Paga</button>`;
            }
            // Print action
            actions += ` <button class="btn btn-secondary btn-sm" onclick="openInvoiceReportView(${inv.id})"><i data-lucide="printer"></i> Stampa</button>`;
            
            const roleSelect = document.getElementById('user-role-select');
            const currentRole = roleSelect ? roleSelect.value : 'admin';
            const isDoctor = currentRole.startsWith('doctor_');
            
            // Edit action
            if (!isDoctor && !isCreditNote) {
                actions += ` <button class="btn btn-primary btn-sm" onclick="openEditInvoiceModal(${inv.id})"><i data-lucide="edit"></i> Rettifica</button>`;
            }

            let recipientName = patientName;
            if (inv.is_insurance_invoice && inv.claim_id) {
                const claim = DB.get('patient_claims').find(c => c.id === inv.claim_id);
                if (claim) {
                    const ins = DB.get('insurances').find(i => i.id === claim.insurance_id);
                    if (ins) {
                        recipientName = `${ins.name} (Paz: ${patientName})`;
                    }
                }
            }

            let amountStyle = '';
            let amountText = `€ ${inv.amount_due.toFixed(2)}`;
            if (isCreditNote) {
                amountStyle = 'style="color: #ef4444;"';
                amountText = `-€ ${Math.abs(inv.amount_due).toFixed(2)}`;
            }

            const tr = document.createElement('tr');
            tr.innerHTML = `
                <td><strong style="font-family: monospace;">${inv.invoice_number}</strong></td>
                <td>${inv.issue_date}</td>
                <td>${recipientName}</td>
                <td style="max-width: 250px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;" title="${servicesText}">${servicesText}</td>
                <td ${amountStyle}><strong>${amountText}</strong></td>
                <td>${paymentBadge}</td>
                <td>${methodDateText}</td>
                <td><div class="row-actions">${actions}</div></td>
            `;
            tbody.appendChild(tr);
        });
    }

    // Calculate KPIs
    let totalEmitted = 0;
    let totalPaid = 0;
    let totalUnpaid = 0;
    const methodCounts = {};

    filteredInvoices.forEach(inv => {
        totalEmitted += inv.amount_due;
        if (inv.payment_status === 'paid') {
            totalPaid += inv.amount_due;
            const method = inv.payment_method || 'Contanti';
            methodCounts[method] = (methodCounts[method] || 0) + inv.amount_due;
        } else {
            totalUnpaid += inv.amount_due;
        }
    });

    document.getElementById('kpi-acc-total-emitted').innerText = `€ ${totalEmitted.toFixed(2)}`;
    document.getElementById('kpi-acc-total-paid').innerText = `€ ${totalPaid.toFixed(2)}`;
    document.getElementById('kpi-acc-total-unpaid').innerText = `€ ${totalUnpaid.toFixed(2)}`;

    // Top Payment Method
    let topMethod = '--';
    let maxAmount = -1;
    for (const [m, amt] of Object.entries(methodCounts)) {
        if (amt > maxAmount) {
            maxAmount = amt;
            topMethod = `${m} (€ ${amt.toFixed(2)})`;
        }
    }
    document.getElementById('kpi-acc-top-method').innerText = topMethod;

    if (window.lucide) window.lucide.createIcons();
};

window.openPrintAccountingReportModal = function() {
    const invoices = DB.get('invoices') || [];
    const patients = DB.get('patients') || [];
    const admissions = DB.get('admissions') || [];
    const appServices = DB.get('appointment_services') || [];
    const labTests = DB.get('lab_tests') || [];
    const services = DB.get('medical_services') || [];

    // Date filters from the main dashboard
    const startDateVal = document.getElementById('filter-acc-start-date').value;
    const endDateVal = document.getElementById('filter-acc-end-date').value;
    const paymentStatusVal = document.getElementById('filter-acc-payment-status').value;

    const filteredInvoices = invoices.filter(inv => {
        if (startDateVal && inv.issue_date < startDateVal) return false;
        if (endDateVal && inv.issue_date > endDateVal) return false;
        if (paymentStatusVal && inv.payment_status !== paymentStatusVal) return false;
        return true;
    });

    // Populate Report Template Info
    const tpl = DB.get('report_templates') || { header_title: 'NEXTCARE', contacts: 'Milano', director: 'Rossi', footer: 'NextCare' };
    document.getElementById('rep-acc-header-title').innerText = tpl.header_title;
    document.getElementById('rep-acc-header-contacts').innerText = tpl.contacts;
    
    const logoContainer = document.getElementById('rep-acc-logo-container');
    const logoImg = document.getElementById('rep-acc-logo');
    if (tpl.logo_base64) {
        logoImg.src = tpl.logo_base64;
        logoContainer.style.display = 'block';
    } else {
        logoContainer.style.display = 'none';
    }
    document.getElementById('rep-acc-footer-disclaimer').innerText = tpl.footer;

    document.getElementById('rep-acc-print-date').innerText = new Date().toLocaleString('it-IT');
    document.getElementById('rep-acc-period-start').innerText = startDateVal || 'Inizio Registro';
    document.getElementById('rep-acc-period-end').innerText = endDateVal || 'Fine Registro';

    // Calculate KPIs
    let totalEmitted = 0;
    let totalPaid = 0;
    let totalUnpaid = 0;
    const methodCounts = {};
    const methodTxCount = {};

    filteredInvoices.forEach(inv => {
        totalEmitted += inv.amount_due;
        if (inv.payment_status === 'paid') {
            totalPaid += inv.amount_due;
            const method = inv.payment_method || 'Contanti';
            methodCounts[method] = (methodCounts[method] || 0.0) + inv.amount_due;
            methodTxCount[method] = (methodTxCount[method] || 0) + 1;
        } else {
            totalUnpaid += inv.amount_due;
        }
    });

    document.getElementById('rep-acc-kpi-emitted').innerText = `€ ${totalEmitted.toFixed(2)}`;
    document.getElementById('rep-acc-kpi-paid').innerText = `€ ${totalPaid.toFixed(2)}`;
    document.getElementById('rep-acc-kpi-unpaid').innerText = `€ ${totalUnpaid.toFixed(2)}`;

    // Populate Payment Breakdown
    const methodsTbody = document.getElementById('rep-acc-methods-tbody');
    methodsTbody.innerHTML = '';
    
    const allMethods = ['Contanti', 'Carta di Credito', 'Bancomat', 'Bonifico Bancario'];
    allMethods.forEach(method => {
        const amt = methodCounts[method] || 0.0;
        const count = methodTxCount[method] || 0;
        const tr = document.createElement('tr');
        tr.style.borderBottom = '1px solid #e2e8f0';
        tr.innerHTML = `
            <td style="padding: 8px 0; font-weight: 500;">${method}</td>
            <td style="padding: 8px 0; text-align: right;">${count}</td>
            <td style="padding: 8px 0; text-align: right; font-weight: 600;">€ ${amt.toFixed(2)}</td>
        `;
        methodsTbody.appendChild(tr);
    });

    // Populate Detailed Invoices
    const invoicesTbody = document.getElementById('rep-acc-invoices-tbody');
    invoicesTbody.innerHTML = '';

    filteredInvoices.forEach(inv => {
        let p = null;
        if (inv.admission_id) {
            const adm = admissions.find(a => a.id === inv.admission_id);
            p = adm ? patients.find(pat => pat.id === adm.patient_id) : null;
        } else if (inv.appointment_id) {
            const app = DB.get('appointments').find(a => a.id === inv.appointment_id);
            p = app ? patients.find(pat => pat.id === app.patient_id) : null;
        } else if (inv.sample_id) {
            const sam = DB.get('lab_samples').find(s => s.id === inv.sample_id);
            p = sam ? patients.find(pat => pat.id === sam.patient_id) : null;
        }

        const patientName = p ? `${p.last_name} ${p.first_name}` : 'Paziente Esterno';
        const isCreditNote = inv.is_credit_note || inv.invoice_number.startsWith('NDC-');
        const statusText = isCreditNote ? 'NOTA CREDITO' : (inv.payment_status === 'paid' ? 'PAGATA' : 'SOSPESA');
        const statusColor = isCreditNote ? '#3b82f6' : (inv.payment_status === 'paid' ? '#16a34a' : '#dc2626');
        const methodDateText = inv.payment_status === 'paid' 
            ? `${inv.payment_method || 'Contanti'} (${inv.paid_at || inv.issue_date})` 
            : '--';

        let amountStyle = '';
        let amountText = `€ ${inv.amount_due.toFixed(2)}`;
        if (isCreditNote) {
            amountStyle = 'style="color: #ef4444;"';
            amountText = `-€ ${Math.abs(inv.amount_due).toFixed(2)}`;
        }

        const tr = document.createElement('tr');
        tr.style.borderBottom = '1px solid #f1f5f9';
        tr.innerHTML = `
            <td style="padding: 8px 0; font-family: monospace; font-weight: 600;">${inv.invoice_number}</td>
            <td style="padding: 8px 0;">${inv.issue_date}</td>
            <td style="padding: 8px 0;">${patientName}</td>
            <td style="padding: 8px 0; text-align: right; font-weight: 600;" ${amountStyle}>${amountText}</td>
            <td style="padding: 8px 0; text-align: center; color: ${statusColor}; font-weight: 700; font-size: 0.75rem;">${statusText}</td>
            <td style="padding: 8px 0;">${methodDateText}</td>
        `;
        invoicesTbody.appendChild(tr);
    });

    openModal('modal-print-accounting-report');
};

window.initAccountingFilters = function() {
    const startInput = document.getElementById('filter-acc-start-date');
    const endInput = document.getElementById('filter-acc-end-date');
    const statusSelect = document.getElementById('filter-acc-payment-status');

    if (startInput) {
        startInput.addEventListener('change', () => renderAccountingDashboard());
        endInput.addEventListener('change', () => renderAccountingDashboard());
        statusSelect.addEventListener('change', () => renderAccountingDashboard());
    }
};

window.switchAccountingSubTab = function(tabName) {
    const buttons = document.querySelectorAll('#tab-accounting .sub-tabs-container .sub-tab-btn');
    buttons.forEach(btn => {
        if (btn.id === `sub-tab-${tabName}`) {
            btn.classList.add('active');
        } else {
            btn.classList.remove('active');
        }
    });

    const contents = document.querySelectorAll('#tab-accounting .sub-tab-content');
    contents.forEach(cnt => {
        if (cnt.id === `sub-content-${tabName}`) {
            cnt.style.display = 'block';
        } else {
            cnt.style.display = 'none';
        }
    });

    if (tabName === 'profit-centers') {
        renderProfitCentersTable();
    }
};

window.renderProfitCentersTable = function() {
    const tbody = document.getElementById('profit-centers-tbody');
    if (!tbody) return;
    tbody.innerHTML = '';

    const pcs = DB.get('profit_centers') || [];
    if (pcs.length === 0) {
        tbody.innerHTML = '<tr><td colspan="4" style="text-align: center;" class="text-muted">Nessun profit center configurato</td></tr>';
        return;
    }

    pcs.forEach(pc => {
        const tr = document.createElement('tr');
        tr.innerHTML = `
            <td><code>${pc.id}</code></td>
            <td><strong>${pc.name}</strong></td>
            <td>${pc.description || '<span class="text-muted">Nessuna descrizione</span>'}</td>
            <td>
                <div class="row-actions">
                    <button class="btn btn-primary btn-sm" onclick="openEditProfitCenterModal(${pc.id})">Modifica</button>
                    <button class="btn btn-secondary btn-sm" onclick="deleteProfitCenter(${pc.id})">Rimuovi</button>
                </div>
            </td>
        `;
        tbody.appendChild(tr);
    });
};

window.openAddProfitCenterModal = function() {
    const form = document.getElementById('form-profit-center');
    if (form) form.reset();
    document.getElementById('profit-center-id').value = '';
    document.getElementById('modal-profit-center-title').innerText = "Nuovo Profit Center";
    document.getElementById('btn-save-profit-center').innerText = "Salva Profit Center";
    openModal('modal-profit-center');
};

window.openEditProfitCenterModal = function(id) {
    const pcs = DB.get('profit_centers') || [];
    const pc = pcs.find(item => item.id === id);
    if (!pc) return;

    document.getElementById('profit-center-id').value = pc.id;
    document.getElementById('profit-center-name').value = pc.name;
    document.getElementById('profit-center-desc').value = pc.description || '';
    document.getElementById('modal-profit-center-title').innerText = "Modifica Profit Center";
    document.getElementById('btn-save-profit-center').innerText = "Salva Modifiche";
    openModal('modal-profit-center');
};

window.handleProfitCenterSubmit = function(event) {
    event.preventDefault();
    const idVal = document.getElementById('profit-center-id').value;
    const nameVal = document.getElementById('profit-center-name').value.trim().toUpperCase();
    const descVal = document.getElementById('profit-center-desc').value.trim();

    if (!nameVal) {
        alert("Il nome del Profit Center è obbligatorio.");
        return;
    }

    const pcs = DB.get('profit_centers') || [];
    const nameExists = pcs.some(pc => pc.name === nameVal && pc.id !== parseInt(idVal || 0));
    if (nameExists) {
        alert("Esiste già un Profit Center con questo nome.");
        return;
    }

    const fields = {
        name: nameVal,
        description: descVal || null
    };

    if (idVal) {
        const pcId = parseInt(idVal);
        DB.update('profit_centers', pcId, fields);
        DB.logAudit(6, "UPDATE_PROFIT_CENTER", "profit_centers", pcId, { name: nameVal });
        alert("Profit Center aggiornato con successo.");
    } else {
        const newPc = DB.insert('profit_centers', fields);
        DB.logAudit(6, "CREATE_PROFIT_CENTER", "profit_centers", newPc.id, { name: nameVal });
        alert("Profit Center creato con successo.");
    }

    closeModal('modal-profit-center');
    renderProfitCentersTable();
};

window.deleteProfitCenter = function(id) {
    const pcs = DB.get('profit_centers') || [];
    const pc = pcs.find(item => item.id === id);
    if (!pc) return;

    const defaults = ["SPECIALISTICA", "IMAGING", "LABORATORIO"];
    if (defaults.includes(pc.name)) {
        if (!confirm(`Attenzione: "${pc.name}" è un Profit Center predefinito di sistema. Se lo elimini, alcune assegnazioni automatiche potrebbero non funzionare. Vuoi davvero continuare?`)) {
            return;
        }
    } else {
        if (!confirm(`Sei sicuro di voler eliminare il Profit Center "${pc.name}"?`)) return;
    }

    const filtered = pcs.filter(item => item.id !== id);
    DB.set('profit_centers', filtered);
    DB.logAudit(6, "DELETE_PROFIT_CENTER", "profit_centers", id, { name: pc.name });

    const services = DB.get('medical_services') || [];
    let clearedCount = 0;
    services.forEach(s => {
        if (s.profit_center === pc.name) {
            s.profit_center = null;
            DB.update('medical_services', s.id, { profit_center: null });
            clearedCount++;
        }
    });

    if (clearedCount > 0) {
        alert(`Profit Center eliminato. Rimosso da ${clearedCount} prestazioni.`);
        renderServices();
    } else {
        alert("Profit Center eliminato con successo.");
    }

    renderProfitCentersTable();
};

// MODULE 9: STAFF & SHIFTS (HRIS) + MEDIC AGENDAS
function renderStaffAndShifts() {
    const staff = DB.get('staff');
    const shifts = DB.get('shifts');
    const clinics = DB.get('clinics');
    const doctors = DB.get('doctors');
    const agendas = DB.get('doctor_agendas') || [];
    const services = DB.get('medical_services');
    const agendaServices = DB.get('doctor_agenda_services') || [];
    
    // Render staff table
    const sTbody = document.querySelector('#staff-table tbody');
    sTbody.innerHTML = '';
    staff.forEach(st => {
        const isDoc = st.role === 'doctor';
        const doc = isDoc ? doctors.find(d => d.staff_id === st.id) : null;
        const specLabel = doc ? ` <span style="font-size:0.75rem; font-weight:600; color:var(--primary);">(${doc.specialization})</span>` : '';
        
        let roleBadge = '';
        if (st.role === 'doctor') roleBadge = '<span class="badge badge-info">Medico</span>';
        else if (st.role === 'nurse') roleBadge = '<span class="badge badge-success">Infermiere</span>';
        else if (st.role === 'technician') roleBadge = '<span class="badge badge-purple">Tecnico</span>';
        else if (st.role === 'therapist') roleBadge = '<span class="badge badge-primary">Terapista</span>';
        else roleBadge = `<span class="badge badge-secondary">${st.role}</span>`;

        let statusText = st.active ? '<span class="badge badge-success">Attivo</span>' : '<span class="badge badge-danger">Inattivo</span>';

        const profilesList = st.profiles ? (typeof st.profiles === 'string' ? JSON.parse(st.profiles) : st.profiles) : [];
        const profilesBadges = profilesList.map(p => `<span class="badge badge-purple" style="margin-right: 2px;">${p}</span>`).join('') || '<span class="text-muted">-</span>';
        const usernameVal = st.username || '<span class="text-muted">-</span>';

        const tr = document.createElement('tr');
        tr.innerHTML = `
            <td>
                <strong>${st.last_name} ${st.first_name}</strong>
                <div>${specLabel}</div>
            </td>
            <td><code>${usernameVal}</code></td>
            <td>${profilesBadges}</td>
            <td>${roleBadge}</td>
            <td>${st.email}</td>
            <td>${statusText}</td>
            <td>
                <div class="row-actions">
                    <button class="btn btn-primary btn-sm" onclick="openEditStaffModal(${st.id})">Modifica</button>
                </div>
            </td>
        `;
        sTbody.appendChild(tr);
    });

    // Render shifts table
    const shTbody = document.querySelector('#shifts-table tbody');
    shTbody.innerHTML = '';
    shifts.forEach(sh => {
        const op = staff.find(st => st.id === sh.staff_id);
        const cli = clinics.find(c => c.id === sh.clinic_id);
        
        const dateStr = new Date(sh.start_time).toLocaleDateString('it-IT');
        const startStr = new Date(sh.start_time).toLocaleTimeString('it-IT', { hour: '2-digit', minute: '2-digit' });
        const endStr = new Date(sh.end_time).toLocaleTimeString('it-IT', { hour: '2-digit', minute: '2-digit' });
        
        const tr = document.createElement('tr');
        tr.innerHTML = `
            <td>${dateStr}</td>
            <td><strong>${op ? op.last_name : 'Sconosciuto'}</strong></td>
            <td><code>${startStr} - ${endStr}</code></td>
            <td>${sh.role_assigned} ${cli ? `(${cli.name})` : ''}</td>
            <td>
                <button class="btn btn-secondary btn-sm" onclick="deleteShift(${sh.id})">Rimuovi</button>
            </td>
        `;
        shTbody.appendChild(tr);
    });

    // Render doctor agendas table
    const agTbody = document.querySelector('#agendas-table tbody');
    agTbody.innerHTML = '';
    if (agendas.length === 0) {
        agTbody.innerHTML = `<tr><td colspan="7" style="text-align: center;" class="text-muted">Nessuna agenda configurata per i medici</td></tr>`;
    } else {
        agendas.forEach(ag => {
            const isGeneric = (ag.doctor_id === null || !ag.doctor_id);
            const doc = !isGeneric ? doctors.find(d => d.id === ag.doctor_id) : null;
            const op = doc ? staff.find(st => st.id === doc.staff_id) : null;
            
            // Find managed services
            const srvIds = agendaServices.filter(as => as.agenda_id === ag.id).map(as => as.service_id);
            const managedSrvs = services.filter(s => srvIds.includes(s.id));
            
            let servicesText = '';
            if (managedSrvs.length === 0) {
                servicesText = '<span class="text-muted">Nessun esame configurato</span>';
            } else if (managedSrvs.length <= 3) {
                servicesText = managedSrvs.map(s => `<span class="badge badge-purple" style="font-size:0.7rem; margin:1px;">${s.name}</span>`).join(' ');
            } else {
                const visiblePart = managedSrvs.slice(0, 3).map(s => `<span class="badge badge-purple" style="font-size:0.7rem; margin:1px;">${s.name}</span>`).join(' ');
                const hiddenPart = managedSrvs.slice(3).map(s => `<span class="badge badge-purple" style="font-size:0.7rem; margin:1px;">${s.name}</span>`).join(' ');
                const toggleId = `agenda-srv-toggle-${ag.id}`;
                servicesText = `
                    <div style="display:inline;">${visiblePart}</div>
                    <span id="${toggleId}-btn" onclick="document.getElementById('${toggleId}').style.display='inline'; this.style.display='none';" style="cursor:pointer; font-size:0.75rem; color:var(--primary); font-weight:700; margin-left:4px; text-decoration:underline; white-space:nowrap;">+ ${managedSrvs.length - 3} altri</span>
                    <span id="${toggleId}" style="display:none;">
                        ${hiddenPart}
                        <span onclick="document.getElementById('${toggleId}').style.display='none'; document.getElementById('${toggleId}-btn').style.display='inline';" style="cursor:pointer; font-size:0.75rem; color:var(--primary); font-weight:700; margin-left:4px; text-decoration:underline; white-space:nowrap;">(nascondi)</span>
                    </span>
                `;
            }

            let hoursText = '';
            let parsedTimeSlots = ag.time_slots;
            if (typeof parsedTimeSlots === 'string') {
                try { parsedTimeSlots = JSON.parse(parsedTimeSlots); } catch(e) { parsedTimeSlots = []; }
            }
            if (parsedTimeSlots && parsedTimeSlots.length > 0) {
                hoursText = parsedTimeSlots.map(slot => `${slot.start}-${slot.end}`).join(', ');
            } else {
                hoursText = `${ag.start_hour || '08:00'}-${ag.end_hour || '14:00'}`;
            }

            const tr = document.createElement('tr');
            tr.innerHTML = `
                <td>
                    ${isGeneric ? `
                        <span class="badge badge-purple" style="font-size:0.7rem; padding: 2px 6px; margin-right:4px;">Reparto</span>
                        <strong>${ag.name || 'Generica'}</strong>
                    ` : `
                        <strong>Dott. ${op ? op.last_name : 'Sconosciuto'}</strong>
                    `}
                </td>
                <td>${isGeneric ? '<code>Generica</code>' : (doc ? doc.specialization : '-')}</td>
                <td>${ag.description || '-'}</td>
                <td><code>${ag.start_date} / ${ag.end_date}</code></td>
                <td>
                    <span style="font-size:0.8rem; font-weight:600; display:block;">${ag.active_days}</span>
                    <span class="text-muted" style="font-size:0.7rem; display:block; margin-top:2px;">${hoursText}</span>
                </td>
                <td><strong>${ag.slot_duration_minutes} min</strong></td>
                <td><div style="max-width:320px; display:flex; flex-wrap:wrap; gap:4px; align-items:center;">${servicesText}</div></td>
                <td>
                    <div class="row-actions">
                        <button class="btn btn-primary btn-sm" onclick="openEditAgendaModal(${ag.id})">Modifica</button>
                        <button class="btn btn-secondary btn-sm" onclick="deleteAgenda(${ag.id})">Elimina</button>
                    </div>
                </td>
            `;
            agTbody.appendChild(tr);
        });
    }
}

window.deleteShift = function(shiftId) {
    if (!confirm("Rimuovere questo turno di lavoro?")) return;
    const shifts = DB.get('shifts');
    DB.set('shifts', shifts.filter(s => s.id !== shiftId));
    DB.logAudit(6, "DELETE_SHIFT", "shifts", shiftId, {});
    renderStaffAndShifts();
};

window.deleteAgenda = function(agendaId) {
    if (!confirm("Confermi la cancellazione di questa agenda operativa medica?")) return;
    
    const agendas = DB.get('doctor_agendas');
    DB.set('doctor_agendas', agendas.filter(a => a.id !== agendaId));
    
    const agendaServices = DB.get('doctor_agenda_services');
    DB.set('doctor_agenda_services', agendaServices.filter(as => as.agenda_id !== agendaId));
    
    DB.logAudit(6, "DELETE_DOCTOR_AGENDA", "doctor_agendas", agendaId, {});
    renderStaffAndShifts();
};

// --- 9B. STAFF / DOCTORS CRUD LOGIC ---
window.toggleDoctorFields = function(role) {
    const docFields = document.getElementById('doctor-spec-fields');
    if (role === 'doctor') {
        docFields.classList.remove('hidden');
        document.getElementById('st-specialization').required = true;
    } else {
        docFields.classList.add('hidden');
        document.getElementById('st-specialization').required = false;
    }
};

window.openAddStaffModal = function() {
    document.getElementById('st-edit-id').value = '';
    document.getElementById('form-add-staff').reset();
    document.getElementById('st-reports-threshold').value = '5';
    document.getElementById('st-username').value = '';
    document.getElementById('st-password').value = '';
    const checkboxes = document.querySelectorAll('input[name="st-profile-checkbox"]');
    checkboxes.forEach(cb => { cb.checked = false; });
    document.getElementById('st-stamp-image-base64').value = '';
    const container = document.getElementById('st-signature-preview-container');
    if (container) container.style.display = 'none';
    document.getElementById('staff-modal-title').innerText = "Registra Nuovo Operatore/Medico";
    document.getElementById('btn-staff-submit').innerText = "Registra Operatore";
    toggleDoctorFields('doctor'); // Default select is doctor
    openModal('modal-add-staff');
};

window.openEditStaffModal = function(staffId) {
    const staff = DB.get('staff');
    const doctors = DB.get('doctors');
    
    const st = staff.find(s => s.id === staffId);
    if (!st) return;

    document.getElementById('st-edit-id').value = st.id;
    document.getElementById('st-first-name').value = st.first_name;
    document.getElementById('st-reports-threshold').value = st.pending_reports_threshold !== undefined ? st.pending_reports_threshold : 5;
    document.getElementById('st-last-name').value = st.last_name;
    document.getElementById('st-email').value = st.email;
    document.getElementById('st-phone').value = st.phone || '';
    document.getElementById('st-role').value = st.role;
    document.getElementById('st-active').checked = st.active === 1;

    document.getElementById('st-username').value = st.username || '';
    document.getElementById('st-password').value = st.password || '';
    
    const profiles = st.profiles ? (typeof st.profiles === 'string' ? JSON.parse(st.profiles) : st.profiles) : [];
    const checkboxes = document.querySelectorAll('input[name="st-profile-checkbox"]');
    checkboxes.forEach(cb => {
        cb.checked = profiles.includes(cb.value);
    });

    toggleDoctorFields(st.role);

    document.getElementById('st-stamp-image-base64').value = '';
    const container = document.getElementById('st-signature-preview-container');
    if (container) container.style.display = 'none';

    if (st.role === 'doctor') {
        const doc = doctors.find(d => d.staff_id === st.id);
        if (doc) {
            document.getElementById('st-specialization').value = doc.specialization;
            document.getElementById('st-visit-duration').value = doc.visit_duration_minutes || 30;
            document.getElementById('st-stamp-text').value = doc.stamp_text || '';
            document.getElementById('st-enabled-validation').checked = (doc.enabled_for_validation === 1 || doc.enabled_for_validation === true);
            const signatureBase64 = doc.stamp_image || '';
            document.getElementById('st-stamp-image-base64').value = signatureBase64;
            const preview = document.getElementById('st-signature-preview');
            if (signatureBase64 && preview && container) {
                preview.src = signatureBase64;
                container.style.display = 'block';
            }
        }
    }

    document.getElementById('staff-modal-title').innerText = "Modifica Operatore Sanitario";
    document.getElementById('btn-staff-submit').innerText = "Salva Modifiche";
    openModal('modal-add-staff');
};

// --- 9C. DOCTOR AGENDA CRUD LOGIC ---
window.addAgendaTimeSlotRow = function(startVal = '08:00', endVal = '14:00') {
    const container = document.getElementById('agenda-time-slots-container');
    if (!container) return;

    const row = document.createElement('div');
    row.className = 'agenda-time-slot-row';
    row.style.display = 'flex';
    row.style.alignItems = 'center';
    row.style.gap = '10px';

    row.innerHTML = `
        <div style="flex: 1; display: flex; align-items: center; gap: 6px;">
            <span style="font-size: 0.75rem; color: var(--text-muted); font-weight: 600; min-width: 30px;">Da:</span>
            <input type="time" class="ag-slot-start" value="${startVal}" required style="width: 100%; padding: 4px 8px; border: 1px solid var(--border-color); border-radius: var(--radius-sm); font-size: 0.8rem; background: var(--bg-surface); color: var(--text-main);">
        </div>
        <div style="flex: 1; display: flex; align-items: center; gap: 6px;">
            <span style="font-size: 0.75rem; color: var(--text-muted); font-weight: 600; min-width: 30px;">A:</span>
            <input type="time" class="ag-slot-end" value="${endVal}" required style="width: 100%; padding: 4px 8px; border: 1px solid var(--border-color); border-radius: var(--radius-sm); font-size: 0.8rem; background: var(--bg-surface); color: var(--text-main);">
        </div>
        <button type="button" class="btn btn-danger btn-sm" onclick="this.parentElement.remove()" style="padding: 4px 8px; font-weight: bold; line-height: 1;" title="Rimuovi fascia">&times;</button>
    `;
    container.appendChild(row);
    if (window.lucide) window.lucide.createIcons();
};

window.openClosuresModal = function() {
    // Populate doctors checkboxes list in the closures form
    const staff = DB.get('staff') || [];
    const doctors = DB.get('doctors') || [];
    const docContainer = document.getElementById('cls-doctors-container');
    if (docContainer) {
        docContainer.innerHTML = '';
        doctors.forEach(d => {
            const st = staff.find(s => s.id === d.staff_id);
            if (st) {
                const prefix = st.first_name.endsWith('a') ? "Dott.ssa" : "Dott.";
                const div = document.createElement('div');
                div.style.display = 'flex';
                div.style.alignItems = 'center';
                div.style.gap = '8px';
                div.innerHTML = `
                    <input type="checkbox" name="cls-doctor-cb" value="${d.id}" id="cls-doc-cb-${d.id}" style="cursor: pointer;">
                    <label for="cls-doc-cb-${d.id}" style="font-size: 0.82rem; cursor: pointer; margin: 0; user-select: none;">${prefix} ${st.first_name} ${st.last_name} (${d.specialization})</label>
                `;
                docContainer.appendChild(div);
            }
        });
    }

    // Reset form fields
    const form = document.getElementById('form-add-closure');
    if (form) {
        form.reset();
        const stInput = document.getElementById('cls-start-time');
        const etInput = document.getElementById('cls-end-time');
        if (stInput) stInput.value = '';
        if (etInput) etInput.value = '';
        const docCheckboxes = document.getElementsByName('cls-doctor-cb');
        docCheckboxes.forEach(cb => cb.checked = false);
    }
    
    // Default to exceptional
    const typeSelect = document.getElementById('cls-type');
    if (typeSelect) typeSelect.value = 'exceptional';
    
    window.toggleClosureDoctorSelect();
    window.renderClosuresList();
    
    openModal('modal-closures-mgmt');
};

window.toggleClosureDoctorSelect = function() {
    const typeSelect = document.getElementById('cls-type');
    const doctorGroup = document.getElementById('grp-cls-doctor');
    if (typeSelect && doctorGroup) {
        if (typeSelect.value === 'fixed') {
            doctorGroup.style.display = 'none';
        } else {
            doctorGroup.style.display = 'block';
        }
    }
};

window.renderClosuresList = function() {
    const closures = DB.get('doctor_closures') || [];
    const tbody = document.getElementById('closures-tbody');
    const badgeCount = document.getElementById('cls-count-badge');
    
    if (badgeCount) {
        badgeCount.innerText = `${closures.length} registrate`;
    }
    
    if (!tbody) return;
    
    if (closures.length === 0) {
        tbody.innerHTML = '<tr><td colspan="4" class="text-muted text-center" style="padding: 15px; font-style: italic;">Nessuna chiusura o assenza programmata registrata.</td></tr>';
        return;
    }
    
    // Sort closures by start_date ascending
    const sorted = [...closures].sort((a, b) => new Date(a.start_date) - new Date(b.start_date));
    
    const staff = DB.get('staff') || [];
    const doctors = DB.get('doctors') || [];
    
    tbody.innerHTML = '';
    sorted.forEach(c => {
        let typeBadge = '';
        let resourceName = '';
        
        if (c.closure_type === 'exceptional') {
            typeBadge = '<span class="badge" style="background-color: var(--warning); color: #fff; padding: 2px 6px; border-radius: 4px; font-size: 0.7rem;">Ferie Medico</span>';
            const doc = doctors.find(d => d.id === parseInt(c.doctor_id));
            const st = doc ? staff.find(s => s.id === doc.staff_id) : null;
            if (st) {
                resourceName = `Dott. ${st.last_name} ${st.first_name}`;
            } else {
                resourceName = `Medico ID ${c.doctor_id}`;
            }
        } else {
            typeBadge = '<span class="badge" style="background-color: var(--primary); color: #fff; padding: 2px 6px; border-radius: 4px; font-size: 0.7rem;">Tutto il Centro</span>';
            resourceName = 'Intero Centro';
        }
        
        // Format dates
        const formatDate = (dStr) => {
            if (!dStr) return '';
            const parts = dStr.split('-');
            return `${parts[2]}/${parts[1]}/${parts[0]}`;
        };
        
        let periodStr = '';
        if (c.start_date === c.end_date) {
            periodStr = formatDate(c.start_date);
        } else {
            periodStr = `${formatDate(c.start_date)} al ${formatDate(c.end_date)}`;
        }
        
        if (c.start_time && c.end_time) {
            periodStr += ` (${c.start_time} - ${c.end_time})`;
        }
        
        const tr = document.createElement('tr');
        tr.innerHTML = `
            <td>
                <div style="display: flex; flex-direction: column; gap: 4px;">
                    <div>${typeBadge}</div>
                    <div style="font-weight: 600;">${resourceName}</div>
                </div>
            </td>
            <td style="vertical-align: middle;">${periodStr}</td>
            <td style="vertical-align: middle; max-width: 200px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;" title="${c.description}">${c.description}</td>
            <td style="text-align: center; vertical-align: middle;">
                <button type="button" class="btn btn-sm" onclick="window.deleteClosure(${c.id})" style="background-color: var(--danger); border-color: var(--danger); color: white; padding: 4px 8px; cursor: pointer;" title="Elimina Chiusura">
                    <i data-lucide="trash-2" style="width: 14px; height: 14px;"></i>
                </button>
            </td>
        `;
        tbody.appendChild(tr);
    });
    
    if (window.lucide) window.lucide.createIcons();
};

window.saveNewClosure = function(event) {
    if (event) event.preventDefault();
    
    const type = document.getElementById('cls-type').value;
    const start_date = document.getElementById('cls-start-date').value;
    const end_date = document.getElementById('cls-end-date').value;
    const start_time = document.getElementById('cls-start-time').value || null;
    const end_time = document.getElementById('cls-end-time').value || null;
    const description = document.getElementById('cls-desc').value.trim();
    
    if (!start_date || !end_date || !description) {
        alert("Si prega di compilare tutti i campi obbligatori.");
        return;
    }
    
    if (new Date(start_date) > new Date(end_date)) {
        alert("La data di inizio non può essere successiva alla data di fine.");
        return;
    }
    
    if ((start_time && !end_time) || (!start_time && end_time)) {
        alert("Se specifichi un orario, devi inserire sia l'ora di inizio che l'ora di fine.");
        return;
    }
    
    if (start_time && end_time && start_time >= end_time) {
        alert("L'ora di inizio deve essere precedente all'ora di fine.");
        return;
    }
    
    const loggedUser = JSON.parse(localStorage.getItem('nextcare_logged_in_user') || '{}');
    const staffId = loggedUser.id || 7;
    
    if (type === 'fixed') {
        const newCls = {
            doctor_id: null,
            start_date: start_date,
            end_date: end_date,
            start_time: start_time,
            end_time: end_time,
            description: description,
            closure_type: type
        };
        const saved = DB.insert('doctor_closures', newCls);
        DB.logAudit(staffId, "ADD_DOCTOR_CLOSURE", "doctor_closures", saved.id, newCls);
    } else {
        const checkedCbs = Array.from(document.getElementsByName('cls-doctor-cb')).filter(cb => cb.checked);
        if (checkedCbs.length === 0) {
            alert("Seleziona almeno un medico per la chiusura eccezionale.");
            return;
        }
        
        checkedCbs.forEach(cb => {
            const docId = parseInt(cb.value);
            const newCls = {
                doctor_id: docId,
                start_date: start_date,
                end_date: end_date,
                start_time: start_time,
                end_time: end_time,
                description: description,
                closure_type: type
            };
            const saved = DB.insert('doctor_closures', newCls);
            DB.logAudit(staffId, "ADD_DOCTOR_CLOSURE", "doctor_closures", saved.id, newCls);
        });
    }
    
    alert("Chiusura/Assenza registrata con successo!");
    
    // Reset form fields
    const form = document.getElementById('form-add-closure');
    if (form) {
        form.reset();
        document.getElementById('cls-type').value = type;
        const stInput = document.getElementById('cls-start-time');
        const etInput = document.getElementById('cls-end-time');
        if (stInput) stInput.value = '';
        if (etInput) etInput.value = '';
        const docCheckboxes = document.getElementsByName('cls-doctor-cb');
        docCheckboxes.forEach(cb => cb.checked = false);
        window.toggleClosureDoctorSelect();
    }
    
    window.renderClosuresList();
};

window.deleteClosure = function(id) {
    if (!confirm("Sei sicuro di voler eliminare questa chiusura? La risorsa tornerà disponibile per le prenotazioni.")) {
        return;
    }
    
    const loggedUser = JSON.parse(localStorage.getItem('nextcare_logged_in_user') || '{}');
    const staffId = loggedUser.id || 7;
    
    DB.delete('doctor_closures', id);
    DB.logAudit(staffId, "DELETE_DOCTOR_CLOSURE", "doctor_closures", id, {});
    
    window.renderClosuresList();
    alert("Chiusura eliminata con successo!");
};

window.initializeItalianHolidays = function() {
    if (!confirm("Confermi l'inizializzazione delle festività nazionali italiane? Saranno aggiunte tutte le festività fisse per l'anno corrente e il successivo.")) {
        return;
    }
    
    const currentYear = new Date().getFullYear();
    const years = [currentYear, currentYear + 1];
    
    const closures = DB.get('doctor_closures') || [];
    let addedCount = 0;
    
    years.forEach(year => {
        // Define fixed holidays
        const holidays = [
            { date: `${year}-01-01`, desc: "Capodanno" },
            { date: `${year}-01-06`, desc: "Epifania" },
            { date: `${year}-04-25`, desc: "Festa della Liberazione" },
            { date: `${year}-05-01`, desc: "Festa del Lavoro" },
            { date: `${year}-06-02`, desc: "Festa della Repubblica" },
            { date: `${year}-08-15`, desc: "Ferragosto" },
            { date: `${year}-11-01`, desc: "Tutti i Santi" },
            { date: `${year}-12-08`, desc: "Immacolata Concezione" },
            { date: `${year}-12-25`, desc: "Natale" },
            { date: `${year}-12-26`, desc: "Santo Stefano" }
        ];
        
        // Calculate Easter and Easter Monday
        const easter = window.getEasterDate(year);
        const yyyy = easter.getFullYear();
        const mm = String(easter.getMonth() + 1).padStart(2, '0');
        const dd = String(easter.getDate()).padStart(2, '0');
        const easterStr = `${yyyy}-${mm}-${dd}`;
        holidays.push({ date: easterStr, desc: "Pasqua" });
        
        const em = new Date(easter.getTime() + 24 * 60 * 60 * 1000);
        const emYyyy = em.getFullYear();
        const emMm = String(em.getMonth() + 1).padStart(2, '0');
        const emDd = String(em.getDate()).padStart(2, '0');
        const emStr = `${emYyyy}-${emMm}-${emDd}`;
        holidays.push({ date: emStr, desc: "Lunedì dell'Angelo (Pasquetta)" });
        
        holidays.forEach(h => {
            // Check if already exists in DB
            const exists = closures.some(c => c.closure_type === 'fixed' && c.doctor_id === null && c.start_date === h.date);
            if (!exists) {
                const newCls = {
                    doctor_id: null,
                    start_date: h.date,
                    end_date: h.date,
                    description: h.desc,
                    closure_type: 'fixed'
                };
                DB.insert('doctor_closures', newCls);
                addedCount++;
            }
        });
    });
    
    const loggedUser = JSON.parse(localStorage.getItem('nextcare_logged_in_user') || '{}');
    const staffId = loggedUser.id || 7;
    DB.logAudit(staffId, "INIT_ITALIAN_HOLIDAYS", "doctor_closures", null, { count: addedCount });
    
    window.renderClosuresList();
    alert(`Inizializzazione completata! Aggiunte ${addedCount} festività nazionali.`);
};

window.handleAgendaTypeChange = function(type) {
    const docGroup = document.getElementById('ag-doctor-group');
    const nameGroup = document.getElementById('ag-name-group');
    const repGroup = document.getElementById('ag-reporting-doctors-group');
    
    const docSelect = document.getElementById('ag-doctor');
    const nameInput = document.getElementById('ag-name');
    
    if (type === 'generic') {
        if (docGroup) {
            docGroup.style.display = 'none';
            docGroup.classList.add('hidden');
        }
        if (docSelect) docSelect.removeAttribute('required');
        
        if (nameGroup) {
            nameGroup.style.display = 'block';
            nameGroup.classList.remove('hidden');
        }
        if (nameInput) nameInput.setAttribute('required', 'required');
        
        if (repGroup) {
            repGroup.style.display = 'block';
            repGroup.classList.remove('hidden');
            
            // Populate checkboxes
            const staff = DB.get('staff') || [];
            const doctorsList = DB.get('doctors') || [];
            const checkboxesContainer = document.getElementById('ag-reporting-doctors-checkboxes');
            if (checkboxesContainer) {
                checkboxesContainer.innerHTML = doctorsList.filter(d => d.active === 1).map(d => {
                    const st = staff.find(s => s.id === d.staff_id);
                    if (!st) return '';
                    return `
                        <label style="display: flex; align-items: center; gap: 8px; font-size: 0.85rem; color: var(--text-main); cursor: pointer;">
                            <input type="checkbox" name="ag-reporting-doctors" value="${d.id}">
                            <span>Dott. ${st.last_name} ${st.first_name}</span>
                        </label>
                    `;
                }).join('') || '<p style="font-size:0.8rem;color:var(--text-muted);margin:0;">Nessun medico trovato</p>';
            }
        }
    } else {
        if (docGroup) {
            docGroup.style.display = 'block';
            docGroup.classList.remove('hidden');
        }
        if (docSelect) docSelect.setAttribute('required', 'required');
        
        if (nameGroup) {
            nameGroup.style.display = 'none';
            nameGroup.classList.add('hidden');
        }
        if (nameInput) nameInput.removeAttribute('required');
        
        if (repGroup) {
            repGroup.style.display = 'none';
            repGroup.classList.add('hidden');
        }
    }
};

window.openAddAgendaModal = function() {
    document.getElementById('ag-edit-id').value = '';
    document.getElementById('form-add-agenda').reset();
    document.getElementById('agenda-modal-title').innerText = "Pianifica Nuova Agenda Medico";
    document.getElementById('btn-agenda-submit').innerText = "Associa Agenda";
    
    // Reset agenda type to doctor
    const typeSelect = document.getElementById('ag-type');
    if (typeSelect) {
        typeSelect.value = 'doctor';
        window.handleAgendaTypeChange('doctor');
    }
    
    // Clear search and tags
    const searchInput = document.getElementById('ag-search-service');
    if (searchInput) searchInput.value = '';
    const resultsDropdown = document.getElementById('ag-search-services-results');
    if (resultsDropdown) resultsDropdown.classList.add('hidden');
    selectedAgendaServiceIds = [];
    renderSelectedAgendaTags();

    // Reset and initialize dynamic time slots container
    const container = document.getElementById('agenda-time-slots-container');
    if (container) {
        container.innerHTML = '';
        window.addAgendaTimeSlotRow('08:00', '14:00');
    }

    // Populate doctors select
    const staff = DB.get('staff');
    const doctors = DB.get('doctors');
    const docSelect = document.getElementById('ag-doctor');
    docSelect.innerHTML = '<option value="">-- Seleziona Medico Specialist --</option>';
    doctors.forEach(d => {
        const st = staff.find(s => s.id === d.staff_id);
        if (st) {
            docSelect.innerHTML += `<option value="${d.id}">Dott. ${st.last_name} ${st.first_name} (${d.specialization})</option>`;
        }
    });

    // Populate branches select for bulk adding
    const branchBulkSelect = document.getElementById('ag-branch-bulk');
    if (branchBulkSelect) {
        branchBulkSelect.innerHTML = '<option value="">-- Seleziona Branca --</option>';
        const medicalServices = DB.get('medical_services') || [];
        const docServices = medicalServices.filter(s => s.type === 'visita' || s.type === 'ris');
        const uniqueBranches = [...new Set(docServices.map(s => s.branch).filter(Boolean))];
        uniqueBranches.sort().forEach(b => {
            branchBulkSelect.innerHTML += `<option value="${b}">${b}</option>`;
        });
    }

    openModal('modal-add-agenda');
};

window.openEditAgendaModal = function(agendaId) {
    const agendas = DB.get('doctor_agendas') || [];
    const agendaServices = DB.get('doctor_agenda_services') || [];
    const ag = agendas.find(a => a.id === agendaId);
    if (!ag) return;

    openAddAgendaModal(); // Sets up doctor list, resets form, clears search/tags, and initializes time slots

    document.getElementById('ag-edit-id').value = ag.id;
    
    // Set type and populate values
    const typeSelect = document.getElementById('ag-type');
    if (typeSelect) {
        const isGeneric = (ag.doctor_id === null || !ag.doctor_id);
        typeSelect.value = isGeneric ? 'generic' : 'doctor';
        window.handleAgendaTypeChange(typeSelect.value);
        
        if (isGeneric) {
            document.getElementById('ag-name').value = ag.name || '';
            let checkedIds = [];
            if (ag.reporting_doctor_ids) {
                try {
                    checkedIds = typeof ag.reporting_doctor_ids === 'string' ? JSON.parse(ag.reporting_doctor_ids) : ag.reporting_doctor_ids;
                } catch(e) {
                    checkedIds = [];
                }
            }
            const checkboxes = document.querySelectorAll('input[name="ag-reporting-doctors"]');
            checkboxes.forEach(cb => {
                cb.checked = checkedIds.includes(parseInt(cb.value)) || checkedIds.includes(cb.value.toString());
            });
        } else {
            document.getElementById('ag-doctor').value = ag.doctor_id || '';
        }
    }
    
    document.getElementById('ag-start-date').value = ag.start_date;
    document.getElementById('ag-end-date').value = ag.end_date;
    document.getElementById('ag-description').value = ag.description || '';
    document.getElementById('ag-slot-duration').value = ag.slot_duration_minutes;
    document.getElementById('ag-start-hour').value = ag.start_hour || '08:00';
    document.getElementById('ag-end-hour').value = ag.end_hour || '14:00';

    // Populate dynamic time slots container with saved values
    const container = document.getElementById('agenda-time-slots-container');
    if (container) {
        container.innerHTML = '';
        let parsedTimeSlots = ag.time_slots;
        if (typeof parsedTimeSlots === 'string') {
            try { parsedTimeSlots = JSON.parse(parsedTimeSlots); } catch(e) { parsedTimeSlots = []; }
        }
        if (parsedTimeSlots && parsedTimeSlots.length > 0) {
            parsedTimeSlots.forEach(slot => {
                window.addAgendaTimeSlotRow(slot.start, slot.end);
            });
        } else {
            window.addAgendaTimeSlotRow(ag.start_hour || '08:00', ag.end_hour || '14:00');
        }
    }

    // Check weekdays
    const activeDays = ag.active_days.split(',');
    const dayCheckboxes = document.querySelectorAll('input[name="ag-days"]');
    dayCheckboxes.forEach(cb => {
        cb.checked = activeDays.includes(cb.value);
    });

    // Populate selected services tags
    selectedAgendaServiceIds = agendaServices.filter(as => as.agenda_id === ag.id).map(as => as.service_id);
    renderSelectedAgendaTags();

    document.getElementById('agenda-modal-title').innerText = "Modifica Agenda Operativa";
    document.getElementById('btn-agenda-submit').innerText = "Salva Modifiche";
    openModal('modal-add-agenda');
};

// --- 10. MOCK DICOM CANVAS VIEWER ---
let dicomBrightness = 100;
let dicomContrast = 100;
let currentDicomImage = 'brain';

function initDicomControls() {
    const brightSlider = document.getElementById('dicom-brightness');
    const contrastSlider = document.getElementById('dicom-contrast');
    const resetBtn = document.getElementById('btn-dicom-reset');
    if (!brightSlider || !contrastSlider || !resetBtn) return;
    
    brightSlider.addEventListener('input', (e) => {
        dicomBrightness = e.target.value; drawDicomImage();
    });
    contrastSlider.addEventListener('input', (e) => {
        dicomContrast = e.target.value; drawDicomImage();
    });
    resetBtn.addEventListener('click', () => {
        brightSlider.value = 100; contrastSlider.value = 100;
        dicomBrightness = 100; dicomContrast = 100;
        drawDicomImage();
    });
}

window.openDicomViewer = function(studyId, isEdit = false) {
    const studies = DB.get('radiology_studies');
    const patients = DB.get('patients');
    const staff = DB.get('staff');
    const services = DB.get('medical_services');
    
    const study = studies.find(s => s.id === studyId);
    const p = patients.find(pat => pat.id === study.patient_id);
    const srv = services.find(sv => sv.id === study.service_id);
    
    document.getElementById('dicom-study-id').value = studyId;
    document.getElementById('dicom-pat-id').innerText = p.uuid.substring(0,8).toUpperCase();
    document.getElementById('dicom-pat-name').innerText = `${p.last_name.toUpperCase()} ${p.first_name.toUpperCase()}`;
    document.getElementById('dicom-study-type').innerText = srv ? srv.name : study.study_type;
    
    const isVisit = study.study_type === 'VISIT';
    const layout = document.querySelector('.dicom-layout');
    if (isVisit) {
        layout.classList.add('no-viewer');
        document.getElementById('dicom-modal-title').innerText = "NextCare Refertazione Visita Specialistica";
        document.getElementById('dicom-radiologist-label').innerText = "Specialista Refertatore *";
        document.getElementById('dicom-report-label').innerText = "Referto Visita Specialistica (WYSIWYG) *";
        document.getElementById('dicom-report-editor').setAttribute('placeholder', "Scrivi qui il referto della visita specialistica...");
    } else {
        layout.classList.remove('no-viewer');
        document.getElementById('dicom-modal-title').innerText = "NextCare WebDICOM Viewer & Reporting Specialistico";
        document.getElementById('dicom-radiologist-label').innerText = "Radiologo Refertatore *";
        document.getElementById('dicom-report-label').innerText = "Referto Radiologico Clinico (WYSIWYG) *";
        document.getElementById('dicom-report-editor').setAttribute('placeholder', "Scrivi qui il referto radiologico dell'esame eseguito...");
    }

    const radSelect = document.getElementById('dicom-radiologist');
    radSelect.innerHTML = isVisit ? '<option value="">-- Seleziona Medico --</option>' : '<option value="">-- Seleziona Radiologo --</option>';
    staff.filter(s => s.role === 'doctor').forEach(st => {
        radSelect.innerHTML += `<option value="${st.id}">Dott. ${st.last_name}</option>`;
    });
    
    currentDicomImage = study.study_type === 'MRI' ? 'brain' : (study.study_type === 'XRAY' ? 'chest' : 'knee');
    
    const reportEditor = document.getElementById('dicom-report-editor');
    const toolbar = document.getElementById('ris-editor-toolbar');
    const submitBtn = document.getElementById('btn-dicom-report-submit');
    
    // Load current study's clinical query & attachment callout
    const queryContainer = document.getElementById('dicom-clinical-query-container');
    const queryTextEl = document.getElementById('dicom-clinical-query-text');
    const queryAttachEl = document.getElementById('dicom-clinical-query-attachment');
    const attachLabel = document.getElementById('lbl-dicom-attachment-name');
    
    if (queryContainer) {
        if (study.clinical_query || study.attachment_name) {
            queryContainer.style.display = 'block';
            queryTextEl.innerHTML = study.clinical_query || '<i>Nessun quesito diagnostico digitato.</i>';
            if (study.attachment_name) {
                queryAttachEl.style.display = 'block';
                attachLabel.innerText = study.attachment_name;
            } else {
                queryAttachEl.style.display = 'none';
            }
        } else {
            queryContainer.style.display = 'none';
        }
    }
    
    const disableFields = (study.status === 'completed' && !isEdit);
    
    if (disableFields) {
        reportEditor.innerHTML = study.report_text;
        reportEditor.contentEditable = "false";
        radSelect.value = study.signed_by;
        radSelect.disabled = true;
        toolbar.style.display = "none";
        submitBtn.style.display = 'none';
    } else {
        reportEditor.innerHTML = study.report_text || (study.clinical_query ? '<h3>REFERTO CLINICO</h3><p><b>Quesito clinico:</b> ' + study.clinical_query + '</p><p>Esame eseguito...</p>' : '');
        reportEditor.contentEditable = "true";
        radSelect.value = study.signed_by || '';
        radSelect.disabled = false;
        toolbar.style.display = "flex";
        submitBtn.style.display = 'block';
        submitBtn.innerText = study.status === 'completed' ? "Salva Modifiche" : "Firma Digitale & Archivia";
    }

    // Load patient clinical history sidebar (RIS and Visite)
    const historyList = document.getElementById('ris-history-list');
    if (historyList) {
        historyList.innerHTML = '';
        const patientPast = studies.filter(s => s.patient_id === study.patient_id && s.status === 'completed' && s.id !== studyId);
        
        if (patientPast.length === 0) {
            historyList.innerHTML = '<span class="text-muted" style="font-size:0.75rem;">Nessun referto storico presente.</span>';
        } else {
            patientPast.forEach(s => {
                const srvObj = services.find(sv => sv.id === s.service_id);
                const sName = srvObj ? srvObj.name : s.study_type;
                const sDate = new Date(s.scheduled_at).toLocaleDateString('it-IT');
                const reporter = staff.find(st => st.id === s.signed_by);
                const rName = reporter ? `Dott. ${reporter.last_name}` : 'Specialista';
                
                const div = document.createElement('div');
                div.style.background = 'var(--bg-surface)';
                div.style.border = '1px solid var(--border-color)';
                div.style.borderRadius = 'var(--radius-sm)';
                div.style.padding = '8px';
                div.style.fontSize = '0.8rem';
                div.style.marginBottom = '6px';
                
                const queryHtml = s.clinical_query 
                    ? `<div style="margin-bottom: 8px; padding: 6px 8px; background: #f1f5f9; border-radius: 4px; font-style: italic; color: #475569; font-size: 0.75rem;"><b>Quesito:</b> ${s.clinical_query}</div>` 
                    : '';
                const attachmentHtml = s.attachment_name 
                    ? `<div style="margin-top: 6px; border-top: 1px dashed var(--border-color); padding-top: 6px;"><a href="#" onclick="window.downloadPastStudyAttachment(event, ${s.id})" style="color: #2563eb; font-weight: 600; text-decoration: underline; display: inline-flex; align-items: center; gap: 4px; font-size: 0.75rem;"><i data-lucide="download" style="width: 10px; height: 10px;"></i> Vedi Allegato: ${s.attachment_name}</a></div>` 
                    : '';
                
                div.innerHTML = `\n                    <div style="display:flex; justify-content:space-between; align-items:center; cursor:pointer;" onclick="this.nextElementSibling.style.display = this.nextElementSibling.style.display === 'none' ? 'block' : 'none'">\n                        <div>\n                            <strong>${sName}</strong><br>\n                            <span style="font-size:0.7rem; color:var(--text-secondary);">${sDate} - ${rName}</span>\n                        </div>\n                        <i data-lucide="chevron-down" style="width:14px; height:14px; color:var(--text-secondary);"></i>\n                    </div>\n                    <div style="display:none; margin-top:8px; border-top:1px dashed var(--border-color); padding-top:6px; font-size:0.75rem; color:var(--text-main); max-height:150px; overflow-y:auto;">\n                        ${queryHtml}\n                        ${s.report_text || 'Referto vuoto'}\n                        ${attachmentHtml}\n                    </div>\n                `;
                historyList.appendChild(div);
            });
            if (window.lucide) window.lucide.createIcons();
        }
    }
    
    // Dose Value / mSv support
    const doseGroup = document.getElementById('dicom-dose-value')?.closest('.form-group');
    if (doseGroup) {
        doseGroup.style.display = isVisit ? 'none' : 'block';
    }
    const doseInput = document.getElementById('dicom-dose-value');
    const doseIndicator = document.getElementById('dicom-dose-class-indicator');
    if (doseInput && doseIndicator) {
        const updateIndicator = () => {
            const val = parseFloat(doseInput.value);
            if (isNaN(val) || val === null || doseInput.value === '') {
                doseIndicator.innerText = '';
                return;
            }
            let text = '';
            if (val === 0) text = "Corrisponde a: Classe 0 (0 mSv) - Ecografia, Risonanza Magnetica (senza radiazioni)";
            else if (val < 1) text = "Corrisponde a: Classe I (< 1 mSv) - RX Torace, RX arti";
            else if (val < 5) text = "Corrisponde a: Classe II (1 - 5 mSv) - RX addome, TC cranio";
            else if (val <= 10) text = "Corrisponde a: Classe III (5 - 10 mSv) - TC torace, TC addome";
            else text = "Corrisponde a: Classe IV (> 10 mSv) - Procedure interventistiche, TC addome-bacino";
            doseIndicator.innerText = text;
        };
        
        // Remove existing listener to avoid duplication
        const newDoseInput = doseInput.cloneNode(true);
        doseInput.parentNode.replaceChild(newDoseInput, doseInput);
        
        newDoseInput.addEventListener('input', updateIndicator);
        
        newDoseInput.value = (study.dose_value_msv !== undefined && study.dose_value_msv !== null) ? study.dose_value_msv : '';
        updateIndicator();

        if (disableFields) {
            newDoseInput.disabled = true;
        } else {
            newDoseInput.disabled = false;
        }
    }
    
    openModal('modal-dicom-viewer');
    if (!isVisit) {
        setTimeout(drawDicomImage, 100);
    }
};

window.downloadStudyAttachment = function(event) {
    event.preventDefault();
    const studyId = parseInt(document.getElementById('dicom-study-id').value);
    const studies = DB.get('radiology_studies') || [];
    const study = studies.find(s => s.id === studyId);
    if (!study || !study.attachment_data) {
        alert("Allegato non trovato per questo studio.");
        return;
    }
    const link = document.createElement('a');
    link.href = study.attachment_data;
    link.download = study.attachment_name;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
};

window.downloadPastStudyAttachment = function(event, studyId) {
    event.preventDefault();
    const studies = DB.get('radiology_studies') || [];
    const study = studies.find(s => s.id === studyId);
    if (!study || !study.attachment_data) {
        alert("Allegato storico non trovato.");
        return;
    }
    const link = document.createElement('a');
    link.href = study.attachment_data;
    link.download = study.attachment_name;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
};

function drawDicomImage() {
    const canvas = document.getElementById('dicom-canvas');
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    
    ctx.fillStyle = '#000000';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    ctx.filter = `brightness(${dicomBrightness}%) contrast(${dicomContrast}%)`;
    
    if (currentDicomImage === 'brain') {
        ctx.strokeStyle = '#cccccc'; ctx.lineWidth = 14; ctx.beginPath(); ctx.arc(225, 200, 120, 0, Math.PI * 2); ctx.stroke();
        ctx.fillStyle = '#555555'; ctx.beginPath(); ctx.arc(225, 200, 105, 0, Math.PI * 2); ctx.fill();
        ctx.strokeStyle = '#999999'; ctx.lineWidth = 4;
        for (let i = 0; i < 8; i++) {
            const angle = (Math.PI / 4) * i;
            ctx.beginPath(); ctx.moveTo(225, 200);
            ctx.quadraticCurveTo(225 + Math.cos(angle + 0.2) * 60, 200 + Math.sin(angle + 0.2) * 60, 225 + Math.cos(angle) * 100, 200 + Math.sin(angle) * 100);
            ctx.stroke();
        }
        ctx.fillStyle = '#111111'; ctx.beginPath();
        ctx.ellipse(200, 190, 18, 30, Math.PI / 6, 0, Math.PI * 2);
        ctx.ellipse(250, 190, 18, 30, -Math.PI / 6, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = '#666666'; ctx.fillRect(215, 300, 20, 80);
    } else if (currentDicomImage === 'chest') {
        ctx.fillStyle = '#888888'; ctx.fillRect(220, 50, 10, 300);
        ctx.strokeStyle = '#bbbbbb'; ctx.lineWidth = 6;
        for (let i = 0; i < 6; i++) {
            const y = 100 + i * 40;
            ctx.beginPath(); ctx.arc(150, y, 60, Math.PI * 1.5, Math.PI * 0.4); ctx.stroke();
            ctx.beginPath(); ctx.arc(300, y, 60, Math.PI * 0.6, Math.PI * 1.5); ctx.stroke();
        }
        ctx.fillStyle = '#222222'; ctx.beginPath();
        ctx.ellipse(150, 180, 50, 90, 0, 0, Math.PI * 2);
        ctx.ellipse(300, 180, 50, 90, 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = '#666666'; ctx.beginPath(); ctx.ellipse(210, 240, 45, 30, Math.PI / 8, 0, Math.PI * 2); ctx.fill();
        ctx.fillStyle = '#999999'; ctx.beginPath(); ctx.arc(140, 310, 80, Math.PI, 0); ctx.arc(310, 310, 80, Math.PI, 0); ctx.fill();
    } else {
        ctx.fillStyle = '#dddddd'; ctx.fillRect(190, 40, 70, 150); ctx.beginPath(); ctx.arc(225, 190, 40, 0, Math.PI); ctx.fill();
        ctx.fillStyle = '#dddddd'; ctx.fillRect(195, 230, 60, 140); ctx.beginPath(); ctx.arc(225, 230, 35, Math.PI, 0); ctx.fill();
        ctx.fillStyle = '#111111'; ctx.fillRect(180, 195, 90, 30);
        ctx.fillStyle = '#cccccc'; ctx.beginPath(); ctx.ellipse(140, 205, 15, 25, 0, 0, Math.PI * 2); ctx.fill();
    }
    ctx.filter = 'none';
}

// --- 11. PATIENT DETAIL & HISTORY ---
window.openPatientDetail = function(patientId) {
    const patients = DB.get('patients');
    const consents = DB.get('patient_consents');
    
    const p = patients.find(pat => pat.id === patientId);
    const c = consents.find(con => con.patient_id === patientId) || { marketing_consent: 0, profiling_consent: 0 };
    
    document.getElementById('det-name').innerText = `${p.last_name} ${p.first_name}`;
    document.getElementById('det-taxcode').innerText = `CF: ${p.tax_code}`;
    document.getElementById('det-birthdate').innerText = new Date(p.birth_date).toLocaleDateString('it-IT');
    document.getElementById('det-gender').innerText = p.gender;
    document.getElementById('det-phone').innerText = p.phone || '-';
    document.getElementById('det-email').innerText = p.email || '-';
    document.getElementById('det-address').innerText = p.address || '-';
    
    const mDot = document.getElementById('det-consent-marketing-dot');
    const mLabel = document.getElementById('det-consent-marketing-label');
    if (c.marketing_consent) { mDot.classList.add('active'); mLabel.innerText = 'SI'; }
    else { mDot.classList.remove('active'); mLabel.innerText = 'NO'; }
    
    const pDot = document.getElementById('det-consent-profiling-dot');
    const pLabel = document.getElementById('det-consent-profiling-label');
    if (c.profiling_consent) { pDot.classList.add('active'); pLabel.innerText = 'SI'; }
    else { pDot.classList.remove('active'); pLabel.innerText = 'NO'; }
    
    buildPatientTimeline(patientId);
    buildPatientAuditLogs(patientId);
    
    DB.logAudit(6, "VIEW_DETAILS", "patients", patientId, { reason: "Consultazione clinica" });
    openModal('modal-patient-detail');
};

window.switchPatientSubTab = function(tabName) {
    currentSubTab = tabName;
    const btns = document.querySelectorAll('.tab-sub-btn');
    btns.forEach(b => b.classList.remove('active'));
    
    const contents = document.querySelectorAll('.subtab-content');
    contents.forEach(c => c.classList.remove('active'));
    
    if (tabName === 'history') {
        btns[0].classList.add('active');
        document.getElementById('subtab-history').classList.add('active');
    } else {
        btns[1].classList.add('active');
        document.getElementById('subtab-logs').classList.add('active');
    }
};

function buildPatientTimeline(patientId) {
    const appointments = DB.get('appointments').filter(a => a.patient_id === patientId);
    const samples = DB.get('lab_samples').filter(s => s.patient_id === patientId);
    const studies = DB.get('radiology_studies').filter(s => s.patient_id === patientId);
    const admissions = DB.get('admissions').filter(a => a.patient_id === patientId);
    const services = DB.get('medical_services');
    
    const timeline = document.getElementById('clinical-timeline');
    timeline.innerHTML = '';
    const events = [];
    
    appointments.forEach(a => {
        events.push({
            date: new Date(a.appointment_datetime),
            type: 'cup',
            title: `CUP - Prenotazione`,
            desc: `Stato: ${a.status.toUpperCase()} | Note: ${a.notes || 'Nessuna'}`
        });
    });
    
    samples.forEach(s => {
        const tests = DB.get('lab_tests').filter(t => t.sample_id === s.id);
        const testRes = tests.map(t => {
            const srv = services.find(sv => sv.id === t.service_id);
            return `${srv ? srv.name : t.test_name}: ${t.result_value || 'In attesa'} ${t.unit || ''}`;
        }).join(', ');
        
        events.push({
            date: new Date(s.collected_at || s.created_at),
            type: 'lis',
            title: `Prelievo LIS - Campione (${s.sample_type})`,
            desc: `Barcode: ${s.barcode} | Stato: ${s.status.toUpperCase()} | Analisi: ${testRes} ${s.report_notes ? `<br><div style="margin-top:6px; border-left: 2px solid var(--purple); padding-left:8px; background:var(--bg-surface); padding:8px; border-radius:4px;" class="text-secondary">${s.report_notes}</div>` : ''}`
        });
    });
    
    studies.forEach(st => {
        const srv = services.find(s => s.id === st.service_id);
        events.push({
            date: new Date(st.scheduled_at),
            type: 'ris',
            title: `RIS - Esame Radiologico (${srv ? srv.name : st.study_type})`,
            desc: `Stato: ${st.status.toUpperCase()} ${st.report_text ? `<br><div style="margin-top:6px; border-left: 2px solid var(--success); padding-left:8px; background:var(--bg-surface); padding:8px; border-radius:4px;" class="text-secondary">${st.report_text}</div>` : ' | In attesa di referto'}`
        });
    });
    
    admissions.forEach(adm => {
        events.push({
            date: new Date(adm.admission_date),
            type: 'admission',
            title: `Ingresso e Ricovero (${adm.department})`,
            desc: `Diagnosi di Ingresso: ${adm.reason} | Stato degenza: ${adm.status.toUpperCase()}`
        });
        if (adm.discharge_date) {
            events.push({
                date: new Date(adm.discharge_date),
                type: 'admission',
                title: `Dimissione Ospedaliera (${adm.department})`,
                desc: `Paziente dimesso regolarmente.`
            });
        }
    });
    
    events.sort((a,b) => b.date - a.date);
    
    if (events.length === 0) {
        timeline.innerHTML = '<p class="text-muted" style="font-size: 0.85rem;">Nessun evento clinico registrato.</p>';
        return;
    }
    
    events.forEach(ev => {
        const dateStr = ev.date.toLocaleString('it-IT', { day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' });
        timeline.innerHTML += `\n            <div class="timeline-item ${ev.type}">\n                <div class="timeline-dot"></div>\n                <div class="timeline-date">${dateStr}</div>\n                <div class="timeline-content">\n                    <h4>${ev.title}</h4>\n                    <div>${ev.desc}</div>\n                </div>\n            </div>\n        `;
    });
}

function buildPatientAuditLogs(patientId) {
    const logs = DB.get('audit_logs');
    const staff = DB.get('staff');
    const container = document.getElementById('audit-log-container');
    container.innerHTML = '';
    
    const filteredLogs = logs.filter(log => {
        if (log.table_name === 'patients' && log.record_id === patientId) return true;
        if (log.table_name === 'patient_consents' && log.record_id === patientId) return true;
        if (log.details && log.details.patient_id === patientId) return true;
        return false;
    });
    
    filteredLogs.sort((a,b) => new Date(b.created_at) - new Date(a.created_at));
    
    if (filteredLogs.length === 0) {
        container.innerHTML = '<p class="text-muted" style="font-size: 0.85rem;">Nessun log di accesso.</p>';
        return;
    }
    
    filteredLogs.forEach(log => {
        const st = staff.find(s => s.id === log.staff_id) || { last_name: "Sistema", role: "admin" };
        const timeStr = new Date(log.created_at).toLocaleString('it-IT');
        
        let actionDesc = log.action === 'VIEW_DETAILS' ? 'Consultazione Fascicolo' : (log.action === 'UPDATE_GDPR' ? 'Modifica Consensi' : `${log.action} su ${log.table_name}`);
        
        container.innerHTML += `\n            <div class="audit-log-item">\n                <div><strong>${st.last_name}</strong> (${st.role}) - ${actionDesc}</div>\n                <span class="audit-log-time">${timeStr}</span>\n            </div>\n        `;
    });
}

// --- 13. AI PREDICTIVE ASSISTANT ---
function initAiAssistant() {
    const aiInput = document.getElementById('ai-input');
    const submitBtn = document.getElementById('ai-submit-btn');
    if (!aiInput) return;
    
    const askAi = () => {
        const text = aiInput.value.trim();
        if (!text) return;
        
        addAiMessage(text, 'user');
        aiInput.value = '';
        
        setTimeout(() => {
            addAiMessage(generateAiAnswer(text), 'assistant');
        }, 800);
    };
    
    submitBtn.addEventListener('click', askAi);
    aiInput.addEventListener('keydown', (e) => { if (e.key === 'Enter') askAi(); });
}

function addAiMessage(text, sender) {
    const chatBox = document.getElementById('ai-response-box');
    const msg = document.createElement('div');
    msg.className = `ai-message ${sender}`;
    msg.innerText = text;
    chatBox.appendChild(msg);
    chatBox.scrollTop = chatBox.scrollHeight;
}

function generateAiAnswer(question) {
    const q = question.toLowerCase();
    const admissions = DB.get('admissions').filter(a => a.status === 'active');
    const shifts = DB.get('shifts');
    const staff = DB.get('staff');
    const invoices = DB.get('invoices');
    
    if (q.includes('saturo') || q.includes('reparto')) {
        const depts = {};
        admissions.forEach(a => { depts[a.department] = (depts[a.department] || 0) + 1; });
        let maxDept = 'Nessuno', maxCount = 0;
        Object.keys(depts).forEach(d => {
            if (depts[d] > maxCount) { maxCount = depts[d]; maxDept = d; }
        });
        return `[NextCare AI] Saturazione reparti: ${admissions.length} ricoverati totali. Reparto più saturo: "${maxDept}" (${maxCount} degenti).`;
    }
    if (q.includes('turno') || q.includes('oggi')) {
        const activeShifts = shifts.map(sh => {
            const s = staff.find(st => st.id === sh.staff_id);
            return `${s.last_name} (${sh.role_assigned})`;
        }).join(', ');
        return `[NextCare AI] Staff in servizio oggi: ${activeShifts || "nessuno pianificato"}.`;
    }
    if (q.includes('fatturato') || q.includes('incasso')) {
        const total = invoices.reduce((acc, inv) => acc + inv.amount_due, 0);
        const paid = invoices.filter(i => i.payment_status === 'paid').reduce((acc, inv) => acc + inv.amount_due, 0);
        return `[NextCare AI] Incasso: emesso € ${total.toFixed(2)}, saldato € ${paid.toFixed(2)} (${Math.round((paid/total)*100)}%).`;
    }
    return `[NextCare AI] Piattaforma online. Puoi chiedermi statistiche sui ricoveri, il personale in turno o l'analisi di fatturazione.`;
}

