window.sendSimulatedEmail = function(patientId, eventName, templateVars) {
    const templates = DB.get('email_templates') || [];
    const tpl = templates.find(t => t.event === eventName);
    if (!tpl) return;

    const patient = DB.get('patients').find(p => p.id === patientId);
    if (!patient || !patient.email) return;

    let parsedSubject = tpl.subject;
    let parsedBody = tpl.body;

    for (const [key, val] of Object.entries(templateVars)) {
        const regex = new RegExp(`{${key}}`, 'g');
        parsedSubject = parsedSubject.replace(regex, val);
        parsedBody = parsedBody.replace(regex, val);
    }

    const newEmail = {
        patient_id: patientId,
        recipient: patient.email,
        event: eventName,
        subject: parsedSubject,
        body: parsedBody,
        sent_at: new Date().toISOString(),
        status: 'sending'
    };

    const emailId = DB.insert('sent_emails', newEmail).id;
    if (typeof currentTab !== 'undefined' && currentTab === 'notifications') {
        if (typeof renderSentEmails === 'function') renderSentEmails();
    }

    const smtpSettings = DB.get('email_settings') || {};
    
    fetch('/api/send-email', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            smtp_settings: smtpSettings,
            email: {
                recipient: patient.email,
                subject: parsedSubject,
                body: parsedBody
            }
        })
    })
    .then(res => res.json())
    .then(res => {
        if (res.success) {
            DB.update('sent_emails', emailId, { status: 'sent' });
            console.log(`[REAL SMTP SUCCESS] E-mail sent to ${patient.email}`);
        } else {
            DB.update('sent_emails', emailId, { status: 'failed', body: parsedBody + `



[Real Send Error: ${res.error}]` });
            console.warn(`[REAL SMTP ERROR] ${res.error}`);
        }
        if (typeof currentTab !== 'undefined' && currentTab === 'notifications') {
            if (typeof renderSentEmails === 'function') renderSentEmails();
        }
    })
    .catch(err => {
        DB.update('sent_emails', emailId, { status: 'failed', body: parsedBody + `



[Network Error: ${err.message}]` });
        if (typeof currentTab !== 'undefined' && currentTab === 'notifications') {
            if (typeof renderSentEmails === 'function') renderSentEmails();
        }
    });

    DB.logAudit(6, "SIMULATE_EMAIL_SEND", "sent_emails", emailId, { event: eventName, recipient: patient.email });
};

window.renderSentEmails = function() {
    const tableBody = document.querySelector('#sent-emails-table tbody');
    if (!tableBody) return;

    tableBody.innerHTML = '';
    const emails = DB.get('sent_emails') || [];
    const patients = DB.get('patients') || [];

    // Sort descending by id or date
    const sortedEmails = [...emails].sort((a, b) => b.id - a.id);

    if (sortedEmails.length === 0) {
        tableBody.innerHTML = `<tr><td colspan="5" style="text-align: center; color: var(--text-muted); padding: 15px;">Nessuna notifica email inviata presente nel registro.</td></tr>`;
        return;
    }

    const eventLabels = {
        'new_appointment': 'Conferma Prenotazione',
        'cancel_appointment': 'Cancellazione',
        'no_show': 'Assente (No-Show)',
        'report_ready': 'Referto Pronto'
    };

    const eventColors = {
        'new_appointment': '#0ea5e9',
        'cancel_appointment': '#ef4444',
        'no_show': '#f97316',
        'report_ready': '#10b981'
    };

    sortedEmails.forEach(email => {
        const patient = patients.find(p => p.id === email.patient_id);
        const patientName = patient ? `${patient.first_name} ${patient.last_name} (${email.recipient})` : email.recipient;
        const eventLabel = eventLabels[email.event] || email.event;
        const eventColor = eventColors[email.event] || '#64748b';
        
        let statusBadge = '';
        if (email.status === 'sent') {
            statusBadge = `<span class="badge" style="background: rgba(16, 185, 129, 0.15); color: #10b981; border: 1px solid rgba(16, 185, 129, 0.2); padding: 4px 8px; border-radius: 4px;">Inviata</span>`;
        } else if (email.status === 'failed') {
            statusBadge = `<span class="badge" style="background: rgba(239, 68, 68, 0.15); color: #ef4444; border: 1px solid rgba(239, 68, 68, 0.2); padding: 4px 8px; border-radius: 4px; cursor: help;" title="${(email.body || '').replace(/"/g, '&quot;')}">Errore</span>`;
        } else {
            statusBadge = `<span class="badge" style="background: rgba(245, 158, 11, 0.15); color: #f59e0b; border: 1px solid rgba(245, 158, 11, 0.2); padding: 4px 8px; border-radius: 4px;">Invio in corso...</span>`;
        }

        const dateStr = email.sent_at ? new Date(email.sent_at).toLocaleString('it-IT') : 'N/A';

        const row = document.createElement('tr');
        row.innerHTML = `\n            <td style="font-family: monospace; font-size: 0.85rem;">${dateStr}</td>\n            <td>${patientName}</td>\n            <td><span class="badge" style="background: ${eventColor}22; color: ${eventColor}; border: 1px solid ${eventColor}44; padding: 3px 6px; border-radius: 4px; font-weight: 600; font-size: 0.75rem;">${eventLabel}</span></td>\n            <td>${email.subject}</td>\n            <td>${statusBadge}</td>\n        `;
        tableBody.appendChild(row);
    });
};

window.loadSelectedEmailTemplate = function() {
    const eventSelect = document.getElementById('email-tpl-event');
    if (!eventSelect) return;

    const eventName = eventSelect.value;
    const templates = DB.get('email_templates') || [];
    const tpl = templates.find(t => t.event === eventName);

    const subjectInput = document.getElementById('email-tpl-subject');
    const bodyInput = document.getElementById('email-tpl-body');

    if (tpl) {
        if (subjectInput) subjectInput.value = tpl.subject;
        if (bodyInput) bodyInput.value = tpl.body;
    } else {
        if (subjectInput) subjectInput.value = '';
        if (bodyInput) bodyInput.value = '';
    }
};

window.saveEmailTemplate = function() {
    const eventSelect = document.getElementById('email-tpl-event');
    if (!eventSelect) return;

    const eventName = eventSelect.value;
    const subjectInput = document.getElementById('email-tpl-subject');
    const bodyInput = document.getElementById('email-tpl-body');

    if (!subjectInput || !bodyInput) return;

    const subject = subjectInput.value.trim();
    const body = bodyInput.value.trim();

    if (!subject || !body) {
        alert("Oggetto e corpo del messaggio sono obbligatori!");
        return;
    }

    let templates = DB.get('email_templates') || [];
    const index = templates.findIndex(t => t.event === eventName);

    if (index !== -1) {
        templates[index].subject = subject;
        templates[index].body = body;
        templates[index].updated_at = new Date().toISOString();
        DB.set('email_templates', templates);
    } else {
        const newTpl = {
            event: eventName,
            subject: subject,
            body: body,
            created_at: new Date().toISOString(),
            updated_at: new Date().toISOString()
        };
        templates.push(newTpl);
        DB.set('email_templates', templates);
    }

    alert("Template salvato con successo!");
};

window.toggleSmtpAuthFields = function() {
    const authSelect = document.getElementById('smtp-auth');
    const credentialsGroup = document.getElementById('smtp-auth-credentials-group');
    const smtpUser = document.getElementById('smtp-user');
    const smtpPass = document.getElementById('smtp-pass');
    
    if (authSelect && credentialsGroup) {
        if (authSelect.value === 'none') {
            credentialsGroup.style.display = 'none';
            if (smtpUser) smtpUser.required = false;
            if (smtpPass) smtpPass.required = false;
        } else {
            credentialsGroup.style.display = 'block';
            if (smtpUser) smtpUser.required = true;
            if (smtpPass) smtpPass.required = true;
        }
    }
};

window.handleSmtpSettingsSubmit = function(event) {
    if (event) event.preventDefault();

    const smtpM365 = document.getElementById('smtp-use-m365');
    const smtpHost = document.getElementById('smtp-host');
    const smtpPort = document.getElementById('smtp-port');
    const smtpUser = document.getElementById('smtp-user');
    const smtpPass = document.getElementById('smtp-pass');
    const smtpSecurity = document.getElementById('smtp-security');
    const smtpAuth = document.getElementById('smtp-auth');
    const smtpIgnoreCert = document.getElementById('smtp-ignore-cert');
    const smtpSenderName = document.getElementById('smtp-sender-name');
    const smtpSenderEmail = document.getElementById('smtp-sender-email');
    const smtpSupportRecipient = document.getElementById('smtp-support-recipient');

    if (!smtpHost || !smtpPort || !smtpSenderEmail) return;

    const isAuth = smtpAuth && smtpAuth.value === 'login';
    if (isAuth) {
        if (!smtpUser || !smtpPass || !smtpUser.value.trim() || !smtpPass.value.trim()) {
            alert("Username e Password SMTP sono obbligatori se l'autenticazione è abilitata.");
            return;
        }
    }

    const settings = {
        smtp_use_m365: smtpM365 && smtpM365.checked ? 1 : 0,
        smtp_host: smtpHost.value.trim(),
        smtp_port: parseInt(smtpPort.value),
        smtp_security: smtpSecurity ? smtpSecurity.value : 'starttls',
        smtp_auth: smtpAuth ? smtpAuth.value : 'login',
        smtp_ignore_cert: smtpIgnoreCert && smtpIgnoreCert.checked ? 1 : 0,
        smtp_sender_name: smtpSenderName ? smtpSenderName.value.trim() : '',
        smtp_sender_email: smtpSenderEmail.value.trim(),
        smtp_support_recipient: smtpSupportRecipient ? smtpSupportRecipient.value.trim() : 'support@nextcare.it',
        smtp_user: isAuth ? smtpUser.value.trim() : '',
        smtp_pass: isAuth ? smtpPass.value.trim() : ''
    };

    DB.set('email_settings', settings);
    alert("Configurazione SMTP salvata con successo!");
};

window.testSmtpConnection = function() {
    const smtpM365 = document.getElementById('smtp-use-m365');
    const smtpHost = document.getElementById('smtp-host');
    const smtpPort = document.getElementById('smtp-port');
    const smtpUser = document.getElementById('smtp-user');
    const smtpPass = document.getElementById('smtp-pass');
    const smtpSecurity = document.getElementById('smtp-security');
    const smtpAuth = document.getElementById('smtp-auth');
    const smtpIgnoreCert = document.getElementById('smtp-ignore-cert');
    const smtpSenderName = document.getElementById('smtp-sender-name');
    const smtpSenderEmail = document.getElementById('smtp-sender-email');

    if (!smtpHost || !smtpPort || !smtpSenderEmail) return;

    const host = smtpHost.value.trim();
    const port = parseInt(smtpPort.value);
    const security = smtpSecurity ? smtpSecurity.value : 'starttls';
    const auth = smtpAuth ? smtpAuth.value : 'login';
    const ignore_cert = smtpIgnoreCert && smtpIgnoreCert.checked ? 1 : 0;
    const sender_name = smtpSenderName ? smtpSenderName.value.trim() : '';
    const sender_email = smtpSenderEmail.value.trim();
    const user = smtpUser ? smtpUser.value.trim() : '';
    const password = smtpPass ? smtpPass.value.trim() : '';

    if (!host || !port || !sender_email) {
        alert("Compilare tutti i campi contrassegnati con asterisco per effettuare il test!");
        return;
    }

    if (auth === 'login' && (!user || !password)) {
        alert("Username e Password SMTP sono obbligatori se l'autenticazione è abilitata.");
        return;
    }

    const testBtn = document.querySelector('button[onclick="testSmtpConnection()"]');
    const originalText = testBtn ? testBtn.innerHTML : "Test Connessione";
    if (testBtn) {
        testBtn.disabled = true;
        testBtn.innerHTML = '<span class="spinner" style="display:inline-block; width:12px; height:12px; border:2px solid #fff; border-top:2px solid transparent; border-radius:50%; animation:spin 1s linear infinite; margin-right:6px;"></span> Connessione...';
    }

    fetch('/api/test-smtp', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ 
            smtp_use_m365: smtpM365 && smtpM365.checked ? 1 : 0, 
            smtp_host: host, 
            smtp_port: port, 
            smtp_security: security,
            smtp_auth: auth,
            smtp_ignore_cert: ignore_cert,
            smtp_sender_name: sender_name,
            smtp_sender_email: sender_email,
            smtp_user: user, 
            smtp_pass: password
        })
    })
    .then(res => res.json())
    .then(res => {
        if (testBtn) {
            testBtn.disabled = false;
            testBtn.innerHTML = originalText;
        }
        if (res.success) {
            alert("Connessione SMTP stabilita con successo!\n\n" + res.data.message);
        } else {
            alert("Errore di connessione SMTP: " + res.error);
        }
    })
    .catch(err => {
        if (testBtn) {
            testBtn.disabled = false;
            testBtn.innerHTML = originalText;
        }
        alert("Errore di rete: Impossibile contattare il server. " + err.message);
    });
};

window.ensureDefaultEmailTemplatesExist = function() {
    let templates = DB.get('email_templates') || [];
    
    const defaults = [
        {
            event: "new_appointment",
            subject: "Conferma Prenotazione - Clinica NextCare",
            body: `Gentile Paziente {paziente},\n\n\n\nLe confermiamo l'avvenuta prenotazione per il giorno {data}.\n\n\n\nPrestazione prenotata: {prestazione}.\n\nDettaglio medico: {dettaglio}.\n\n\n\nSi prega di presentarsi in struttura 10 minuti prima dell'inizio dello slot.\n\n\n\nCordiali Saluti,\n\nSegreteria NextCare`
        },
        {
            event: "report_ready",
            subject: "Referto Diagnostico Pronto - Clinica NextCare",
            body: `Gentile Paziente {paziente},\n\n\n\nLe comunichiamo che il referto relativo all'esame {prestazione} eseguito il {data} è stato firmato digitalmente ed è ora disponibile nel suo Fascicolo Sanitario.\n\n\n\nFirma Digitale: {dettaglio}.\n\n\n\nPuoi scaricare il referto direttamente al seguente indirizzo:\n\nhttp://localhost:8000/#download-report\n\n\n\nCordiali Saluti,\n\nNextCare Health Systems`
        },
        {
            event: "cancel_appointment",
            subject: "Cancellazione Prenotazione - Clinica NextCare",
            body: `Gentile Paziente {paziente},\n\n\n\nLe comunichiamo che la sua prenotazione per il giorno {data} ({prestazione}) è stata annullata.\n\n\n\nMotivo dell'annullamento: {dettaglio}.\n\n\n\nSe desidera rischedulare l'appuntamento, può farlo cliccando sul seguente link:\n\nhttp://localhost:8000/#reschedule\n\n\n\nCordiali Saluti,\n\nSegreteria NextCare`
        },
        {
            event: "no_show",
            subject: "Mancata Presentazione (No Show) - Clinica NextCare",
            body: `Gentile Paziente {paziente},\n\n\n\nLe comunichiamo che in data {data} non si è presentato/a per l'appuntamento della prestazione: {prestazione}.\n\n\n\n{dettaglio}\n\n\n\nLa invitiamo a contattare la segreteria o rischedulare l'appuntamento cliccando sul seguente link:\n\nhttp://localhost:8000/#reschedule\n\n\n\nCordiali Saluti,\n\nSegreteria NextCare`
        }
    ];

    let changed = false;
    defaults.forEach(defTpl => {
        if (!templates.some(t => t.event === defTpl.event)) {
            templates.push(defTpl);
            changed = true;
        }
    });

    if (changed) {
        DB.set('email_templates', templates);
        console.log("[Auto-Seeding] Nuovi template email configurati con successo.");
    }
};

window.markAsNoShow = function(appId) {
    if (!confirm("Sei sicuro di voler contrassegnare questo paziente come Assente (No Show)?")) {
        return;
    }
    
    DB.update('appointments', appId, { status: 'no_show' });
    DB.logAudit(6, "NO_SHOW_APPOINTMENT", "appointments", appId, { status: 'no_show' });
    
    const app = DB.get('appointments').find(a => a.id === appId);
    const patient = app ? DB.get('patients').find(p => p.id === app.patient_id) : null;
    const appServices = DB.get('appointment_services') || [];
    const services = DB.get('medical_services') || [];
    const linkedServices = appServices.filter(as => as.appointment_id === appId).map(as => services.find(s => s.id === as.service_id)).filter(Boolean);
    const serviceNames = linkedServices.map(s => s.name).join(', ') || 'Prestazione';
    const appDateStr = app ? new Date(app.appointment_datetime).toLocaleString('it-IT') : 'N/A';

    if (patient) {
        const pName = `${patient.first_name} ${patient.last_name}`;
        window.sendSimulatedEmail(patient.id, 'no_show', {
            paziente: pName,
            data: appDateStr,
            prestazione: serviceNames,
            dettaglio: "La mancata presentazione all'appuntamento senza preavviso comporta la necessità di rischedulare la prestazione."
        });
    }

    renderAppointments();
    if (typeof renderDashboard === 'function') {
        renderDashboard();
    }
};

// --- 17. SQL SCHEMA DDL VIEWER ---
function loadSqlSchema() {
    fetch('schema.sql')
        .then(response => {
            if (!response.ok) throw new Error("File schema.sql non trovato.");
            return response.text();
        })
        .then(code => {
            const sqlCodeEl = document.getElementById('sql-code-element');
            if (sqlCodeEl) sqlCodeEl.innerText = code;
        })
        .catch(err => {
            const sqlCodeEl = document.getElementById('sql-code-element');
            if (sqlCodeEl) sqlCodeEl.innerText = "-- Impossibile caricare schema.sql:\n\n-- " + err.message;
        });
}

window.copySqlCode = function() {
    const sqlText = document.getElementById('sql-code-element').innerText;
    navigator.clipboard.writeText(sqlText).then(() => {
        alert("Codice DDL SQL copiato negli appunti!");
    }).catch(err => {
        alert("Errore nella copia negli appunti:\n\n" + err);
    });
};


