    // FORM: Add Shift HRIS
    document.getElementById('form-add-shift').addEventListener('submit', async (e) => {
        e.preventDefault();
        const staffId = parseInt(document.getElementById('sh-staff').value);
        const day = document.getElementById('sh-date').value;
        const start = document.getElementById('sh-start').value;
        const end = document.getElementById('sh-end').value;
        const role = document.getElementById('sh-role').value;
        const type = document.getElementById('sh-type').value;

        const loggedUser = JSON.parse(localStorage.getItem('nextcare_logged_in_user') || '{}');
        const loggedStaffId = loggedUser.id || 1;

        if (type === 'single') {
            const shift = {
                staff_id: staffId,
                start_time: `${day}T${start}`,
                end_time: `${day}T${end}`,
                role_assigned: role
            };
            const newShift = DB.insert('shifts', shift);
            DB.logAudit(loggedStaffId, "SHIFT_SCHEDULE", "shifts", newShift.id, { staff_id: staffId, type: 'single' });
        } else {
            const endDate = document.getElementById('sh-end-date').value;
            if (!endDate) {
                alert("Specifica la data di fine ricorrenza.");
                return;
            }

            const parts = day.split('-');
            const endParts = endDate.split('-');
            let current = new Date(parts[0], parts[1] - 1, parts[2]);
            const stopDate = new Date(endParts[0], endParts[1] - 1, endParts[2]);

            if (current > stopDate) {
                alert("La data di fine ricorrenza deve essere successiva alla data di inizio.");
                return;
            }

            let count = 0;
            if (type === 'weekly') {
                const checkedDays = Array.from(document.querySelectorAll('input[name="sh-weekly-days"]:checked')).map(cb => parseInt(cb.value));
                if (checkedDays.length === 0) {
                    alert("Seleziona almeno un giorno della settimana per la ricorrenza.");
                    return;
                }

                while (current <= stopDate) {
                    const dayOfWeek = current.getDay();
                    if (checkedDays.includes(dayOfWeek)) {
                        const y = current.getFullYear();
                        const m = String(current.getMonth() + 1).padStart(2, '0');
                        const d = String(current.getDate()).padStart(2, '0');
                        const dateStr = `${y}-${m}-${d}`;
                        const shift = {
                            staff_id: staffId,
                            start_time: `${dateStr}T${start}`,
                            end_time: `${dateStr}T${end}`,
                            role_assigned: role
                        };
                        DB.insert('shifts', shift);
                        count++;
                    }
                    current.setDate(current.getDate() + 1);
                }
            } else if (type === 'monthly') {
                let monthsDiff = 0;
                while (true) {
                    let nextDate = new Date(parts[0], parts[1] - 1 + monthsDiff, parts[2]);
                    if (nextDate > stopDate) break;
                    
                    const y = nextDate.getFullYear();
                    const m = String(nextDate.getMonth() + 1).padStart(2, '0');
                    const d = String(nextDate.getDate()).padStart(2, '0');
                    const dateStr = `${y}-${m}-${d}`;
                    
                    const shift = {
                        staff_id: staffId,
                        start_time: `${dateStr}T${start}`,
                        end_time: `${dateStr}T${end}`,
                        role_assigned: role
                    };
                    DB.insert('shifts', shift);
                    count++;
                    monthsDiff++;
                }
            }
            DB.logAudit(loggedStaffId, "SHIFT_SCHEDULE_RECURRING", "shifts", null, { staff_id: staffId, type: type, count: count });
        }

        await DB.waitForSync();

        closeModal('modal-add-shift');
        document.getElementById('form-add-shift').reset();
        renderStaffAndShifts();
    });

