window.printLisAcceptanceReceipt = function(sampleId) {
    const samples = DB.get('lab_samples') || [];
    const patients = DB.get('patients') || [];
    const tests = DB.get('lab_tests') || [];
    const services = DB.get('medical_services') || [];

    const sample = samples.find(s => s.id === parseInt(sampleId));
    if (!sample) return;
    const patient = patients.find(p => p.id === sample.patient_id);
    if (!patient) return;

    let sessionSamples = [sample];
    if (sample.session_uid) {
        sessionSamples = samples.filter(s => s.session_uid === sample.session_uid);
    } else {
        const dateStr = (sample.collected_at || sample.created_at || '').substring(0, 13);
        sessionSamples = samples.filter(s => !s.session_uid && s.patient_id === sample.patient_id && (s.collected_at || s.created_at || '').substring(0, 13) === dateStr);
    }

    const patientName = `${patient.last_name.toUpperCase()} ${patient.first_name}`;
    const patientBirth = new Date(patient.birth_date).toLocaleDateString('it-IT');
    const patientTax = patient.tax_code;
    const collectDate = new Date(sample.collected_at || sample.created_at).toLocaleString('it-IT');

    const barcodesStr = sessionSamples.map(s => s.barcode).join(', ');

    let testRows = '';
    let globalIdx = 1;
    sessionSamples.forEach(s => {
        const samTests = tests.filter(t => t.sample_id === s.id);
        samTests.forEach(t => {
            const srv = services.find(sv => sv.id === t.service_id);
            const code = srv ? srv.code || 'N/A' : 'N/A';
            testRows += `\n                <tr>\n                    <td style="border-bottom: 1px solid #e2e8f0; padding: 8px;">${globalIdx++}</td>\n                    <td style="border-bottom: 1px solid #e2e8f0; padding: 8px;"><code>${code}</code></td>\n                    <td style="border-bottom: 1px solid #e2e8f0; padding: 8px;"><strong>${t.test_name}</strong></td>\n                    <td style="border-bottom: 1px solid #e2e8f0; padding: 8px;">${s.sample_type}</td>\n                    <td style="border-bottom: 1px solid #e2e8f0; padding: 8px; font-family: monospace; font-weight: bold;">${s.barcode}</td>\n                </tr>\n            `;
        });
    });

    const printWindow = window.open('', '_blank');
    if (!printWindow) {
        alert("Errore: Pop-up bloccato dal browser! Consenti i pop-up per questo sito.");
        return;
    }
    printWindow.document.write(`\n        <html>\n        <head>\n            <title>Ricevuta Accettazione LIS - ${barcodesStr}</title>\n            <style>\n                body { font-family: 'Inter', -apple-system, sans-serif; padding: 40px; color: #1e293b; line-height: 1.5; }\n                .header { border-bottom: 2px solid #2563eb; padding-bottom: 15px; margin-bottom: 30px; display: flex; justify-content: space-between; align-items: center; }\n                .header h1 { color: #2563eb; margin: 0; font-size: 1.8rem; }\n                .header p { margin: 5px 0 0 0; color: #64748b; font-size: 0.9rem; }\n                .grid { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; margin-bottom: 30px; }\n                .info-box { background: #f8fafc; border: 1px solid #e2e8f0; padding: 15px; border-radius: 8px; }\n                .info-box h3 { margin: 0 0 10px 0; color: #1e293b; font-size: 1rem; border-bottom: 1px solid #e2e8f0; padding-bottom: 5px; }\n                .info-row { display: flex; justify-content: space-between; font-size: 0.85rem; margin-bottom: 5px; }\n                .info-row span { color: #64748b; }\n                .info-row strong { color: #1e293b; }\n                table { width: 100%; border-collapse: collapse; margin-top: 20px; font-size: 0.9rem; }\n                th { background-color: #f1f5f9; font-weight: 700; color: #475569; text-align: left; padding: 10px 8px; border-bottom: 2px solid #cbd5e1; }\n                .footer { margin-top: 50px; border-top: 1px solid #e2e8f0; padding-top: 15px; font-size: 0.8rem; color: #94a3b8; text-align: center; }\n            </style>\n        </head>\n        <body>\n            <div class="header">\n                <div>\n                    <h1>NEXTCARE LAB</h1>\n                    <p>Accettazione e Prelievo Laboratorio</p>\n                </div>\n                <div style="text-align: right;">\n                    <div style="font-family: monospace; font-size: 1.05rem; font-weight: 700; letter-spacing: 1px;">${barcodesStr}</div>\n                    <div style="font-size: 0.8rem; color: #64748b;">ID Sessione: ${sample.session_uid || 'Legacy'}</div>\n                </div>\n            </div>\n            \n            <div class="grid">\n                <div class="info-box">\n                    <h3>Dettagli Paziente</h3>\n                    <div class="info-row"><span>Cognome e Nome:</span><strong>${patientName}</strong></div>\n                    <div class="info-row"><span>Codice Fiscale:</span><strong>${patientTax}</strong></div>\n                    <div class="info-row"><span>Data Nascita:</span><strong>${patientBirth}</strong></div>\n                </div>\n                <div class="info-box">\n                    <h3>Dettagli Accettazione</h3>\n                    <div class="info-row"><span>Data/Ora Prelievo:</span><strong>${collectDate}</strong></div>\n                    <div class="info-row"><span>Stato Campione:</span><strong>Accettato / Prelievo eseguito</strong></div>\n                    <div class="info-row"><span>Operatore:</span><strong>Infermiere Accettazione</strong></div>\n                </div>\n            </div>\n\n            <h3 style="border-bottom: 1px solid #e2e8f0; padding-bottom: 5px; margin-bottom: 15px;">Elenco Analisi Richieste</h3>\n            <table>\n                <thead>\n                    <tr>\n                        <th style="width: 50px;">#</th>\n                        <th style="width: 120px;">Codice CUR</th>\n                        <th>Esame</th>\n                        <th>Tipo Contenitore</th>\n                        <th>Barcode Provetta</th>\n                    </tr>\n                </thead>\n                <tbody>\n                    ${testRows}\n                </tbody>\n            </table>\n\n            <div class="footer">\n                NextCare App - Soluzioni Software per la Sanità. Pagina stampata il ${new Date().toLocaleString('it-IT')}.\n            </div>\n            \n            <script>\n                window.onload = function() {\n                    window.print();\n                    setTimeout(function() { window.close(); }, 500);\n                }\n            </script>\n        </body>\n        </html>\n    `);
    printWindow.document.close();
};

