window.switchConfigSubTab = function(subTabId) {
    const panels = ['prices', 'companies', 'insurances'];
    panels.forEach(p => {
        const btn = document.getElementById(`btn-subtab-${p}`);
        const panel = document.getElementById(`config-panel-${p}`);
        if (p === subTabId) {
            if (btn) btn.classList.remove('btn-outline');
            if (panel) panel.style.display = 'block';
        } else {
            if (btn) btn.classList.add('btn-outline');
            if (panel) panel.style.display = 'none';
        }
    });

    if (subTabId === 'insurances') {
        window.renderInsurancesTable();
    } else if (subTabId === 'prices') {
        populatePriceListsDropdown('config-select-listino');
        window.loadListinoPricesTable();
    } else if (subTabId === 'companies') {
        window.renderCompanies();
    }
};

window.renderInsuranceConfig = function() {
    window.switchConfigSubTab('prices');
};

window.renderInsurancesTable = function() {
    try {
        const tbody = document.querySelector('#config-insurances-table tbody');
        if (!tbody) return;
        tbody.innerHTML = '';

        const insurances = DB.get('insurances') || [];
        const priceLists = DB.get('price_lists') || [];

        if (insurances.length === 0) {
            tbody.innerHTML = `<tr><td colspan="5" style="text-align: center;" class="text-muted">Nessuna convenzione assicurativa configurata.</td></tr>`;
            return;
        }

        insurances.forEach(ins => {
            if (!ins) return;
            const listino = priceLists.find(l => l && l.id === parseInt(ins.price_list_id));
            const listinoName = listino ? listino.name : `Listino ${ins.price_list_id}`;
            const modeText = ins.billing_mode === 'split' ? 'Fatture Distinte (Split)' : 'Fattura Unica (Single)';
            
            const tr = document.createElement('tr');
            tr.innerHTML = `\n                <td>${ins.id}</td>\n                <td><strong>${ins.name}</strong></td>\n                <td>${listinoName}</td>\n                <td><span class="badge ${ins.billing_mode === 'split' ? 'badge-purple' : 'badge-info'}">${modeText}</span></td>\n                <td>\n                    <button class="btn btn-secondary btn-sm" onclick="window.openAddInsuranceModal(${ins.id})"><i data-lucide="edit"></i> Modifica</button>\n                    <button class="btn btn-danger btn-sm" onclick="window.deleteInsurance(${ins.id})" style="margin-left:5px;"><i data-lucide="trash-2"></i> Elimina</button>\n                </td>\n            `;
            tbody.appendChild(tr);
        });

        if (window.lucide) window.lucide.createIcons();
    } catch (error) {
        console.error("Errore in renderInsurancesTable:", error);
        const tbody = document.querySelector('#config-insurances-table tbody');
        if (tbody) {
            tbody.innerHTML = `<tr><td colspan="5" style="text-align:center; color: var(--danger-color);" class="text-danger">\n                <strong>Errore nel rendering delle convenzioni:</strong><br>${error.message}\n            </td></tr>`;
        }
    }
};

window.deleteInsurance = function(insId) {
    if (!confirm("Confermi di voler eliminare questa convenzione assicurativa?")) return;
    const insurances = DB.get('insurances') || [];
    const filtered = insurances.filter(i => i.id !== parseInt(insId));
    DB.set('insurances', filtered);
    DB.logAudit(6, "DELETE_INSURANCE", "insurances", insId, {});
    window.renderInsurancesTable();
};

window.openAddInsuranceModal = function(insId = null) {
    const modalTitle = document.getElementById('ins-modal-title');
    const form = document.getElementById('form-add-insurance');
    form.reset();

    // Populate price lists select
    const priceListSelect = document.getElementById('ins-price-list');
    priceListSelect.innerHTML = '';
    const priceLists = DB.get('price_lists') || [];
    priceLists.forEach(l => {
        priceListSelect.innerHTML += `<option value="${l.id}">${l.name}</option>`;
    });

    if (insId) {
        modalTitle.innerText = "Modifica Convenzione Assicurativa";
        const insurances = DB.get('insurances') || [];
        const ins = insurances.find(i => i.id === parseInt(insId));
        if (ins) {
            document.getElementById('ins-id').value = ins.id;
            document.getElementById('ins-name').value = ins.name;
            document.getElementById('ins-price-list').value = ins.price_list_id;
            document.getElementById('ins-billing-mode').value = ins.billing_mode || 'single';
        }
    } else {
        modalTitle.innerText = "Nuova Convenzione Assicurativa";
        document.getElementById('ins-id').value = '';
    }

    openModal('modal-add-insurance');
};

window.handleAddInsuranceSubmit = function(e) {
    e.preventDefault();
    const idVal = document.getElementById('ins-id').value;
    const name = document.getElementById('ins-name').value;
    const priceListId = parseInt(document.getElementById('ins-price-list').value);
    const billingMode = document.getElementById('ins-billing-mode').value;

    const insurances = DB.get('insurances') || [];

    if (idVal) {
        // Update
        const insId = parseInt(idVal);
        const index = insurances.findIndex(i => i.id === insId);
        if (index !== -1) {
            insurances[index] = { ...insurances[index], name, price_list_id: priceListId, billing_mode: billingMode };
            DB.set('insurances', insurances);
            DB.logAudit(6, "UPDATE_INSURANCE", "insurances", insId, { name, billingMode });
        }
    } else {
        // Create
        const nextId = insurances.length > 0 ? Math.max(...insurances.map(i => i.id)) + 1 : 1;
        const newIns = { id: nextId, name, price_list_id: priceListId, billing_mode: billingMode };
        insurances.push(newIns);
        DB.set('insurances', insurances);
        DB.logAudit(6, "CREATE_INSURANCE", "insurances", nextId, { name, billingMode });
    }

    closeModal('modal-add-insurance');
    window.renderInsurancesTable();
};

window.renderTubesTable = function() {
    try {
        const tbody = document.querySelector('#config-tubes-table tbody');
        if (!tbody) return;
        tbody.innerHTML = '';

        const tubes = DB.get('tube_types') || [];

        if (tubes.length === 0) {
            tbody.innerHTML = `<tr><td colspan="4" style="text-align: center;" class="text-muted">Nessun tipo provetta configurato.</td></tr>`;
            return;
        }

        tubes.forEach(t => {
            if (!t) return;
            const tr = document.createElement('tr');
            tr.innerHTML = `\n                <td>${t.id}</td>\n                <td>${window.getTubeBadgeHtml(t.name)}</td>\n                <td><code style="font-size:0.95rem; font-weight:700;">${t.suffix}</code></td>\n                <td>\n                    <button class="btn btn-secondary btn-sm" onclick="window.openAddTubeTypeModal(${t.id})"><i data-lucide="edit"></i> Modifica</button>\n                    <button class="btn btn-danger btn-sm" onclick="window.deleteTubeType(${t.id})" style="margin-left:5px;"><i data-lucide="trash-2"></i> Elimina</button>\n                </td>\n            `;
            tbody.appendChild(tr);
        });

        if (window.lucide) window.lucide.createIcons();
    } catch (error) {
        console.error("Errore in renderTubesTable:", error);
        const tbody = document.querySelector('#config-tubes-table tbody');
        if (tbody) {
            tbody.innerHTML = `<tr><td colspan="4" style="text-align:center; color: var(--danger-color);" class="text-danger">\n                <strong>Errore nel rendering delle provette:</strong><br>${error.message}\n            </td></tr>`;
        }
    }
};

window.deleteTubeType = function(tubeId) {
    if (!confirm("Confermi di voler eliminare questo tipo di provetta?")) return;
    const tubes = DB.get('tube_types') || [];
    const filtered = tubes.filter(t => t.id !== parseInt(tubeId));
    DB.set('tube_types', filtered);
    DB.logAudit(6, "DELETE_TUBE_TYPE", "tube_types", tubeId, {});
    window.renderTubesTable();
    populateTubeTypesDropdown('srv-sample');
};

window.openAddTubeTypeModal = function(tubeId = null) {
    const modalTitle = document.getElementById('tube-modal-title');
    const form = document.getElementById('form-add-tube-type');
    form.reset();

    if (tubeId) {
        modalTitle.innerText = "Modifica Tipo Provetta LIS";
        const tubes = DB.get('tube_types') || [];
        const tube = tubes.find(t => t.id === parseInt(tubeId));
        if (tube) {
            document.getElementById('tube-id').value = tube.id;
            document.getElementById('tube-name').value = tube.name;
            document.getElementById('tube-suffix').value = tube.suffix;
        }
    } else {
        modalTitle.innerText = "Nuovo Tipo Provetta LIS";
        document.getElementById('tube-id').value = '';
    }

    openModal('modal-add-tube-type');
};

window.handleAddTubeTypeSubmit = function(e) {
    e.preventDefault();
    const idVal = document.getElementById('tube-id').value;
    const name = document.getElementById('tube-name').value;
    const suffix = document.getElementById('tube-suffix').value.trim();

    if (!/^[0-9]{3}$/.test(suffix)) {
        alert("Errore: Il suffisso deve essere composto da esattamente 3 cifre numeriche (es. 001).");
        return;
    }

    const tubes = DB.get('tube_types') || [];
    const duplicate = tubes.find(t => t.suffix === suffix && t.id !== parseInt(idVal || -1));
    if (duplicate) {
        alert(`Errore: Il suffisso "${suffix}" è già associato a un'altra provetta ("${duplicate.name}"). Deve essere univoco.`);
        return;
    }

    if (idVal) {
        // Update
        const tubeId = parseInt(idVal);
        const index = tubes.findIndex(t => t.id === tubeId);
        if (index !== -1) {
            tubes[index] = { ...tubes[index], name, suffix };
            DB.set('tube_types', tubes);
            DB.logAudit(6, "UPDATE_TUBE_TYPE", "tube_types", tubeId, { name, suffix });
        }
    } else {
        // Create
        const nextId = tubes.length > 0 ? Math.max(...tubes.map(t => t.id)) + 1 : 1;
        const newTube = { id: nextId, name, suffix };
        tubes.push(newTube);
        DB.set('tube_types', tubes);
        DB.logAudit(6, "CREATE_TUBE_TYPE", "tube_types", nextId, { name, suffix });
    }

    closeModal('modal-add-tube-type');
    window.renderTubesTable();
    populateTubeTypesDropdown('srv-sample');
};

window.loadListinoPricesTable = function() {
    try {
        const listinoSelect = document.getElementById('config-select-listino');
        const tbody = document.querySelector('#config-prices-table tbody');
        if (!tbody || !listinoSelect) return;
        tbody.innerHTML = '';

        const listinoId = parseInt(listinoSelect.value || 1);
        const services = DB.get('medical_services') || [];
        const priceListItems = DB.get('price_list_items') || [];

        if (services.length === 0) {
            tbody.innerHTML = `<tr><td colspan="5" style="text-align: center;" class="text-muted">Nessuna prestazione in catalogo.</td></tr>`;
            return;
        }

        services.forEach(srv => {
            if (!srv) return;
            const item = priceListItems.find(p => p && p.price_list_id === listinoId && p.service_id === srv.id);
            const currentPrice = item ? item.price : srv.price;

            const tr = document.createElement('tr');
            tr.innerHTML = `\n                <td><code>${srv.code || 'N/A'}</code></td>\n                <td><strong>${srv.name}</strong></td>\n                <td><span class="badge badge-outline" style="text-transform:uppercase;">${srv.branch || srv.type}</span></td>\n                <td>€ ${Number(srv.price || 0).toFixed(2)}</td>\n                <td>\n                    <div style="display:flex; align-items:center; gap:8px;">\n                        <span>€</span>\n                        <input type="number" step="0.01" class="form-control price-override-input" \n                               data-service-id="${srv.id}" value="${Number(currentPrice || 0).toFixed(2)}" \n                               style="width: 100px; padding: 4px 8px; border: 1px solid var(--border-color); border-radius: var(--radius-sm);">\n                    </div>\n                </td>\n            `;
            tbody.appendChild(tr);
        });
    } catch (error) {
        console.error("Errore in loadListinoPricesTable:", error);
        const tbody = document.querySelector('#config-prices-table tbody');
        if (tbody) {
            tbody.innerHTML = `<tr><td colspan="5" style="text-align:center; color: var(--danger-color);" class="text-danger">\n                <strong>Errore nel rendering dei listini prezzi:</strong><br>${error.message}\n            </td></tr>`;
        }
    }
};

window.saveListinoPrices = function() {
    const listinoSelect = document.getElementById('config-select-listino');
    if (!listinoSelect) return;
    const listinoId = parseInt(listinoSelect.value || 1);

    const priceListItems = DB.get('price_list_items') || [];
    const inputs = document.querySelectorAll('#config-prices-table .price-override-input');
    
    let filteredItems = priceListItems.filter(p => p.price_list_id !== listinoId);

    inputs.forEach(input => {
        const serviceId = parseInt(input.dataset.serviceId);
        const price = parseFloat(input.value || 0);
        
        filteredItems.push({
            price_list_id: listinoId,
            service_id: serviceId,
            price: price
        });
    });

    DB.set('price_list_items', filteredItems);
    DB.logAudit(6, "SAVE_PRICE_LIST_OVERRIDES", "price_list_items", null, { price_list_id: listinoId, items_count: inputs.length });
    alert("Tariffe del listino salvate correttamente!");
    window.loadListinoPricesTable();
};

