window.duplicateCurrentPricelist = function() {
    const listinoSelect = document.getElementById('config-select-listino');
    if (!listinoSelect) return;
    const currentId = parseInt(listinoSelect.value || 1);
    const priceLists = DB.get('price_lists') || [];
    const currentList = priceLists.find(l => l.id === currentId);
    if (!currentList) {
        alert("Nessun listino selezionato da duplicare.");
        return;
    }

    const form = document.getElementById('form-manage-pricelist');
    if (form) form.reset();

    document.getElementById('new-pl-name').value = `Copia di ${currentList.name}`;

    const baseSelect = document.getElementById('new-pl-base');
    if (baseSelect) {
        baseSelect.innerHTML = '<option value="">-- Nessuno (Prezzi Standard Catalogo) --</option>';
        priceLists.forEach(l => {
            baseSelect.innerHTML += `<option value="${l.id}">${l.name}</option>`;
        });
        baseSelect.value = currentId;
    }

    const varGroup = document.getElementById('pl-variation-group');
    if (varGroup) varGroup.style.display = 'block';
    
    openModal('modal-manage-pricelists');
};

window.updateAllPriceListsDropdowns = function() {
    const ids = ['sam-listino', 'ris-listino', 'adm-listino', 'checkin-listino', 'config-select-listino', 'company-pricelist'];
    ids.forEach(id => {
        if (typeof window.populatePriceListsDropdown === 'function') {
            window.populatePriceListsDropdown(id);
        }
    });
};

window.submitManagePricelist = function(e) {
    if (e) e.preventDefault();
    const name = document.getElementById('new-pl-name').value.trim();
    const baseIdVal = document.getElementById('new-pl-base').value;
    const varVal = document.getElementById('new-pl-variation').value.trim();

    if (!name) {
        alert("Inserisci un nome valido per il listino.");
        return;
    }

    // Insert new pricelist
    const newPl = DB.insert('price_lists', { name: name });
    if (!newPl) {
        alert("Errore durante la creazione del listino.");
        return;
    }

    if (baseIdVal) {
        const baseId = parseInt(baseIdVal);
        const allItems = DB.get('price_list_items') || [];
        const baseItems = allItems.filter(item => item.price_list_id === baseId);
        const pct = varVal ? parseFloat(varVal) : 0;

        baseItems.forEach(baseItem => {
            let newPrice = baseItem.price;
            if (pct !== 0) {
                newPrice = baseItem.price * (1 + pct / 100);
                newPrice = Math.round(newPrice * 100) / 100;
            }
            allItems.push({
                price_list_id: newPl.id,
                service_id: baseItem.service_id,
                price: newPrice
            });
        });

        DB.set('price_list_items', allItems);
    }

    DB.logAudit(6, "CREATE_PRICE_LIST", "price_lists", newPl.id, { name, base_price_list_id: baseIdVal || null, variation_percent: varVal || 0 });

    // Update all dropdowns
    window.updateAllPriceListsDropdowns();

    // Select the newly created price list in config
    const listinoSelect = document.getElementById('config-select-listino');
    if (listinoSelect) {
        listinoSelect.value = newPl.id;
    }

    // Close modal and refresh table
    closeModal('modal-manage-pricelists');
    window.loadListinoPricesTable();
    alert(`Listino "${newPl.name}" creato con successo!`);
};

