window.previewStaffSignature = function(input) {
    const file = input.files[0];
    if (file) {
        const reader = new FileReader();
        reader.onload = function(e) {
            const base64 = e.target.result;
            document.getElementById('st-stamp-image-base64').value = base64;
            const preview = document.getElementById('st-signature-preview');
            const container = document.getElementById('st-signature-preview-container');
            if (preview && container) {
                preview.src = base64;
                container.style.display = 'block';
            }
        };
        reader.readAsDataURL(file);
    }
};

window.isUserAuthorizedToValidate = function() {
    const roleSelect = document.getElementById('user-role-select');
    const currentRole = roleSelect ? roleSelect.value : 'admin';
    if (currentRole === 'admin' || currentRole === 'biologo') return true;
    
    let docId = null;
    if (currentRole === 'doctor_1') docId = 1;
    else if (currentRole === 'doctor_2') docId = 2;
    
    if (docId) {
        const doctors = DB.get('doctors') || [];
        const doc = doctors.find(d => d.id === docId);
        if (doc && (doc.enabled_for_validation === 1 || doc.enabled_for_validation === true)) {
            return true;
        }
    }
    return false;
};

window.validateSample = function(sampleId) {
    if (!window.isUserAuthorizedToValidate()) {
        alert("Errore di autorizzazione: Solo l'amministratore, il biologo o un medico abilitato alla validazione possono convalidare questo esame.");
        return;
    }
    
    const loggedUser = JSON.parse(localStorage.getItem('nextcare_logged_in_user') || '{}');
    const currentStaffId = loggedUser.id || 6;
    
    const samples = DB.get('lab_samples') || [];
    const sam = samples.find(s => s.id === sampleId);
    if (!sam) return;

    // Find all samples in the same session
    let sessionSamples = [];
    if (sam.session_uid) {
        sessionSamples = samples.filter(s => s.session_uid === sam.session_uid && s.status !== 'suspended');
    } else {
        const patId = sam.patient_id;
        const dateStr = (sam.collected_at || sam.created_at || '').substring(0, 10);
        sessionSamples = samples.filter(s => {
            const sDateStr = (s.collected_at || s.created_at || '').substring(0, 10);
            return s.patient_id === patId && sDateStr === dateStr && !s.session_uid && s.status !== 'suspended';
        });
    }

    if (sessionSamples.length === 0) {
        sessionSamples = [sam];
    }

    const sessionSampleIds = sessionSamples.map(s => s.id);
    const tests = DB.get('lab_tests') || [];
    const timestamp = new Date().toISOString();
    tests.forEach(t => {
        if (sessionSampleIds.includes(t.sample_id)) {
            t.verified_by = currentStaffId;
            t.verified_at = timestamp;
        }
    });
    DB.set('lab_tests', tests);
    
    sessionSamples.forEach(currSam => {
        DB.update('lab_samples', currSam.id, { status: 'validated' });
        DB.logAudit(currentStaffId, "VALIDATE_LIS_SAMPLE", "lab_samples", currSam.id, { validated_by: currentStaffId });
    });
    
    if (sam.session_uid) {
        window.checkAndAutoReportAcceptance(sam.session_uid);
    }
    
    alert("Risultati dell'intera accettazione LIS convalidati clinicamente con successo!");
    closeModal('modal-enter-results');
    renderSamples();
    if (typeof window.renderLisValidationView === 'function') {
        window.renderLisValidationView();
    }
};

window.unvalidateSample = function(sampleId) {
    if (!window.isUserAuthorizedToValidate()) {
        alert("Errore di autorizzazione: Solo l'amministratore, il biologo o un medico abilitato alla validazione possono svalidare questo esame.");
        return;
    }
    
    if (!confirm("Sei sicuro di voler svalidare tutti i campioni di questa accettazione? Lo stato tornerà a 'Da Validare' e sarà possibile modificare o ripetere i risultati.")) {
        return;
    }
    
    const loggedUser = JSON.parse(localStorage.getItem('nextcare_logged_in_user') || '{}');
    const currentStaffId = loggedUser.id || 6;
    
    const samples = DB.get('lab_samples') || [];
    const sam = samples.find(s => s.id === sampleId);
    if (!sam) return;

    // Find all samples in the same session
    let sessionSamples = [];
    if (sam.session_uid) {
        sessionSamples = samples.filter(s => s.session_uid === sam.session_uid && s.status !== 'suspended');
    } else {
        const patId = sam.patient_id;
        const dateStr = (sam.collected_at || sam.created_at || '').substring(0, 10);
        sessionSamples = samples.filter(s => {
            const sDateStr = (s.collected_at || s.created_at || '').substring(0, 10);
            return s.patient_id === patId && sDateStr === dateStr && !s.session_uid && s.status !== 'suspended';
        });
    }

    if (sessionSamples.length === 0) {
        sessionSamples = [sam];
    }

    const sessionSampleIds = sessionSamples.map(s => s.id);
    const tests = DB.get('lab_tests') || [];
    const testsChanged = [];
    tests.forEach(t => {
        if (sessionSampleIds.includes(t.sample_id)) {
            t.verified_by = null;
            t.verified_at = null;
        }
    });
    DB.set('lab_tests', tests);
    
    sessionSamples.forEach(currSam => {
        DB.update('lab_samples', currSam.id, { 
            status: 'to_validate',
            signed_by_doctor_id: null
        });
        DB.logAudit(currentStaffId, "UNVALIDATE_LIS_SAMPLE", "lab_samples", currSam.id, { unvalidated_by: currentStaffId });
    });
    
    alert("Campioni svalidati con successo. Lo stato è stato reimpostato su 'Da Validare'.");
    closeModal('modal-enter-results');
    renderSamples();
    if (typeof window.renderLisValidationView === 'function') {
        window.renderLisValidationView();
    }
    if (typeof renderDashboard === 'function') {
        renderDashboard();
    }
};

window.repeatSample = function(sampleId) {
    if (!window.isUserAuthorizedToValidate()) {
        alert("Errore di autorizzazione: Solo l'amministratore, il biologo o un medico abilitato alla validazione possono richiedere la ripetizione di questo esame.");
        return;
    }
    
    if (!confirm("ATTENZIONE: Sei sicuro di voler ripetere l'esame per tutti i campioni di questa accettazione? Tutti i risultati verranno azzerati e i campioni torneranno in lavorazione.")) {
        return;
    }
    
    const loggedUser = JSON.parse(localStorage.getItem('nextcare_logged_in_user') || '{}');
    const currentStaffId = loggedUser.id || 6;
    
    const samples = DB.get('lab_samples') || [];
    const sam = samples.find(s => s.id === sampleId);
    if (!sam) return;

    // Find all samples in the same session
    let sessionSamples = [];
    if (sam.session_uid) {
        sessionSamples = samples.filter(s => s.session_uid === sam.session_uid && s.status !== 'suspended');
    } else {
        const patId = sam.patient_id;
        const dateStr = (sam.collected_at || sam.created_at || '').substring(0, 10);
        sessionSamples = samples.filter(s => {
            const sDateStr = (s.collected_at || s.created_at || '').substring(0, 10);
            return s.patient_id === patId && sDateStr === dateStr && !s.session_uid && s.status !== 'suspended';
        });
    }

    if (sessionSamples.length === 0) {
        sessionSamples = [sam];
    }

    const sessionSampleIds = sessionSamples.map(s => s.id);
    const tests = DB.get('lab_tests') || [];
    tests.forEach(t => {
        if (sessionSampleIds.includes(t.sample_id)) {
            t.result_value = null;
            t.status = null;
            t.verified_by = null;
            t.verified_at = null;
        }
    });
    DB.set('lab_tests', tests);
    
    sessionSamples.forEach(currSam => {
        DB.update('lab_samples', currSam.id, { 
            status: 'processing',
            signed_by_doctor_id: null,
            report_notes: null
        });
        DB.logAudit(currentStaffId, "REPEAT_LIS_SAMPLE", "lab_samples", currSam.id, { requested_by: currentStaffId });
    });
    
    alert("Ripetizione accettazione impostata correttamente. I campioni sono tornati in lavorazione e i risultati precedenti sono stati azzerati.");
    closeModal('modal-enter-results');
    renderSamples();
    if (typeof window.renderLisValidationView === 'function') {
        window.renderLisValidationView();
    }
    if (typeof renderDashboard === 'function') {
        renderDashboard();
    }
    if (typeof window.renderLisInstrumentEntryView === 'function') {
        window.renderLisInstrumentEntryView();
    }
};

