window.drawWbcScattergram = function(patientId) {
    const canvas = document.getElementById('val-scatter-canvas');
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    
    // Fill dark background
    ctx.fillStyle = '#0f172a';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    
    // Draw axes
    ctx.strokeStyle = '#334155';
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(15, 5);
    ctx.lineTo(15, canvas.height - 15);
    ctx.lineTo(canvas.width - 5, canvas.height - 15);
    ctx.stroke();
    
    // Axis labels
    ctx.fillStyle = '#64748b';
    ctx.font = '7px sans-serif';
    ctx.fillText("SSC (Complessità)", 20, 10);
    ctx.fillText("FSC (Volume)", canvas.width - 60, canvas.height - 5);
    
    // Generate cluster centers based on patient condition
    let lymPct = 32.4;
    let monoPct = 6.8;
    let neutPct = 58.2;
    let eosPct = 2.1;
    let basoPct = 0.5;
    
    if (patientId === 1) { // Mario Rossi - Normal
        lymPct = 30.5; monoPct = 7.2; neutPct = 59.8; eosPct = 2.0; basoPct = 0.5;
    } else if (patientId === 2) { // Flavia Bianchi - Lymphocytosis
        lymPct = 48.2; monoPct = 5.1; neutPct = 44.5; eosPct = 1.8; basoPct = 0.4;
    } else if (patientId === 3) { // Giovanni Verdi - Neutrophilia
        lymPct = 15.4; monoPct = 8.5; neutPct = 72.8; eosPct = 3.0; basoPct = 0.3;
    }
    
    document.getElementById('val-wbc-lym-pct').innerText = lymPct.toFixed(1) + '%';
    document.getElementById('val-wbc-mono-pct').innerText = monoPct.toFixed(1) + '%';
    document.getElementById('val-wbc-neut-pct').innerText = neutPct.toFixed(1) + '%';
    document.getElementById('val-wbc-eos-pct').innerText = eosPct.toFixed(1) + '%';
    document.getElementById('val-wbc-baso-pct').innerText = basoPct.toFixed(1) + '%';
    
    // Draw point clusters using Box-Muller transform for normal distribution
    function drawCluster(centerX, centerY, stdX, stdY, count, color) {
        ctx.fillStyle = color;
        for (let i = 0; i < count; i++) {
            let u1 = Math.random();
            let u2 = Math.random();
            if (u1 === 0) u1 = 0.0001;
            const z0 = Math.sqrt(-2.0 * Math.log(u1)) * Math.cos(2.0 * Math.PI * u2);
            const z1 = Math.sqrt(-2.0 * Math.log(u1)) * Math.sin(2.0 * Math.PI * u2);
            
            const x = centerX + z0 * stdX;
            const y = centerY + z1 * stdY;
            
            // Check canvas boundaries
            if (x >= 16 && x <= canvas.width - 6 && y >= 6 && y <= canvas.height - 16) {
                ctx.beginPath();
                ctx.arc(x, y, 0.8, 0, Math.PI * 2);
                ctx.fill();
            }
        }
    }
    
    // Debris/Platelets cluster (bottom-left)
    drawCluster(25, canvas.height - 20, 3, 2, 80, '#475569');
    
    // Lymphocytes (blue) - lower-left/mid-left
    let lymCount = Math.round(lymPct * 6);
    drawCluster(55, canvas.height - 40, 8, 8, lymCount, '#38bdf8');
    
    // Monocytes (green) - middle
    let monoCount = Math.round(monoPct * 6);
    drawCluster(90, canvas.height - 50, 10, 8, monoCount, '#4ade80');
    
    // Neutrophils (orange) - upper-right
    let neutCount = Math.round(neutPct * 6);
    drawCluster(135, canvas.height - 90, 15, 12, neutCount, '#f97316');
    
    // Eosinophils (yellow) - upper-mid
    let eosCount = Math.round(eosPct * 6);
    drawCluster(110, canvas.height - 110, 8, 6, eosCount, '#eab308');
    
    // Basophils (purple) - lower-right
    let basoCount = Math.round(basoPct * 6);
    drawCluster(75, canvas.height - 85, 6, 6, basoCount, '#a855f7');
};

window.selectTestForTrend = function(testName, patientId, unit, referenceRange) {
    const samples = DB.get('lab_samples') || [];
    const tests = DB.get('lab_tests') || [];
    
    const patientSamples = samples.filter(s => s.patient_id === patientId && (s.status === 'validated' || s.status === 'completed' || s.status === 'to_validate'));
    const patientSampleIds = patientSamples.map(s => s.id);
    
    const pastTests = tests.filter(t => patientSampleIds.includes(t.sample_id) && t.test_name === testName && t.result_value !== null && t.result_value !== undefined && String(t.result_value).trim() !== '');
    
    const historyData = pastTests.map(t => {
        const sam = patientSamples.find(s => s.id === t.sample_id);
        const dateStr = sam ? (sam.collected_at || sam.created_at) : null;
        return {
            date: dateStr ? new Date(dateStr) : new Date(),
            dateStr: dateStr ? new Date(dateStr).toLocaleDateString('it-IT') : '-',
            result_value: t.result_value,
            status: t.status
        };
    });
    
    historyData.sort((a, b) => a.date - b.date);
    
    const container = document.getElementById('val-trend-section');
    if (!container) return;
    
    document.getElementById('val-trend-test-title').innerText = `Storico & Andamento: ${testName}`;
    
    const listDiv = document.getElementById('val-history-list');
    if (listDiv) {
        listDiv.innerHTML = '';
        if (historyData.length === 0) {
            listDiv.innerHTML = '<span style="color: var(--text-secondary); font-style: italic;">Nessun dato storico.</span>';
        } else {
            const sortedList = [...historyData].sort((a,b) => b.date - a.date);
            let listHTML = '<table style="width:100%; border-collapse:collapse; font-size:0.72rem; text-align:left;">';
            listHTML += '<thead style="border-bottom:1px solid var(--border-color); color:var(--text-secondary);"><tr><th style="padding:2px 0;">Data</th><th style="padding:2px 0; text-align:right;">Risultato</th></tr></thead><tbody>';
            sortedList.forEach(item => {
                const valColor = item.status === 'flagged' ? 'color: var(--danger); font-weight:bold;' : 'color: var(--text-primary);';
                listHTML += `<tr style="border-bottom:1px solid var(--border-color);"><td style="padding:3px 0; color:var(--text-secondary);">${item.dateStr}</td><td style="padding:3px 0; text-align:right; ${valColor}">${item.result_value} ${unit}</td></tr>`;
            });
            listHTML += '</tbody></table>';
            listDiv.innerHTML = listHTML;
        }
    }
    
    const canvas = document.getElementById('val-trend-canvas');
    if (canvas) {
        const rect = canvas.getBoundingClientRect();
        canvas.width = rect.width || 380;
        canvas.height = rect.height || 130;
        
        const ctx = canvas.getContext('2d');
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        
        ctx.strokeStyle = '#e2e8f0';
        ctx.lineWidth = 1;
        ctx.strokeRect(0, 0, canvas.width, canvas.height);
        
        const numericalVals = historyData.filter(pt => !isNaN(parseFloat(String(pt.result_value).replace(',', '.')))).map(pt => ({
            date: pt.date,
            dateStr: pt.dateStr,
            val: parseFloat(String(pt.result_value).replace(',', '.'))
        }));
        
        if (numericalVals.length < 2) {
            ctx.fillStyle = '#64748b';
            ctx.font = '10px sans-serif';
            ctx.textAlign = 'center';
            ctx.fillText("Dati storici insufficienti per il grafico", canvas.width / 2, canvas.height / 2);
            ctx.textAlign = 'left';
            return;
        }
        
        const vals = numericalVals.map(d => d.val);
        let minVal = Math.min(...vals);
        let maxVal = Math.max(...vals);
        
        const range = maxVal - minVal;
        if (range === 0) {
            minVal = minVal * 0.8;
            maxVal = maxVal * 1.2;
        } else {
            minVal = minVal - range * 0.15;
            maxVal = maxVal + range * 0.15;
        }
        
        const valRange = maxVal - minVal;
        
        const paddingLeft = 35;
        const paddingRight = 15;
        const paddingTop = 15;
        const paddingBottom = 20;
        
        const graphWidth = canvas.width - paddingLeft - paddingRight;
        const graphHeight = canvas.height - paddingTop - paddingBottom;
        
        const getX = (index) => paddingLeft + (index / (numericalVals.length - 1)) * graphWidth;
        const getY = (val) => paddingTop + graphHeight - ((val - minVal) / valRange) * graphHeight;
        
        ctx.strokeStyle = '#f1f5f9';
        ctx.lineWidth = 1;
        for (let i = 0; i <= 4; i++) {
            const yVal = minVal + (i / 4) * valRange;
            const y = getY(yVal);
            ctx.beginPath();
            ctx.moveTo(paddingLeft, y);
            ctx.lineTo(canvas.width - paddingRight, y);
            ctx.stroke();
            
            ctx.fillStyle = '#64748b';
            ctx.font = '7px monospace';
            ctx.fillText(yVal.toFixed(1), 5, y + 3.5);
        }
        
        ctx.strokeStyle = '#0284c7';
        ctx.lineWidth = 2;
        ctx.beginPath();
        numericalVals.forEach((d, idx) => {
            const x = getX(idx);
            const y = getY(d.val);
            if (idx === 0) ctx.moveTo(x, y);
            else ctx.lineTo(x, y);
        });
        ctx.stroke();
        
        numericalVals.forEach((d, idx) => {
            const x = getX(idx);
            const y = getY(d.val);
            
            ctx.fillStyle = '#0284c7';
            ctx.beginPath();
            ctx.arc(x, y, 3.5, 0, Math.PI * 2);
            ctx.fill();
            ctx.fillStyle = '#ffffff';
            ctx.beginPath();
            ctx.arc(x, y, 1.5, 0, Math.PI * 2);
            ctx.fill();
            
            const labelStr = d.dateStr.split('/')[0] + '/' + d.dateStr.split('/')[1];
            ctx.fillStyle = '#64748b';
            ctx.font = '7px sans-serif';
            ctx.textAlign = 'center';
            ctx.fillText(labelStr, x, canvas.height - 6);
        });
        ctx.textAlign = 'left';
    }

    const isEmocromo = testName.toLowerCase().includes('emocromo');
    const scatterSection = document.getElementById('val-scattergram-section');
    if (scatterSection) {
        if (isEmocromo) {
            scatterSection.style.display = 'block';
            if (typeof window.drawWbcScattergram === 'function') {
                window.drawWbcScattergram(patientId);
            }
        } else {
            scatterSection.style.display = 'none';
        }
    }
};

window.printValidationList = function() {
    const samples = DB.get('lab_samples') || [];
    const patients = DB.get('patients') || [];
    const tests = DB.get('lab_tests') || [];

    const patientQuery = (document.getElementById('val-filter-patient')?.value || '').toLowerCase().trim();
    const barcodeQuery = (document.getElementById('val-filter-barcode')?.value || '').toLowerCase().trim();
    const startDate = document.getElementById('val-filter-start-date')?.value || '';
    const endDate = document.getElementById('val-filter-end-date')?.value || '';
    const statusFilter = document.getElementById('val-filter-status')?.value || 'to_validate';
    const flagsFilter = document.getElementById('val-filter-flags')?.value || 'all';

    const validStatuses = ['to_validate', 'validated', 'completed'];

    const filtered = samples.filter(sam => {
        if (!validStatuses.includes(sam.status)) return false;
        if (statusFilter !== 'all' && sam.status !== statusFilter) return false;
        if (barcodeQuery && !sam.barcode.toLowerCase().includes(barcodeQuery)) return false;
        
        const p = patients.find(pat => pat.id === sam.patient_id) || {};
        const pName = `${p.first_name || ''} ${p.last_name || ''} ${p.fiscal_code || ''}`.toLowerCase();
        if (patientQuery && !pName.includes(patientQuery)) return false;
        
        if (startDate) {
            const collected = new Date(sam.collected_at || sam.created_at);
            const start = new Date(startDate);
            start.setHours(0,0,0,0);
            if (collected < start) return false;
        }
        if (endDate) {
            const collected = new Date(sam.collected_at || sam.created_at);
            const end = new Date(endDate);
            end.setHours(23,59,59,999);
            if (collected > end) return false;
        }
        
        if (flagsFilter !== 'all') {
            const samTests = tests.filter(t => t.sample_id === sam.id);
            const hasFlags = samTests.some(t => t.status === 'flagged');
            if (flagsFilter === 'has_flags' && !hasFlags) return false;
            if (flagsFilter === 'normal_only' && hasFlags) return false;
        }
        
        return true;
    });

    if (filtered.length === 0) {
        alert("Nessun campione da stampare con i filtri correnti.");
        return;
    }

    const printWindow = window.open('', '_blank');
    if (!printWindow) {
        alert("Abilita i pop-up per poter visualizzare la stampa.");
        return;
    }

    let rowsHTML = '';
    filtered.forEach(sam => {
        const p = patients.find(pat => pat.id === sam.patient_id) || {};
        const pName = `${p.last_name || ''} ${p.first_name || ''}`.toUpperCase();
        const samTests = tests.filter(t => t.sample_id === sam.id);
        
        let testsListHTML = '<div style="font-size:0.75rem; color:#475569;">';
        samTests.forEach(t => {
            const isFlag = t.status === 'flagged';
            const flagText = isFlag ? ' <strong style="color:#ef4444;">[!]</strong>' : '';
            testsListHTML += `<span style="margin-right:12px; display:inline-block;">${t.test_name}: <strong>${t.result_value || '-'}</strong> ${t.unit || ''}${flagText}</span>`;
        });
        testsListHTML += '</div>';

        let statusText = 'Da Validare';
        if (sam.status === 'validated') statusText = 'Validato';
        else if (sam.status === 'completed') statusText = 'Refertato';

        const dateStr = sam.collected_at ? new Date(sam.collected_at).toLocaleDateString('it-IT') : new Date(sam.created_at).toLocaleDateString('it-IT');

        rowsHTML += `\n            <tr style="border-bottom:1px solid #e2e8f0;">\n                <td style="padding:8px; font-family:monospace; font-weight:bold;">${sam.barcode}</td>\n                <td style="padding:8px;">${dateStr}</td>\n                <td style="padding:8px; font-weight:bold;">${pName}</td>\n                <td style="padding:8px;">${sam.sample_type}</td>\n                <td style="padding:8px;">${statusText}</td>\n                <td style="padding:8px;">${testsListHTML}</td>\n            </tr>\n        `;
    });

    const filterInfo = `Filtri attivi: ${statusFilter === 'to_validate' ? 'Solo Da Validare' : statusFilter === 'validated' ? 'Solo Validati' : 'Tutti'} | Anomali: ${flagsFilter === 'has_flags' ? 'Solo Fuori Soglia' : flagsFilter === 'normal_only' ? 'Solo Normali' : 'Tutti'}`;

    printWindow.document.write(`\n        <html>\n        <head>\n            <title>NextCare LIS - Stampa Elenco Validazione</title>\n            <style>\n                body { font-family: sans-serif; color: #1e293b; padding: 20px; }\n                table { width: 100%; border-collapse: collapse; margin-top: 20px; }\n                th { background-color: #f1f5f9; text-align: left; padding: 8px; font-size: 0.8rem; text-transform: uppercase; color: #475569; border-bottom: 2px solid #cbd5e1; }\n                .header-table { width: 100%; border: none; margin-bottom: 20px; }\n                .header-table td { border: none; padding: 0; }\n                @media print {\n                    button { display: none; }\n                    body { padding: 0; }\n                }\n            </style>\n        </head>\n        <body>\n            <table class="header-table">\n                <tr>\n                    <td>\n                        <h2 style="margin:0; color:#0284c7;">NextCare - LIS</h2>\n                        <p style="margin:4px 0 0 0; font-size:0.85rem; color:#64748b;">Elenco Campioni per Validazione Clinica</p>\n                    </td>\n                    <td style="text-align:right; font-size:0.8rem; color:#64748b;">\n                        Stampato il: ${new Date().toLocaleString('it-IT')}<br>\n                        ${filterInfo}\n                    </td>\n                </tr>\n            </table>\n\n            <table>\n                <thead>\n                    <tr>\n                        <th style="width:100px;">Barcode</th>\n                        <th style="width:90px;">Data Prelievo</th>\n                        <th style="width:180px;">Paziente</th>\n                        <th style="width:100px;">Tipo</th>\n                        <th style="width:90px;">Stato</th>\n                        <th>Analisi e Risultati</th>\n                    </tr>\n                </thead>\n                <tbody>\n                    ${rowsHTML}\n                </tbody>\n            </table>\n\n            <div style="margin-top:30px; text-align:center;">\n                <button onclick="window.print();" style="padding:8px 16px; background-color:#0284c7; color:white; border:none; border-radius:4px; font-weight:bold; cursor:pointer;">Avvia Stampa</button>\n            </div>\n            <script>\n                window.onload = function() {\n                    setTimeout(function() { window.print(); }, 300);\n                }\n            </script>\n        </body>\n        </html>\n    `);
    printWindow.document.close();
};

window.selectedValidationSampleId = null;
window.selectedValidationSampleIds = [];

window.checkTestValueIsNormal = function(resultValue, referenceRange) {
    if (resultValue === null || resultValue === undefined || String(resultValue).trim() === '') {
        return 'pending';
    }
    const cleanValStr = String(resultValue).replace(',', '.').trim();
    const val = parseFloat(cleanValStr);
    if (isNaN(val)) {
        return 'completed'; // non-numeric (e.g. "Positivo", "Tracce"), assume normal
    }
    if (!referenceRange) return 'completed';

    const cleanRange = referenceRange.trim().replace(/\s+/g, '');

    // min-max
    const hyphenMatch = cleanRange.match(/^([0-9.]+)-([0-9.]+)$/);
    if (hyphenMatch) {
        const min = parseFloat(hyphenMatch[1]);
        const max = parseFloat(hyphenMatch[2]);
        return (val >= min && val <= max) ? 'completed' : 'flagged';
    }

    // < threshold
    const lessMatch = cleanRange.match(/^<([0-9.]+)$/);
    if (lessMatch) {
        return (val < parseFloat(lessMatch[1])) ? 'completed' : 'flagged';
    }

    // > threshold
    const greaterMatch = cleanRange.match(/^>([0-9.]+)$/);
    if (greaterMatch) {
        return (val > parseFloat(greaterMatch[1])) ? 'completed' : 'flagged';
    }

    // <= threshold
    const lessEqMatch = cleanRange.match(/^<=([0-9.]+)$/);
    if (lessEqMatch) {
        return (val <= parseFloat(lessEqMatch[1])) ? 'completed' : 'flagged';
    }

    // >= threshold
    const greaterEqMatch = cleanRange.match(/^>=([0-9.]+)$/);
    if (greaterEqMatch) {
        return (val >= parseFloat(greaterEqMatch[1])) ? 'completed' : 'flagged';
    }

    return 'completed';
};

window.isValidationSampleSelected = function(sampleId) {
    return window.selectedValidationSampleIds.includes(sampleId);
};

window.toggleAllValidationSelection = function(checked) {
    const checkboxes = document.querySelectorAll('.val-sample-checkbox');
    window.selectedValidationSampleIds = [];
    checkboxes.forEach(cb => {
        cb.checked = checked;
        const sId = parseInt(cb.getAttribute('data-sample-id'));
        if (checked && sId) {
            window.selectedValidationSampleIds.push(sId);
        }
    });
    window.updateValidationSelectedCount();
};

window.updateValidationSelectedCount = function() {
    const checkboxes = document.querySelectorAll('.val-sample-checkbox');
    const checkedIds = [];
    checkboxes.forEach(cb => {
        if (cb.checked) {
            checkedIds.push(parseInt(cb.getAttribute('data-sample-id')));
        }
    });
    window.selectedValidationSampleIds = checkedIds;

    const countSpan = document.getElementById('val-selected-count');
    if (countSpan) {
        countSpan.innerText = window.selectedValidationSampleIds.length;
    }
};

window.applyLisValidationFilters = function() {
    window.renderLisValidationView();
};

window.renderLisValidationView = function() {
    if (typeof window.seedValidationHistory === 'function') {
        window.seedValidationHistory();
    }
    const samples = DB.get('lab_samples') || [];
    const patients = DB.get('patients') || [];
    const tests = DB.get('lab_tests') || [];

    const patientQuery = (document.getElementById('val-filter-patient')?.value || '').toLowerCase().trim();
    const barcodeQuery = (document.getElementById('val-filter-barcode')?.value || '').toLowerCase().trim();
    const startDate = document.getElementById('val-filter-start-date')?.value || '';
    const endDate = document.getElementById('val-filter-end-date')?.value || '';
    const statusFilter = document.getElementById('val-filter-status')?.value || 'to_validate';
    const flagsFilter = document.getElementById('val-filter-flags')?.value || 'all';

    const validStatuses = ['to_validate', 'validated', 'completed'];

    const filtered = samples.filter(sam => {
        if (!validStatuses.includes(sam.status)) return false;

        const p = patients.find(pat => pat.id === sam.patient_id);
        if (!p) return false;

        if (patientQuery) {
            const fullName = `${p.last_name} ${p.first_name}`.toLowerCase();
            if (!fullName.includes(patientQuery)) return false;
        }

        if (barcodeQuery) {
            if (!sam.barcode.toLowerCase().includes(barcodeQuery)) return false;
        }

        const samDate = sam.collected_at ? sam.collected_at.substring(0, 10) : '';
        if (startDate && samDate < startDate) return false;
        if (endDate && samDate > endDate) return false;

        if (statusFilter !== 'all' && sam.status !== statusFilter) return false;

        const samTests = tests.filter(t => t.sample_id === sam.id);
        const hasFlag = samTests.some(t => t.status === 'flagged');
        
        if (flagsFilter === 'has_flags' && !hasFlag) return false;
        if (flagsFilter === 'normal_only' && hasFlag) return false;

        return true;
    });

    filtered.sort((a, b) => new Date(b.collected_at || 0) - new Date(a.collected_at || 0));

    const tbody = document.getElementById('val-samples-tbody');
    if (!tbody) return;
    tbody.innerHTML = '';

    if (filtered.length === 0) {
        tbody.innerHTML = `\n            <tr>\n                <td colspan="3" style="padding: 30px; text-align: center; color: var(--text-secondary); font-size: 0.85rem;">\n                    Nessun campione corrisponde ai filtri selezionati.\n                </td>\n            </tr>\n        `;
        window.selectedValidationSampleId = null;
        document.getElementById('val-detail-placeholder').style.display = 'flex';
        document.getElementById('val-detail-container').style.display = 'none';
        window.updateValidationSelectedCount();
        return;
    }

    filtered.forEach(sam => {
        const p = patients.find(pat => pat.id === sam.patient_id) || {};
        const pName = `${p.last_name} ${p.first_name}`;
        const formattedDate = sam.collected_at ? new Date(sam.collected_at).toLocaleDateString('it-IT') : '-';

        let statusBadge = '';
        if (sam.status === 'to_validate') {
            statusBadge = '<span class="badge badge-warning" style="background-color: #f97316; color: #fff; font-size: 0.7rem; padding: 2px 6px;">Da Validare</span>';
        } else if (sam.status === 'validated') {
            statusBadge = '<span class="badge badge-success" style="background-color: #10b981; color: #fff; font-size: 0.7rem; padding: 2px 6px;">Validato</span>';
        } else if (sam.status === 'completed') {
            statusBadge = '<span class="badge badge-info" style="background-color: #3b82f6; color: #fff; font-size: 0.7rem; padding: 2px 6px;">Refertato</span>';
        }

        const isChecked = window.isValidationSampleSelected(sam.id) ? 'checked' : '';

        const tr = document.createElement('tr');
        tr.style.cursor = 'pointer';
        tr.style.borderBottom = '1px solid var(--border-color)';
        if (window.selectedValidationSampleId === sam.id) {
            tr.style.background = 'var(--bg-base)';
        }

        tr.innerHTML = `\n            <td style="padding: 10px 12px; text-align: center;" onclick="event.stopPropagation()">\n                <input type="checkbox" class="val-sample-checkbox" data-sample-id="${sam.id}" ${isChecked} onchange="window.updateValidationSelectedCount()" style="cursor: pointer;">\n            </td>\n            <td style="padding: 10px 12px; font-size: 0.8rem;" onclick="window.selectValidationSample(${sam.id})">\n                <strong style="font-family: monospace; color: var(--text-primary);">${sam.barcode}</strong><br>\n                <span style="color: var(--text-secondary); font-weight: 500;">${pName}</span><br>\n                <span style="font-size: 0.7rem; color: var(--text-secondary);">${formattedDate} - ${sam.sample_type.split(' ')[0]}</span>\n            </td>\n            <td style="padding: 10px 12px; text-align: center; vertical-align: middle;" onclick="window.selectValidationSample(${sam.id})">\n                ${statusBadge}\n            </td>\n        `;
        tbody.appendChild(tr);
    });

    if (window.selectedValidationSampleId && filtered.some(s => s.id === window.selectedValidationSampleId)) {
        window.selectValidationSample(window.selectedValidationSampleId);
    } else {
        window.selectedValidationSampleId = null;
        document.getElementById('val-detail-placeholder').style.display = 'flex';
        document.getElementById('val-detail-container').style.display = 'none';
    }

    window.updateValidationSelectedCount();
};

window.selectValidationSample = function(sampleId) {
    window.selectedValidationSampleId = sampleId;

    const tbody = document.getElementById('val-samples-tbody');
    if (tbody) {
        const rows = tbody.querySelectorAll('tr');
        rows.forEach(r => {
            r.style.background = '';
        });
    }

    const checkboxes = document.querySelectorAll('.val-sample-checkbox');
    checkboxes.forEach(cb => {
        const sId = parseInt(cb.getAttribute('data-sample-id'));
        if (sId === sampleId) {
            const tr = cb.closest('tr');
            if (tr) tr.style.background = 'var(--bg-base)';
        }
    });

    const samples = DB.get('lab_samples') || [];
    const patients = DB.get('patients') || [];
    const tests = DB.get('lab_tests') || [];
    const staff = DB.get('staff') || [];

    const sam = samples.find(s => s.id === sampleId);
    if (!sam) return;

    const p = patients.find(pat => pat.id === sam.patient_id) || {};
    const pName = `${p.last_name} ${p.first_name}`;

    document.getElementById('val-detail-patient-name').innerText = pName;
    document.getElementById('val-detail-barcode').innerText = sam.barcode;
    document.getElementById('val-detail-type').innerText = sam.sample_type;

    let statusBadge = '';
    if (sam.status === 'to_validate') {
        statusBadge = '<span class="badge badge-warning" style="background-color: #f97316; color: #fff; font-size: 0.8rem; padding: 4px 8px;">Da Validare</span>';
    } else if (sam.status === 'validated') {
        statusBadge = '<span class="badge badge-success" style="background-color: #10b981; color: #fff; font-size: 0.8rem; padding: 4px 8px;">Validato</span>';
    } else if (sam.status === 'completed') {
        statusBadge = '<span class="badge badge-info" style="background-color: #3b82f6; color: #fff; font-size: 0.8rem; padding: 4px 8px;">Refertato</span>';
    }
    document.getElementById('val-detail-status-badge').innerHTML = statusBadge;

    const samTests = tests.filter(t => t.sample_id === sampleId);
    const testsTbody = document.getElementById('val-detail-tests-tbody');
    testsTbody.innerHTML = '';

    const categories = {
        'MICROBIOLOGIA': [],
        'CHIMICA CLINICA': [],
        'ELETTROFORESI PROTEICA': [],
        'EMOCROMO COMPLETO': [],
        'ESAME URINE': []
    };
    
    samTests.forEach(t => {
        let cat = 'CHIMICA CLINICA';
        let cleanName = t.test_name;
        
        if (window.isMicrobiologyService(t)) {
            cat = 'MICROBIOLOGIA';
        } else if (t.test_name.startsWith('Emocromo (')) {
            cat = 'EMOCROMO COMPLETO';
            cleanName = t.test_name.replace('Emocromo (', '').replace(')', '');
        } else if (t.test_name.startsWith('Elettroforesi (')) {
            cat = 'ELETTROFORESI PROTEICA';
            cleanName = t.test_name.replace('Elettroforesi (', '').replace(')', '');
        } else if (t.test_name.startsWith('Esame Urine (')) {
            cat = 'ESAME URINE';
            cleanName = t.test_name.replace('Esame Urine (', '').replace(')', '');
        }
        
        categories[cat].push({ original: t, cleanName: cleanName });
    });

    Object.keys(categories).forEach(catName => {
        const list = categories[catName];
        if (list.length === 0) return;
        
        const headerTr = document.createElement('tr');
        headerTr.style = 'background-color: var(--bg-base); border-bottom: 1px solid var(--border-color); pointer-events: none;';
        headerTr.innerHTML = `\n            <td colspan="5" style="padding: 6px 10px; font-weight: 700; color: var(--text-secondary); font-size: 0.72rem; text-transform: uppercase; letter-spacing: 0.5px; background-color: var(--bg-base);">\n                ${catName}\n            </td>\n        `;
        testsTbody.appendChild(headerTr);
        
        list.forEach(item => {
            const t = item.original;
            const isFlagged = t.status === 'flagged';
            const isVerified = t.verified_by !== null;
            
            let rowStyle = '';
            let flagBadge = '';
            if (window.isMicrobiologyService(t)) {
                if (t.result_value === 'Sviluppo Batterico') {
                    rowStyle = 'background-color: #fef2f2; color: #991b1b; font-weight: 500;';
                    flagBadge = '<span class="badge" style="background-color: #ef4444; color: #fff; font-size: 0.65rem; padding: 1px 4px;">POSITIVO</span>';
                } else if (t.result_value === 'Sterile') {
                    rowStyle = 'background-color: #f0fdf4; color: #166534;';
                    flagBadge = '<span class="badge" style="background-color: #10b981; color: #fff; font-size: 0.65rem; padding: 1px 4px;">NEGATIVO</span>';
                } else {
                    rowStyle = 'background-color: var(--bg-surface);';
                    flagBadge = '<span class="badge" style="background-color: #64748b; color: #fff; font-size: 0.65rem; padding: 1px 4px;">IN CORSO</span>';
                }
            } else {
                if (isFlagged) {
                    rowStyle = 'background-color: #fef2f2; color: #991b1b; font-weight: 500;';
                    flagBadge = '<span class="badge" style="background-color: #ef4444; color: #fff; font-size: 0.65rem; padding: 1px 4px;">FUORI SOGLIA</span>';
                } else {
                    rowStyle = 'background-color: #f0fdf4; color: #166534;';
                    flagBadge = '<span class="badge" style="background-color: #10b981; color: #fff; font-size: 0.65rem; padding: 1px 4px;">NORMALE</span>';
                }
            }

            let verBadge = '';
            if (isVerified) {
                const verStaff = staff.find(s => s.id === t.verified_by) || {};
                const verName = verStaff.last_name ? `${verStaff.first_name[0]}. ${verStaff.last_name}` : 'Sist.';
                verBadge = `<span class="text-success" style="font-size: 0.7rem; font-weight: bold;"><i data-lucide="check" style="width: 12px; height: 12px; display: inline-block; vertical-align: middle; margin-right: 2px;"></i> Validato (${verName})</span>`;
            } else {
                verBadge = '<span class="text-muted" style="font-size: 0.7rem; font-style: italic;">In attesa</span>';
            }

            const microDetailHTML = window.formatMicrobiologyDetailsForView(t);

            const tr = document.createElement('tr');
            tr.style = rowStyle + '; border-bottom: 1px solid var(--border-color); cursor: pointer; transition: all 0.15s ease;';
            tr.innerHTML = `\n                <td style="padding: 10px 10px; font-weight: 600; padding-left: 22px;">\n                    ${item.cleanName}\n                    ${microDetailHTML}\n                </td>\n                <td style="padding: 10px 10px; text-align: center; font-weight: bold; font-size: 0.9rem;">${t.result_value !== null ? t.result_value : '-'}</td>\n                <td style="padding: 10px 10px; font-family: monospace;">${t.unit || '-'}</td>\n                <td style="padding: 10px 10px;">${t.reference_range || 'N/A'}</td>\n                <td style="padding: 10px 10px; text-align: center;">\n                    <div style="display: flex; flex-direction: column; gap: 2px; align-items: center;">\n                        ${flagBadge}\n                        ${verBadge}\n                    </div>\n                </td>\n            `;
            tr.onclick = () => {
                const allRows = testsTbody.querySelectorAll('tr');
                allRows.forEach(r => {
                    r.style.borderLeft = '';
                    r.style.boxShadow = '';
                });
                tr.style.borderLeft = '4px solid var(--primary)';
                tr.style.boxShadow = 'inset 4px 0 0 var(--primary)';
                window.selectTestForTrend(t.test_name, sam.patient_id, t.unit || '', t.reference_range || '');
            };
            testsTbody.appendChild(tr);
        });
    });

    if (window.lucide) window.lucide.createIcons();

    document.getElementById('val-detail-placeholder').style.display = 'none';
    document.getElementById('val-detail-container').style.display = 'flex';

    if (samTests.length > 0) {
        const firstParamRow = Array.from(testsTbody.querySelectorAll('tr')).find(r => r.style.cursor === 'pointer');
        if (firstParamRow) {
            firstParamRow.click();
        }
    }

    const btnVal = document.getElementById('btn-val-detail-validate');
    if (btnVal) {
        if (sam.status === 'to_validate') {
            btnVal.disabled = false;
            btnVal.style.opacity = '1';
            btnVal.style.cursor = 'pointer';
        } else {
            btnVal.disabled = true;
            btnVal.style.opacity = '0.5';
            btnVal.style.cursor = 'not-allowed';
        }
    }
};

window.validateCurrentSample = function() {
    if (!window.selectedValidationSampleId) return;

    if (!window.isUserAuthorizedToValidate()) {
        alert("Errore di autorizzazione: Solo l'amministratore, il biologo o un medico abilitato alla validazione possono convalidare esami.");
        return;
    }
    
    if (!confirm("Confermi la validazione dei risultati per questo campione?")) return;

    const loggedUser = JSON.parse(localStorage.getItem('nextcare_logged_in_user') || '{}');
    const currentStaffId = loggedUser.id || 5;

    const sampleId = window.selectedValidationSampleId;
    const tests = DB.get('lab_tests') || [];
    const timestamp = new Date().toISOString();
    
    tests.forEach(t => {
        if (t.sample_id === sampleId) {
            t.verified_by = currentStaffId;
            t.verified_at = timestamp;
        }
    });
    DB.set('lab_tests', tests);

    const updatedSample = DB.update('lab_samples', sampleId, { status: 'validated' });
    DB.logAudit(currentStaffId, "LAB_VALIDATE_SAMPLE", "lab_samples", sampleId, { validated_by: currentStaffId });

    if (updatedSample && updatedSample.session_uid) {
        window.checkAndAutoReportAcceptance(updatedSample.session_uid);
    }

    alert("Campione validato con successo!");
    window.renderLisValidationView();
};

window.editResultsFromValidation = function() {
    if (!window.selectedValidationSampleId) return;
    window.openResultsModal(window.selectedValidationSampleId, true);
};

window.validateSelectedSamples = function() {
    if (!window.isUserAuthorizedToValidate()) {
        alert("Errore di autorizzazione: Solo l'amministratore, il biologo o un medico abilitato alla validazione possono convalidare esami.");
        return;
    }

    if (window.selectedValidationSampleIds.length === 0) {
        alert("Seleziona almeno un campione da validare.");
        return;
    }

    if (!confirm(`Confermi la validazione di ${window.selectedValidationSampleIds.length} campioni selezionati?`)) return;

    const loggedUser = JSON.parse(localStorage.getItem('nextcare_logged_in_user') || '{}');
    const currentStaffId = loggedUser.id || 5;

    const samples = DB.get('lab_samples') || [];
    const tests = DB.get('lab_tests') || [];
    const timestamp = new Date().toISOString();

    let count = 0;
    window.selectedValidationSampleIds.forEach(id => {
        const sam = samples.find(s => s.id === id);
        if (sam && sam.status === 'to_validate') {
            sam.status = 'validated';
            tests.forEach(t => {
                if (t.sample_id === id) {
                    t.verified_by = currentStaffId;
                    t.verified_at = timestamp;
                }
            });
            DB.logAudit(currentStaffId, "LAB_VALIDATE_SAMPLE", "lab_samples", id, { validated_by: currentStaffId });
            count++;
        }
    });

    const validatedSessionUids = new Set();
    window.selectedValidationSampleIds.forEach(id => {
        const sam = samples.find(s => s.id === id);
        if (sam && sam.status === 'validated' && sam.session_uid) {
            validatedSessionUids.add(sam.session_uid);
        }
    });

    DB.set('lab_samples', samples);
    DB.set('lab_tests', tests);

    validatedSessionUids.forEach(uid => {
        window.checkAndAutoReportAcceptance(uid);
    });

    alert(`Validati con successo ${count} campioni.`);
    window.selectedValidationSampleIds = [];
    window.renderLisValidationView();
};

window.validateSelectedAcceptances = function() {
    if (!window.isUserAuthorizedToValidate()) {
        alert("Errore di autorizzazione: Solo l'amministratore, il biologo o un medico abilitato alla validazione possono convalidare esami.");
        return;
    }

    if (window.selectedValidationSampleIds.length === 0) {
        alert("Seleziona almeno un campione per individuare le accettazioni da validare.");
        return;
    }

    const loggedUser = JSON.parse(localStorage.getItem('nextcare_logged_in_user') || '{}');
    const currentStaffId = loggedUser.id || 5;

    const samples = DB.get('lab_samples') || [];
    const selectedSamples = samples.filter(s => window.selectedValidationSampleIds.includes(s.id));
    
    const sessionKeys = new Set();
    selectedSamples.forEach(sam => {
        const key = sam.session_uid || `LEGACY-${sam.patient_id}-${(sam.collected_at || sam.created_at || '').substring(0, 13)}`;
        sessionKeys.add(key);
    });

    if (!confirm(`Confermi la validazione di tutte le accettazioni/sessioni collegate (${sessionKeys.size} sessioni)?`)) return;

    const tests = DB.get('lab_tests') || [];
    const timestamp = new Date().toISOString();
    let sampleCount = 0;

    samples.forEach(sam => {
        const key = sam.session_uid || `LEGACY-${sam.patient_id}-${(sam.collected_at || sam.created_at || '').substring(0, 13)}`;
        if (sessionKeys.has(key)) {
            if (sam.status === 'to_validate') {
                sam.status = 'validated';
                tests.forEach(t => {
                    if (t.sample_id === sam.id) {
                        t.verified_by = currentStaffId;
                        t.verified_at = timestamp;
                    }
                });
                DB.logAudit(currentStaffId, "LAB_VALIDATE_SAMPLE", "lab_samples", sam.id, { validated_by: currentStaffId });
                sampleCount++;
            }
        }
    });

    DB.set('lab_samples', samples);
    DB.set('lab_tests', tests);

    sessionKeys.forEach(key => {
        if (key && !key.startsWith('LEGACY-')) {
            window.checkAndAutoReportAcceptance(key);
        }
    });

    alert(`Validazione completata per le sessioni selezionate. Validati ${sampleCount} campioni.`);
    window.selectedValidationSampleIds = [];
    window.renderLisValidationView();
};

window.autoValidateNormalFiltered = function() {
    if (!window.isUserAuthorizedToValidate()) {
        alert("Errore di autorizzazione: Solo l'amministratore, il biologo o un medico abilitato alla validazione possono eseguire la validazione.");
        return;
    }

    const samples = DB.get('lab_samples') || [];
    const patients = DB.get('patients') || [];
    const tests = DB.get('lab_tests') || [];

    const patientQuery = (document.getElementById('val-filter-patient')?.value || '').toLowerCase().trim();
    const barcodeQuery = (document.getElementById('val-filter-barcode')?.value || '').toLowerCase().trim();
    const startDate = document.getElementById('val-filter-start-date')?.value || '';
    const endDate = document.getElementById('val-filter-end-date')?.value || '';
    const statusFilter = document.getElementById('val-filter-status')?.value || 'to_validate';
    const flagsFilter = document.getElementById('val-filter-flags')?.value || 'all';

    const validStatuses = ['to_validate'];

    const filtered = samples.filter(sam => {
        if (!validStatuses.includes(sam.status)) return false;

        const p = patients.find(pat => pat.id === sam.patient_id);
        if (!p) return false;

        if (patientQuery) {
            const fullName = `${p.last_name} ${p.first_name}`.toLowerCase();
            if (!fullName.includes(patientQuery)) return false;
        }

        if (barcodeQuery) {
            if (!sam.barcode.toLowerCase().includes(barcodeQuery)) return false;
        }

        const samDate = sam.collected_at ? sam.collected_at.substring(0, 10) : '';
        if (startDate && samDate < startDate) return false;
        if (endDate && samDate > endDate) return false;

        if (statusFilter !== 'all' && sam.status !== statusFilter) return false;

        const samTests = tests.filter(t => t.sample_id === sam.id);
        const hasFlag = samTests.some(t => t.status === 'flagged');
        
        if (flagsFilter === 'has_flags' && !hasFlag) return false;
        if (flagsFilter === 'normal_only' && hasFlag) return false;

        return true;
    });

    if (filtered.length === 0) {
        alert("Nessun campione in attesa corrisponde ai filtri selezionati.");
        return;
    }

    if (!confirm(`Confermi la validazione automatica delle analisi NORMALI nei ${filtered.length} campioni filtrati? I risultati fuori soglia rimarranno in sospeso.`)) return;

    const loggedUser = JSON.parse(localStorage.getItem('nextcare_logged_in_user') || '{}');
    const currentStaffId = loggedUser.id || 5;

    const timestamp = new Date().toISOString();
    let validatedTestsCount = 0;
    let validatedSamplesCount = 0;

    filtered.forEach(sam => {
        const samTests = tests.filter(t => t.sample_id === sam.id);
        
        samTests.forEach(t => {
            if (t.status === 'completed' && t.verified_by === null) {
                t.verified_by = currentStaffId;
                t.verified_at = timestamp;
                validatedTestsCount++;
            }
        });

        const allValidated = samTests.every(t => t.verified_by !== null);
        if (allValidated) {
            sam.status = 'validated';
            validatedSamplesCount++;
            DB.logAudit(currentStaffId, "LAB_VALIDATE_SAMPLE", "lab_samples", sam.id, { validated_by: currentStaffId, auto: true });
        }
    });

    DB.set('lab_tests', tests);
    DB.set('lab_samples', samples);

    alert(`Auto-validazione completata!\n\n- Analisi normali convalidate: ${validatedTestsCount}\n\n- Campioni interamente convalidati: ${validatedSamplesCount}/${filtered.length}`);
    window.renderLisValidationView();
};

window.printDivContent = function(elementOrId) {
    const el = (typeof elementOrId === 'string') ? document.getElementById(elementOrId) : elementOrId;
    if (!el) return;
    
    let iframe = document.getElementById('nextcare-print-iframe');
    if (!iframe) {
        iframe = document.createElement('iframe');
        iframe.id = 'nextcare-print-iframe';
        iframe.style.position = 'absolute';
        iframe.style.width = '0px';
        iframe.style.height = '0px';
        iframe.style.border = 'none';
        document.body.appendChild(iframe);
    }
    
    const doc = iframe.contentWindow.document;
    doc.open();
    doc.write('<html><head><title>Stampa Documento</title>');
    
    const links = document.querySelectorAll('link[rel="stylesheet"], style');
    links.forEach(l => {
        doc.write(l.outerHTML);
    });
    
    doc.write(`\n        <style>\n            body { background: white !important; color: black !important; padding: 20px !important; font-family: 'Inter', -apple-system, sans-serif; }\n            .report-print-container { box-shadow: none !important; border: none !important; padding: 0 !important; margin: 0 !important; max-width: 100% !important; width: 100% !important; pointer-events: none !important; }\n            @media print {\n                body { padding: 0 !important; }\n            }\n        </style>\n        </head>\n        <body>\n            <div class="report-print-container">\n                ${el.innerHTML}\n            </div>\n            <script>\n                window.onload = function() {\n                    window.focus();\n                    setTimeout(function() {\n                        window.print();\n                    }, 250);\n                };\n            </script>\n        </body>\n        </html>\n    `);
    doc.close();
};

window.printActiveModalReport = function() {
    const activeOverlay = document.querySelector('.modal-overlay.active');
    if (activeOverlay) {
        const printContainer = activeOverlay.querySelector('.report-print-container');
        if (printContainer) {
            window.printDivContent(printContainer);
            return;
        }
    }
    window.print();
};

window.drawLisTrendChart = function(data, testName, unit) {
    const chartContainer = document.getElementById('lis-chart-container');
    const canvas = document.getElementById('lis-trend-canvas');
    if (!canvas || !chartContainer) return;
    
    chartContainer.style.display = 'block';
    
    const ctx = canvas.getContext('2d');
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    ctx.strokeStyle = '#e2e8f0';
    ctx.lineWidth = 1;
    ctx.strokeRect(0, 0, canvas.width, canvas.height);
    
    ctx.fillStyle = '#1e293b';
    ctx.font = 'bold 10px sans-serif';
    ctx.fillText(`${testName} (${unit})`, 10, 15);
    
    const vals = data.map(d => d.val);
    const minVal = Math.min(...vals) * 0.9;
    const maxVal = Math.max(...vals) * 1.1;
    const valRange = maxVal - minVal || 1;
    
    const paddingLeft = 35;
    const paddingRight = 15;
    const paddingTop = 30;
    const paddingBottom = 25;
    
    const graphWidth = canvas.width - paddingLeft - paddingRight;
    const graphHeight = canvas.height - paddingTop - paddingBottom;
    
    const getX = (index) => paddingLeft + (index / (data.length - 1)) * graphWidth;
    const getY = (val) => paddingTop + graphHeight - ((val - minVal) / valRange) * graphHeight;
    
    ctx.strokeStyle = '#f1f5f9';
    ctx.lineWidth = 1;
    for (let i = 0; i <= 4; i++) {
        const yVal = minVal + (i / 4) * valRange;
        const y = getY(yVal);
        ctx.beginPath();
        ctx.moveTo(paddingLeft, y);
        ctx.lineTo(canvas.width - paddingRight, y);
        ctx.stroke();
        
        ctx.fillStyle = '#64748b';
        ctx.font = '8px monospace';
        ctx.fillText(yVal.toFixed(1), 5, y + 3);
    }
    
    ctx.strokeStyle = '#8b5cf6';
    ctx.lineWidth = 2;
    ctx.beginPath();
    data.forEach((d, idx) => {
        const x = getX(idx);
        const y = getY(d.val);
        if (idx === 0) ctx.moveTo(x, y);
        else ctx.lineTo(x, y);
    });
    ctx.stroke();
    
    data.forEach((d, idx) => {
        const x = getX(idx);
        const y = getY(d.val);
        
        ctx.fillStyle = '#8b5cf6';
        ctx.beginPath();
        ctx.arc(x, y, 4, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = '#ffffff';
        ctx.beginPath();
        ctx.arc(x, y, 2, 0, Math.PI * 2);
        ctx.fill();
        
        const dateObj = new Date(d.date);
        const dateStr = `${dateObj.getDate()}/${dateObj.getMonth() + 1}`;
        ctx.fillStyle = '#64748b';
        ctx.font = '8px sans-serif';
        ctx.textAlign = 'center';
        ctx.fillText(dateStr, x, canvas.height - 8);
    });
    ctx.textAlign = 'left';
};

window.openEditAppointmentModal = function(appId) {
    const appointments = DB.get('appointments') || [];
    const app = appointments.find(a => a.id === appId);
    if (!app) return;
    
    openAddAppointmentModal();
    
    document.getElementById('app-edit-id').value = app.id;
    window.setPatientSelectValue('app-patient', app.patient_id);
    document.getElementById('app-doctor').value = app.doctor_id || '';
    document.getElementById('app-datetime').value = app.appointment_datetime;
    document.getElementById('app-notes').value = app.notes || '';
    document.getElementById('app-duration').value = app.duration_minutes || 30;
    
    const appServices = DB.get('appointment_services') || [];
    selectedCupServiceIds = appServices.filter(as => as.appointment_id === appId).map(as => as.service_id);
    renderSelectedCupTags();
    
    document.querySelector('#modal-add-appointment h2').innerText = "Riprogramma / Modifica Prenotazione";
    document.querySelector('#form-add-appointment button[type="submit"]').innerText = "Salva Modifiche";
};

window.openCancelAppointmentModal = function(appId) {
    document.getElementById('cancel-app-id').value = appId;
    document.getElementById('cancel-reason').value = '';
    document.getElementById('cancel-notes').value = '';
    openModal('modal-cancel-appointment');
};

window.handleCancelAppointmentSubmit = function(e) {
    e.preventDefault();
    const appId = parseInt(document.getElementById('cancel-app-id').value);
    const reason = document.getElementById('cancel-reason').value;
    const notes = document.getElementById('cancel-notes').value;
    
    if (!reason) {
        alert("Selezionare il motivo dell'annullamento.");
        return;
    }
    
    const app = DB.get('appointments').find(a => a.id === appId);
    
    DB.update('appointments', appId, {
        status: 'cancelled',
        cancellation_reason: reason,
        cancellation_notes: notes
    });
    DB.logAudit(6, "CANCEL_APPOINTMENT", "appointments", appId, { reason, notes });

    // Send cancellation email
    const patient = app ? DB.get('patients').find(p => p.id === app.patient_id) : null;
    const appServices = DB.get('appointment_services') || [];
    const services = DB.get('medical_services') || [];
    const linkedServices = appServices.filter(as => as.appointment_id === appId).map(as => services.find(s => s.id === as.service_id)).filter(Boolean);
    const serviceNames = linkedServices.map(s => s.name).join(', ') || 'Prestazione';
    const appDateStr = app ? new Date(app.appointment_datetime).toLocaleString('it-IT') : 'N/A';

    if (patient) {
        const pName = `${patient.first_name} ${patient.last_name}`;
        const detail = `Motivo: ${reason}. Note: ${notes || 'Nessuna nota aggiuntiva'}`;
        window.sendSimulatedEmail(patient.id, 'cancel_appointment', {
            paziente: pName,
            data: appDateStr,
            prestazione: serviceNames,
            dettaglio: detail
        });
    }
    
    closeModal('modal-cancel-appointment');
    renderAppointments();
};

window.runPacsQueryRetrieve = function() {
    const queryName = document.getElementById('pacs-query-name').value.trim().toLowerCase();
    const queryModality = document.getElementById('pacs-query-modality').value;
    
    const log = document.getElementById('pacs-results-log');
    log.style.display = 'block';
    log.innerHTML = 'Avvio C-FIND RQ sul server PACS...<br>Stabilisco associazione DICOM... OK<br>Ricerca per parametri in corso...<br>';
    
    setTimeout(() => {
        const dummyStudies = [
            { id: 101, patientName: "Mario Rossi", birthDate: "1980-01-01", studyDate: "2026-06-11", modality: "CR", desc: "RX Torace Standard", dicom_uid: "1.2.840.113619.2.134.1" },
            { id: 102, patientName: "Mario Rossi", birthDate: "1980-01-01", studyDate: "2026-05-10", modality: "MR", desc: "Risonanza Encefalo", dicom_uid: "1.2.840.113619.2.134.2" },
            { id: 103, patientName: "Flavia Bianchi", birthDate: "1992-06-15", studyDate: "2026-06-02", modality: "US", desc: "Ecografia Addome", dicom_uid: "1.2.840.113619.2.134.3" }
        ];
        
        const filtered = dummyStudies.filter(s => {
            if (queryName && !s.patientName.toLowerCase().includes(queryName)) return false;
            if (queryModality && s.modality !== queryModality) return false;
            return true;
        });
        
        log.innerHTML += `C-FIND RSP Ricevuto. Trovati ${filtered.length} studi.<br>Rilascio associazione DICOM.`;
        
        const resultsDiv = document.getElementById('pacs-study-list');
        resultsDiv.innerHTML = '';
        
        if (filtered.length === 0) {
            resultsDiv.innerHTML = '<span class="text-muted" style="font-size:0.75rem; padding: 5px;">Nessun record corrispondente sul PACS</span>';
        } else {
            filtered.forEach(s => {
                resultsDiv.innerHTML += `\n                    <div style="display:flex; justify-content:space-between; align-items:center; padding:6px; background:var(--bg-base); border:1px solid var(--border-color); border-radius:4px; font-size:0.75rem; margin-bottom: 4px;">\n                        <div>\n                            <strong>${s.patientName}</strong> (${s.modality})<br>\n                            <span style="font-size:0.65rem; color:var(--text-secondary);">${s.desc} - ${s.studyDate}</span>\n                        </div>\n                        <button type="button" class="btn btn-secondary btn-sm" onclick="window.retrievePacsStudy('${s.dicom_uid}', '${s.patientName}', '${s.desc}')" style="padding:2px 6px; font-size:0.65rem;">C-GET</button>\n                    </div>\n                `;
            });
        }
    }, 1000);
};

window.retrievePacsStudy = function(uid, patName, desc) {
    document.getElementById('dicom-pat-id').innerText = "PACS-" + uid.split('.').pop();
    document.getElementById('dicom-pat-name').innerText = patName.toUpperCase();
    document.getElementById('dicom-study-type').innerText = desc;
    currentDicomImage = 'chest';
    drawDicomImage();
    alert(`[PACS INTEGRATION] Studio ${uid} recuperato con successo tramite C-GET. Caricato nel Visualizzatore DICOM.`);
};

window.sendDicomWorklist = function(studyId, eqId) {
    const studies = DB.get('radiology_studies') || [];
    const study = studies.find(s => s.id === studyId);
    if (!study) return;
    
    const equipments = DB.get('equipment') || [];
    const eq = equipments.find(e => e.id === eqId);
    if (!eq) return;
    
    const p = DB.get('patients').find(pat => pat.id === study.patient_id);
    const pName = p ? `${p.last_name} ${p.first_name}` : 'Paziente';
    
    alert(`[MWL DISPATCH SIMULATOR]\nInvio record Modality Worklist (C-FIND RSP):\n- Strumento: ${eq.name} (AE: ${eq.dicom_aetitle || 'EC_ROOM1'})\n- Indirizzo: ${eq.dicom_ip || '192.168.1.150'}:${eq.dicom_port || '104'}\n- Paziente: ${pName}\n- Esame: UID ${study.dicom_series_uid}\n- Stato: Inviato con successo al Modality Worklist!`);
};

window.initLisSimulator = function() {
    window.renderLisLogsAndSimulators();
    
    // Setup interval for logs polling
    if (!window.lisLogsInterval) {
        window.lisLogsInterval = setInterval(() => {
            if (currentTab === 'lis-logs') {
                window.pollInstrumentsLogsAndStatus();
            }
        }, 3000);
    }
};

