window.safeFormatDate = function(dateStr) {
    if (!dateStr) return '--';
    try {
        const d = new Date(dateStr);
        if (isNaN(d.getTime())) return '--';
        return d.toLocaleString('it-IT', { day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' });
    } catch (e) {
        return '--';
    }
};

window.renderReportingServices = function() {
    try {
        const appointments = (DB.get('appointments') || []).filter(Boolean);
        const appServices = (DB.get('appointment_services') || []).filter(Boolean);
        const services = (DB.get('medical_services') || []).filter(Boolean);
        const patients = (DB.get('patients') || []).filter(Boolean);
        const staff = (DB.get('staff') || []).filter(Boolean);
        const invoices = (DB.get('invoices') || []).filter(Boolean);
        const labTests = (DB.get('lab_tests') || []).filter(Boolean);
        const labSamples = (DB.get('lab_samples') || []).filter(Boolean);
        const radiologyStudies = (DB.get('radiology_studies') || []).filter(Boolean);
        const priceListItems = (DB.get('price_list_items') || []).filter(Boolean);

        // Dynamically populate branch select options (moved below to list population)

        // Read filters
        const typeVal = document.getElementById('rep-srv-filter-type').value;
        const statusVal = document.getElementById('rep-srv-filter-status').value;
        const startVal = document.getElementById('rep-srv-filter-start').value;
        const endVal = document.getElementById('rep-srv-filter-end').value;
        const branchVal = document.getElementById('rep-srv-filter-branch').value;
        const searchVal = document.getElementById('rep-srv-filter-search').value.toLowerCase().trim();

        const formatReportingCurrency = (val) => {
            const num = Number(val) || 0;
            return num < 0 ? `-€ ${Math.abs(num).toFixed(2)}` : `€ ${num.toFixed(2)}`;
        };

        let list = [];

        // 1. Gather LIS performances from lab_tests
        labTests.forEach(test => {
            const sample = labSamples.find(s => s.id === test.sample_id);
            if (!sample) return;
            
            const patient = patients.find(p => p.id === sample.patient_id);
            const srv = services.find(s => s.id === test.service_id) || { name: test.test_name, type: 'lis', code: '', price: 0, branch: 'Laboratorio' };

            // Resolve verifier doctor
            let docName = '--';
            if (test.verified_by) {
                const st = staff.find(s => s.id === test.verified_by);
                if (st) docName = `Dott. ${st.last_name}`;
            }

            // Determine status
            let status = 'in_progress';
            if (test.status === 'completed' || test.status === 'flagged') {
                status = 'completed';
            }

            // Resolve pricing from invoice
            const invoice = invoices.find(i => i.sample_id === sample.id && !i.is_insurance_invoice);
            let gross = Number(srv.price) || 0;
            let discount = 0;

            if (invoice) {
                if (invoice.custom_rates && invoice.custom_rates[srv.id] !== undefined) {
                    gross = Number(invoice.custom_rates[srv.id]) || 0;
                } else {
                    const listItem = priceListItems.find(pl => pl.price_list_id === invoice.price_list_id && pl.service_id === srv.id);
                    gross = Number(listItem ? listItem.price : gross) || 0;
                }
                const discount_value = Number(invoice.discount_value) || 0;
                const discount_amount = Number(invoice.discount_amount) || 0;
                const subtotal = Number(invoice.subtotal) || 0;
                if (invoice.discount_type === 'percentage') {
                    discount = gross * (discount_value / 100);
                } else if (invoice.discount_type === 'flat' && subtotal > 0) {
                    discount = discount_amount * (gross / subtotal);
                }
            } else {
                gross = 0.00;
                discount = 0.00;
            }
            discount = Number(discount) || 0;
            let net = gross - discount;

            list.push({
                date: sample.collected_at,
                patient_name: patient ? `${patient.last_name} ${patient.first_name}` : 'Paziente Esterno',
                patient_tax_code: patient ? patient.tax_code : '',
                service_name: srv.name,
                service_code: srv.code || '',
                doctor_name: docName,
                type: 'lis',
                branch: srv.branch || 'Laboratorio',
                gross: gross,
                discount: discount,
                net: net,
                status: status
            });
        });

        // 2. Gather RIS and Visit performances from radiology_studies
        radiologyStudies.forEach(study => {
            const patient = patients.find(p => p.id === study.patient_id);
            const srv = services.find(s => s.id === study.service_id) || { name: study.study_type === 'VISIT' ? 'Visita Specialistica' : 'Esame RIS', type: study.study_type === 'VISIT' ? 'visita' : 'ris', code: '', price: 0, branch: 'Diagnostica per immagini' };

            // Resolve doctor
            let docName = '--';
            const docStaffId = study.signed_by || study.doctor_id;
            if (docStaffId) {
                const st = staff.find(s => s.id === docStaffId);
                if (st) docName = `Dott. ${st.last_name}`;
            }

            // Determine status
            let status = 'in_progress';
            if (study.status === 'completed' || study.signed_at) {
                status = 'completed';
            }

            // Resolve pricing from invoice
            const invoice = invoices.find(i => (i.study_id === study.id || (i.appointment_id && appointments.some(a => a.id === i.appointment_id && a.patient_id === study.patient_id && window.compareDatetimes(a.appointment_datetime, study.scheduled_at)))) && !i.is_insurance_invoice);
            let gross = Number(srv.price) || 0;
            let discount = 0;

            if (invoice) {
                if (invoice.custom_rates && invoice.custom_rates[srv.id] !== undefined) {
                    gross = Number(invoice.custom_rates[srv.id]) || 0;
                } else {
                    const listItem = priceListItems.find(pl => pl.price_list_id === invoice.price_list_id && pl.service_id === srv.id);
                    gross = Number(listItem ? listItem.price : gross) || 0;
                }
                const discount_value = Number(invoice.discount_value) || 0;
                const discount_amount = Number(invoice.discount_amount) || 0;
                const subtotal = Number(invoice.subtotal) || 0;
                if (invoice.discount_type === 'percentage') {
                    discount = gross * (discount_value / 100);
                } else if (invoice.discount_type === 'flat' && subtotal > 0) {
                    discount = discount_amount * (gross / subtotal);
                }
            } else {
                gross = 0.00;
                discount = 0.00;
            }
            discount = Number(discount) || 0;
            let net = gross - discount;

            list.push({
                date: study.scheduled_at,
                patient_name: patient ? `${patient.last_name} ${patient.first_name}` : 'Paziente Esterno',
                patient_tax_code: patient ? patient.tax_code : '',
                service_name: srv.name,
                service_code: srv.code || '',
                doctor_name: docName,
                type: study.study_type === 'VISIT' ? 'visita' : 'ris',
                branch: srv.branch || (study.study_type === 'VISIT' ? 'Visita' : 'Radiologia'),
                gross: gross,
                discount: discount,
                net: net,
                status: status
            });
        });

        // 3. Gather scheduled appointments that have not been checked in yet (avoiding duplicates)
        appointments.forEach(app => {
            if (app.status !== 'scheduled') return; // completed/cancelled are handled via studies or skipped

            const patient = patients.find(p => p.id === app.patient_id);
            const srvIds = appServices.filter(as => as.appointment_id === app.id).map(as => as.service_id);
            const bookedServices = services.filter(s => srvIds.includes(s.id));

            // Resolve doctor
            let docName = '--';
            if (app.doctor_id) {
                const doc = DB.get('doctors').find(d => d.id === app.doctor_id);
                const st = doc ? staff.find(s => s.id === doc.staff_id) : null;
                if (st) docName = `Dott. ${st.last_name}`;
            }

            bookedServices.forEach(srv => {
                list.push({
                    date: app.appointment_datetime,
                    patient_name: patient ? `${patient.last_name} ${patient.first_name}` : 'Paziente',
                    patient_tax_code: patient ? patient.tax_code : '',
                    service_name: srv.name,
                    service_code: srv.code || '',
                    doctor_name: docName,
                    type: srv.type,
                    branch: srv.branch || 'Generale',
                    gross: Number(srv.price) || 0,
                    discount: 0,
                    net: Number(srv.price) || 0,
                    status: 'scheduled'
                });
            });
        });

        // 4. Gather Credit Notes (storni) from invoices
        invoices.forEach(inv => {
            const isCN = !!inv.is_credit_note || (inv.invoice_number && inv.invoice_number.startsWith('NDC-'));
            if (!isCN) return;

            let patient = null;
            if (inv.admission_id) {
                const adm = appointments.find(a => a.id === inv.admission_id);
                patient = adm ? patients.find(pat => pat.id === adm.patient_id) : null;
            } else if (inv.appointment_id) {
                const app = appointments.find(a => a.id === inv.appointment_id);
                patient = app ? patients.find(pat => pat.id === app.patient_id) : null;
            } else if (inv.sample_id) {
                const sam = labSamples.find(s => s.id === inv.sample_id);
                patient = sam ? patients.find(pat => pat.id === sam.patient_id) : null;
            } else if (inv.study_id) {
                const st = radiologyStudies.find(s => s.id === inv.study_id);
                patient = st ? patients.find(pat => pat.id === st.patient_id) : null;
            }

            const pName = patient ? `${patient.last_name} ${patient.first_name}` : 'Paziente Esterno';
            const pTax = patient ? patient.tax_code : '';

            // Check for stornati services in custom_rates
            const stornati = inv.custom_rates?.stornati_services;
            if (Array.isArray(stornati) && stornati.length > 0) {
                stornati.forEach(srv => {
                    list.push({
                        date: inv.issue_date + "T00:00",
                        patient_name: pName,
                        patient_tax_code: pTax,
                        service_name: `${srv.name} (Stornato)`,
                        service_code: srv.code || '',
                        doctor_name: '--',
                        type: srv.type === 'lis' ? 'lis' : (srv.type === 'VISIT' || srv.type === 'visita' ? 'visita' : 'ris'),
                        branch: srv.branch || (srv.type === 'lis' ? 'Laboratorio' : (srv.type === 'VISIT' || srv.type === 'visita' ? 'Visita' : 'Radiologia')),
                        gross: -Math.abs(srv.price),
                        discount: 0,
                        net: -Math.abs(srv.price),
                        status: 'stornata'
                    });
                });
            } else {
                // Fallback: representing the credit note as a single negative entry
                list.push({
                    date: inv.issue_date + "T00:00",
                    patient_name: pName,
                    patient_tax_code: pTax,
                    service_name: `Storno / Rimborso (${inv.invoice_number})`,
                    service_code: '',
                    doctor_name: '--',
                    type: 'storno',
                    branch: 'Amministrazione',
                    gross: -Math.abs(Number(inv.subtotal) || 0),
                    discount: 0,
                    net: -Math.abs(Number(inv.amount_due) || 0),
                    status: 'stornata'
                });
            }
        });

        // 5. Gather completed Rehab Sessions as individual performances
        const rehabCycles = DB.get('rehab_cycles') || [];
        const rehabSessions = DB.get('rehab_sessions') || [];
        rehabSessions.forEach(session => {
            if (session.status !== 'completed') return;

            const rc = rehabCycles.find(c => c.id === session.cycle_id);
            if (!rc) return;

            const patient = patients.find(p => p.id === rc.patient_id);
            
            let docName = '--';
            if (session.therapist_id) {
                const st = staff.find(s => s.id === session.therapist_id);
                if (st) docName = `${st.first_name.substring(0, 1)}. ${st.last_name}`;
            } else if (rc.doctor_id) {
                const st = staff.find(s => s.id === rc.doctor_id);
                if (st) docName = `Dott. ${st.last_name}`;
            }

            // Pricing
            const invoice = invoices.find(i => i.rehab_cycle_id === rc.id && !i.is_insurance_invoice);
            let gross = 50.00;
            let discount = 0;
            if (invoice) {
                gross = (Number(invoice.subtotal) || (rc.total_sessions * 50.00)) / rc.total_sessions;
                const discount_value = Number(invoice.discount_value) || 0;
                const discount_amount = Number(invoice.discount_amount) || 0;
                const subtotal = Number(invoice.subtotal) || 0;
                if (invoice.discount_type === 'percentage') {
                    discount = gross * (discount_value / 100);
                } else if (invoice.discount_type === 'flat' && subtotal > 0) {
                    discount = discount_amount * (gross / subtotal);
                }
            }
            discount = Number(discount) || 0;
            const net = gross - discount;

            list.push({
                date: session.scheduled_at || session.created_at,
                patient_name: patient ? `${patient.last_name} ${patient.first_name}` : 'Paziente',
                patient_tax_code: patient ? patient.tax_code : '',
                service_name: `Seduta Fisioterapia #${session.session_number} - ${rc.diagnosis || 'Riabilitazione'}`,
                service_code: 'FISIO',
                doctor_name: docName,
                type: 'rehab',
                branch: 'Fisioterapia',
                gross: gross,
                discount: discount,
                net: net,
                status: 'completed'
            });
        });

        // 6. Dynamically populate branch select options based on actual entries in list
        const branchSelect = document.getElementById('rep-srv-filter-branch');
        if (branchSelect && branchSelect.options.length <= 1) {
            const branches = [...new Set(list.map(s => s.branch).filter(Boolean))];
            branches.forEach(b => {
                const opt = document.createElement('option');
                opt.value = b;
                opt.innerText = b;
                branchSelect.appendChild(opt);
            });
        }

        const aiSearchVal = document.getElementById('rep-srv-filter-ai-search')?.value || '';
        let aiFilter = null;
        if (aiSearchVal) {
            aiFilter = window.parseNaturalLanguageQuery(aiSearchVal, 'rep_srv');
        }

        // Apply filtering
        const filtered = list.filter(item => {
            if (typeVal && item.type !== typeVal) return false;
            if (branchVal && item.branch !== branchVal) return false;

            if (aiFilter?.serviceType) {
                if (aiFilter.serviceType === 'visita' && item.type !== 'visita') return false;
                if (aiFilter.serviceType === 'lis' && item.type !== 'lis') return false;
                if (aiFilter.serviceType === 'ris' && item.type !== 'ris') return false;
                if (aiFilter.serviceType === 'rehab' && item.type !== 'rehab') return false;
            }

            const dateStr = item.date ? item.date.substring(0, 10) : '';
            if (startVal && dateStr < startVal) return false;
            if (aiFilter?.startDate && dateStr < aiFilter.startDate) return false;

            if (endVal && dateStr > endVal) return false;
            if (aiFilter?.endDate && dateStr > aiFilter.endDate) return false;

            if (statusVal && item.status !== statusVal) return false;
            if (aiFilter?.status) {
                if (aiFilter.status === 'scheduled' && item.status !== 'scheduled') return false;
                if (aiFilter.status === 'completed' && item.status !== 'completed') return false;
                if (aiFilter.status === 'in_progress' && item.status !== 'in_progress') return false;
                if (aiFilter.status === 'stornata' && item.status !== 'stornata') return false;
            }

            if (aiFilter?.doctorName) {
                if (!item.doctor_name.toLowerCase().includes(aiFilter.doctorName)) return false;
            }

            const searchQuery = (aiFilter ? aiFilter.textQuery : searchVal).toLowerCase().trim();
            if (searchQuery) {
                const pName = item.patient_name.toLowerCase();
                const pTax = item.patient_tax_code.toLowerCase();
                const dName = item.doctor_name.toLowerCase();
                const sName = item.service_name.toLowerCase();
                if (!pName.includes(searchQuery) && !pTax.includes(searchQuery) && !dName.includes(searchQuery) && !sName.includes(searchQuery)) {
                    return false;
                }
            }
            return true;
        });

        // Render table rows
        const tbody = document.querySelector('#reporting-services-table tbody');
        if (tbody) {
            tbody.innerHTML = '';
            
            const paginated = window.setupTablePagination('reporting-services-table', filtered, () => window.renderReportingServices());

            if (filtered.length === 0) {
                tbody.innerHTML = `<tr><td colspan="9" style="text-align:center;" class="text-muted">Nessuna prestazione erogata per i filtri selezionati</td></tr>`;
            } else {
                paginated.forEach(item => {
                    const tr = document.createElement('tr');
                    let statusBadge = '';
                    if (item.status === 'scheduled') statusBadge = '<span class="badge badge-info">Prenotata</span>';
                    else if (item.status === 'in_progress') statusBadge = '<span class="badge badge-warning">Accettata</span>';
                    else if (item.status === 'stornata') statusBadge = '<span class="badge badge-danger">Stornata</span>';
                    else statusBadge = '<span class="badge badge-success">Refertata</span>';

                    const displayDate = window.safeFormatDate(item.date);

                    const gVal = Number(item.gross) || 0;
                    const dVal = Number(item.discount) || 0;
                    const nVal = Number(item.net) || 0;

                    tr.innerHTML = `\n                        <td>${displayDate}</td>\n                        <td><strong>${item.patient_name}</strong><br><span style="font-size:0.7rem; color:var(--text-secondary); font-family:monospace;">${item.patient_tax_code}</span></td>\n                        <td>${item.service_name} ${item.service_code ? `<br><code style="font-size:0.75rem;">(${item.service_code})</code>` : ''}</td>\n                        <td>${item.doctor_name}</td>\n                        <td><span style="font-size:0.75rem; text-transform:uppercase; font-weight:600;">${item.type}</span> / <span class="text-muted" style="font-size:0.75rem;">${item.branch}</span></td>\n                        <td>${formatReportingCurrency(gVal)}</td>\n                        <td><span class="${dVal > 0 ? 'text-danger' : 'text-muted'}">${formatReportingCurrency(dVal)}</span></td>\n                        <td><strong>${formatReportingCurrency(nVal)}</strong></td>\n                        <td>${statusBadge}</td>\n                    `;
                    tbody.appendChild(tr);
                });
            }
        }

        // Update KPIs
        let totalGross = 0;
        let totalDiscount = 0;
        let totalNet = 0;

        filtered.forEach(item => {
            totalGross += Number(item.gross) || 0;
            totalDiscount += Number(item.discount) || 0;
            totalNet += Number(item.net) || 0;
        });

        const countKpi = document.getElementById('rep-srv-kpi-count');
        const revenueKpi = document.getElementById('rep-srv-kpi-revenue');
        const discountKpi = document.getElementById('rep-srv-kpi-discount');
        const netKpi = document.getElementById('rep-srv-kpi-net');

        if (countKpi) countKpi.innerText = filtered.length;
        if (revenueKpi) revenueKpi.innerText = formatReportingCurrency(totalGross);
        if (discountKpi) discountKpi.innerText = formatReportingCurrency(totalDiscount);
        if (netKpi) netKpi.innerText = formatReportingCurrency(totalNet);
    } catch (error) {
        console.error("Errore in renderReportingServices:", error);
        const tbody = document.querySelector('#reporting-services-table tbody');
        if (tbody) {
            tbody.innerHTML = `<tr><td colspan="9" style="text-align:center; color: var(--danger-color);" class="text-danger">\n                <strong>Errore nel rendering delle prestazioni:</strong><br>${error.message}\n            </td></tr>`;
        }
    }
};

