window.openEditTubeModal = function(id) {
    const tubes = DB.get('tube_types') || [];
    const tube = tubes.find(t => t.id === id);
    if (!tube) return;
    
    document.getElementById('tube-id').value = tube.id;
    document.getElementById('tube-name').value = tube.name;
    document.getElementById('tube-suffix').value = tube.suffix;
    document.getElementById('modal-tube-title').innerText = 'Modifica Tipo Provetta LIS';
    document.getElementById('btn-save-tube').innerText = 'Aggiorna Provetta';
    openModal('modal-add-tube');
};

window.handleTubeSubmit = function(e) {
    e.preventDefault();
    const idVal = document.getElementById('tube-id').value;
    const name = document.getElementById('tube-name').value.trim();
    const suffix = document.getElementById('tube-suffix').value.trim();
    
    const tubes = DB.get('tube_types') || [];
    
    // Verify suffix uniqueness
    const suffixDuplicate = tubes.find(t => t.suffix === suffix && (!idVal || t.id !== parseInt(idVal)));
    if (suffixDuplicate) {
        alert(`Errore: Il suffisso '${suffix}' è già in uso dalla provetta '${suffixDuplicate.name}'.`);
        return;
    }
    
    if (idVal) {
        const id = parseInt(idVal);
        DB.update('tube_types', id, { name, suffix });
        DB.logAudit(4, "UPDATE_TUBE_TYPE", "tube_types", id, { name, suffix });
    } else {
        const newTube = DB.insert('tube_types', { name, suffix });
        DB.logAudit(4, "CREATE_TUBE_TYPE", "tube_types", newTube.id, { name, suffix });
    }
    
    closeModal('modal-add-tube');
    window.renderServicesTubesTable();
    
    // Sync change dropdowns
    populateTubeTypesDropdown('srv-sample');
};

window.deleteServicesTubeType = function(id) {
    if (!confirm("Sei sicuro di voler eliminare questo tipo di provetta? I campioni esistenti associati rimarranno inalterati, ma non sarà più possibile selezionare questa provetta per nuovi esami.")) return;
    DB.delete('tube_types', id);
    DB.logAudit(4, "DELETE_TUBE_TYPE", "tube_types", id, {});
    window.renderServicesTubesTable();
    
    // Sync change dropdowns
    populateTubeTypesDropdown('srv-sample');
};

