// PRINT REGISTER OF INVOICES
window.printInvoicesReport = function() {
    const invoices = DB.get('invoices') || [];
    const patients = DB.get('patients') || [];
    const admissions = DB.get('admissions') || [];
    const appServices = DB.get('appointment_services') || [];
    const labTests = DB.get('lab_tests') || [];
    const services = DB.get('medical_services') || [];

    const startDateVal = document.getElementById('filter-acc-start-date').value;
    const endDateVal = document.getElementById('filter-acc-end-date').value;
    const paymentStatusVal = document.getElementById('filter-acc-payment-status').value;
    const aiSearchVal = document.getElementById('filter-acc-ai-search')?.value || '';

    let aiFilter = null;
    if (aiSearchVal) {
        aiFilter = window.parseNaturalLanguageQuery(aiSearchVal, 'accounting');
    }

    const filtered = invoices.filter(inv => {
        let p = null;
        let servicesList = [];
        
        if (inv.admission_id) {
            const adm = admissions.find(a => a.id === inv.admission_id);
            p = adm ? patients.find(pat => pat.id === adm.patient_id) : null;
            servicesList.push("Ricovero Ospedaliero");
        } else if (inv.appointment_id) {
            const app = DB.get('appointments').find(a => a.id === inv.appointment_id);
            p = app ? patients.find(pat => pat.id === app.patient_id) : null;
            const srvIds = appServices.filter(as => as.appointment_id === inv.appointment_id).map(as => as.service_id);
            const booked = services.filter(sv => srvIds.includes(sv.id));
            booked.forEach(srv => servicesList.push(srv.name));
        } else if (inv.sample_id) {
            const sam = DB.get('lab_samples').find(s => s.id === inv.sample_id);
            p = sam ? patients.find(pat => pat.id === sam.patient_id) : null;
            const srvIds = labTests.filter(t => t.sample_id === inv.sample_id).map(t => t.service_id);
            const booked = services.filter(sv => srvIds.includes(sv.id));
            booked.forEach(srv => servicesList.push(srv.name));
        }

        const patientName = p ? `${p.last_name} ${p.first_name}`.toLowerCase() : '';
        const servicesText = servicesList.join(', ').toLowerCase();

        if (startDateVal && inv.issue_date < startDateVal) return false;
        if (aiFilter?.startDate && inv.issue_date < aiFilter.startDate) return false;

        if (endDateVal && inv.issue_date > endDateVal) return false;
        if (aiFilter?.endDate && inv.issue_date > aiFilter.endDate) return false;

        if (paymentStatusVal && inv.payment_status !== paymentStatusVal) return false;
        if (aiFilter?.status) {
            if (aiFilter.status === 'completed' && inv.payment_status !== 'paid') return false;
            if (aiFilter.status === 'unpaid' && inv.payment_status !== 'unpaid') return false;
        }

        const searchQuery = (aiFilter ? aiFilter.textQuery : '').toLowerCase().trim();
        if (searchQuery) {
            const matchesPatient = patientName.includes(searchQuery) || (p && p.tax_code.toLowerCase().includes(searchQuery));
            const matchesServices = servicesText.includes(searchQuery);
            const matchesInvoiceNum = String(inv.invoice_number).includes(searchQuery);
            if (!matchesPatient && !matchesServices && !matchesInvoiceNum) return false;
        }

        return true;
    });

    let totalAmount = 0;
    let totalPaid = 0;
    let totalUnpaid = 0;

    let rowsHtml = '';
    filtered.forEach(inv => {
        let p = null;
        if (inv.admission_id) {
            const adm = admissions.find(a => a.id === inv.admission_id);
            p = adm ? patients.find(pat => pat.id === adm.patient_id) : null;
        } else if (inv.appointment_id) {
            const app = DB.get('appointments').find(a => a.id === inv.appointment_id);
            p = app ? patients.find(pat => pat.id === app.patient_id) : null;
        } else if (inv.sample_id) {
            const sam = DB.get('lab_samples').find(s => s.id === inv.sample_id);
            p = sam ? patients.find(pat => pat.id === sam.patient_id) : null;
        }

        const pName = p ? `${p.last_name} ${p.first_name}` : 'Paziente Esterno';
        const pTax = p ? p.tax_code : '-';
        const amount = Number(inv.total_amount || 0);
        totalAmount += amount;
        if (inv.payment_status === 'paid') totalPaid += amount;
        else totalUnpaid += amount;

        const pStatus = inv.payment_status === 'paid' ? '<span style="color: #16a34a; font-weight: bold;">Pagata</span>' : '<span style="color: #dc2626; font-weight: bold;">Non Pagata</span>';

        rowsHtml += `\n            <tr>\n                <td>Fattura N. ${inv.invoice_number}</td>\n                <td>${new Date(inv.issue_date).toLocaleDateString('it-IT')}</td>\n                <td>${pName}<br><small style="color:#666;">${pTax}</small></td>\n                <td>€ ${amount.toFixed(2)}</td>\n                <td>${pStatus}</td>\n            </tr>\n        `;
    });

    const printWin = window.open('', '_blank');
    printWin.document.write(`\n        <html>\n        <head>\n            <title>NextCare - Registro Fatture</title>\n            <style>\n                body { font-family: sans-serif; padding: 20px; color: #333; }\n                h1 { margin-bottom: 5px; color: #1e3a8a; }\n                table { width: 100%; border-collapse: collapse; margin-top: 20px; }\n                th, td { border: 1px solid #ddd; padding: 10px; text-align: left; }\n                th { background-color: #f3f4f6; }\n                .summary { margin-top: 20px; font-size: 1.1rem; text-align: right; }\n                .footer { margin-top: 50px; font-size: 0.8rem; text-align: center; color: #666; border-top: 1px dashed #ccc; padding-top: 10px; }\n            </style>\n        </head>\n        <body>\n            <h1>Registro delle Fatture Emesse</h1>\n            <p>Generato il: ${new Date().toLocaleString('it-IT')}</p>\n            ${startDateVal || endDateVal ? `<p>Periodo di selezione: ${startDateVal || 'Inizio'} al ${endDateVal || 'Fine'}</p>` : ''}\n            \n            <table>\n                <thead>\n                    <tr>\n                        <th>N. Documento</th>\n                        <th>Data Emissione</th>\n                        <th>Paziente / Codice Fiscale</th>\n                        <th>Importo Totale</th>\n                        <th>Stato Pagamento</th>\n                    </tr>\n                </thead>\n                <tbody>\n                    ${rowsHtml || '<tr><td colspan="5" style="text-align: center;">Nessun documento trovato</td></tr>'}\n                </tbody>\n            </table>\n\n            <div class="summary">\n                <p><strong>Totale Emesso:</strong> € ${totalAmount.toFixed(2)}</p>\n                <p><strong>Totale Pagato:</strong> € ${totalPaid.toFixed(2)}</p>\n                <p><strong>Totale Insoluto (Non Pagato):</strong> € ${totalUnpaid.toFixed(2)}</p>\n            </div>\n\n            <div class="footer">\n                NextCare Digital Health Platform &copy; ${new Date().getFullYear()} - Documento ad uso interno.\n            </div>\n\n            <script>\n                window.onload = function() { window.print(); }\n            </script>\n        </body>\n        </html>\n    `);
    printWin.document.close();
};

