// --- PRINT LIS ACC REPORT ---
window.printLisAccReport = function() {
    const samples = DB.get('lab_samples') || [];
    const patients = DB.get('patients') || [];
    const tests = DB.get('lab_tests') || [];
    const services = DB.get('medical_services') || [];

    const sessions = {};
    samples.forEach(sam => {
        let key = sam.session_uid;
        if (!key) {
            const dateStr = (sam.collected_at || sam.created_at || '').substring(0, 13);
            key = `LEGACY-${sam.patient_id}-${dateStr}`;
        }

        if (!sessions[key]) {
            sessions[key] = {
                session_uid: sam.session_uid || null,
                legacy_key: !sam.session_uid ? key : null,
                patient_id: sam.patient_id,
                collected_at: sam.collected_at || sam.created_at,
                samples: []
            };
        }
        sessions[key].samples.push(sam);
    });

    const sortedSessions = Object.values(sessions).sort((a, b) => new Date(b.collected_at) - new Date(a.collected_at));

    // Read filter inputs
    const aiSearchVal = document.getElementById('lis-acc-ai-search')?.value || '';
    const startDateVal = document.getElementById('lis-acc-filter-start')?.value || '';
    const endDateVal = document.getElementById('lis-acc-filter-end')?.value || '';
    const statusFilterVal = document.getElementById('lis-acc-filter-status')?.value || '';

    let aiFilter = null;
    if (aiSearchVal) {
        aiFilter = window.parseNaturalLanguageQuery(aiSearchVal, 'lis_acc');
    }

    const filteredSessions = sortedSessions.filter(session => {
        const p = patients.find(pat => pat.id === session.patient_id);
        if (!p) return false;

        const sessionDate = session.collected_at ? session.collected_at.substring(0, 10) : '';

        // Calculate session status
        const sessionSamples = session.samples;
        const sessionSampleIds = sessionSamples.map(s => s.id);
        const sessionTests = tests.filter(t => sessionSampleIds.includes(t.sample_id));
        
        let calculatedStatus = 'da prelevare';
        const allCompleted = sessionTests.length > 0 && sessionTests.every(t => t.status === 'completed');
        const hasProcessing = sessionSamples.some(s => s.status === 'received' || s.status === 'processing');
        if (allCompleted) calculatedStatus = 'completato';
        else if (hasProcessing || sessionSamples.some(s => s.status === 'collected')) calculatedStatus = 'in lavorazione';

        const testsText = sessionTests.map(t => {
            const srv = services.find(sv => sv.id === t.service_id);
            return srv ? srv.name.toLowerCase() : '';
        }).join(' ');

        // Apply start date filter
        if (startDateVal && sessionDate < startDateVal) return false;
        if (aiFilter?.startDate && sessionDate < aiFilter.startDate) return false;

        // Apply end date filter
        if (endDateVal && sessionDate > endDateVal) return false;
        if (aiFilter?.endDate && sessionDate > aiFilter.endDate) return false;

        // Apply status filter
        if (statusFilterVal && calculatedStatus !== statusFilterVal) return false;
        if (aiFilter?.status) {
            if (aiFilter.status === 'scheduled' && calculatedStatus !== 'da prelevare') return false;
            if (aiFilter.status === 'completed' && calculatedStatus !== 'completato') return false;
            if (aiFilter.status === 'in_progress' && calculatedStatus !== 'in lavorazione') return false;
        }

        // Apply text query search
        const searchQuery = (aiFilter ? aiFilter.textQuery : '').toLowerCase().trim();
        if (searchQuery) {
            const matchesPatient = `${p.first_name} ${p.last_name}`.toLowerCase().includes(searchQuery) || p.tax_code.toLowerCase().includes(searchQuery);
            const matchesTests = testsText.includes(searchQuery);
            if (!matchesPatient && !matchesTests) return false;
        }

        return true;
    });

    if (filteredSessions.length === 0) {
        alert("Nessuna accettazione da stampare per i filtri attivi.");
        return;
    }

    const printWindow = window.open('', '_blank');
    if (!printWindow) {
        alert("Abilita i pop-up per poter visualizzare il report.");
        return;
    }

    let rowsHtml = '';
    filteredSessions.forEach(sess => {
        const patient = patients.find(p => p.id === sess.patient_id);
        const pName = patient ? `${patient.last_name} ${patient.first_name}` : 'Sconosciuto';
        const pTax = patient ? patient.tax_code : '';
        const displayDate = window.safeFormatDate(sess.collected_at);

        // Barcodes
        const barcodes = sess.samples.map(s => s.barcode).join(', ');

        // Status
        const sessionSamples = sess.samples;
        const sessionSampleIds = sessionSamples.map(s => s.id);
        const sessionTests = tests.filter(t => sessionSampleIds.includes(t.sample_id));
        
        let calculatedStatus = 'Da prelevare';
        let badgeColor = '#3b82f6';
        const allCompleted = sessionTests.length > 0 && sessionTests.every(t => t.status === 'completed');
        const hasProcessing = sessionSamples.some(s => s.status === 'received' || s.status === 'processing');
        if (allCompleted) {
            calculatedStatus = 'Completato';
            badgeColor = '#10b981';
        } else if (hasProcessing || sessionSamples.some(s => s.status === 'collected')) {
            calculatedStatus = 'In lavorazione';
            badgeColor = '#f59e0b';
        }

        // Exams
        const examNames = sessionTests.map(t => {
            const srv = services.find(sv => sv.id === t.service_id);
            return srv ? srv.name : t.test_name;
        });
        const examsStr = [...new Set(examNames)].join(', ') || 'Nessun esame';

        rowsHtml += `\n            <tr>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;">${displayDate}</td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;"><strong>${pName}</strong><br><small style="color:#64748b;">${pTax}</small></td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0; font-family: monospace;">${barcodes}</td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;"><span style="display:inline-block; padding: 4px 8px; border-radius: 4px; color: white; background: ${badgeColor}; font-size: 0.75rem; font-weight: 700;">${calculatedStatus}</span></td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0; font-size: 0.8rem; color: #475569;">${examsStr}</td>\n            </tr>\n        `;
    });

    printWindow.document.write(`\n        <html>\n        <head>\n            <title>NextCare - Report Accettazioni LIS</title>\n            <style>\n                body { font-family: sans-serif; padding: 20px; color: #333; }\n                h1 { margin-bottom: 5px; color: #1e3a8a; }\n                table { width: 100%; border-collapse: collapse; margin-top: 20px; }\n                th, td { border: 1px solid #ddd; padding: 10px; text-align: left; }\n                th { background-color: #f3f4f6; }\n                .footer { margin-top: 50px; font-size: 0.8rem; text-align: center; color: #666; border-top: 1px dashed #ccc; padding-top: 10px; }\n            </style>\n        </head>\n        <body>\n            <h1>Registro Accettazioni LIS (Laboratorio)</h1>\n            <p>Generato il: ${new Date().toLocaleString('it-IT')}</p>\n            ${startDateVal || endDateVal ? `<p>Periodo: ${startDateVal || 'Inizio'} al ${endDateVal || 'Fine'}</p>` : ''}\n            \n            <table>\n                <thead>\n                    <tr>\n                        <th>Data Accettazione</th>\n                        <th>Paziente</th>\n                        <th>Codici a Barre</th>\n                        <th>Stato</th>\n                        <th>Esami Eseguiti</th>\n                    </tr>\n                </thead>\n                <tbody>\n                    ${rowsHtml}\n                </tbody>\n            </table>\n\n            <div class="footer">\n                NextCare Digital Health Platform &copy; ${new Date().getFullYear()} - Documento ad uso interno.\n            </div>\n\n            <script>\n                window.onload = function() { window.print(); }\n            </script>\n        </body>\n        </html>\n    `);
    printWindow.document.close();
};

// --- PRINT RIS REPORT ---
window.printRisReport = function() {
    const studies = DB.get('radiology_studies') || [];
    const patients = DB.get('patients') || [];
    const doctors = DB.get('doctors') || [];
    const staff = DB.get('staff') || [];
    const services = DB.get('medical_services') || [];

    const roleSelect = document.getElementById('user-role-select');
    const currentRole = roleSelect ? roleSelect.value : 'admin';

    // Read filter inputs
    const aiSearchVal = document.getElementById('ris-ai-search')?.value || '';
    const startDateVal = document.getElementById('ris-filter-start')?.value || '';
    const endDateVal = document.getElementById('ris-filter-end')?.value || '';
    const statusFilterVal = document.getElementById('ris-filter-status')?.value || '';
    const doctorFilterVal = document.getElementById('ris-filter-doctor')?.value || '';
    const requestingDoctorFilterVal = document.getElementById('ris-filter-requesting-doctor')?.value || '';

    let aiFilter = null;
    if (aiSearchVal) {
        aiFilter = window.parseNaturalLanguageQuery(aiSearchVal, 'ris');
    }

    const filtered = studies.filter(st => {
        const p = patients.find(pat => pat.id === st.patient_id);
        if (!p) return false;

        const doc = doctors.find(d => d.id === st.doctor_id);
        const docStaff = doc ? staff.find(s => s.id === doc.staff_id) : null;
        const docName = docStaff ? `${docStaff.first_name} ${docStaff.last_name}`.toLowerCase() : '';

        const srv = services.find(sv => sv.id === st.service_id);
        const srvName = srv ? srv.name.toLowerCase() : '';

        const studyDate = st.scheduled_at ? st.scheduled_at.substring(0, 10) : '';

        // Apply doctor filter (Medico Refertante)
        if (doctorFilterVal && st.signed_by !== parseInt(doctorFilterVal)) return false;

        // Apply requesting doctor filter (Medico Richiedente)
        if (requestingDoctorFilterVal && st.doctor_id !== parseInt(requestingDoctorFilterVal)) return false;
        if (aiFilter?.doctorName && !docName.includes(aiFilter.doctorName)) return false;

        // Apply start date filter
        if (startDateVal && studyDate < startDateVal) return false;
        if (aiFilter?.startDate && studyDate < aiFilter.startDate) return false;

        // Apply end date filter
        if (endDateVal && studyDate > endDateVal) return false;
        if (aiFilter?.endDate && studyDate > aiFilter.endDate) return false;

        // Apply status filter
        if (statusFilterVal && st.status !== statusFilterVal) return false;
        if (aiFilter?.status) {
            if (aiFilter.status === 'scheduled' && st.status !== 'scheduled') return false;
            if (aiFilter.status === 'completed' && st.status !== 'completed') return false;
        }

        // Apply role filter
        if (currentRole === 'doctor_1' && st.doctor_id !== 1) return false;
        if (currentRole === 'doctor_2' && st.doctor_id !== 2) return false;

        // Apply text query search
        const searchQuery = (aiFilter ? aiFilter.textQuery : '').toLowerCase().trim();
        if (searchQuery) {
            const matchesPatient = `${p.first_name} ${p.last_name}`.toLowerCase().includes(searchQuery) || p.tax_code.toLowerCase().includes(searchQuery);
            const matchesSrv = srvName.includes(searchQuery);
            if (!matchesPatient && !matchesSrv) return false;
        }

        return true;
    });

    if (filtered.length === 0) {
        alert("Nessuno studio RIS da stampare.");
        return;
    }

    const printWindow = window.open('', '_blank');
    if (!printWindow) {
        alert("Abilita i pop-up per poter visualizzare la stampa.");
        return;
    }

    let rowsHtml = '';
    filtered.forEach(st => {
        const p = patients.find(pat => pat.id === st.patient_id);
        const pName = p ? `${p.last_name} ${p.first_name}` : 'Sconosciuto';
        const pTax = p ? p.tax_code : '';

        const doc = doctors.find(d => d.id === st.doctor_id);
        const docStaff = doc ? staff.find(s => s.id === doc.staff_id) : null;
        const docNameStr = docStaff ? `Dott. ${docStaff.last_name}` : 'Non assegnato';

        const signerStaff = st.signed_by ? staff.find(s => s.id === st.signed_by) : null;
        const signerNameStr = signerStaff ? `Dott. ${signerStaff.last_name}` : 'Non refertato';

        const srv = services.find(sv => sv.id === st.service_id);
        const examName = srv ? srv.name : 'Esame RIS';

        const dateStr = window.safeFormatDate(st.scheduled_at);
        
        let statusLabel = 'Pianificato';
        let badgeColor = '#3b82f6';
        if (st.status === 'completed') {
            statusLabel = 'Refertato';
            badgeColor = '#10b981';
        }

        rowsHtml += `\n            <tr>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;"><strong>${pName}</strong><br><small style="color:#64748b;">${pTax}</small></td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;">${examName}</td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;">${docNameStr}</td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;">${signerNameStr}</td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;">${dateStr}</td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;"><span style="display:inline-block; padding: 4px 8px; border-radius: 4px; color: white; background: ${badgeColor}; font-size: 0.75rem; font-weight: 700;">${statusLabel}</span></td>\n            </tr>\n        `;
    });

    printWindow.document.write(`\n        <html>\n        <head>\n            <title>NextCare - Registro Studi RIS</title>\n            <style>\n                body { font-family: sans-serif; padding: 20px; color: #333; }\n                h1 { margin-bottom: 5px; color: #1e3a8a; }\n                table { width: 100%; border-collapse: collapse; margin-top: 20px; }\n                th, td { border: 1px solid #ddd; padding: 10px; text-align: left; }\n                th { background-color: #f3f4f6; }\n                .footer { margin-top: 50px; font-size: 0.8rem; text-align: center; color: #666; border-top: 1px dashed #ccc; padding-top: 10px; }\n            </style>\n        </head>\n        <body>\n            <h1>Registro Studi di Radiologia (RIS)</h1>\n            <p>Generato il: ${new Date().toLocaleString('it-IT')}</p>\n            ${startDateVal || endDateVal ? `<p>Periodo: ${startDateVal || 'Inizio'} al ${endDateVal || 'Fine'}</p>` : ''}\n            \n            <table>
                <thead>
                    <tr>
                        <th>Paziente</th>
                        <th>Esame</th>
                        <th>Medico Esecutore</th>
                        <th>Medico Refertante</th>
                        <th>Data Esame</th>
                        <th>Stato</th>
                    </tr>
                </thead>
                <tbody>
                    ${rowsHtml}
                </tbody>
            </table>\n\n            <div class="footer">\n                NextCare Digital Health Platform &copy; ${new Date().getFullYear()} - Documento ad uso interno.\n            </div>\n\n            <script>\n                window.onload = function() { window.print(); }\n            </script>\n        </body>\n        </html>\n    `);
    printWindow.document.close();
};

// --- PRINT CUP REPORT ---
window.printCupReport = function() {
    const appointments = DB.get('appointments') || [];
    const patients = DB.get('patients') || [];
    const doctors = DB.get('doctors') || [];
    const staff = DB.get('staff') || [];
    const services = DB.get('medical_services') || [];
    const appServices = DB.get('appointment_services') || [];

    const roleSelect = document.getElementById('user-role-select');
    const currentRole = roleSelect ? roleSelect.value : 'admin';

    // Read filter inputs
    const aiSearchVal = document.getElementById('cup-ai-search')?.value || '';
    const startDateVal = document.getElementById('cup-filter-start-date')?.value || '';
    const endDateVal = document.getElementById('cup-filter-end-date')?.value || '';
    const doctorFilterVal = document.getElementById('cup-filter-doctor')?.value || '';
    const statusFilterVal = document.getElementById('cup-filter-status')?.value || '';

    let aiFilter = null;
    if (aiSearchVal) {
        aiFilter = window.parseNaturalLanguageQuery(aiSearchVal, 'cup');
    }

    const filtered = appointments.filter(app => {
        const p = patients.find(pat => pat.id === app.patient_id);
        if (!p) return false;

        const doc = doctors.find(d => d.id === app.doctor_id);
        const s = doc ? staff.find(st => st.id === doc.staff_id) : null;
        const docName = s ? `${s.first_name} ${s.last_name}`.toLowerCase() : '';

        const srvIds = appServices.filter(as => as.appointment_id === app.id).map(as => as.service_id);
        const associatedServices = services.filter(sv => srvIds.includes(sv.id));
        const servicesText = associatedServices.map(sv => sv.name.toLowerCase()).join(' ');

        const appDateStr = app.appointment_datetime.substring(0, 10);

        // Apply role filter
        if (currentRole === 'doctor_1' && app.doctor_id !== 1) return false;
        if (currentRole === 'doctor_2' && app.doctor_id !== 2) return false;

        // Apply start date filter
        if (startDateVal && appDateStr < startDateVal) return false;
        if (aiFilter?.startDate && appDateStr < aiFilter.startDate) return false;

        // Apply end date filter
        if (endDateVal && appDateStr > endDateVal) return false;
        if (aiFilter?.endDate && appDateStr > aiFilter.endDate) return false;

        // Apply doctor filter
        if (doctorFilterVal && app.doctor_id !== parseInt(doctorFilterVal)) return false;
        if (aiFilter?.doctorName && !docName.includes(aiFilter.doctorName)) return false;

        // Apply status filter
        if (statusFilterVal && app.status !== statusFilterVal) return false;
        if (aiFilter?.status) {
            if (aiFilter.status === 'scheduled' && app.status !== 'scheduled') return false;
            if (aiFilter.status === 'completed' && app.status !== 'completed') return false;
            if (aiFilter.status === 'cancelled' && app.status !== 'cancelled') return false;
        }

        // Apply text query search
        const searchQuery = (aiFilter ? aiFilter.textQuery : '').toLowerCase().trim();
        if (searchQuery) {
            const matchesPatient = `${p.first_name} ${p.last_name}`.toLowerCase().includes(searchQuery) || p.tax_code.toLowerCase().includes(searchQuery);
            const matchesDoctor = docName.includes(searchQuery);
            const matchesService = servicesText.includes(searchQuery);
            if (!matchesPatient && !matchesDoctor && !matchesService) return false;
        }

        return true;
    });

    if (filtered.length === 0) {
        alert("Nessuna prenotazione da stampare.");
        return;
    }

    const printWindow = window.open('', '_blank');
    if (!printWindow) {
        alert("Abilita i pop-up per poter visualizzare la stampa.");
        return;
    }

    let rowsHtml = '';
    filtered.forEach(app => {
        const p = patients.find(pat => pat.id === app.patient_id);
        const pName = p ? `${p.last_name} ${p.first_name}` : 'Sconosciuto';
        const pTax = p ? p.tax_code : '';

        const doc = doctors.find(d => d.id === app.doctor_id);
        const s = doc ? staff.find(st => st.id === doc.staff_id) : null;
        const docNameStr = s ? `Dott. ${s.last_name}` : 'Non assegnato';

        const srvIds = appServices.filter(as => as.appointment_id === app.id).map(as => as.service_id);
        const associatedServices = services.filter(sv => srvIds.includes(sv.id));
        const servicesNames = associatedServices.map(sv => sv.name).join(', ') || 'Nessuna prestazione';

        const displayDate = window.safeFormatDate(app.appointment_datetime);

        let statusLabel = 'Pianificata';
        let badgeColor = '#3b82f6';
        if (app.status === 'completed') {
            statusLabel = 'Completata';
            badgeColor = '#10b981';
        } else if (app.status === 'cancelled') {
            statusLabel = 'Annullata';
            badgeColor = '#ef4444';
        }

        rowsHtml += `\n            <tr>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;">${displayDate}</td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;"><strong>${pName}</strong><br><small style="color:#64748b;">${pTax}</small></td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;">${docNameStr}</td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0; font-size: 0.8rem; color: #475569;">${servicesNames}</td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;"><span style="display:inline-block; padding: 4px 8px; border-radius: 4px; color: white; background: ${badgeColor}; font-size: 0.75rem; font-weight: 700;">${statusLabel}</span></td>\n            </tr>\n        `;
    });

    printWindow.document.write(`\n        <html>\n        <head>\n            <title>NextCare - Report Prenotazioni CUP</title>\n            <style>\n                body { font-family: sans-serif; padding: 20px; color: #333; }\n                h1 { margin-bottom: 5px; color: #1e3a8a; }\n                table { width: 100%; border-collapse: collapse; margin-top: 20px; }\n                th, td { border: 1px solid #ddd; padding: 10px; text-align: left; }\n                th { background-color: #f3f4f6; }\n                .footer { margin-top: 50px; font-size: 0.8rem; text-align: center; color: #666; border-top: 1px dashed #ccc; padding-top: 10px; }\n            </style>\n        </head>\n        <body>\n            <h1>Registro delle Prenotazioni CUP</h1>\n            <p>Generato il: ${new Date().toLocaleString('it-IT')}</p>\n            ${startDateVal || endDateVal ? `<p>Periodo: ${startDateVal || 'Inizio'} al ${endDateVal || 'Fine'}</p>` : ''}\n            \n            <table>\n                <thead>\n                    <tr>\n                        <th>Data e Ora</th>\n                        <th>Paziente</th>\n                        <th>Medico Assegnato</th>\n                        <th>Prestazioni</th>\n                        <th>Stato</th>\n                    </tr>\n                </thead>\n                <tbody>\n                    ${rowsHtml}\n                </tbody>\n            </table>\n\n            <div class="footer">\n                NextCare Digital Health Platform &copy; ${new Date().getFullYear()} - Documento ad uso interno.\n            </div>\n\n            <script>\n                window.onload = function() { window.print(); }\n            </script>\n        </body>\n        </html>\n    `);
    printWindow.document.close();
};

// --- PRINT ADMISSIONS REPORT ---
window.printAdmReport = function() {
    const admissions = DB.get('admissions') || [];
    const patients = DB.get('patients') || [];
    const clinics = DB.get('clinics') || [];

    // Fetch filter values
    const aiSearchVal = document.getElementById('adm-ai-search')?.value || '';
    const startDateVal = document.getElementById('adm-filter-start')?.value || '';
    const endDateVal = document.getElementById('adm-filter-end')?.value || '';
    const clinicFilterVal = document.getElementById('adm-filter-clinic')?.value || '';

    let aiFilter = null;
    if (aiSearchVal) {
        aiFilter = window.parseNaturalLanguageQuery(aiSearchVal, 'adm');
    }

    const filtered = admissions.filter(adm => {
        const p = patients.find(pat => pat.id === adm.patient_id);
        if (!p) return false;

        const admDate = adm.admission_date ? adm.admission_date.substring(0, 10) : '';

        // Apply department (clinic) filter
        if (clinicFilterVal) {
            const selectedClinic = clinics.find(c => c.id === parseInt(clinicFilterVal));
            if (selectedClinic && adm.department.toLowerCase() !== selectedClinic.name.toLowerCase()) return false;
        }

        // Apply start date
        if (startDateVal && admDate < startDateVal) return false;
        if (aiFilter?.startDate && admDate < aiFilter.startDate) return false;

        // Apply end date
        if (endDateVal && admDate > endDateVal) return false;
        if (aiFilter?.endDate && admDate > aiFilter.endDate) return false;

        // Apply active vs discharged filter if specified, otherwise show all
        if (aiFilter?.status) {
            if (aiFilter.status === 'completed' && adm.status !== 'discharged') return false;
            if (aiFilter.status === 'in_progress' && adm.status !== 'active') return false;
        } else if (aiSearchVal.toLowerCase().includes('dimess') || aiSearchVal.toLowerCase().includes('storico')) {
            if (adm.status !== 'discharged') return false;
        } else if (aiSearchVal.toLowerCase().includes('attivo') || aiSearchVal.toLowerCase().includes('degente')) {
            if (adm.status !== 'active') return false;
        }

        // Apply text search
        const searchQuery = (aiFilter ? aiFilter.textQuery : '').toLowerCase().trim();
        if (searchQuery) {
            const matchesPatient = `${p.first_name} ${p.last_name}`.toLowerCase().includes(searchQuery) || p.tax_code.toLowerCase().includes(searchQuery);
            const matchesDept = adm.department.toLowerCase().includes(searchQuery);
            if (!matchesPatient && !matchesDept) return false;
        }

        return true;
    });

    if (filtered.length === 0) {
        alert("Nessun ricovero da stampare.");
        return;
    }

    const printWindow = window.open('', '_blank');
    if (!printWindow) {
        alert("Abilita i pop-up per poter visualizzare la stampa.");
        return;
    }

    let rowsHtml = '';
    filtered.forEach(adm => {
        const p = patients.find(pat => pat.id === adm.patient_id);
        const pName = p ? `${p.last_name} ${p.first_name}` : 'Sconosciuto';
        const pTax = p ? p.tax_code : '';

        const entranceDate = window.safeFormatDate(adm.admission_date);
        const exitDate = adm.discharge_date ? window.safeFormatDate(adm.discharge_date) : 'In corso';

        let statusLabel = 'Degente';
        let badgeColor = '#f59e0b';
        if (adm.status === 'discharged') {
            statusLabel = 'Dimesso';
            badgeColor = '#10b981';
        }

        rowsHtml += `\n            <tr>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;"><strong>${pName}</strong><br><small style="color:#64748b;">${pTax}</small></td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;">${adm.department}</td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;">${entranceDate}</td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;">${exitDate}</td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;"><span style="display:inline-block; padding: 4px 8px; border-radius: 4px; color: white; background: ${badgeColor}; font-size: 0.75rem; font-weight: 700;">${statusLabel}</span></td>\n            </tr>\n        `;
    });

    printWindow.document.write(`\n        <html>\n        <head>\n            <title>NextCare - Registro Ricoveri</title>\n            <style>\n                body { font-family: sans-serif; padding: 20px; color: #333; }\n                h1 { margin-bottom: 5px; color: #1e3a8a; }\n                table { width: 100%; border-collapse: collapse; margin-top: 20px; }\n                th, td { border: 1px solid #ddd; padding: 10px; text-align: left; }\n                th { background-color: #f3f4f6; }\n                .footer { margin-top: 50px; font-size: 0.8rem; text-align: center; color: #666; border-top: 1px dashed #ccc; padding-top: 10px; }\n            </style>\n        </head>\n        <body>\n            <h1>Registro Ricoveri Ospedalieri</h1>\n            <p>Generato il: ${new Date().toLocaleString('it-IT')}</p>\n            ${startDateVal || endDateVal ? `<p>Periodo: ${startDateVal || 'Inizio'} al ${endDateVal || 'Fine'}</p>` : ''}\n            \n            <table>\n                <thead>\n                    <tr>\n                        <th>Paziente</th>\n                        <th>Reparto</th>\n                        <th>Data Ingresso</th>\n                        <th>Data Dimissione</th>\n                        <th>Stato</th>\n                    </tr>\n                </thead>\n                <tbody>\n                    ${rowsHtml}\n                </tbody>\n            </table>\n\n            <div class="footer">\n                NextCare Digital Health Platform &copy; ${new Date().getFullYear()} - Documento ad uso interno.\n            </div>\n\n            <script>\n                window.onload = function() { window.print(); }\n            </script>\n        </body>\n        </html>\n    `);
    printWindow.document.close();
};

// --- PRINT OUTPATIENT ACCEPTANCES REPORT ---
window.printAccReport = function() {
    const accTbody = document.querySelector('#outpatient-acceptances-table tbody');
    if (!accTbody) return;

    const samples = DB.get('lab_samples') || [];
    const studies = DB.get('radiology_studies') || [];
    const tests = DB.get('lab_tests') || [];
    const services = DB.get('medical_services') || [];
    const patients = DB.get('patients') || [];

    const acceptancesList = [];

    // 1. Process LIS samples
    samples.forEach(sess => {
        const p = patients.find(pat => pat.id === sess.patient_id);
        if (!p) return;

        const sessionSamples = sess.samples || [];
        const sessionSampleIds = sessionSamples.map(s => s.id);
        const sessionTests = tests.filter(t => sessionSampleIds.includes(t.sample_id));
        
        let calculatedStatus = 'Da prelevare';
        const allCompleted = sessionTests.length > 0 && sessionTests.every(t => t.status === 'completed');
        const hasProcessing = sessionSamples.some(s => s.status === 'received' || s.status === 'processing');
        if (allCompleted) {
            calculatedStatus = 'Completato';
        } else if (hasProcessing || sessionSamples.some(s => s.status === 'collected')) {
            calculatedStatus = 'In lavorazione';
        }

        const examNames = sessionTests.map(t => {
            const srv = services.find(sv => sv.id === t.service_id);
            return srv ? srv.name : t.test_name;
        });
        const examsStr = [...new Set(examNames)].join(', ') || 'Nessun esame';

        acceptancesList.push({
            patientName: `${p.last_name} ${p.first_name}`,
            patientTax: p.tax_code,
            type: 'LIS (Laboratorio)',
            dateRaw: sess.collected_at || '',
            dateStr: window.safeFormatDate(sess.collected_at),
            details: examsStr,
            status: calculatedStatus
        });
    });

    // 2. Process RIS studies
    studies.forEach(st => {
        const p = patients.find(pat => pat.id === st.patient_id);
        if (!p) return;

        const srv = services.find(sv => sv.id === st.service_id);
        const examName = srv ? srv.name : 'Esame RIS';

        let statusLabel = 'Pianificato';
        if (st.status === 'completed') {
            statusLabel = 'Refertato';
        } else if (st.status === 'executed') {
            statusLabel = 'Erogato';
        } else if (st.status === 'in_progress') {
            statusLabel = 'In Esecuzione';
        }

        acceptancesList.push({
            patientName: `${p.last_name} ${p.first_name}`,
            patientTax: p.tax_code,
            type: st.study_type === 'VISIT' ? 'Visita Specialistica' : 'RIS (Radiologia)',
            dateRaw: st.scheduled_at || '',
            dateStr: window.safeFormatDate(st.scheduled_at),
            details: examName,
            status: statusLabel
        });
    });

    // Sort by date (newest first)
    acceptancesList.sort((a, b) => new Date(b.dateRaw) - new Date(a.dateRaw));

    // Apply filters
    const accAiSearchVal = document.getElementById('acc-ai-search')?.value || '';
    const accFilterType = document.getElementById('acc-filter-type')?.value || '';
    const accFilterStart = document.getElementById('acc-filter-start')?.value || '';
    const accFilterEnd = document.getElementById('acc-filter-end')?.value || '';

    let filtered = acceptancesList;

    if (accFilterType) {
        filtered = filtered.filter(acc => {
            if (accFilterType === 'lis') return acc.type.includes('LIS');
            if (accFilterType === 'ris') return acc.type.includes('RIS');
            if (accFilterType === 'visit') return acc.type.includes('Visita');
            return true;
        });
    }

    if (accFilterStart) {
        filtered = filtered.filter(acc => {
            const d = acc.dateRaw ? acc.dateRaw.substring(0, 10) : '';
            return d >= accFilterStart;
        });
    }

    if (accFilterEnd) {
        filtered = filtered.filter(acc => {
            const d = acc.dateRaw ? acc.dateRaw.substring(0, 10) : '';
            return d <= accFilterEnd;
        });
    }

    if (accAiSearchVal) {
        const query = accAiSearchVal.toLowerCase().trim();
        filtered = filtered.filter(acc => {
            return acc.patientName.toLowerCase().includes(query) || 
                   acc.patientTax.toLowerCase().includes(query) || 
                   acc.type.toLowerCase().includes(query) || 
                   acc.details.toLowerCase().includes(query) || 
                   acc.status.toLowerCase().includes(query);
        });
    }

    if (filtered.length === 0) {
        alert("Nessuna accettazione ambulatoriale da stampare.");
        return;
    }

    const printWindow = window.open('', '_blank');
    if (!printWindow) {
        alert("Abilita i pop-up per poter visualizzare la stampa.");
        return;
    }

    let rowsHtml = '';
    filtered.forEach(acc => {
        let badgeColor = '#f59e0b';
        if (acc.status === 'Completato' || acc.status === 'Refertato') badgeColor = '#10b981';
        else if (acc.status === 'Erogato') badgeColor = '#06b6d4';

        rowsHtml += `\n            <tr>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;"><strong>${acc.patientName}</strong><br><small style="color:#64748b;">${acc.patientTax}</small></td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;">${acc.type}</td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;">${acc.dateStr}</td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0; font-size: 0.8rem; color: #475569;">${acc.details}</td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;"><span style="display:inline-block; padding: 4px 8px; border-radius: 4px; color: white; background: ${badgeColor}; font-size: 0.75rem; font-weight: 700;">${acc.status}</span></td>\n            </tr>\n        `;
    });

    printWindow.document.write(`\n        <html>\n        <head>\n            <title>NextCare - Registro Accettazioni Ambulatoriali</title>\n            <style>\n                body { font-family: sans-serif; padding: 20px; color: #333; }\n                h1 { margin-bottom: 5px; color: #1e3a8a; }\n                table { width: 100%; border-collapse: collapse; margin-top: 20px; }\n                th, td { border: 1px solid #ddd; padding: 10px; text-align: left; }\n                th { background-color: #f3f4f6; }\n                .footer { margin-top: 50px; font-size: 0.8rem; text-align: center; color: #666; border-top: 1px dashed #ccc; padding-top: 10px; }\n            </style>\n        </head>\n        <body>\n            <h1>Registro Accettazioni (Prestazioni Ambulatoriali)</h1>\n            <p>Generato il: ${new Date().toLocaleString('it-IT')}</p>\n            ${accFilterStart || accFilterEnd ? `<p>Periodo: ${accFilterStart || 'Inizio'} al ${accFilterEnd || 'Fine'}</p>` : ''}\n            \n            <table>\n                <thead>\n                    <tr>\n                        <th>Paziente</th>\n                        <th>Tipologia</th>\n                        <th>Data Accettazione</th>\n                        <th>Prestazioni / Dettagli</th>\n                        <th>Stato</th>\n                    </tr>\n                </thead>\n                <tbody>\n                    ${rowsHtml}\n                </tbody>\n            </table>\n\n            <div class="footer">\n                NextCare Digital Health Platform &copy; ${new Date().getFullYear()} - Documento ad uso interno.\n            </div>\n\n            <script>\n                window.onload = function() { window.print(); }\n            </script>\n        </body>\n        </html>\n    `);
    printWindow.document.close();
};

// --- PRINT INVOICES REPORT ---
window.printInvReport = function() {
    const admissions = DB.get('admissions') || [];
    const patients = DB.get('patients') || [];
    const invoices = DB.get('invoices') || [];

    // Fetch filters
    const invAiSearchVal = document.getElementById('inv-ai-search')?.value || '';
    const invFilterStatus = document.getElementById('inv-filter-status')?.value || '';
    const invFilterStart = document.getElementById('inv-filter-start')?.value || '';
    const invFilterEnd = document.getElementById('inv-filter-end')?.value || '';

    const filtered = invoices.filter(inv => {
        // Apply status filter
        if (invFilterStatus && inv.payment_status !== invFilterStatus) return false;

        // Apply start date
        if (invFilterStart && inv.issue_date < invFilterStart) return false;

        // Apply end date
        if (invFilterEnd && inv.issue_date > invFilterEnd) return false;

        // Fetch patient for text search
        let p = null;
        if (inv.admission_id) {
            const adm = admissions.find(a => a.id === inv.admission_id);
            p = adm ? patients.find(pat => pat.id === adm.patient_id) : null;
        } else if (inv.appointment_id) {
            const app = DB.get('appointments').find(a => a.id === inv.appointment_id);
            p = app ? patients.find(pat => pat.id === app.patient_id) : null;
        } else if (inv.sample_id) {
            const sam = DB.get('lab_samples').find(s => s.id === inv.sample_id);
            p = sam ? patients.find(pat => pat.id === sam.patient_id) : null;
        } else if (inv.study_id) {
            const st = DB.get('radiology_studies').find(s => s.id === inv.study_id);
            p = st ? patients.find(pat => pat.id === st.patient_id) : null;
        }

        const patientName = p ? `${p.last_name} ${p.first_name}` : 'Paziente Esterno';
        const patientTax = p ? p.tax_code : '';

        if (invAiSearchVal) {
            const query = invAiSearchVal.toLowerCase().trim();
            const matchesInvoice = inv.invoice_number.toLowerCase().includes(query);
            const matchesPatient = patientName.toLowerCase().includes(query) || (patientTax && patientTax.toLowerCase().includes(query));
            if (!matchesInvoice && !matchesPatient) return false;
        }

        return true;
    });

    if (filtered.length === 0) {
        alert("Nessuna fattura da stampare.");
        return;
    }

    const printWindow = window.open('', '_blank');
    if (!printWindow) {
        alert("Abilita i pop-up per poter visualizzare la stampa.");
        return;
    }

    let rowsHtml = '';
    let grandTotal = 0;
    filtered.forEach(inv => {
        let p = null;
        let detailsLabel = '';

        if (inv.admission_id) {
            const adm = admissions.find(a => a.id === inv.admission_id);
            p = adm ? patients.find(pat => pat.id === adm.patient_id) : null;
            detailsLabel = 'Ricovero';
        } else if (inv.appointment_id) {
            const app = DB.get('appointments').find(a => a.id === inv.appointment_id);
            p = app ? patients.find(pat => pat.id === app.patient_id) : null;
            detailsLabel = 'CUP/Ambulatorio';
        } else if (inv.sample_id) {
            const sam = DB.get('lab_samples').find(s => s.id === inv.sample_id);
            p = sam ? patients.find(pat => pat.id === sam.patient_id) : null;
            detailsLabel = 'LIS Laboratorio';
        } else if (inv.study_id) {
            const st = DB.get('radiology_studies').find(s => s.id === inv.study_id);
            p = st ? patients.find(pat => pat.id === st.patient_id) : null;
            detailsLabel = st && st.study_type === 'VISIT' ? 'Visita Specialistica' : 'RIS Radiologia';
        }

        const patientName = p ? `${p.last_name} ${p.first_name}` : 'Paziente Esterno';
        const patientTax = p ? p.tax_code : '';

        let paymentLabel = 'Non Pagata';
        let badgeColor = '#ef4444';
        if (inv.payment_status === 'paid') {
            paymentLabel = 'Pagata';
            badgeColor = '#10b981';
        } else if (inv.payment_status === 'partial') {
            paymentLabel = 'Parziale';
            badgeColor = '#f59e0b';
        }

        grandTotal += Number(inv.amount_due) || 0;

        rowsHtml += `\n            <tr>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0; font-family: monospace; font-weight: 700;">${inv.invoice_number}</td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;"><strong>${patientName}</strong><br><small style="color:#64748b;">${patientTax}</small></td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0;">${detailsLabel} - ${inv.issue_date}</td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0; font-weight: bold; text-align: right;">€ ${inv.amount_due.toFixed(2)}</td>\n                <td style="padding: 10px; border-bottom: 1px solid #e2e8f0; text-align: center;"><span style="display:inline-block; padding: 4px 8px; border-radius: 4px; color: white; background: ${badgeColor}; font-size: 0.75rem; font-weight: 700;">${paymentLabel}</span></td>\n            </tr>\n        `;
    });

    printWindow.document.write(`\n        <html>\n        <head>\n            <title>NextCare - Registro Fatture & Ticket</title>\n            <style>\n                body { font-family: sans-serif; padding: 20px; color: #333; }\n                h1 { margin-bottom: 5px; color: #1e3a8a; }\n                table { width: 100%; border-collapse: collapse; margin-top: 20px; }\n                th, td { border: 1px solid #ddd; padding: 10px; text-align: left; }\n                th { background-color: #f3f4f6; }\n                .footer { margin-top: 50px; font-size: 0.8rem; text-align: center; color: #666; border-top: 1px dashed #ccc; padding-top: 10px; }\n            </style>\n        </head>\n        <body>\n            <h1>Registro Fatture & Ticket Emessi</h1>\n            <p>Generato il: ${new Date().toLocaleString('it-IT')}</p>\n            ${invFilterStart || invFilterEnd ? `<p>Periodo: ${invFilterStart || 'Inizio'} al ${invFilterEnd || 'Fine'}</p>` : ''}\n            \n            <table>\n                <thead>\n                    <tr>\n                        <th>Fattura N.</th>\n                        <th>Intestatario</th>\n                        <th>Dettaglio & Data</th>\n                        <th style="text-align: right;">Importo</th>\n                        <th style="text-align: center;">Stato Pagamento</th>\n                    </tr>\n                </thead>\n                <tbody>\n                    ${rowsHtml}\n                    <tr>\n                        <td colspan="3" style="text-align: right; font-weight: bold; padding: 10px;">TOTALE REGISTRO:</td>\n                        <td style="text-align: right; font-weight: bold; padding: 10px; color: #1e3a8a; font-size: 1.1rem;">€ ${grandTotal.toFixed(2)}</td>\n                        <td></td>\n                    </tr>\n                </tbody>\n            </table>\n\n            <div class="footer">\n                NextCare Digital Health Platform &copy; ${new Date().getFullYear()} - Documento ad uso interno.\n            </div>\n\n            <script>\n                window.onload = function() { window.print(); }\n            </script>\n        </body>\n        </html>\n    `);
    printWindow.document.close();
};

window.tablePaginationStates = {};

window.setupTablePagination = function(tableId, filteredData, onPageChangedCallback) {
    if (!window.tablePaginationStates[tableId]) {
        window.tablePaginationStates[tableId] = {
            currentPage: 1,
            pageLimit: 20,
            callback: onPageChangedCallback
        };
    }
    
    const state = window.tablePaginationStates[tableId];
    state.callback = onPageChangedCallback;

    const totalPages = Math.ceil(filteredData.length / state.pageLimit) || 1;
    if (state.currentPage > totalPages) {
        state.currentPage = totalPages;
    }
    const startIndex = (state.currentPage - 1) * state.pageLimit;
    const endIndex = Math.min(startIndex + state.pageLimit, filteredData.length);
    const paginatedData = filteredData.slice(startIndex, endIndex);

    const tableEl = document.getElementById(tableId);
    if (!tableEl) return paginatedData;

    let container = tableEl.closest('.table-container');
    if (!container) {
        container = tableEl.parentElement;
    }

    container.style.maxHeight = '800px';
    container.style.overflowY = 'auto';

    let pagDiv = container.querySelector(`.pagination-controls[data-table="${tableId}"]`);
    if (!pagDiv) {
        pagDiv = container.parentElement.querySelector(`.pagination-controls[data-table="${tableId}"]`);
    }
    if (!pagDiv) {
        pagDiv = document.createElement('div');
        pagDiv.className = 'pagination-controls';
        pagDiv.setAttribute('data-table', tableId);
        pagDiv.style.display = 'flex';
        pagDiv.style.justifyContent = 'space-between';
        pagDiv.style.alignItems = 'center';
        pagDiv.style.padding = '15px';
        pagDiv.style.borderTop = '1px solid var(--border-color)';
        pagDiv.style.background = 'var(--bg-card)';
        pagDiv.style.borderRadius = '0 0 8px 8px';
        pagDiv.style.fontSize = '0.82rem';
        pagDiv.style.marginTop = '-1px';
        
        container.after(pagDiv);
    }

    if (filteredData.length === 0) {
        pagDiv.style.display = 'none';
        return paginatedData;
    } else {
        pagDiv.style.display = 'flex';
    }

    pagDiv.innerHTML = `\n        <div style="display: flex; align-items: center; gap: 8px;">\n            <span style="color: var(--text-secondary);">Elementi per pagina:</span>\n            <select class="srv-pagination-limit-select" style="padding: 4px 8px; border-radius: 4px; background: var(--bg-body); border: 1px solid var(--border-color); color: var(--text-primary); cursor: pointer; font-size: 0.8rem;">\n                <option value="10" ${state.pageLimit === 10 ? 'selected' : ''}>10</option>\n                <option value="20" ${state.pageLimit === 20 ? 'selected' : ''}>20</option>\n                <option value="50" ${state.pageLimit === 50 ? 'selected' : ''}>50</option>\n                <option value="100" ${state.pageLimit === 100 ? 'selected' : ''}>100</option>\n                <option value="all" ${state.pageLimit === 999999 ? 'selected' : ''}>Tutti</option>\n            </select>\n        </div>\n        <div style="display: flex; align-items: center; gap: 4px;" class="srv-pagination-buttons-container">\n        </div>\n        <div class="srv-pagination-info-text" style="color: var(--text-secondary); font-weight: 500;">\n            Mostrati ${startIndex + 1}-${endIndex} di ${filteredData.length}\n        </div>\n    `;

    const selectEl = pagDiv.querySelector('.srv-pagination-limit-select');
    selectEl.addEventListener('change', (e) => {
        window.changeTablePageLimit(tableId, e.target.value);
    });

    const buttonsContainer = pagDiv.querySelector('.srv-pagination-buttons-container');
    
    const createPageBtn = (pageNum, text, isActive, isDisabled) => {
        const btn = document.createElement('button');
        btn.className = `btn ${isActive ? 'btn-primary' : 'btn-secondary'}`;
        btn.style.padding = '4px 10px';
        btn.style.fontSize = '0.75rem';
        btn.style.minWidth = '30px';
        btn.style.margin = '0 2px';
        btn.disabled = isDisabled;
        btn.innerText = text;
        btn.onclick = (e) => {
            e.preventDefault();
            window.changeTablePage(tableId, pageNum);
        };
        return btn;
    };

    buttonsContainer.appendChild(createPageBtn(1, '<<', false, state.currentPage === 1));
    buttonsContainer.appendChild(createPageBtn(state.currentPage - 1, '<', false, state.currentPage === 1));

    let startPage = Math.max(1, state.currentPage - 2);
    let endPage = Math.min(totalPages, startPage + 4);
    if (endPage - startPage < 4) {
        startPage = Math.max(1, endPage - 4);
    }

    for (let i = startPage; i <= endPage; i++) {
        buttonsContainer.appendChild(createPageBtn(i, i.toString(), i === state.currentPage, false));
    }

    buttonsContainer.appendChild(createPageBtn(state.currentPage + 1, '>', false, state.currentPage === totalPages));
    buttonsContainer.appendChild(createPageBtn(totalPages, '>>', false, state.currentPage === totalPages));

    return paginatedData;
};

window.changeTablePageLimit = function(tableId, limit) {
    const state = window.tablePaginationStates[tableId];
    if (limit === 'all') {
        state.pageLimit = 999999;
    } else {
        state.pageLimit = parseInt(limit);
    }
    state.currentPage = 1;
    if (state.callback) state.callback();
};

window.changeTablePage = function(tableId, pageNum) {
    const state = window.tablePaginationStates[tableId];
    state.currentPage = pageNum;
    if (state.callback) state.callback();
};

