// switchLisSubTab duplicate removed (using original definition on line 2740)

window.selectedReportingSessionUids = [];

window.toggleCheckAllReporting = function(checkbox) {
    const checked = checkbox.checked;
    const checkboxes = document.querySelectorAll('.rep-session-checkbox');
    window.selectedReportingSessionUids = [];
    checkboxes.forEach(cb => {
        cb.checked = checked;
        const uid = cb.getAttribute('data-session-uid');
        if (checked && uid) {
            window.selectedReportingSessionUids.push(uid);
        }
    });
    window.updateReportingSelectedCount();
};

window.updateReportingSelectedCount = function() {
    const checkboxes = document.querySelectorAll('.rep-session-checkbox');
    const checkedUids = [];
    checkboxes.forEach(cb => {
        if (cb.checked) {
            checkedUids.push(cb.getAttribute('data-session-uid'));
        }
    });
    window.selectedReportingSessionUids = checkedUids;

    const countSpan = document.getElementById('rep-selected-count');
    if (countSpan) {
        countSpan.innerText = window.selectedReportingSessionUids.length;
    }
};

window.checkAndAutoReportAcceptance = function(sessionUid) {
    if (!sessionUid) return;
    const samples = DB.get('lab_samples') || [];
    const sessionSamples = samples.filter(s => s.session_uid === sessionUid);
    if (sessionSamples.length === 0) return;

    const allValidated = sessionSamples.every(s => s.status === 'validated' || s.status === 'completed');
    if (allValidated) {
        const reports = DB.get('lab_reports') || [];
        let rep = reports.find(r => r.session_uid === sessionUid);
        const timestamp = new Date().toISOString();
        if (!rep) {
            const newRep = {
                id: reports.length > 0 ? Math.max(...reports.map(r => r.id)) + 1 : 1,
                session_uid: sessionUid,
                status: 'official',
                notes: 'Generato automaticamente a convalida completata.',
                released_at: timestamp,
                released_by: 5
            };
            reports.push(newRep);
            DB.set('lab_reports', reports);
            DB.logAudit(5, "LAB_REPORT_AUTO_OFFICIAL", "lab_reports", newRep.id, { session_uid: sessionUid });
        } else if (rep.status !== 'official') {
            rep.status = 'official';
            rep.released_at = timestamp;
            rep.released_by = 5;
            rep.notes = (rep.notes || '') + '\n\n[Auto] Promosso a Ufficiale a convalida completata.';
            DB.set('lab_reports', reports);
            DB.logAudit(5, "LAB_REPORT_AUTO_OFFICIAL", "lab_reports", rep.id, { session_uid: sessionUid });
        }
    }
};

window.renderLisReportingView = function() {
    const samples = DB.get('lab_samples') || [];
    const patients = DB.get('patients') || [];
    const reports = DB.get('lab_reports') || [];

    // Filter filters
    const searchVal = (document.getElementById('rep-filter-patient')?.value || '').toLowerCase().trim();
    const statusFilter = document.getElementById('rep-filter-status')?.value || 'all';

    // Group samples by session_uid
    const sessionsMap = {};
    samples.forEach(sam => {
        if (!sam.session_uid) return;
        if (!sessionsMap[sam.session_uid]) {
            sessionsMap[sam.session_uid] = [];
        }
        sessionsMap[sam.session_uid].push(sam);
    });

    const tbody = document.querySelector('#lis-reporting-table tbody');
    if (!tbody) return;
    tbody.innerHTML = '';

    const sessions = [];
    Object.keys(sessionsMap).forEach(uid => {
        const sSamples = sessionsMap[uid];
        const firstSample = sSamples[0];
        const pat = patients.find(p => p.id === firstSample.patient_id) || {};
        const patName = pat.last_name ? `${pat.last_name} ${pat.first_name}` : `Paziente ID: ${firstSample.patient_id}`;

        const totalCount = sSamples.length;
        const validatedCount = sSamples.filter(s => s.status === 'validated' || s.status === 'completed').length;
        const progressStr = `${validatedCount}/${totalCount}`;
        const isAllValidated = (validatedCount === totalCount);

        const rep = reports.find(r => r.session_uid === uid);
        let repStatus = 'none'; // 'none', 'preliminary', 'official'
        let repStatusText = 'Nessuno';
        let badgeStyle = 'background-color: var(--text-secondary); color: white;';
        
        if (rep) {
            repStatus = rep.status;
            if (rep.status === 'preliminary') {
                repStatusText = 'Bozza Preliminare';
                badgeStyle = 'background-color: #f59e0b; color: white;';
            } else if (rep.status === 'official') {
                repStatusText = 'Firma Ufficiale';
                badgeStyle = 'background-color: #10b981; color: white;';
            }
        }

        // Apply filters
        if (searchVal) {
            if (!patName.toLowerCase().includes(searchVal) && !uid.toLowerCase().includes(searchVal)) {
                return;
            }
        }

        if (statusFilter !== 'all') {
            if (statusFilter === 'ready_official') {
                if (!isAllValidated || repStatus === 'official') return;
            }
            if (statusFilter === 'incomplete') {
                if (isAllValidated) return;
            }
            if (statusFilter === 'reported') {
                if (repStatus !== 'official') return;
            }
        }

        const collectedDate = firstSample.collected_at ? new Date(firstSample.collected_at).toLocaleDateString('it-IT') : '-';

        sessions.push({
            session_uid: uid,
            patient_name: patName,
            progress: progressStr,
            isAllValidated: isAllValidated,
            repStatus: repStatus,
            repStatusText: repStatusText,
            badgeStyle: badgeStyle,
            collectedDate: collectedDate,
            report: rep,
            samples: sSamples
        });
    });

    // Sort by session date desc
    sessions.sort((a, b) => b.session_uid.localeCompare(a.session_uid));

    if (sessions.length === 0) {
        tbody.innerHTML = `\n            <tr>\n                <td colspan="8" style="padding: 30px; text-align: center; color: var(--text-secondary); font-size: 0.85rem;">\n                    Nessuna accettazione trovata per i criteri di ricerca selezionati.\n                </td>\n            </tr>\n        `;
        return;
    }

    sessions.forEach(sess => {
        const isChecked = window.selectedReportingSessionUids?.includes(sess.session_uid) ? 'checked' : '';
        const tr = document.createElement('tr');
        tr.style.borderBottom = '1px solid var(--border-color)';
        
        tr.innerHTML = `\n            <td style="padding: 12px 10px; text-align: center;">\n                <input type="checkbox" class="rep-session-checkbox" data-session-uid="${sess.session_uid}" ${isChecked} onchange="window.updateReportingSelectedCount()" style="cursor: pointer;">\n            </td>\n            <td style="padding: 12px 10px; color: var(--text-secondary); font-size: 0.8rem;">${sess.collectedDate}</td>\n            <td style="padding: 12px 10px; font-weight: 500;">\n                ${sess.patient_name}<br>\n                <span style="font-family: monospace; font-size: 0.72rem; color: var(--text-secondary);">${sess.session_uid}</span>\n            </td>\n            <td style="padding: 12px 10px; font-size: 0.8rem;">${sess.samples.length} campioni</td>\n            <td style="padding: 12px 10px;">\n                <div style="display: flex; align-items: center; gap: 6px;">\n                    <span style="font-weight: 600; font-size: 0.85rem;">${sess.progress}</span>\n                    <span style="width: 60px; background-color: var(--border-color); height: 6px; border-radius: 3px; overflow: hidden; display: inline-block;">\n                        <span style="display: block; height: 100%; width: ${(parseInt(sess.progress.split('/')[0])/parseInt(sess.progress.split('/')[1]))*100}%; background-color: var(--primary);"></span>\n                    </span>\n                </div>\n            </td>\n            <td style="padding: 12px 10px; font-size: 0.8rem; font-weight: 500;">\n                ${sess.isAllValidated ? '<span class="text-success">Referto Ufficiale</span>' : '<span class="text-warning">Referto Preliminare</span>'}\n            </td>\n            <td style="padding: 12px 10px;">\n                <span class="badge" style="${sess.badgeStyle} font-size: 0.75rem; padding: 2px 8px; border-radius: 4px; font-weight: 600;">${sess.repStatusText}</span>\n            </td>\n            <td style="padding: 12px 10px; text-align: center;">\n                <button class="btn btn-sm btn-outline" onclick="window.openLisReportingDetailModal('${sess.session_uid}')" style="padding: 4px 8px; font-size: 0.75rem; display: inline-flex; align-items: center; gap: 4px;">\n                    <i data-lucide="edit-3" style="width: 12px; height: 12px;"></i> Gestisci\n                </button>\n            </td>\n        `;
        tbody.appendChild(tr);
    });

    if (window.lucide) window.lucide.createIcons();
};

window.bulkPrintLisReports = function() {
    if (!window.selectedReportingSessionUids || window.selectedReportingSessionUids.length === 0) {
        alert("Seleziona almeno un'accettazione da stampare.");
        return;
    }

    const samples = DB.get('lab_samples') || [];
    const patients = DB.get('patients') || [];
    const tests = DB.get('lab_tests') || [];
    const reports = DB.get('lab_reports') || [];
    const staff = DB.get('staff') || [];
    const services = DB.get('medical_services') || [];

    let printHtml = `\n        <!DOCTYPE html>\n        <html>\n        <head>\n            <title>Stampa Referti LIS</title>\n            <style>\n                body { font-family: 'Segoe UI', Roboto, sans-serif; color: #333; margin: 20px; line-height: 1.4; }\n                .report-page { max-width: 800px; margin: 0 auto 40px auto; border: 1px solid #ddd; padding: 30px; box-shadow: 0 4px 6px rgba(0,0,0,0.05); position: relative; }\n                .report-header { display: flex; justify-content: space-between; border-bottom: 2px solid #2563eb; padding-bottom: 15px; margin-bottom: 20px; }\n                .logo-section h1 { margin: 0; color: #2563eb; font-size: 1.6rem; }\n                .logo-section p { margin: 2px 0 0 0; font-size: 0.8rem; color: #666; }\n                .meta-section { text-align: right; font-size: 0.85rem; color: #444; }\n                .patient-box { background: #f8fafc; border: 1px solid #e2e8f0; border-radius: 6px; padding: 15px; display: grid; grid-template-columns: 1fr 1fr; gap: 10px; margin-bottom: 25px; font-size: 0.9rem; }\n                .patient-box div strong { color: #475569; }\n                .section-title { font-size: 1.1rem; font-weight: bold; color: #1e3a8a; border-bottom: 1px solid #cbd5e1; padding-bottom: 5px; margin-top: 20px; margin-bottom: 10px; }\n                table { width: 100%; border-collapse: collapse; margin-bottom: 20px; font-size: 0.88rem; }\n                th { background-color: #f1f5f9; text-align: left; padding: 8px 10px; border-bottom: 2px solid #cbd5e1; color: #475569; }\n                td { padding: 8px 10px; border-bottom: 1px solid #e2e8f0; }\n                .flag-normal { color: #16a34a; font-weight: 600; }\n                .flag-out { color: #dc2626; font-weight: bold; background-color: #fef2f2; padding: 2px 6px; border-radius: 4px; }\n                .report-footer { border-top: 1px solid #cbd5e1; padding-top: 15px; margin-top: 30px; display: flex; justify-content: space-between; font-size: 0.8rem; color: #666; }\n                .watermark { position: absolute; top: 40%; left: 10%; right: 10%; transform: rotate(-30deg); font-size: 5rem; color: rgba(239, 68, 68, 0.08); font-weight: 900; text-transform: uppercase; text-align: center; pointer-events: none; }\n                .watermark-official { color: rgba(16, 185, 129, 0.06); }\n                @media print {\n                    body { margin: 0; }\n                    .report-page { border: none; padding: 0; box-shadow: none; page-break-after: always; max-width: 100%; }\n                    .report-page:last-child { page-break-after: avoid; }\n                }\n            </style>\n        </head>\n        <body>\n    `;

    window.selectedReportingSessionUids.forEach(uid => {
        const sessionSamples = samples.filter(s => s.session_uid === uid);
        if (sessionSamples.length === 0) return;
        
        const firstSample = sessionSamples[0];
        const pat = patients.find(p => p.id === firstSample.patient_id) || {};
        const rep = reports.find(r => r.session_uid === uid);
        const repStatus = rep?.status || 'preliminary';
        const repNotes = rep?.notes || 'Nessuna nota aggiuntiva.';

        const patName = `${pat.last_name || ''} ${pat.first_name || ''}`;
        const patGender = pat.gender || 'N/D';
        const patBirth = pat.birth_date ? new Date(pat.birth_date).toLocaleDateString('it-IT') : 'N/D';
        const patTax = pat.tax_code || 'N/D';

        const sampleIds = sessionSamples.map(s => s.id);
        const sessionTests = tests.filter(t => sampleIds.includes(t.sample_id));

        const collectedDate = firstSample.collected_at ? new Date(firstSample.collected_at).toLocaleString('it-IT') : '-';
        const printedDate = new Date().toLocaleString('it-IT');

        const watermarkText = repStatus === 'official' ? 'REFERTO UFFICIALE' : 'BOZZA PRELIMINARE';
        const watermarkClass = repStatus === 'official' ? 'watermark-official' : '';

        printHtml += `\n            <div class="report-page">\n                <div class="watermark ${watermarkClass}">${watermarkText}</div>\n                <div class="report-header">\n                    <div class="logo-section">\n                        <h1>NextCare Health Systems</h1>\n                        <p>Digital Health Clinic - Laboratorio Analisi Cliniche</p>\n                    </div>\n                    <div class="meta-section">\n                        <strong>ID Sessione:</strong> ${uid}<br>\n                        <strong>Data Accettazione:</strong> ${collectedDate}<br>\n                        <strong>Data Stampa:</strong> ${printedDate}\n                    </div>\n                </div>\n                <div class="patient-box">\n                    <div><strong>Cognome e Nome:</strong> ${patName}</div>\n                    <div><strong>Codice Fiscale:</strong> ${patTax}</div>\n                    <div><strong>Data di Nascita:</strong> ${patBirth}</div>\n                    <div><strong>Genere:</strong> ${patGender}</div>\n                </div>\n\n                <div class="section-title">RISULTATI ANALISI DI LABORATORIO</div>\n                <table>\n                    <thead>\n                        <tr>\n                            <th>Esame / Parametro</th>\n                            <th style="text-align: center;">Risultato</th>\n                            <th>Unità</th>\n                            <th>Valori di Riferimento</th>\n                            <th style="text-align: center;">Stato</th>\n                        </tr>\n                    </thead>\n                    <tbody>\n        `;

        if (sessionTests.length === 0) {
            printHtml += `<tr><td colspan="5" style="text-align:center;">Nessun risultato disponibile.</td></tr>`;
        } else {
            // Group tests by service_id to render cascaded parameters (with robust fallback matching)
            const groups = {};
            sessionTests.forEach(t => {
                let key = t.service_id;
                if (!key) {
                    if (t.test_name.startsWith('Emocromo (')) {
                        const s = services.find(srv => srv.name.toLowerCase().includes('emocromo'));
                        key = s ? s.id : 'emocromo';
                    } else if (t.test_name.startsWith('Elettroforesi (')) {
                        const s = services.find(srv => srv.name.toLowerCase().includes('elettroforesi'));
                        key = s ? s.id : 'elettroforesi';
                    } else if (t.test_name.startsWith('Esame Urine (')) {
                        const s = services.find(srv => srv.name.toLowerCase().includes('urine'));
                        key = s ? s.id : 'urine';
                    } else {
                        const s = services.find(srv => srv.name.toLowerCase().replace(/\s*\(lis\)\s*/g, '') === t.test_name.toLowerCase());
                        key = s ? s.id : 'unknown-' + t.test_name;
                    }
                }
                if (!groups[key]) {
                    groups[key] = [];
                }
                groups[key].push(t);
            });

            Object.keys(groups).forEach(serviceId => {
                const groupTests = groups[serviceId];
                const srv = services.find(s => s.id === parseInt(serviceId));
                const srvName = srv ? srv.name : (groupTests[0] ? groupTests[0].test_name : 'Esame Sconosciuto');

                const isMultiParam = groupTests.length > 1 || (srv && srv.parameters && srv.parameters.length > 1);

                if (isMultiParam) {
                    // Header row for main exam in bold
                    printHtml += `\n                        <tr style="background-color: #f8fafc; border-bottom: 2px solid #cbd5e1;">\n                            <td colspan="5" style="padding: 10px 10px; font-weight: 700; color: #1e3a8a; font-size: 0.95rem; text-transform: uppercase;">\n                                ${srvName}\n                            </td>\n                        </tr>\n                    `;

                    // Indented parameters
                    groupTests.forEach(t => {
                        const isFlagged = t.status === 'flagged';
                        const flagCell = t.status === 'suspended'
                            ? '<span style="color: #dc2626; font-weight: 600;">SOSPESO</span>'
                            : (isFlagged ? '<span class="flag-out">FUORI SOGLIA</span>' : '<span class="flag-normal">NORMALE</span>');
                        
                        printHtml += `\n                            <tr style="${t.status === 'suspended' ? 'opacity: 0.5; text-decoration: line-through;' : ''}">\n                                <td style="padding: 8px 10px 8px 30px; font-weight: 500; color: #334155;">\n                                    &bull;&nbsp;${t.test_name}\n                                </td>\n                                <td style="text-align: center; font-weight: bold; font-size: 0.95rem; color: ${t.status === 'flagged' ? '#dc2626' : '#333'};">\n                                    ${t.status === 'suspended' ? 'SOSPESO' : (t.result_value !== null ? t.result_value : '-')}\n                                </td>\n                                <td style="font-family: monospace;">${t.unit || '-'}</td>\n                                <td>${t.reference_range || 'N/A'}</td>\n                                <td style="text-align: center;">${flagCell}</td>\n                            </tr>\n                        `;
                    });
                } else {
                    // Simple single parameter exam
                    const t = groupTests[0];
                    if (!t) return;
                    const isFlagged = t.status === 'flagged';
                    const flagCell = t.status === 'suspended'
                        ? '<span style="color: #dc2626; font-weight: 600;">SOSPESO</span>'
                        : (isFlagged ? '<span class="flag-out">FUORI SOGLIA</span>' : '<span class="flag-normal">NORMALE</span>');

                    printHtml += `\n                        <tr style="${t.status === 'suspended' ? 'opacity: 0.5; text-decoration: line-through;' : ''}">\n                            <td style="font-weight: 600; padding: 10px 10px;">${srvName}</td>\n                            <td style="text-align: center; font-weight: bold; font-size: 0.95rem; color: ${t.status === 'flagged' ? '#dc2626' : '#333'};">\n                                ${t.status === 'suspended' ? 'SOSPESO' : (t.result_value !== null ? t.result_value : '-')}\n                            </td>\n                            <td style="font-family: monospace;">${t.unit || '-'}</td>\n                            <td>${t.reference_range || 'N/A'}</td>\n                            <td style="text-align: center;">${flagCell}</td>\n                        </tr>\n                    `;
                }
            });
        }

        printHtml += `\n                    </tbody>\n                </table>\n\n                <div class="section-title">NOTE ED OSSERVAZIONI</div>\n                <div style="background-color: #f8fafc; border: 1px solid #cbd5e1; border-radius: 4px; padding: 12px; font-size: 0.85rem; min-height: 50px; white-space: pre-line;">\n                    ${repNotes}\n                </div>\n\n                <div class="report-footer">\n                    <div>Referto firmato digitalmente da Dr. LIS Administrator (NextCare)</div>\n                    <div>Pagina 1 di 1</div>\n                </div>\n            </div>\n        `;
    });

    printHtml += `\n        </body>\n        </html>\n    `;

    const printWindow = window.open('', '_blank');
    printWindow.document.write(printHtml);
    printWindow.document.close();
    setTimeout(() => {
        printWindow.print();
    }, 500);
};

window.bulkFinalizeOfficialReports = function() {
    if (!window.selectedReportingSessionUids || window.selectedReportingSessionUids.length === 0) {
        alert("Seleziona almeno un'accettazione da rilasciare ufficialmente.");
        return;
    }

    const samples = DB.get('lab_samples') || [];
    const reports = DB.get('lab_reports') || [];
    const timestamp = new Date().toISOString();

    let successCount = 0;
    let failCount = 0;

    window.selectedReportingSessionUids.forEach(uid => {
        const sessionSamples = samples.filter(s => s.session_uid === uid);
        const allValidated = sessionSamples.every(s => s.status === 'validated' || s.status === 'completed');
        if (!allValidated) {
            failCount++;
            return;
        }

        let rep = reports.find(r => r.session_uid === uid);
        if (!rep) {
            rep = {
                id: reports.length > 0 ? Math.max(...reports.map(r => r.id)) + 1 : 1,
                session_uid: uid,
                status: 'official',
                notes: '',
                released_at: timestamp,
                released_by: 5
            };
            reports.push(rep);
            successCount++;
            DB.logAudit(5, "LAB_REPORT_MANUAL_OFFICIAL", "lab_reports", rep.id, { session_uid: uid });
        } else if (rep.status !== 'official') {
            rep.status = 'official';
            rep.released_at = timestamp;
            rep.released_by = 5;
            successCount++;
            DB.logAudit(5, "LAB_REPORT_MANUAL_OFFICIAL", "lab_reports", rep.id, { session_uid: uid });
        }
    });

    DB.set('lab_reports', reports);
    window.selectedReportingSessionUids = [];
    window.renderLisReportingView();

    let msg = `Operazione completata con successo.\n\nRilasciati: ${successCount} referti.`;
    if (failCount > 0) {
        msg += `\n\nNon rilasciati: ${failCount} (convalida campioni incompleta).`;
    }
    alert(msg);
};

window.openLisReportingDetailModal = function(sessionUid) {
    const samples = DB.get('lab_samples') || [];
    const patients = DB.get('patients') || [];
    const tests = DB.get('lab_tests') || [];
    const reports = DB.get('lab_reports') || [];

    const sessionSamples = samples.filter(s => s.session_uid === sessionUid);
    if (sessionSamples.length === 0) return;

    const firstSample = sessionSamples[0];
    const pat = patients.find(p => p.id === firstSample.patient_id) || {};
    const patName = `${pat.last_name || ''} ${pat.first_name || ''}`;

    const sampleIds = sessionSamples.map(s => s.id);
    const sessionTests = tests.filter(t => sampleIds.includes(t.sample_id));

    const rep = reports.find(r => r.session_uid === sessionUid);
    const repStatus = rep?.status || 'none';
    const repNotes = rep?.notes || '';

    const totalCount = sessionSamples.length;
    const validatedCount = sessionSamples.filter(s => s.status === 'validated' || s.status === 'completed').length;
    const isAllValidated = (validatedCount === totalCount);

    let modal = document.getElementById('modal-lis-reporting-detail');
    if (!modal) {
        modal = document.createElement('div');
        modal.id = 'modal-lis-reporting-detail';
        modal.className = 'modal';
        modal.style.zIndex = '9999';
        document.body.appendChild(modal);
    }

    const isLocked = (repStatus === 'official');
    const statusLabel = repStatus === 'official' 
        ? '<span class="badge badge-success" style="background-color:#10b981;color:#fff;">UFFICIALE (Rilasciato)</span>' 
        : (repStatus === 'preliminary' 
            ? '<span class="badge badge-warning" style="background-color:#f59e0b;color:#fff;">BOZZA PRELIMINARE</span>' 
            : '<span class="badge badge-secondary" style="background-color:#64748b;color:#fff;">NESSUNO</span>');

    const lockNotice = isLocked 
        ? `<div style="background-color:#fef2f2; color:#991b1b; padding: 10px; border-radius: var(--radius-sm); border:1px solid #fee2e2; margin-bottom:15px; font-size:0.8rem; font-weight:600;">\n             <i data-lucide="lock" style="width:14px; height:14px; display:inline-block; vertical-align:middle; margin-right:4px;"></i> \n             Referto Ufficiale Rilasciato. I valori sono bloccati e non sono ammesse modifiche.\n           </div>`
        : '';

    const services = DB.get('medical_services') || [];
    let testsRows = '';
    
    // Group sessionTests by service_id (with robust fallback matching)
    const groups = {};
    sessionTests.forEach(t => {
        let key = t.service_id;
        if (!key) {
            if (t.test_name.startsWith('Emocromo (')) {
                const s = services.find(srv => srv.name.toLowerCase().includes('emocromo'));
                key = s ? s.id : 'emocromo';
            } else if (t.test_name.startsWith('Elettroforesi (')) {
                const s = services.find(srv => srv.name.toLowerCase().includes('elettroforesi'));
                key = s ? s.id : 'elettroforesi';
            } else if (t.test_name.startsWith('Esame Urine (')) {
                const s = services.find(srv => srv.name.toLowerCase().includes('urine'));
                key = s ? s.id : 'urine';
            } else {
                const s = services.find(srv => srv.name.toLowerCase().replace(/\s*\(lis\)\s*/g, '') === t.test_name.toLowerCase());
                key = s ? s.id : 'unknown-' + t.test_name;
            }
        }
        if (!groups[key]) {
            groups[key] = [];
        }
        groups[key].push(t);
    });

    Object.keys(groups).forEach(serviceId => {
        const groupTests = groups[serviceId];
        const srv = services.find(s => s.id === parseInt(serviceId));
        const srvName = srv ? srv.name : (groupTests[0] ? groupTests[0].test_name : 'Esame Sconosciuto');

        const isMultiParam = groupTests.length > 1 || (srv && srv.parameters && srv.parameters.length > 1);

        if (isMultiParam) {
            // Header row for main exam in bold
            testsRows += `\n                <tr style="background: var(--bg-base); border-bottom: 1px solid var(--border-color);">\n                    <td colspan="5" style="padding: 10px 10px; font-weight: 700; color: var(--primary); text-transform: uppercase;">\n                        ${srvName}\n                    </td>\n                </tr>\n            `;

            // Indented parameters
            groupTests.forEach(t => {
                const isFlagged = t.status === 'flagged';
                const flagBadge = isFlagged 
                    ? '<span class="badge" style="background-color:#ef4444;color:#fff;font-size:0.65rem;padding:2px 4px;">FUORI SOGLIA</span>' 
                    : '<span class="badge" style="background-color:#10b981;color:#fff;font-size:0.65rem;padding:2px 4px;">NORMALE</span>';
                
                testsRows += `\n                    <tr style="border-bottom: 1px solid var(--border-color); ${t.status === 'suspended' ? 'opacity: 0.5; text-decoration: line-through;' : ''}">\n                        <td style="padding:8px 10px 8px 25px; font-weight:500; color: var(--text-primary);">&bull;&nbsp;${t.test_name}</td>\n                        <td style="padding:8px 10px; text-align:center; font-weight:bold; color: ${t.status === 'flagged' ? '#dc2626' : 'var(--text-primary)'};">${t.status === 'suspended' ? 'SOSPESO' : (t.result_value !== null ? t.result_value : '-')}</td>\n                        <td style="padding:8px 10px; font-family:monospace;">${t.unit || '-'}</td>\n                        <td style="padding:8px 10px;">${t.reference_range || 'N/A'}</td>\n                        <td style="padding:8px 10px; text-align:center;">${t.status === 'suspended' ? '<span class="badge" style="background-color:#ef4444;color:#fff;font-size:0.65rem;padding:2px 4px;">SOSPESO</span>' : flagBadge}</td>\n                    </tr>\n                `;
            });
        } else {
            // Simple single parameter exam
            const t = groupTests[0];
            if (!t) return;
            const isFlagged = t.status === 'flagged';
            let flagBadge = '';
            if (window.isMicrobiologyService(t)) {
                if (t.result_value === 'Sviluppo Batterico') {
                    flagBadge = '<span class="badge" style="background-color: #ef4444; color: #fff; font-size: 0.65rem; padding: 2px 4px;">POSITIVO</span>';
                } else if (t.result_value === 'Sterile') {
                    flagBadge = '<span class="badge" style="background-color: #10b981; color: #fff; font-size: 0.65rem; padding: 2px 4px;">NEGATIVO</span>';
                } else {
                    flagBadge = '<span class="badge" style="background-color: #64748b; color: #fff; font-size: 0.65rem; padding: 2px 4px;">IN CORSO</span>';
                }
            } else {
                flagBadge = isFlagged 
                    ? '<span class="badge" style="background-color:#ef4444;color:#fff;font-size:0.65rem;padding:2px 4px;">FUORI SOGLIA</span>' 
                    : '<span class="badge" style="background-color:#10b981;color:#fff;font-size:0.65rem;padding:2px 4px;">NORMALE</span>';
            }

            const microDetailHTML = window.formatMicrobiologyDetailsForView(t);

            testsRows += `\n                <tr style="border-bottom: 1px solid var(--border-color); ${t.status === 'suspended' ? 'opacity: 0.5; text-decoration: line-through;' : ''}">\n                    <td style="padding:10px 10px; font-weight:600;">\n                        ${srvName}\n                        ${microDetailHTML}\n                    </td>\n                    <td style="padding:10px 10px; text-align:center; font-weight:bold; color: ${t.status === 'flagged' ? '#dc2626' : 'var(--text-primary)'};">${t.status === 'suspended' ? 'SOSPESO' : (t.result_value !== null ? t.result_value : '-')}</td>\n                    <td style="padding:10px 10px; font-family:monospace;">${t.unit || '-'}</td>\n                    <td style="padding:10px 10px;">${t.reference_range || 'N/A'}</td>\n                    <td style="padding:10px 10px; text-align:center;">${t.status === 'suspended' ? '<span class="badge" style="background-color:#ef4444;color:#fff;font-size:0.65rem;padding:2px 4px;">SOSPESO</span>' : flagBadge}</td>\n                </tr>\n            `;
        }
    });

    modal.innerHTML = `\n        <div class="modal-content" style="max-width: 700px; border-radius: var(--radius-lg); padding: 0; overflow: hidden; background: var(--bg-surface);">\n            <!-- Modal Header -->\n            <div style="background: var(--primary); color: #fff; padding: 16px 24px; display: flex; justify-content: space-between; align-items: center;">\n                <h3 style="margin: 0; font-size: 1.15rem; font-weight: 700;">Gestione Referto LIS</h3>\n                <span style="cursor: pointer; font-size: 1.5rem; line-height: 1;" onclick="window.closeLisReportingDetailModal()">&times;</span>\n            </div>\n            \n            <!-- Modal Body -->\n            <div style="padding: 24px; max-height: 75vh; overflow-y: auto;">\n                ${lockNotice}\n                \n                <!-- Patient info & status -->\n                <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 15px; background: var(--bg-base); padding: 15px; border-radius: var(--radius-md); border: 1px solid var(--border-color); margin-bottom: 20px; font-size: 0.85rem;">\n                    <div>\n                        <strong>Paziente:</strong> ${patName}<br>\n                        <strong>Codice Fiscale:</strong> ${pat.tax_code || 'N/D'}<br>\n                        <strong>ID Sessione:</strong> <span style="font-family:monospace; font-weight:bold;">${sessionUid}</span>\n                    </div>\n                    <div>\n                        <strong>Progresso Validazione:</strong> ${validatedCount}/${totalCount} campioni convalidati<br>\n                        <strong>Stato Referto:</strong> ${statusLabel}\n                    </div>\n                </div>\n\n                <!-- Tests table -->\n                <h4 style="font-size:0.9rem; font-weight:700; margin-bottom:10px;">Esami e Risultati</h4>\n                <div style="border:1px solid var(--border-color); border-radius:var(--radius-md); overflow:hidden; margin-bottom:20px;">\n                    <table style="width:100%; border-collapse:collapse; text-align:left; font-size:0.8rem;">\n                        <thead>\n                            <tr style="background:var(--bg-base); border-bottom:1px solid var(--border-color);">\n                                <th style="padding:8px 10px;">Analisi</th>\n                                <th style="padding:8px 10px; text-align:center; width:90px;">Risultato</th>\n                                <th style="padding:8px 10px; width:70px;">Unità</th>\n                                <th style="padding:8px 10px; width:100px;">Riferimento</th>\n                                <th style="padding:8px 10px; text-align:center; width:90px;">Stato</th>\n                            </tr>\n                        </thead>\n                        <tbody>\n                            ${testsRows}\n                        </tbody>\n                    </table>\n                </div>\n\n                <!-- Textarea for notes -->\n                <div class="form-group">\n                    <label for="rep-modal-notes" style="font-weight:600; font-size:0.85rem; margin-bottom:6px; display:block;">Note e Osservazioni di Refertazione</label>\n                    <textarea id="rep-modal-notes" rows="4" style="width:100%; padding:10px; border:1px solid var(--border-color); border-radius:var(--radius-sm); font-size:0.85rem; background:var(--bg-surface); color:var(--text-primary); resize:vertical;" ${isLocked ? 'disabled' : ''}>${repNotes}</textarea>\n                </div>\n            </div>\n\n            <!-- Modal Footer -->\n            <div style="padding: 15px 24px; background: var(--bg-base); border-top: 1px solid var(--border-color); display: flex; justify-content: space-between; align-items: center; gap: 10px;">\n                <div>\n                    <button class="btn btn-secondary btn-sm" onclick="window.printSingleLisReport('${sessionUid}')" style="display: inline-flex; align-items: center; gap: 4px;">\n                        <i data-lucide="printer" style="width:12px; height:12px;"></i> Stampa / Anteprima\n                    </button>\n                </div>\n                <div style="display:flex; gap:10px;">\n                    <button class="btn btn-secondary btn-sm" onclick="window.closeLisReportingDetailModal()">Chiudi</button>\n                    <button class="btn btn-secondary btn-sm" onclick="window.submitReportingDetailForm('${sessionUid}', 'preliminary')" style="background-color:#f59e0b; color:#fff; border-color:#f59e0b;" ${isLocked ? 'disabled style="opacity:0.5; cursor:not-allowed;"' : ''}>Salva Bozza</button>\n                    <button class="btn btn-primary btn-sm" onclick="window.submitReportingDetailForm('${sessionUid}', 'official')" ${isLocked ? 'disabled style="opacity:0.5; cursor:not-allowed;"' : ''}>Firma Referto Ufficiale</button>\n                </div>\n            </div>\n        </div>\n    `;

    modal.style.display = 'flex';
    if (window.lucide) window.lucide.createIcons();
};

window.closeLisReportingDetailModal = function() {
    const modal = document.getElementById('modal-lis-reporting-detail');
    if (modal) modal.style.display = 'none';
};

window.submitReportingDetailForm = function(sessionUid, status) {
    const samples = DB.get('lab_samples') || [];
    const sessionSamples = samples.filter(s => s.session_uid === sessionUid);
    const totalCount = sessionSamples.length;
    const validatedCount = sessionSamples.filter(s => s.status === 'validated' || s.status === 'completed').length;
    const isAllValidated = (validatedCount === totalCount);

    if (status === 'official' && !isAllValidated) {
        alert("Impossibile rilasciare il referto Ufficiale: tutti i campioni associati a questa sessione devono essere preventivamente convalidati (Progresso attuale: " + validatedCount + "/" + totalCount + ").");
        return;
    }

    if (status === 'official') {
        if (!confirm("Sei sicuro di voler firmare digitalmente questo referto come Ufficiale?\n\nQuesta azione bloccherà definitivamente le note e i risultati clinici.")) {
            return;
        }
    }

    const notes = document.getElementById('rep-modal-notes').value;
    const reports = DB.get('lab_reports') || [];
    let rep = reports.find(r => r.session_uid === sessionUid);
    const timestamp = new Date().toISOString();

    if (!rep) {
        rep = {
            id: reports.length > 0 ? Math.max(...reports.map(r => r.id)) + 1 : 1,
            session_uid: sessionUid,
            status: status,
            notes: notes,
            released_at: status === 'official' ? timestamp : null,
            released_by: status === 'official' ? 5 : null
        };
        reports.push(rep);
    } else {
        rep.status = status;
        rep.notes = notes;
        if (status === 'official') {
            rep.released_at = timestamp;
            rep.released_by = 5;
        }
    }

    DB.set('lab_reports', reports);
    DB.logAudit(5, "LAB_REPORT_COMPILE", "lab_reports", rep.id, { status: status, session_uid: sessionUid });

    alert(status === 'official' ? "Referto firmato e rilasciato con successo!" : "Bozza salvata con successo.");
    window.closeLisReportingDetailModal();
    window.renderLisReportingView();
};

window.printSingleLisReport = function(sessionUid) {
    const prevSelected = window.selectedReportingSessionUids || [];
    window.selectedReportingSessionUids = [sessionUid];
    window.bulkPrintLisReports();
    window.selectedReportingSessionUids = prevSelected;
};



// ==========================================
// MODULE: UNIFIED REPORTS & PDF BULK EXPORT
// ==========================================

window.renderUnifiedReports = function(query = '') {
    if (typeof window.seedValidationHistory === 'function') {
        window.seedValidationHistory();
    }
    const labReports = DB.get('lab_reports') || [];
    const samples = DB.get('lab_samples') || [];
    const tests = DB.get('lab_tests') || [];
    const services = DB.get('medical_services') || [];
    const patients = DB.get('patients') || [];
    const staff = DB.get('staff') || [];
    const radStudies = DB.get('radiology_studies') || [];

    const roleSelect = document.getElementById('user-role-select');
    const currentRole = roleSelect ? roleSelect.value : 'admin';

    const unified = [];

    // 1. Process LIS Reports
    if (currentRole !== 'doctor_1' && currentRole !== 'doctor_2') {
        labReports.forEach(rep => {
            const sessionSamples = samples.filter(s => s.session_uid === rep.session_uid);
            if (sessionSamples.length === 0) return;
            const firstSample = sessionSamples[0];
            const pat = patients.find(p => p.id === firstSample.patient_id);
            if (!pat) return;

            const sampleIds = sessionSamples.map(s => s.id);
            const sessionTests = tests.filter(t => sampleIds.includes(t.sample_id));
            const srvIds = [...new Set(sessionTests.map(t => t.service_id).filter(id => id !== null))];
            let examName = '';
            if (srvIds.length > 0) {
                examName = srvIds.map(id => {
                    const srv = services.find(s => s.id === id);
                    return srv ? srv.name : 'Analisi';
                }).filter((v, i, a) => a.indexOf(v) === i).join(', ');
            } else {
                examName = 'Esami di Laboratorio';
            }

            const validator = staff.find(st => st.id === rep.released_by) || staff.find(st => st.id === firstSample.verified_by) || { last_name: "Moretti", first_name: "Luca", id: 5 };
            const docName = `Dott. ${validator.first_name} ${validator.last_name}`;

            unified.push({
                id: rep.id,
                uid: rep.session_uid,
                patient_id: pat.id,
                patient_name: `${pat.last_name} ${pat.first_name}`,
                patient_tax_code: pat.tax_code,
                type: 'LIS',
                date: rep.released_at || firstSample.collected_at || firstSample.created_at,
                service_name: examName,
                doctor_id: validator.id,
                doctor_name: docName,
                status: rep.status === 'official' ? 'Firmato (Ufficiale)' : 'Bozza (Preliminare)',
                status_raw: rep.status,
                sample_id: firstSample.id
            });
        });
    }

    // 2. Process RIS & VISIT Reports (Completed only)
    if (currentRole !== 'biologo') {
        radStudies.forEach(study => {
            if (study.status !== 'completed' || !study.report_text) return;
            if (currentRole === 'doctor_1' && study.doctor_id !== 1 && study.signed_by !== 1) return;
            if (currentRole === 'doctor_2' && study.doctor_id !== 2 && study.signed_by !== 2) return;

            const pat = patients.find(p => p.id === study.patient_id);
            if (!pat) return;

            const srv = services.find(s => s.id === study.service_id);
            const examName = srv ? srv.name : (study.study_type === 'VISIT' ? 'Visita Specialistica' : 'Esame Radiologico');

            const signer = staff.find(st => st.id === study.signed_by) || staff.find(st => st.id === study.doctor_id) || { last_name: "Bianchi", first_name: "Giulia", id: 2 };
            const docName = `Dott. ${signer.first_name} ${signer.last_name}`;

            unified.push({
                id: study.id,
                uid: study.dicom_series_uid || `STUDY-${study.id}`,
                patient_id: pat.id,
                patient_name: `${pat.last_name} ${pat.first_name}`,
                patient_tax_code: pat.tax_code,
                type: study.study_type === 'VISIT' ? 'VISIT' : 'RIS',
                date: study.signed_at || study.scheduled_at,
                service_name: examName,
                doctor_id: signer.id,
                doctor_name: docName,
                status: 'Firmato (Ufficiale)',
                status_raw: 'completed',
                sample_id: null
            });
        });
    }

    // Populate Doctor Filter once or preserve selection
    const docSelect = document.getElementById('rep-unif-filter-doctor');
    if (docSelect) {
        const prevVal = docSelect.value;
        docSelect.innerHTML = '<option value="">Tutti i Medici</option>';
        const uniqueDocs = [];
        unified.forEach(item => {
            if (item.doctor_id && !uniqueDocs.some(d => d.id === item.doctor_id)) {
                uniqueDocs.push({ id: item.doctor_id, name: item.doctor_name });
            }
        });
        uniqueDocs.forEach(d => {
            const option = document.createElement('option');
            option.value = d.id;
            option.textContent = d.name;
            docSelect.appendChild(option);
        });
        docSelect.value = prevVal;
        if (docSelect.value !== prevVal) docSelect.value = "";
    }

    // Apply Filter Logic
    const searchVal = (document.getElementById('rep-unif-search')?.value || query).toLowerCase().trim();
    const typeVal = document.getElementById('rep-unif-filter-type')?.value || '';
    const docVal = document.getElementById('rep-unif-filter-doctor')?.value || '';
    const startVal = document.getElementById('rep-unif-filter-start')?.value || '';
    const endVal = document.getElementById('rep-unif-filter-end')?.value || '';

    const filtered = unified.filter(item => {
        // Search text
        if (searchVal) {
            const matchesPatient = item.patient_name.toLowerCase().includes(searchVal) || item.patient_tax_code.toLowerCase().includes(searchVal);
            const matchesSrv = item.service_name.toLowerCase().includes(searchVal);
            const matchesDoc = item.doctor_name.toLowerCase().includes(searchVal);
            if (!matchesPatient && !matchesSrv && !matchesDoc) return false;
        }

        // Report type
        if (typeVal && item.type !== typeVal) return false;

        // Doctor
        if (docVal && String(item.doctor_id) !== String(docVal)) return false;

        // Date start
        const dateStr = item.date ? item.date.substring(0, 10) : '';
        if (startVal && dateStr < startVal) return false;

        // Date end
        if (endVal && dateStr > endVal) return false;

        return true;
    });

    // Save filtered list globally for bulk export
    window.currentFilteredUnifiedReports = filtered;

    // Update statistics cards based on all produced reports
    const statTotal = document.getElementById('stat-total-reports');
    const statLis = document.getElementById('stat-lis-reports');
    const statRis = document.getElementById('stat-ris-reports');
    const statVisit = document.getElementById('stat-visit-reports');

    if (statTotal) statTotal.textContent = unified.length;
    if (statLis) statLis.textContent = unified.filter(i => i.type === 'LIS').length;
    if (statRis) statRis.textContent = unified.filter(i => i.type === 'RIS').length;
    if (statVisit) statVisit.textContent = unified.filter(i => i.type === 'VISIT').length;

    // Pagination
    const paginated = window.setupTablePagination('unified-reports-table', filtered, () => window.renderUnifiedReports());

    const tbody = document.getElementById('unified-reports-tbody');
    if (!tbody) return;
    tbody.innerHTML = '';

    if (filtered.length === 0) {
        tbody.innerHTML = `<tr><td colspan="8" style="text-align: center;" class="text-muted">Nessun referto trovato</td></tr>`;
        return;
    }

    paginated.forEach(item => {
        const tr = document.createElement('tr');

        let typeBadge = '';
        if (item.type === 'LIS') {
            typeBadge = '<span class="badge badge-success" style="background-color: #10b981; color: white; border: none; font-weight:600;">LIS (Lab)</span>';
        } else if (item.type === 'RIS') {
            typeBadge = '<span class="badge badge-info" style="background-color: #06b6d4; color: white; border: none; font-weight:600;">RIS (Radio)</span>';
        } else if (item.type === 'VISIT') {
            typeBadge = '<span class="badge badge-primary" style="background-color: #3b82f6; color: white; border: none; font-weight:600;">Visita</span>';
        }

        let statusBadge = '';
        if (item.status_raw === 'preliminary') {
            statusBadge = '<span class="badge badge-warning" style="background-color: #f59e0b; color: white; border: none;">Bozza</span>';
        } else {
            statusBadge = '<span class="badge badge-success" style="background-color: #10b981; color: white; border: none;">Firmato</span>';
        }

        const dateStr = item.date ? new Date(item.date).toLocaleString('it-IT', { day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' }) : 'N/A';

        tr.innerHTML = `\n            <td style="text-align: center;">\n                <input type="checkbox" class="rep-unif-row-checkbox" data-type="${item.type}" data-id="${item.id}" data-uid="${item.uid}" data-sample-id="${item.sample_id || ''}">\n            </td>\n            <td>\n                <strong>${item.patient_name}</strong><br>\n                <small class="text-muted" style="font-family: monospace;">${item.patient_tax_code}</small>\n            </td>\n            <td>${typeBadge}</td>\n            <td>${dateStr}</td>\n            <td><div style="max-width: 200px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;" title="${item.service_name}">${item.service_name}</div></td>\n            <td>${item.doctor_name}</td>\n            <td>${statusBadge}</td>\n            <td>\n                <button class="btn btn-secondary btn-sm" onclick="window.viewUnifiedReport('${item.type}', ${item.id}, '${item.uid}', ${item.sample_id})">\n                    <i data-lucide="eye" style="width: 14px; height: 14px; vertical-align: middle; margin-right: 4px;"></i> Apri\n                </button>\n                <button class="btn btn-primary btn-sm" onclick="window.exportSingleReportPdf('${item.type}', ${item.id}, '${item.uid}', ${item.sample_id})" style="margin-left: 5px;">\n                    <i data-lucide="file-text" style="width: 14px; height: 14px; vertical-align: middle; margin-right: 4px;"></i> PDF\n                </button>\n            </td>\n        `;
        tbody.appendChild(tr);
    });

    if (window.lucide) window.lucide.createIcons();
};

window.filterUnifiedReports = function() {
    if (window.tablePaginationStates && window.tablePaginationStates['unified-reports-table']) {
        window.tablePaginationStates['unified-reports-table'].currentPage = 1;
    }
    window.renderUnifiedReports();
};

window.toggleSelectAllReports = function(masterCheckbox) {
    const checkboxes = document.querySelectorAll('.rep-unif-row-checkbox');
    checkboxes.forEach(cb => {
        cb.checked = masterCheckbox.checked;
    });
};

window.viewUnifiedReport = function(type, id, uid, sampleId) {
    if (type === 'LIS') {
        window.openLisReportView(sampleId);
    } else {
        window.openRisReportView(id);
    }
};

window.exportSingleReportPdf = function(type, id, uid, sampleId) {
    // 1. Render report in the DOM modal
    if (type === 'LIS') {
        window.openLisReportView(sampleId);
        document.getElementById('modal-lis-report-view').style.opacity = '0';
        document.getElementById('modal-lis-report-view').style.pointerEvents = 'none';
    } else {
        window.openRisReportView(id);
        document.getElementById('modal-ris-report-view').style.opacity = '0';
        document.getElementById('modal-ris-report-view').style.pointerEvents = 'none';
    }

    setTimeout(() => {
        const modalId = (type === 'LIS') ? 'modal-lis-report-view' : 'modal-ris-report-view';
        const modalEl = document.getElementById(modalId);
        if (!modalEl) {
            alert("Errore: Impossibile trovare la modale del referto.");
            return;
        }

        const reportContainer = modalEl.querySelector('.report-print-container');
        if (!reportContainer) {
            alert("Errore: Impossibile trovare il contenitore del referto.");
            return;
        }

        // Get patient name
        const patients = DB.get('patients') || [];
        let patName = 'Paziente_Ignoto';
        let patId = null;

        if (type === 'LIS') {
            const sample = (DB.get('lab_samples') || []).find(s => s.id === sampleId);
            if (sample) patId = sample.patient_id;
        } else {
            const study = (DB.get('radiology_studies') || []).find(s => s.id === id);
            if (study) patId = study.patient_id;
        }

        if (patId !== null) {
            const pat = patients.find(p => p.id === patId);
            if (pat) {
                patName = `${pat.last_name}_${pat.first_name}`.replace(/\s+/g, '_').toUpperCase();
            }
        }

        const dateStr = new Date().toISOString().substring(0, 10);
        const filename = `Referto_${type}_${patName}_${dateStr}.pdf`;

        const opt = {
            margin:       10,
            filename:     filename,
            image:        { type: 'jpeg', quality: 0.98 },
            html2canvas:  { scale: 2, useCORS: true, logging: false },
            jsPDF:        { unit: 'mm', format: 'a4', orientation: 'portrait' }
        };

        html2pdf().from(reportContainer).set(opt).toPdf().get('pdf').then(function(pdf) {
            const pdfBase64 = pdf.output('datauristring').split(',')[1];

            // Send to server filesystem
            fetch('/api/save-pdf-report', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    filename: filename,
                    base64_content: pdfBase64
                })
            })
            .then(res => res.json())
            .then(resData => {
                if (resData.success) {
                    alert(`Referto salvato con successo sul filesystem del server in:\n\n${resData.data.path}\n\n\n\nIl browser avvierà anche il download locale.`);
                } else {
                    alert(`Referto scaricato, ma errore nel salvataggio su filesystem: ${resData.error}`);
                }
            })
            .catch(err => {
                console.error("Errore API save-pdf-report:", err);
            });

            // Trigger browser download
            pdf.save(filename);

            // Close modal overlay
            modalEl.style.display = 'none';
            modalEl.style.opacity = '1';
            modalEl.style.pointerEvents = 'auto';
        });

    }, 400);
};

window.bulkExportReports = function() {
    let itemsToExport = [];

    const checkboxes = document.querySelectorAll('.rep-unif-row-checkbox:checked');
    if (checkboxes.length > 0) {
        checkboxes.forEach(cb => {
            const type = cb.getAttribute('data-type');
            const id = parseInt(cb.getAttribute('data-id'));
            const uid = cb.getAttribute('data-uid');
            const sampleId = cb.getAttribute('data-sample-id') ? parseInt(cb.getAttribute('data-sample-id')) : null;
            itemsToExport.push({ type, id, uid, sampleId });
        });
    } else {
        if (window.currentFilteredUnifiedReports && window.currentFilteredUnifiedReports.length > 0) {
            if (confirm(`Nessun referto selezionato manualmente. Vuoi esportare in blocco tutti i ${window.currentFilteredUnifiedReports.length} referti corrispondenti ai filtri attuali?`)) {
                itemsToExport = window.currentFilteredUnifiedReports.map(item => ({
                    type: item.type,
                    id: item.id,
                    uid: item.uid,
                    sampleId: item.sample_id
                }));
            } else {
                return;
            }
        } else {
            alert("Nessun referto disponibile per l'esportazione.");
            return;
        }
    }

    if (itemsToExport.length === 0) return;

    alert(`Inizio esportazione massiva di ${itemsToExport.length} referti.\n\nI file verranno scaricati e scritti sul filesystem. Premi OK per iniziare.`);

    let index = 0;
    let successCount = 0;

    function exportNext() {
        if (index >= itemsToExport.length) {
            alert(`Esportazione massiva completata!\n\n${successCount} referti salvati con successo nella cartella 'esportazioni_referti' del server.`);
            const selectAll = document.getElementById('rep-unif-select-all');
            if (selectAll) selectAll.checked = false;
            window.renderUnifiedReports();
            return;
        }

        const item = itemsToExport[index];

        if (item.type === 'LIS') {
            window.openLisReportView(item.sampleId);
            document.getElementById('modal-lis-report-view').style.opacity = '0';
            document.getElementById('modal-lis-report-view').style.pointerEvents = 'none';
        } else {
            window.openRisReportView(item.id);
            document.getElementById('modal-ris-report-view').style.opacity = '0';
            document.getElementById('modal-ris-report-view').style.pointerEvents = 'none';
        }

        setTimeout(() => {
            const modalId = (item.type === 'LIS') ? 'modal-lis-report-view' : 'modal-ris-report-view';
            const modalEl = document.getElementById(modalId);
            if (!modalEl) {
                index++;
                exportNext();
                return;
            }

            const reportContainer = modalEl.querySelector('.report-print-container');
            if (!reportContainer) {
                index++;
                exportNext();
                return;
            }

            const patients = DB.get('patients') || [];
            let patName = 'Paziente_Ignoto';
            let patId = null;

            if (item.type === 'LIS') {
                const sample = (DB.get('lab_samples') || []).find(s => s.id === item.sampleId);
                if (sample) patId = sample.patient_id;
            } else {
                const study = (DB.get('radiology_studies') || []).find(s => s.id === item.id);
                if (study) patId = study.patient_id;
            }

            if (patId !== null) {
                const pat = patients.find(p => p.id === patId);
                if (pat) {
                    patName = `${pat.last_name}_${pat.first_name}`.replace(/\s+/g, '_').toUpperCase();
                }
            }

            const dateStr = new Date().toISOString().substring(0, 10);
            const filename = `Referto_${item.type}_${patName}_${dateStr}.pdf`;

            const opt = {
                margin:       10,
                filename:     filename,
                image:        { type: 'jpeg', quality: 0.98 },
                html2canvas:  { scale: 2, useCORS: true, logging: false },
                jsPDF:        { unit: 'mm', format: 'a4', orientation: 'portrait' }
            };

            html2pdf().from(reportContainer).set(opt).toPdf().get('pdf').then(function(pdf) {
                const pdfBase64 = pdf.output('datauristring').split(',')[1];

                fetch('/api/save-pdf-report', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        filename: filename,
                        base64_content: pdfBase64
                    })
                })
                .then(res => res.json())
                .then(resData => {
                    if (resData.success) {
                        successCount++;
                    }
                })
                .catch(err => {
                    console.error("Errore bulk saving:", err);
                })
                .finally(() => {
                    pdf.save(filename);
                    modalEl.style.display = 'none';
                    modalEl.style.opacity = '1';
                    modalEl.style.pointerEvents = 'auto';
                    index++;
                    exportNext();
                });
            });

        }, 400);
    }

    exportNext();
};


// Force-seed historical appointments and reports once if not present
(function() {
    setTimeout(() => {
        if (typeof DB !== 'undefined' && typeof window.seedValidationHistory === 'function') {
            // Skip client-side force-seeding in MySQL mode to prevent startup race conditions
            if (window.location.port !== '8001') {
                console.log("[Seed] MySQL mode active, skipping client-side force-seed.");
                return;
            }
            const appointments = DB.get('appointments') || [];
            const radStudies = DB.get('radiology_studies') || [];
            if (!appointments.some(a => a.id === 101) || !radStudies.some(s => s.id === 101)) {
                // Clear LIS mock samples
                let samples = DB.get('lab_samples') || [];
                samples = samples.filter(s => !s.barcode || (!s.barcode.startsWith('VAL-S-') && !s.barcode.startsWith('VAL-B-') && !s.barcode.startsWith('VAL-U-') && !s.barcode.startsWith('VAL-PEND-')));
                DB.set('lab_samples', samples);
                
                let tests = DB.get('lab_tests') || [];
                const activeSampleIds = new Set(samples.map(s => s.id));
                tests = tests.filter(t => activeSampleIds.has(t.sample_id));
                DB.set('lab_tests', tests);
                
                // Clear matching LIS reports
                let reports = DB.get('lab_reports') || [];
                reports = reports.filter(r => !r.session_uid || !r.session_uid.startsWith('SESS-VAL-'));
                DB.set('lab_reports', reports);

                // Clear RIS mock studies (IDs 101, 102, 103, 105, 106)
                let radStudies = DB.get('radiology_studies') || [];
                radStudies = radStudies.filter(s => s.id !== 101 && s.id !== 102 && s.id !== 103 && s.id !== 105 && s.id !== 106);
                DB.set('radiology_studies', radStudies);

                // Clear mock appointments
                let apps = DB.get('appointments') || [];
                apps = apps.filter(a => a.id < 100 || (a.id !== 101 && a.id !== 102 && a.id !== 103 && a.id !== 104 && a.id !== 105 && a.id !== 106 && a.id < 1000));
                DB.set('appointments', apps);
                
                window.seedValidationHistory();
                console.log("Forced historical seed complete (with RIS/VISIT mocks).");
            }
        }
    }, 500);
})();

// ==========================================================
// ACCEPTANCE MODIFICATION AND AUTOMATIC BILLING ADJUSTMENTS
// ==========================================================

window.openEditAcceptanceModal = function(type, id) {
    console.log("openEditAcceptanceModal called with type:", type, "and id:", id);
    let associatedRecipe = null;
    
    // Clear and prepare form inputs
    document.getElementById('edit-acc-type').value = type;
    document.getElementById('edit-acc-id').value = id;
    document.getElementById('edit-acc-search-service').value = '';
    document.getElementById('edit-acc-search-results').style.display = 'none';
    document.getElementById('edit-acc-services-tbody').innerHTML = '';
    
    const lblDose = document.getElementById('lbl-edit-acc-dose-class');
    const valDose = document.getElementById('edit-acc-dose-class');
    if (lblDose) lblDose.style.display = 'none';
    if (valDose) valDose.style.display = 'none';
    
    const patients = DB.get('patients') || [];
    const services = DB.get('medical_services') || [];
    const invoices = DB.get('invoices') || [];
    
    let patientObj = null;
    let dateStr = '';
    let invoiceNum = 'Nessuna';
    let invoiceObj = null;
    
    // Store current list of services to edit in a global variable
    window.currentEditingServices = [];
    
    if (type === 'LIS') {
        const samples = DB.get('lab_samples') || [];
        const tests = DB.get('lab_tests') || [];
        let groupSamples = samples.filter(s => s.session_uid === id);
        if (groupSamples.length === 0 && id.startsWith('LIS-FALLBACK-')) {
            groupSamples = samples.filter(s => {
                if (s.session_uid) return false;
                const fallbackId = 'LIS-FALLBACK-' + s.patient_id + '-' + s.collected_at;
                return fallbackId === id;
            });
        }
        
        if (groupSamples.length === 0) {
            alert("Accettazione LIS non trovata.");
            return;
        }
        
        const firstSample = groupSamples[0];
        patientObj = patients.find(p => p.id === firstSample.patient_id);
        dateStr = window.safeFormatDate(firstSample.collected_at);
        
        const groupSampleIds = groupSamples.map(s => s.id);
        associatedRecipe = (DB.get('ssn_recipes') || []).find(r => r.sample_id && groupSampleIds.includes(r.sample_id));
        const groupTests = tests.filter(t => groupSampleIds.includes(t.sample_id));
        
        invoiceObj = invoices.find(i => groupSampleIds.includes(i.sample_id) && !i.is_insurance_invoice);
        if (invoiceObj) {
            invoiceNum = invoiceObj.invoice_number;
        }
        
        groupTests.forEach(t => {
            const srv = services.find(sv => sv.id === t.service_id);
            if (srv) {
                window.currentEditingServices.push({
                    id: srv.id,
                    code: srv.code,
                    name: srv.name,
                    price: Number(srv.price) || 0,
                    sample_type: srv.sample_type,
                    reference_range: srv.reference_range || '',
                    unit: srv.unit || '',
                    branch: srv.branch || 'Laboratorio',
                    type: srv.type || 'lis'
                });
            }
        });
    } else {
        const studies = DB.get('radiology_studies') || [];
        const study = studies.find(s => s.id === id);
        
        if (!study) {
            alert("Accettazione RIS/Visita non trovata.");
            return;
        }
        
        patientObj = patients.find(p => p.id === study.patient_id);
        associatedRecipe = (DB.get('ssn_recipes') || []).find(r => r.study_id === study.id);
        dateStr = window.safeFormatDate(study.scheduled_at);
        
        invoiceObj = invoices.find(i => i.study_id === study.id && !i.is_insurance_invoice);
        if (invoiceObj) {
            invoiceNum = invoiceObj.invoice_number;
        }
        
        const srv = services.find(sv => sv.id === study.service_id);
        if (srv) {
            window.currentEditingServices.push({
                id: srv.id,
                code: srv.code,
                name: srv.name,
                price: Number(srv.price) || 0,
                branch: srv.branch || (study.study_type === 'VISIT' ? 'Visita' : 'Radiologia'),
                type: study.study_type === 'VISIT' ? 'visita' : 'ris'
            });
        }
        
        const isVisit = study.study_type === 'VISIT';
        if (!isVisit && srv && srv.dose_class_id && lblDose && valDose) {
            const dc = (DB.get('dose_classes') || []).find(c => c.id === srv.dose_class_id);
            if (dc) {
                valDose.innerText = `Classe ${dc.code} (${dc.range_msv} - ${dc.description})`;
                lblDose.style.display = 'inline';
                valDose.style.display = 'inline';
            }
        }
    }
    
    if (patientObj) {
        document.getElementById('edit-acc-patient-name').innerText = `${patientObj.last_name.toUpperCase()} ${patientObj.first_name.toUpperCase()}`;
        document.getElementById('edit-acc-patient-tax').innerText = patientObj.tax_code;
    } else {
        document.getElementById('edit-acc-patient-name').innerText = "Paziente Sconosciuto";
        document.getElementById('edit-acc-patient-tax').innerText = "--";
    }
    document.getElementById('edit-acc-date-str').innerText = dateStr;
    document.getElementById('edit-acc-invoice-num').innerText = invoiceNum;
    
    // Set financial summary based on invoice
    window.currentEditingInvoice = invoiceObj;
    const origTotal = invoiceObj ? Number(invoiceObj.amount_due) : 0;
    window.currentEditingOrigTotal = origTotal;
    
    // Cache the original services so we can track stornati (removed) ones
    window.currentEditingOrigServices = [...window.currentEditingServices];
    
    document.getElementById('edit-acc-orig-total').innerText = `€ ${origTotal.toFixed(2)}`;
    
    // Render the table rows for selected services
    window.renderEditAcceptanceServicesTable();
    
    // Setup autocomplete search field
    const searchInput = document.getElementById('edit-acc-search-service');
    const searchResults = document.getElementById('edit-acc-search-results');
    
    // Handle input in search
    searchInput.oninput = function() {
        const query = searchInput.value.toLowerCase().trim();
        searchResults.innerHTML = '';
        if (!query) {
            searchResults.style.display = 'none';
            return;
        }
        
        // Filter services by type matching the acceptance type
        let filteredSrv = [];
        if (type === 'LIS') {
            filteredSrv = services.filter(s => s.type === 'lis');
        } else if (type === 'RIS') {
            filteredSrv = services.filter(s => s.type === 'ris');
        } else {
            // VISIT
            filteredSrv = services.filter(s => s.type === 'visita');
        }
        
        // Filter by query
        filteredSrv = filteredSrv.filter(s => s.name.toLowerCase().includes(query) || (s.code && s.code.toLowerCase().includes(query)));
        
        if (filteredSrv.length === 0) {
            searchResults.innerHTML = '<div style="padding: 8px; color: var(--text-secondary); font-size: 0.8rem;">Nessuna prestazione trovata.</div>';
        } else {
            filteredSrv.forEach(s => {
                const div = document.createElement('div');
                div.style.padding = '8px 12px';
                div.style.cursor = 'pointer';
                div.style.borderBottom = '1px solid var(--border-color)';
                div.className = 'autocomplete-item';
                div.onmouseenter = function() { div.style.backgroundColor = 'var(--bg-base)'; };
                div.onmouseleave = function() { div.style.backgroundColor = 'transparent'; };
                div.innerHTML = `<strong>${s.code || ''}</strong> - ${s.name} <span style="float: right; color: var(--primary);">€ ${(Number(s.price) || 0).toFixed(2)}</span>`;
                div.onclick = function() {
                    // Check if already in list (for RIS/VISIT we usually edit 1-to-1, but let's support multiple if LIS)
                    if (type !== 'LIS') {
                        window.currentEditingServices = [{
                            id: s.id,
                            code: s.code,
                            name: s.name,
                            price: Number(s.price) || 0,
                            sample_type: s.sample_type,
                            reference_range: s.reference_range || '',
                            unit: s.unit || ''
                        }];
                        window.renderEditAcceptanceServicesTable();
                        searchResults.style.display = 'none';
                        searchInput.value = '';
                        return;
                    }
                    if (window.currentEditingServices.some(item => item.id === s.id)) {
                        alert("Prestazione già selezionata.");
                        searchResults.style.display = 'none';
                        searchInput.value = '';
                        return;
                    }
                    window.currentEditingServices.push({
                        id: s.id,
                        code: s.code,
                        name: s.name,
                        price: Number(s.price) || 0,
                        sample_type: s.sample_type,
                        reference_range: s.reference_range || '',
                        unit: s.unit || ''
                    });
                    window.renderEditAcceptanceServicesTable();
                    searchResults.style.display = 'none';
                    searchInput.value = '';
                };
                searchResults.appendChild(div);
            });
        }
        searchResults.style.display = 'block';
    };
    
    // Close search results if clicked outside
    const outsideClickListener = function(e) {
        if (e.target !== searchInput && e.target !== searchResults) {
            searchResults.style.display = 'none';
            document.removeEventListener('click', outsideClickListener);
        }
    };
    document.addEventListener('click', outsideClickListener);
    
    const recipeCard = document.getElementById('edit-acc-recipe-card');
    if (recipeCard) {
        if (associatedRecipe) {
            document.getElementById('edit-acc-recipe-nre').innerText = associatedRecipe.nre || '--';
            document.getElementById('edit-acc-recipe-date').innerText = associatedRecipe.recipe_date || '--';
            document.getElementById('edit-acc-recipe-exemption').innerText = associatedRecipe.exemption_code || 'Nessuna';
            document.getElementById('edit-acc-recipe-diagnosis').innerText = associatedRecipe.diagnostic_question || 'Nessuno';
            recipeCard.style.display = 'block';
        } else {
            recipeCard.style.display = 'none';
        }
    }
    
    openModal('modal-edit-acceptance');
};

window.renderEditAcceptanceServicesTable = function() {
    const tbody = document.getElementById('edit-acc-services-tbody');
    tbody.innerHTML = '';
    
    const type = document.getElementById('edit-acc-type').value;
    
    if (window.currentEditingServices.length === 0) {
        tbody.innerHTML = '<tr><td colspan="4" style="text-align: center;" class="text-muted">Nessuna prestazione selezionata.</td></tr>';
    } else {
        window.currentEditingServices.forEach((srv, idx) => {
            const tr = document.createElement('tr');
            tr.innerHTML = `
                <td style="padding: 6px;">${srv.code || '--'}</td>
                <td style="padding: 6px;">${srv.name}</td>
                <td style="padding: 6px; text-align: right;">€ ${srv.price.toFixed(2)}</td>
                <td style="padding: 6px; text-align: center;">
                    <button type="button" class="btn btn-danger btn-sm" style="padding: 2px 6px;" onclick="window.removeEditingService(${idx})">
                        <i data-lucide="trash-2" style="width: 12px; height: 12px;"></i>
                    </button>
                </td>
            `;
            tbody.appendChild(tr);
        });
        if (window.lucide) window.lucide.createIcons();
    }
    
    // Update Financial Panel
    window.recalculateEditAcceptanceFinancials();
};

window.removeEditingService = function(idx) {
    const type = document.getElementById('edit-acc-type').value;
    if (type !== 'LIS') {
        // RIS/VISIT must have at least one exam, cannot remove the only one without replacing
        alert("Le accettazioni RIS/Visite devono avere almeno una prestazione. Aggiungi la nuova prima di rimuovere la corrente.");
        return;
    }
    window.currentEditingServices.splice(idx, 1);
    window.renderEditAcceptanceServicesTable();
};

window.recalculateEditAcceptanceFinancials = function() {
    const invoice = window.currentEditingInvoice;
    const origTotal = window.currentEditingOrigTotal;
    
    // Sum prices of currently editing services
    let subtotal = window.currentEditingServices.reduce((sum, s) => sum + s.price, 0);
    
    // Apply discount if there was any in the original invoice
    let discount = 0;
    let discount_value = 0;
    let discount_amount = 0;
    let discount_type = 'flat';
    
    if (invoice) {
        discount_value = Number(invoice.discount_value) || 0;
        discount_amount = Number(invoice.discount_amount) || 0;
        discount_type = invoice.discount_type || 'flat';
        
        if (discount_type === 'percentage') {
            discount = subtotal * (discount_value / 100);
        } else if (discount_type === 'flat') {
            // Apply original flat discount, but cap it at the subtotal
            discount = Math.min(discount_amount, subtotal);
        }
    }
    
    let net = subtotal - discount;
    let stampDuty = 0.00;
    if (net > 77.47) {
        stampDuty = 2.00;
    }
    
    let newTotal = net + stampDuty;
    let diff = newTotal - origTotal;
    
    document.getElementById('edit-acc-new-total').innerText = `€ ${newTotal.toFixed(2)}`;
    
    const diffEl = document.getElementById('edit-acc-diff');
    const noteContainer = document.getElementById('edit-acc-admin-note-container');
    
    if (diff > 0) {
        diffEl.innerText = `+ € ${diff.toFixed(2)}`;
        diffEl.style.color = '#10b981'; // Green
        
        if (invoice && invoice.payment_status === 'paid') {
            noteContainer.style.background = 'rgba(16, 185, 129, 0.1)';
            noteContainer.style.color = '#10b981';
            noteContainer.innerHTML = `<i data-lucide="info" style="width: 14px; height: 14px; display: inline-block; vertical-align: middle; margin-right: 4px;"></i> <strong>Rettifica:</strong> L'accettazione è già pagata. Verrà emessa una <strong>Fattura Integrativa</strong> per la differenza di <strong>€ ${diff.toFixed(2)}</strong> (stato Non Pagata).`;
        } else {
            noteContainer.style.background = 'rgba(59, 130, 246, 0.1)';
            noteContainer.style.color = '#3b82f6';
            noteContainer.innerHTML = `<i data-lucide="info" style="width: 14px; height: 14px; display: inline-block; vertical-align: middle; margin-right: 4px;"></i> <strong>Rettifica:</strong> L'importo della fattura originaria non pagata verrà aggiornato a <strong>€ ${newTotal.toFixed(2)}</strong>.`;
        }
    } else if (diff < 0) {
        const absDiff = Math.abs(diff);
        diffEl.innerText = `- € ${absDiff.toFixed(2)}`;
        diffEl.style.color = '#ef4444'; // Red
        
        if (invoice && invoice.payment_status === 'paid') {
            noteContainer.style.background = 'rgba(239, 68, 68, 0.1)';
            noteContainer.style.color = '#ef4444';
            noteContainer.innerHTML = `<i data-lucide="alert-triangle" style="width: 14px; height: 14px; display: inline-block; vertical-align: middle; margin-right: 4px;"></i> <strong>Rettifica:</strong> L'accettazione è già pagata. Verrà emessa una <strong>Nota di Credito</strong> per il rimborso di <strong>€ ${absDiff.toFixed(2)}</strong> (stato Pagata, metodo Contanti).`;
        } else {
            noteContainer.style.background = 'rgba(59, 130, 246, 0.1)';
            noteContainer.style.color = '#3b82f6';
            noteContainer.innerHTML = `<i data-lucide="info" style="width: 14px; height: 14px; display: inline-block; vertical-align: middle; margin-right: 4px;"></i> <strong>Rettifica:</strong> L'importo della fattura originaria non pagata verrà ridotto a <strong>€ ${newTotal.toFixed(2)}</strong>.`;
        }
    } else {
        diffEl.innerText = `€ 0.00`;
        diffEl.style.color = 'var(--text-primary)';
        noteContainer.style.background = 'var(--bg-base)';
        noteContainer.style.color = 'var(--text-secondary)';
        noteContainer.innerHTML = `Nessuna variazione di importo.`;
    }
    if (window.lucide) window.lucide.createIcons();
    
    // Store variables to be used in submit
    window.currentEditingNewTotal = newTotal;
    window.currentEditingDiff = diff;
    window.currentEditingSubtotal = subtotal;
    window.currentEditingDiscount = discount;
    window.currentEditingStampDuty = stampDuty;
};

window.submitEditAcceptance = function() {
    const type = document.getElementById('edit-acc-type').value;
    const id = document.getElementById('edit-acc-id').value; // session_uid for LIS, studyId for RIS/VISIT
    
    // Validate we have selected services
    if (!window.currentEditingServices || window.currentEditingServices.length === 0) {
        alert("Devi selezionare almeno una prestazione.");
        return;
    }
    
    const invoice = window.currentEditingInvoice;
    const diff = window.currentEditingDiff;
    const newTotal = window.currentEditingNewTotal;
    const subtotal = window.currentEditingSubtotal;
    const discount = window.currentEditingDiscount;
    const stampDuty = window.currentEditingStampDuty;
    
    if (type === 'LIS') {
        const samples = DB.get('lab_samples') || [];
        const tests = DB.get('lab_tests') || [];
        
        let currentSamples = samples.filter(s => s.session_uid === id);
        if (currentSamples.length === 0 && id.startsWith('LIS-FALLBACK-')) {
            currentSamples = samples.filter(s => {
                if (s.session_uid) return false;
                const fallbackId = 'LIS-FALLBACK-' + s.patient_id + '-' + s.collected_at;
                return fallbackId === id;
            });
        }
        
        if (currentSamples.length === 0) {
            alert("Accettazione LIS non trovata.");
            return;
        }
        
        const patientId = currentSamples[0].patient_id;
        const requestingDoctor = currentSamples[0].requesting_doctor;
        const collectedAt = currentSamples[0].collected_at;
        const collectedBy = currentSamples[0].collected_by;
        
        // Find which sample_types are required now
        const requiredSampleTypes = [...new Set(window.currentEditingServices.map(s => s.sample_type).filter(Boolean))];
        
        // Maintain samples
        let updatedSamples = [...samples];
        let updatedTests = [...tests];
        
        // Map required sample type to sample ID in this session
        const sampleTypeToId = {};
        
        // Keep or delete existing samples in this session
        const currentSamplesToDelete = [];
        currentSamples.forEach(sam => {
            if (requiredSampleTypes.includes(sam.sample_type)) {
                sampleTypeToId[sam.sample_type] = sam.id;
                // If it didn't have session_uid, let's assign it now!
                if (!sam.session_uid) {
                    sam.session_uid = id;
                }
            } else {
                currentSamplesToDelete.push(sam.id);
            }
        });
        
        // Delete samples no longer required (and their tests)
        if (currentSamplesToDelete.length > 0) {
            updatedSamples = updatedSamples.filter(s => !currentSamplesToDelete.includes(s.id));
            updatedTests = updatedTests.filter(t => !currentSamplesToDelete.includes(t.sample_id));
        }
        
        // Create new samples for required types not yet present
        const tubeTypes = DB.get('tube_types') || [];
        requiredSampleTypes.forEach(stype => {
            if (!sampleTypeToId[stype]) {
                const tubeType = tubeTypes.find(t => t.name.toLowerCase().includes(stype.toLowerCase()));
                const suffix = tubeType ? tubeType.suffix : 'XXX';
                const newBarcode = window.getNextBarcode(suffix);
                
                const newSample = {
                    patient_id: patientId,
                    barcode: newBarcode,
                    sample_type: stype,
                    status: 'collected',
                    session_uid: id,
                    collected_at: collectedAt || new Date().toISOString().replace('T', ' ').substring(0, 19),
                    collected_by: collectedBy || 1,
                    requesting_doctor: requestingDoctor
                };
                
                const nextId = updatedSamples.length > 0 ? Math.max(...updatedSamples.map(s => s.id)) + 1 : 1;
                newSample.id = nextId;
                updatedSamples.push(newSample);
                sampleTypeToId[stype] = nextId;
            }
        });
        
        // Re-create tests for this LIS session
        let otherTests = updatedTests.filter(t => !currentSamples.map(s => s.id).includes(t.sample_id));
        const newTestsForSession = [];
        
        window.currentEditingServices.forEach(srv => {
            const sampleId = sampleTypeToId[srv.sample_type];
            if (!sampleId) return;
            
            // Check if test already existed in the original session to preserve values
            const existingTest = tests.find(t => currentSamples.map(s => s.id).includes(t.sample_id) && t.service_id === srv.id);
            
            const nextTestId = (otherTests.length + newTestsForSession.length) > 0 
                ? Math.max(...otherTests.map(t => t.id), ...newTestsForSession.map(t => t.id)) + 1 
                : 1;
                
            const newTest = {
                id: nextTestId,
                sample_id: sampleId,
                service_id: srv.id,
                test_name: srv.name,
                result_value: existingTest ? existingTest.result_value : null,
                reference_range: srv.reference_range || '',
                unit: srv.unit || '',
                status: existingTest ? existingTest.status : 'pending',
                verified_by: existingTest ? existingTest.verified_by : null,
                verified_at: existingTest ? existingTest.verified_at : null
            };
            newTestsForSession.push(newTest);
        });
        
        updatedTests = [...otherTests, ...newTestsForSession];
        
        // Save LIS samples and tests
        DB.set('lab_samples', updatedSamples);
        DB.set('lab_tests', updatedTests);
        
        DB.logAudit(6, "EDIT_LIS_ACCEPTANCE", "lab_samples", id, { session_uid: id, exams_count: window.currentEditingServices.length });
    } else {
        // RIS / VISIT
        const studyId = parseInt(id, 10);
        const studies = DB.get('radiology_studies') || [];
        const studyIndex = studies.findIndex(s => s.id === studyId);
        
        if (studyIndex === -1) {
            alert("Accettazione RIS/Visita non trovata.");
            return;
        }
        
        const selectedSrv = window.currentEditingServices[0];
        
        studies[studyIndex].service_id = selectedSrv.id;
        studies[studyIndex].study_type = type === 'VISIT' ? 'VISIT' : (selectedSrv.branch || 'XRAY');
        
        DB.set('radiology_studies', studies);
        DB.logAudit(6, "EDIT_RIS_VISIT_ACCEPTANCE", "radiology_studies", studyId, { study_id: studyId, service_id: selectedSrv.id });
    }
    
    // Billing storno and adjustments
    if (invoice) {
        const invoices = DB.get('invoices') || [];
        const invIndex = invoices.findIndex(i => i.id === invoice.id);
        
        if (invIndex !== -1) {
            if (invoice.payment_status !== 'paid') {
                // Unpaid invoice: update directly
                invoices[invIndex].subtotal = subtotal;
                invoices[invIndex].discount_amount = discount;
                invoices[invIndex].stamp_duty = stampDuty;
                invoices[invIndex].amount_due = newTotal;
                
                DB.set('invoices', invoices);
                DB.logAudit(6, "BILL_UPDATE_UNPAID", "invoices", invoice.id, { invoice_number: invoice.invoice_number, amount: newTotal });
            } else {
                // Paid invoice
                if (diff > 0) {
                    // Integrative invoice
                    const newInvoiceNum = window.getNextInvoiceNumber();
                    const newInv = {
                        admission_id: invoice.admission_id || null,
                        appointment_id: invoice.appointment_id || null,
                        sample_id: invoice.sample_id || null,
                        study_id: invoice.study_id || null,
                        invoice_number: newInvoiceNum,
                        issue_date: new Date().toISOString().split('T')[0],
                        subtotal: diff - stampDuty,
                        discount_value: 0,
                        discount_type: 'flat',
                        discount_amount: 0,
                        price_list_id: invoice.price_list_id || null,
                        claim_id: invoice.claim_id || null,
                        stamp_duty: stampDuty,
                        amount_due: diff,
                        amount_paid: 0.0,
                        payment_status: 'unpaid',
                        payment_method: null,
                        paid_at: null,
                        is_insurance_invoice: false
                    };
                    DB.insert('invoices', newInv);
                    DB.logAudit(6, "BILL_EMIT_INTEGRATIVE", "invoices", null, { invoice_number: newInvoiceNum, amount: diff, parent_invoice: invoice.invoice_number });
                } else if (diff < 0) {
                    // Credit Note (Negative invoice)
                    const ndcNum = window.getNextCreditNoteNumber();
                    const absDiff = Math.abs(diff);
                    
                    // Identify stornati (removed) services
                    const stornatiServices = [];
                    if (window.currentEditingOrigServices) {
                        window.currentEditingOrigServices.forEach(origSrv => {
                            const stillPresent = window.currentEditingServices.some(s => s.id === origSrv.id);
                            if (!stillPresent) {
                                stornatiServices.push(origSrv);
                            }
                        });
                    }
                    
                    const newInv = {
                        admission_id: invoice.admission_id || null,
                        appointment_id: invoice.appointment_id || null,
                        sample_id: invoice.sample_id || null,
                        study_id: invoice.study_id || null,
                        invoice_number: ndcNum,
                        issue_date: new Date().toISOString().split('T')[0],
                        subtotal: -absDiff,
                        discount_value: 0,
                        discount_type: 'flat',
                        discount_amount: 0,
                        price_list_id: invoice.price_list_id || null,
                        claim_id: invoice.claim_id || null,
                        stamp_duty: 0.00,
                        amount_due: -absDiff,
                        amount_paid: -absDiff, // mark as paid (refunded)
                        payment_status: 'paid',
                        payment_method: 'Contanti', // Forced Cash
                        paid_at: new Date().toISOString().split('T')[0],
                        is_insurance_invoice: false,
                        is_credit_note: true,
                        custom_rates: {
                            stornati_services: stornatiServices
                        }
                    };
                    
                    DB.insert('invoices', newInv);
                    DB.logAudit(6, "BILL_EMIT_CREDIT_NOTE", "invoices", null, { invoice_number: ndcNum, amount: -absDiff, parent_invoice: invoice.invoice_number });
                }
            }
        }
    }
    
    // Close modal and refresh views
    closeModal('modal-edit-acceptance');
    alert("Accettazione modificata con successo!");
    
    if (typeof window.renderAdmissionsAndInvoices === 'function') {
        window.renderAdmissionsAndInvoices();
    }
};

// --- CONSENT TEMPLATES MANAGEMENT MODULE ---

window.switchSubTemplatesTab = function(subtab) {
    const generalBtn = document.getElementById('btn-subtab-general-tpl');
    const consentsBtn = document.getElementById('btn-subtab-consents-tpl');
    const risBtn = document.getElementById('btn-subtab-ris-tpl');
    const generalContent = document.getElementById('subtab-general-tpl-content');
    const consentsContent = document.getElementById('subtab-consents-tpl-content');
    const risContent = document.getElementById('sub-content-ris-templates');
    
    if (subtab === 'general') {
        if (generalBtn) { generalBtn.className = 'btn btn-sm btn-primary'; }
        if (consentsBtn) { consentsBtn.className = 'btn btn-sm btn-secondary'; }
        if (risBtn) { risBtn.className = 'btn btn-sm btn-secondary'; }
        if (generalContent) generalContent.style.display = 'block';
        if (consentsContent) consentsContent.style.display = 'none';
        if (risContent) risContent.style.display = 'none';
    } else if (subtab === 'consents') {
        if (generalBtn) { generalBtn.className = 'btn btn-sm btn-secondary'; }
        if (consentsBtn) { consentsBtn.className = 'btn btn-sm btn-primary'; }
        if (risBtn) { risBtn.className = 'btn btn-sm btn-secondary'; }
        if (generalContent) generalContent.style.display = 'none';
        if (consentsContent) consentsContent.style.display = 'block';
        if (risContent) risContent.style.display = 'none';
        window.renderConsentTemplatesList();
    } else {
        if (generalBtn) { generalBtn.className = 'btn btn-sm btn-secondary'; }
        if (consentsBtn) { consentsBtn.className = 'btn btn-sm btn-secondary'; }
        if (risBtn) { risBtn.className = 'btn btn-sm btn-primary'; }
        if (generalContent) generalContent.style.display = 'none';
        if (consentsContent) consentsContent.style.display = 'none';
        if (risContent) risContent.style.display = 'block';
        if (typeof window.renderRisTemplatesTable === 'function') window.renderRisTemplatesTable();
    }
};

window.handleConsentScopeChange = function(value) {
    const grpModality = document.getElementById('consent-grp-modality');
    const grpDoctor = document.getElementById('consent-grp-doctor');
    const grpGenderAge = document.getElementById('consent-grp-gender-age');
    
    if (grpModality) grpModality.style.display = (value === 'by_modality' || value === 'gender_age') ? 'block' : 'none';
    if (grpDoctor) grpDoctor.style.display = (value === 'by_doctor') ? 'block' : 'none';
    if (grpGenderAge) grpGenderAge.style.display = (value === 'gender_age') ? 'flex' : 'none';
};

window.initializeConsentsEditor = function() {
    const docSelect = document.getElementById('consent-tpl-doctor');
    if (docSelect) {
        docSelect.innerHTML = '';
        const staffList = DB.get('staff') || [];
        const doctors = staffList.filter(s => s.role === 'doctor' || s.role === 'manager');
        doctors.forEach(d => {
            const opt = document.createElement('option');
            opt.value = d.id;
            opt.innerText = `Dott. ${d.first_name} ${d.last_name}`;
            docSelect.appendChild(opt);
        });
    }
    window.renderConsentTemplatesList();
};

window.renderConsentTemplatesList = function() {
    const listEl = document.getElementById('consents-templates-list');
    if (!listEl) return;
    
    listEl.innerHTML = '';
    const templates = DB.get('consent_templates') || [];
    const staffList = DB.get('staff') || [];
    
    if (templates.length === 0) {
        listEl.innerHTML = '<span class="text-muted" style="font-size:0.85rem; padding: 10px;">Nessun modello di consenso salvato.</span>';
        return;
    }
    
    templates.forEach(t => {
        let ruleText = "Generico (Tutti)";
        if (t.scope === 'by_modality') {
            ruleText = `Branca: ${t.modality}`;
        } else if (t.scope === 'by_doctor') {
            const doc = staffList.find(s => s.id === t.doctor_id);
            ruleText = doc ? `Medico: Dr. ${doc.last_name}` : 'Medico Associato';
        } else if (t.scope === 'gender_age') {
            ruleText = `Filtro: ${t.gender === 'F' ? 'Femmine' : (t.gender === 'M' ? 'Maschi' : 'Tutti')}, ${t.min_age || 0}-${t.max_age || 100} anni (${t.modality})`;
        }
        
        const div = document.createElement('div');
        div.style.padding = '10px 12px';
        div.style.background = 'var(--bg-surface)';
        div.style.border = '1px solid var(--border-color)';
        div.style.borderRadius = 'var(--radius-sm)';
        div.style.display = 'flex';
        div.style.justifyContent = 'space-between';
        div.style.alignItems = 'center';
        div.style.cursor = 'pointer';
        div.onclick = () => window.loadConsentTemplateForEdit(t.id);
        
        div.innerHTML = `
            <div style="flex:1;">
                <strong style="font-size:0.85rem; color:var(--text-primary);">${t.title}</strong><br>
                <span style="font-size:0.75rem; color:var(--text-secondary);">${ruleText}</span>
            </div>
            <button class="btn btn-danger btn-sm" style="padding: 2px 6px; font-size: 0.7rem;" onclick="event.stopPropagation(); window.deleteConsentTemplate(${t.id})">Rimuovi</button>
        `;
        listEl.appendChild(div);
    });
};

window.initNewConsentTemplate = function() {
    const form = document.getElementById('form-consent-template');
    if (form) form.reset();
    document.getElementById('consent-tpl-id').value = '';
    const editor = document.getElementById('consent-tpl-rich-editor');
    if (editor) editor.innerHTML = '';
    document.getElementById('consent-form-title').innerText = "Nuovo Modello di Consenso";
    window.handleConsentScopeChange('all');
};

window.loadConsentTemplateForEdit = function(id) {
    const templates = DB.get('consent_templates') || [];
    const t = templates.find(item => item.id === id);
    if (!t) return;
    
    document.getElementById('consent-tpl-id').value = t.id;
    document.getElementById('consent-tpl-title').value = t.title;
    document.getElementById('consent-tpl-scope').value = t.scope;
    
    if (t.modality) document.getElementById('consent-tpl-modality').value = t.modality;
    if (t.doctor_id) document.getElementById('consent-tpl-doctor').value = t.doctor_id;
    if (t.gender) document.getElementById('consent-tpl-gender').value = t.gender;
    if (t.min_age) document.getElementById('consent-tpl-min-age').value = t.min_age;
    if (t.max_age) document.getElementById('consent-tpl-max-age').value = t.max_age;
    
    const editor = document.getElementById('consent-tpl-rich-editor');
    if (editor) editor.innerHTML = t.content;
    
    document.getElementById('consent-form-title').innerText = "Modifica Modello di Consenso";
    window.handleConsentScopeChange(t.scope);
};

window.importConsentTextFile = function(input) {
    const file = input.files[0];
    if (!file) return;
    
    const reader = new FileReader();
    reader.onload = function(e) {
        const text = e.target.result;
        // Convert plain text newlines to HTML paragraphs/breaks
        const formatted = text.split('\n\n').map(line => line.trim() ? `<p>${line}</p>` : '<br>').join('');
        const editor = document.getElementById('consent-tpl-rich-editor');
        if (editor) {
            editor.innerHTML = formatted;
        }
        alert(`File "${file.name}" importato con successo nel corpo del testo!`);
    };
    reader.readAsText(file, 'UTF-8');
    input.value = ''; // Reset uploader
};

window.saveConsentTemplate = function() {
    const idVal = document.getElementById('consent-tpl-id').value;
    const titleVal = document.getElementById('consent-tpl-title').value;
    const scopeVal = document.getElementById('consent-tpl-scope').value;
    
    const modalityVal = document.getElementById('consent-tpl-modality').value;
    const docVal = document.getElementById('consent-tpl-doctor').value;
    const genderVal = document.getElementById('consent-tpl-gender').value;
    const minAgeVal = document.getElementById('consent-tpl-min-age').value;
    const maxAgeVal = document.getElementById('consent-tpl-max-age').value;
    
    const editor = document.getElementById('consent-tpl-rich-editor');
    const contentVal = editor ? editor.innerHTML : '';
    
    if (!titleVal || !contentVal) {
        alert("Inserire titolo e testo del modello.");
        return;
    }
    
    const template = {
        title: titleVal,
        content: contentVal,
        scope: scopeVal,
        modality: (scopeVal === 'by_modality' || scopeVal === 'gender_age') ? modalityVal : null,
        doctor_id: (scopeVal === 'by_doctor') ? parseInt(docVal) : null,
        gender: (scopeVal === 'gender_age') ? genderVal : 'all',
        min_age: (scopeVal === 'gender_age' && minAgeVal) ? parseInt(minAgeVal) : null,
        max_age: (scopeVal === 'gender_age' && maxAgeVal) ? parseInt(maxAgeVal) : null
    };
    
    if (idVal) {
        const id = parseInt(idVal);
        DB.update('consent_templates', id, template);
        DB.logAudit(6, "CONSENT_TEMPLATE_UPDATE", "consent_templates", id, { title: titleVal });
        alert("Modello di consenso modificato con successo!");
    } else {
        const newTpl = DB.insert('consent_templates', template);
        DB.logAudit(6, "CONSENT_TEMPLATE_CREATE", "consent_templates", newTpl.id, { title: titleVal });
        alert("Modello di consenso creato con successo!");
    }
    
    window.initNewConsentTemplate();
    window.renderConsentTemplatesList();
};

window.deleteConsentTemplate = function(id) {
    if (confirm("Sei sicuro di voler rimuovere questo modello di consenso?")) {
        DB.delete('consent_templates', id);
        DB.logAudit(6, "CONSENT_TEMPLATE_DELETE", "consent_templates", id, {});
        window.renderConsentTemplatesList();
        window.initNewConsentTemplate();
    }
};

window.closeConsentsModalAndPay = function() {
    closeModal('modal-print-consents');
    if (window.pendingInvoiceIdAfterConsents) {
        const invId = window.pendingInvoiceIdAfterConsents;
        window.pendingInvoiceIdAfterConsents = null;
        setTimeout(() => {
            window.promptDirectPaymentAndPrint(invId);
        }, 150);
    }
};

window.evaluateRequiredConsents = function(patientId, serviceIds, doctorId) {
    const patients = DB.get('patients') || [];
    const patient = patients.find(p => p.id === patientId);
    if (!patient) return [];
    
    // Calculate patient age
    const pBirth = new Date(patient.birth_date);
    const ageDiff = Date.now() - pBirth.getTime();
    const ageDate = new Date(ageDiff);
    const age = Math.abs(ageDate.getUTCFullYear() - 1970);
    const gender = patient.gender || 'all';
    
    const services = DB.get('medical_services') || [];
    const executionServices = services.filter(s => serviceIds.includes(s.id));
    
    const allTemplates = DB.get('consent_templates') || [];
    const requiredTemplates = [];
    
    allTemplates.forEach(tpl => {
        let matches = false;
        if (tpl.scope === 'all') {
            matches = true;
        } else if (tpl.scope === 'by_modality') {
            const matchesMod = executionServices.filter(s => s.type.toUpperCase() === tpl.modality.toUpperCase() || (tpl.modality === 'VISIT' && s.type === 'visita'));
            if (matchesMod.length > 0) {
                matches = true;
            }
        } else if (tpl.scope === 'by_doctor') {
            if (doctorId === tpl.doctor_id) {
                matches = true;
            }
        } else if (tpl.scope === 'gender_age') {
            const genderMatch = (tpl.gender === 'all' || tpl.gender.toUpperCase() === gender.toUpperCase());
            const minAge = tpl.min_age !== null ? tpl.min_age : 0;
            const maxAge = tpl.max_age !== null ? tpl.max_age : 150;
            const ageMatch = (age >= minAge && age <= maxAge);
            const matchesMod = executionServices.filter(s => s.type.toUpperCase() === tpl.modality.toUpperCase() || (tpl.modality === 'VISIT' && s.type === 'visita'));
            if (genderMatch && ageMatch && matchesMod.length > 0) {
                matches = true;
            }
        }
        if (matches) {
            requiredTemplates.push(tpl);
        }
    });
    return requiredTemplates;
};

window.printPatientConsent = function(templateId, patientId, serviceIds, doctorId) {
    const templates = DB.get('consent_templates') || [];
    const tpl = templates.find(t => t.id === templateId);
    if (!tpl) return;
    
    const patients = DB.get('patients') || [];
    const patient = patients.find(p => p.id === patientId);
    if (!patient) return;
    
    const services = DB.get('medical_services') || [];
    const executionServices = services.filter(s => serviceIds.includes(s.id));
    const serviceNames = executionServices.map(s => s.name);
    
    const staffList = DB.get('staff') || [];
    const doctor = staffList.find(s => s.id === doctorId);
    const doctorName = doctor ? `Dr. ${doctor.first_name} ${doctor.last_name}` : 'Specialista Refertatore';
    
    let printedContent = tpl.content
        .replace(/{paziente}/g, `${patient.first_name} ${patient.last_name}`)
        .replace(/{codice_fiscale}/g, patient.tax_code || '')
        .replace(/{data_nascita}/g, patient.birth_date ? new Date(patient.birth_date).toLocaleDateString('it-IT') : '')
        .replace(/{data}/g, new Date().toLocaleDateString('it-IT'))
        .replace(/{prestazioni}/g, serviceNames.join(', '))
        .replace(/{medico}/g, doctorName);
        
    const printWindow = window.open('', '_blank');
    if (!printWindow) {
        alert("Pop-up bloccato dal browser. Abilita i pop-up per procedere alla stampa.");
        return;
    }
    
    printWindow.document.write(`
        <html>
        <head>
            <title>Stampa Consenso Informato - NextCare</title>
            <style>
                body { font-family: 'Outfit', 'Helvetica Neue', Arial, sans-serif; padding: 40px; color: #1e293b; line-height: 1.6; max-width: 800px; margin: 0 auto; }
                h2 { color: #2563eb; font-size: 1.4rem; border-bottom: 2px solid #cbd5e1; padding-bottom: 8px; margin-bottom: 24px; text-transform: uppercase; text-align: center; }
                p { margin-bottom: 16px; font-size: 1.05rem; text-align: justify; }
                .signature-container { margin-top: 60px; display: grid; grid-template-columns: 1fr 1fr; gap: 60px; }
                .signature-box { border-top: 1px solid #94a3b8; padding-top: 8px; text-align: center; font-size: 0.95rem; color: #64748b; }
                @media print {
                    body { padding: 20px; }
                }
            </style>
        </head>
        <body>
            <div style="text-align: center; margin-bottom: 30px;">
                <div style="font-size: 1.8rem; font-weight: 800; color: #2563eb; letter-spacing: -1px; display: inline-block;">NEXTCARE</div>
                <div style="font-size: 0.8rem; color: #64748b; text-transform: uppercase; letter-spacing: 2px; font-weight: 600;">Piattaforma Sanitaria Digitale</div>
            </div>
            
            ${printedContent}
            
            <div class="signature-container">
                <div class="signature-box">Firma Leggibile del Paziente (o Genitore/Tutore)</div>
                <div class="signature-box">Firma del Medico / Operatore Sanitario</div>
            </div>
        </body>
        </html>
    `);
    
    printWindow.document.close();
    printWindow.focus();
    setTimeout(() => {
        printWindow.print();
        printWindow.close();
    }, 250);
};

