        if (companyInvoices.length === 0) {
            tbodyInv.innerHTML = '<tr><td colspan="4" style="text-align:center; padding:10px; color:var(--text-muted);">Nessuna fattura aziendale disponibile.</td></tr>';
        }
        if (window.lucide) window.lucide.createIcons();
