window.loadLicenseInfo = function() {
    fetch('/api/system-settings')
    .then(res => res.json())
    .then(res => {
        if (res && res.success && res.data) {
            const serial = res.data.license_serial || 'NC-ENT-2026-9482-1048';
            let info = {
                version: "1.0",
                type: "Enterprise",
                expiry: "31/12/2029",
                owner: "NextCare Demo Clinic"
            };
            if (res.data.license_info) {
                try {
                    info = JSON.parse(res.data.license_info);
                } catch(e) {
                    console.error("Error parsing license_info", e);
                }
            }
            
            const serialEl = document.getElementById('license-curr-serial');
            if (serialEl) serialEl.innerText = serial;
            
            const whatsNewSerialEl = document.getElementById('whats-new-license-serial');
            if (whatsNewSerialEl) whatsNewSerialEl.innerText = serial;
            
            const ownerEl = document.getElementById('license-curr-owner');
            if (ownerEl) ownerEl.innerText = info.owner || "NextCare Demo Clinic";
            
            const expiryEl = document.getElementById('license-curr-expiry');
            if (expiryEl) expiryEl.innerText = info.expiry || "31/12/2026";
            
            const statusEl = document.getElementById('license-curr-status');
            if (statusEl) {
                let parts = info.expiry.split('/');
                let expiryDate;
                if (parts.length === 3) {
                    expiryDate = new Date(parts[2], parts[1] - 1, parts[0]);
                } else {
                    expiryDate = new Date(info.expiry);
                }
                const now = new Date();
                if (expiryDate < now) {
                    statusEl.className = "badge badge-danger";
                    statusEl.innerText = "Scaduta / Non Valida";
                } else {
                    statusEl.className = "badge badge-success";
                    statusEl.innerText = "Attiva / Valida";
                }
            }
            
            // Check limits status returned by server
            const status = res.data.license_status;
            if (status) {
                // Render package name
                const pkgEl = document.getElementById('license-package-name');
                if (pkgEl) pkgEl.innerText = status.package || 'Enterprise';
                
                // Render Doctors Limit
                const docTextEl = document.getElementById('license-curr-doctors-text');
                const docBarEl = document.getElementById('license-curr-doctors-bar');
                if (docTextEl && docBarEl) {
                    const maxDocText = status.max_doctors === -1 ? 'Illimitati' : status.max_doctors;
                    docTextEl.innerText = `${status.active_doctors} / ${maxDocText}`;
                    const pct = status.max_doctors === -1 ? Math.min(100, (status.active_doctors / 50) * 100) : Math.min(100, (status.active_doctors / status.max_doctors) * 100);
                    docBarEl.style.width = `${pct}%`;
                    docBarEl.style.backgroundColor = status.max_doctors === -1 ? 'var(--primary)' : (pct >= 100 ? 'var(--danger)' : pct >= 80 ? 'var(--warning)' : 'var(--primary)');
                }
                
                // Render Users Limit
                const userTextEl = document.getElementById('license-curr-users-text');
                const userBarEl = document.getElementById('license-curr-users-bar');
                if (userTextEl && userBarEl) {
                    const maxUserText = status.max_users === -1 ? 'Illimitati' : status.max_users;
                    userTextEl.innerText = `${status.active_users} / ${maxUserText}`;
                    const pct = status.max_users === -1 ? Math.min(100, (status.active_users / 100) * 100) : Math.min(100, (status.active_users / status.max_users) * 100);
                    userBarEl.style.width = `${pct}%`;
                    userBarEl.style.backgroundColor = status.max_users === -1 ? 'var(--success)' : (pct >= 100 ? 'var(--danger)' : pct >= 80 ? 'var(--warning)' : 'var(--success)');
                }
                
                // Render Reports Limit
                const repTextEl = document.getElementById('license-curr-reports-text');
                const repBarEl = document.getElementById('license-curr-reports-bar');
                if (repTextEl && repBarEl) {
                    const maxRepText = status.max_reports === -1 ? 'Illimitati' : status.max_reports;
                    repTextEl.innerText = `${status.monthly_reports} / ${maxRepText}`;
                    const pct = status.max_reports === -1 ? Math.min(100, (status.monthly_reports / 5000) * 100) : Math.min(100, (status.monthly_reports / status.max_reports) * 100);
                    repBarEl.style.width = `${pct}%`;
                    repBarEl.style.backgroundColor = status.max_reports === -1 ? 'var(--primary)' : (pct >= 100 ? 'var(--danger)' : pct >= 80 ? 'var(--warning)' : 'var(--primary)');
                }
                
                // Handle UI blocking
                if (status.blocked) {
                    window.showLicenseBlockScreen(status.reason);
                } else {
                    window.hideLicenseBlockScreen();
                }
            }
        }
    })
    .catch(err => console.error("Error loading license info", err));
};

window.showLicenseBlockScreen = function(reason) {
    let blockDiv = document.getElementById('nextcare-license-block-screen');
    if (!blockDiv) {
        blockDiv = document.createElement('div');
        blockDiv.id = 'nextcare-license-block-screen';
        blockDiv.style.cssText = `
            position: fixed;
            top: 0;
            left: 0;
            width: 100vw;
            height: 100vh;
            background: rgba(15, 23, 42, 0.98);
            z-index: 100000000;
            display: flex;
            align-items: center;
            justify-content: center;
            font-family: 'Outfit', 'Inter', sans-serif;
            color: #ffffff;
            padding: 20px;
        `;
        document.body.appendChild(blockDiv);
    }
    
    blockDiv.innerHTML = `
        <div style="background: #1e293b; border: 1px solid rgba(255, 255, 255, 0.1); padding: 40px; border-radius: 16px; max-width: 550px; width: 100%; box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5); text-align: center;">
            <div style="display: flex; align-items: center; justify-content: center; gap: 10px; margin-bottom: 24px;">
                <div style="background: #ef4444; color: white; width: 44px; height: 44px; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-weight: bold; font-size: 1.5rem;">⚠️</div>
                <h2 style="margin: 0; font-size: 1.5rem; font-weight: 800; font-family: 'Outfit'; letter-spacing: -0.5px; color: white;">Limiti di Licenza Superati</h2>
            </div>
            
            <p style="color: #cbd5e1; font-size: 0.95rem; line-height: 1.6; margin-bottom: 24px;" id="block-screen-reason">
                ${reason}
            </p>
            
            <div style="background: rgba(239, 68, 68, 0.05); border: 1px solid rgba(239, 68, 68, 0.2); border-radius: 8px; padding: 15px; margin-bottom: 24px; font-size: 0.85rem; color: #fca5a5; line-height: 1.5;">
                Il sistema è temporaneamente bloccato. È necessario attivare una licenza valida (Starter, Professional o Enterprise) per ripristinare l'accesso.
            </div>
            
            <div style="margin-bottom: 24px;">
                <a href="license_generator.html" target="_blank" class="btn btn-primary" style="display: inline-flex; align-items: center; justify-content: center; gap: 8px; width: 100%; text-decoration: none; padding: 12px; font-weight: 600; text-transform: none; font-size: 0.95rem; border-radius: 8px; background: #2563eb; color: white; border: none; cursor: pointer; text-align: center;">
                    Accedi al Generatore di Licenze (Riservato)
                </a>
            </div>
            
            <div style="border-top: 1px solid rgba(255, 255, 255, 0.1); padding-top: 24px; text-align: left;">
                <h3 style="font-size: 0.95rem; font-weight: 600; margin-bottom: 15px; color: #e2e8f0;">Attivazione Rapida Nuova Licenza</h3>
                <form id="block-screen-activation-form" onsubmit="window.handleBlockScreenActivation(event)">
                    <div style="margin-bottom: 15px;">
                        <input type="text" id="block-license-serial-input" required placeholder="NC-XXXXX-YYYYY-ZZZZZ" style="width: 100%; padding: 12px; border-radius: 6px; border: 1px solid rgba(255, 255, 255, 0.15); background: #0f172a; color: white; font-family: monospace; font-size: 1rem; text-transform: uppercase;">
                    </div>
                    <button type="submit" class="btn btn-primary" style="width: 100%; padding: 12px; font-weight: 600; border-radius: 6px; background: #10b981; color: white; border: none; cursor: pointer;">
                        Attiva Licenza e Sblocca
                    </button>
                </form>
            </div>
        </div>
    `;
};

window.hideLicenseBlockScreen = function() {
    const blockDiv = document.getElementById('nextcare-license-block-screen');
    if (blockDiv) {
        blockDiv.remove();
    }
};

window.handleBlockScreenActivation = function(e) {
    e.preventDefault();
    const serialInput = document.getElementById('block-license-serial-input');
    if (!serialInput) return;
    const serial = serialInput.value.trim();
    if (!serial) return;
    
    fetch('/api/activate-license', {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json'
        },
        body: JSON.stringify({ serial_number: serial })
    })
    .then(res => res.json())
    .then(res => {
        if (res && res.success) {
            alert("Licenza attivata con successo! Il sistema è stato sbloccato.");
            window.hideLicenseBlockScreen();
            window.loadLicenseInfo();
            window.location.reload();
        } else {
            alert("Errore attivazione: " + (res.error || "Errore sconosciuto"));
        }
    })
    .catch(err => {
        console.error(err);
        alert("Errore di rete durante l'attivazione della licenza.");
    });
};

window.initLicenseForm = function() {
    const form = document.getElementById('form-license-activation');
    if (!form) return;
    
    form.addEventListener('submit', (e) => {
        e.preventDefault();
        const serialInput = document.getElementById('license-serial-input');
        const infoInput = document.getElementById('license-info-input');
        if (!serialInput) return;
        
        const serial = serialInput.value.trim().toUpperCase();
        
        fetch('/api/activate-license', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                'serial_number': serial
            })
        })
        .then(res => res.json())
        .then(res => {
            if (res && res.success) {
                alert("Licenza NextCare attivata con successo per " + res.data.owner + "!");
                window.loadLicenseInfo();
                if (serialInput) serialInput.value = '';
                if (infoInput) infoInput.value = '';
            } else {
                alert("Errore durante l'attivazione della licenza: " + (res.error || "Errore sconosciuto"));
            }
        })
        .catch(err => {
            console.error("Error activating license", err);
            alert("Errore di rete durante l'attivazione della licenza.");
        });
    });
};

// Initial setup, datalists and form bindings
(function() {
    if (typeof window.loadLicenseInfo === 'function') window.loadLicenseInfo();
    if (typeof window.initLicenseForm === 'function') window.initLicenseForm();
    // Populate exemptions datalists once at load
    apiCall('/api/db-get-all', { table: 'ssn_exemptions' }, (res) => {
        const dl1 = document.getElementById('checkin-exemption-list');
        const dl2 = document.getElementById('recipe-exemption-list');
        if (res && res.success && res.data) {
            const html = res.data.map(ex => `<option value="${ex.code}">${ex.name} (Quota: ${ex.pct}%)</option>`).join('');
            if (dl1) dl1.innerHTML = html;
            if (dl2) dl2.innerHTML = html;
        }
    });

    // Event listener for check-in exemption changes
    const chkEx = document.getElementById('checkin-ssn-exemption');
    if (chkEx) {
        chkEx.addEventListener('input', () => window.updateCheckinCalculations());
        chkEx.addEventListener('change', () => window.updateCheckinCalculations());
    }

    // Intercept window.openModal to clear SSN states when opening add dialogs
    const originalOpenModal = window.openModal;
    window.openModal = function(modalId) {
        if (modalId === 'modal-add-sample') {
            const chk = document.getElementById('sam-ssn-enabled');
            if (chk) chk.checked = false;
            const sum = document.getElementById('sam-ssn-summary');
            if (sum) {
                sum.innerHTML = '';
                sum.style.display = 'none';
            }
            window.tempSsnRecipe.lis = null;
            const listino = document.getElementById('sam-listino');
            if (listino) listino.value = 1;
            
            // Populate companies dropdown
            if (typeof window.populateCompaniesDropdown === 'function') {
                window.populateCompaniesDropdown('sam-company');
            }
        } else if (modalId === 'modal-add-ris') {
            const chk = document.getElementById('ris-ssn-enabled');
            if (chk) chk.checked = false;
            const sum = document.getElementById('ris-ssn-summary');
            if (sum) {
                sum.innerHTML = '';
                sum.style.display = 'none';
            }
            window.tempSsnRecipe.ris = null;
            const listino = document.getElementById('ris-listino');
            if (listino) listino.value = 1;
            
            // Reset requester type
            const reqType = document.getElementById('ris-requester-type');
            if (reqType) {
                reqType.value = 'internal';
                window.toggleRisRequester('internal');
            }
            const reqExt = document.getElementById('ris-requester-external');
            if (reqExt) reqExt.value = '';

            // Populate companies, doctors/TSRM, and price lists
            if (typeof window.populateCompaniesDropdown === 'function') {
                window.populateCompaniesDropdown('ris-company');
            }
            if (typeof window.populateDropdownsRIS === 'function') {
                window.populateDropdownsRIS();
            }
            if (typeof window.populatePriceListsDropdown === 'function') {
                window.populatePriceListsDropdown('ris-listino');
            }
        } else if (modalId === 'modal-add-shift') {
            const shType = document.getElementById('sh-type');
            if (shType) shType.value = 'single';
            if (typeof window.toggleShiftRecurrenceFields === 'function') {
                window.toggleShiftRecurrenceFields('single');
            }
        }
        if (originalOpenModal) originalOpenModal(modalId);
    };

    // Clone and re-bind forms to run the correct handlers
    const checkinForm = document.getElementById('form-checkin-appointment');
    if (checkinForm) {
        const newForm = checkinForm.cloneNode(true);
        checkinForm.parentNode.replaceChild(newForm, checkinForm);
        newForm.addEventListener('submit', window.customCheckinSubmit);
    }

    const samForm = document.getElementById('form-add-sample');
    if (samForm) {
        const newForm = samForm.cloneNode(true);
        samForm.parentNode.replaceChild(newForm, samForm);
        newForm.addEventListener('submit', window.customLisSubmit);
    }

    const risForm = document.getElementById('form-add-ris');
    if (risForm) {
        const newForm = risForm.cloneNode(true);
        risForm.parentNode.replaceChild(newForm, risForm);
        newForm.addEventListener('submit', window.customRisSubmit);
    }

    // Bind change listeners to listinos for autocomplete/search tag pricing sync
    const samListino = document.getElementById('sam-listino');
    if (samListino) {
        samListino.addEventListener('change', () => {
            if (typeof renderSelectedLisTags === 'function') renderSelectedLisTags();
        });
    }

    const risListino = document.getElementById('ris-listino');
    if (risListino) {
        risListino.addEventListener('change', () => {
            const search = document.getElementById('ris-service-search');
            if (search && search.value) {
                search.dispatchEvent(new Event('input'));
            }
        });
    }

    // Initialize RIS service search autocomplete
    window.initRisSearchTags();

    // Initialize Doctor autocomplete
    setTimeout(() => {
        if (typeof window.initDoctorAutocomplete === 'function') {
            window.initDoctorAutocomplete('comp-config-doctor', 'comp-config-doctor-search', 'comp-config-doctor-suggestions');
        }
        if (typeof window.populateCompServicesDropdown === 'function') {
            window.populateCompServicesDropdown();
        }
    }, 0);
})();

// --- DOCTOR COMPENSATIONS INTEGRATION ---
window.initDoctorAutocomplete = function(inputId, searchInputId, suggestionsId) {
    const searchInput = document.getElementById(searchInputId);
    const hiddenInput = document.getElementById(inputId);
    const suggestionsBox = document.getElementById(suggestionsId);
    if (!searchInput || !hiddenInput || !suggestionsBox) return;

    searchInput.addEventListener('input', () => {
        const query = searchInput.value.toLowerCase().trim();
        if (!query) {
            suggestionsBox.style.display = 'none';
            hiddenInput.value = '';
            hiddenInput.dispatchEvent(new Event('change', { bubbles: true }));
            return;
        }

        const doctors = DB.get('doctors') || [];
        const staff = DB.get('staff') || [];
        const matches = [];

        doctors.forEach(d => {
            const s = staff.find(st => st.id === d.staff_id);
            if (s) {
                const fullName = `Dott. ${s.first_name} ${s.last_name}`.toLowerCase();
                const revFullName = `Dott. ${s.last_name} ${s.first_name}`.toLowerCase();
                const spec = (d.specialization || '').toLowerCase();
                if (fullName.includes(query) || revFullName.includes(query) || spec.includes(query)) {
                    matches.push({
                        doctor: d,
                        staff: s,
                        text: `Dott. ${s.last_name} ${s.first_name} (${d.specialization})`
                    });
                }
            }
        });

        if (matches.length === 0) {
            suggestionsBox.innerHTML = '<div style="padding: 12px; text-align: center; color: var(--text-secondary); font-size: 0.85rem;">Nessun medico trovato.</div>';
            suggestionsBox.style.display = 'block';
            hiddenInput.value = '';
            hiddenInput.dispatchEvent(new Event('change', { bubbles: true }));
            return;
        }

        suggestionsBox.innerHTML = '';
        matches.slice(0, 10).forEach(m => {
            const item = document.createElement('div');
            item.className = 'patient-suggestion-item';
            item.innerHTML = `<strong>Dott. ${m.staff.last_name} ${m.staff.first_name}</strong><span class="tax-code">${m.doctor.specialization || ''}</span>`;
            item.addEventListener('click', () => {
                searchInput.value = m.text;
                hiddenInput.value = m.doctor.id;
                suggestionsBox.style.display = 'none';
                hiddenInput.dispatchEvent(new Event('change', { bubbles: true }));
            });
            suggestionsBox.appendChild(item);
        });
        suggestionsBox.style.display = 'block';
    });

    // Close suggestions box on clicking outside
    document.addEventListener('click', (e) => {
        if (!searchInput.contains(e.target) && !suggestionsBox.contains(e.target)) {
            suggestionsBox.style.display = 'none';
        }
    });

    // Handle programmatically setting value (e.g. form resets)
    hiddenInput.addEventListener('change', () => {
        const docId = parseInt(hiddenInput.value);
        if (!docId) {
            searchInput.value = '';
            return;
        }
        const doctors = DB.get('doctors') || [];
        const staff = DB.get('staff') || [];
        const d = doctors.find(doc => doc.id === docId);
        if (d) {
            const s = staff.find(st => st.id === d.staff_id);
            if (s) {
                const expectedText = `Dott. ${s.last_name} ${s.first_name} (${d.specialization})`;
                if (searchInput.value !== expectedText) {
                    searchInput.value = expectedText;
                }
            }
        } else {
            searchInput.value = '';
        }
    });
};

window.populateCompServicesDropdown = function() {
    const select = document.getElementById('comp-config-service');
    if (select) {
        const services = DB.get('medical_services') || [];
        select.innerHTML = '<option value="">-- Tutte le prestazioni --</option>';
        services.forEach(s => {
            select.innerHTML += `<option value="${s.id}">${s.name} (${s.code || ''}) - € ${parseFloat(s.price || 0).toFixed(2)}</option>`;
        });
    }

    const branchSelect = document.getElementById('comp-config-branch');
    if (branchSelect) {
        const services = DB.get('medical_services') || [];
        const branches = new Set();
        services.forEach(s => {
            if (s && s.branch) {
                branches.add(s.branch.trim());
            } else if (s && s.type) {
                // Fallback to type (formatted nicely) if branch is missing
                const typeStr = s.type.trim();
                const displayType = typeStr === 'lis' ? 'Laboratorio LIS' : typeStr === 'ris' ? 'Radiologia RIS' : typeStr;
                branches.add(displayType);
            }
        });
        
        branchSelect.innerHTML = '<option value="">-- Tutte le Branche / Nessuna --</option>';
        Array.from(branches).sort().forEach(br => {
            branchSelect.innerHTML += `<option value="${br}">${br}</option>`;
        });
    }
};

window.loadDoctorCompensations = function() {
    apiCall('/api/compensations-list', {}, (res) => {
        if (res && res.success) {
            window.doctorCompConfigs = res.configs || [];
            window.doctorCompCalculated = res.calculated || [];
            
            // Populate filter select
            const filterDoc = document.getElementById('comp-filter-doctor');
            if (filterDoc) {
                const currentVal = filterDoc.value;
                const doctors = DB.get('doctors') || [];
                const staff = DB.get('staff') || [];
                
                let html = '<option value="">Tutti i Medici</option>';
                doctors.forEach(d => {
                    const s = staff.find(st => st.id === d.staff_id);
                    if (s) {
                        html += `<option value="${d.id}">Dott. ${s.last_name} ${s.first_name} (${d.specialization})</option>`;
                    }
                });
                filterDoc.innerHTML = html;
                filterDoc.value = currentVal;
            }
            
            window.renderCompRules(window.doctorCompConfigs);
            window.renderCompensations();
        } else {
            console.error("Errore recupero compensi:", res ? res.error : "Unknown error");
        }
    });
};

window.renderCompRules = function(configs) {
    const container = document.getElementById('comp-rules-list');
    if (!container) return;
    container.innerHTML = '';
    if (!configs || configs.length === 0) {
        container.innerHTML = '<div style="padding: 12px; text-align: center; color: var(--text-secondary); font-size: 0.85rem;">Nessuna regola configurata.</div>';
        return;
    }
    configs.forEach(c => {
        const docName = c.doctor_name || `Medico ID ${c.doctor_id}`;
        const serviceText = c.service_name ? `Prestazione: ${c.service_name}` : (c.branch ? `Branca: ${c.branch}` : 'Tutte le prestazioni');
        const triggerText = c.trigger_event === 'erogato' ? 'Check-in' : (c.trigger_event === 'refertato' ? 'Firma Referto' : 'Fattura');
        const valueText = c.compensation_type === 'percentage' ? `${c.value}%` : `€ ${parseFloat(c.value).toFixed(2)}`;
        const typeText = c.patient_type ? `Tariffa: ${c.patient_type}` : 'Tutte le tariffe';
        
        container.innerHTML += `
            <div style="background: var(--bg-surface); border: 1px solid var(--border-color); border-radius: 8px; padding: 10px; display: flex; justify-content: space-between; align-items: center; font-size: 0.8rem; box-shadow: var(--shadow-sm);">
                <div>
                    <div style="font-weight: 600; color: var(--text-primary); margin-bottom: 2px;">${docName}</div>
                    <div style="color: var(--text-secondary); font-size: 0.75rem; margin-bottom: 2px;">${serviceText} | ${typeText}</div>
                    <div style="color: var(--primary); font-size: 0.75rem; font-weight: 500;">Trigger: ${triggerText} &rarr; Compenso: ${valueText}</div>
                </div>
                <button type="button" class="btn btn-danger btn-sm" onclick="window.deleteCompConfig(${c.id})" style="padding: 4px 6px; font-size: 0.7rem;">
                    &#128465;
                </button>
            </div>
        `;
    });
};

window.renderCompensations = function() {
    const container = document.getElementById('compensations-table-body');
    if (!container) return;
    container.innerHTML = '';
    const doctorFilter = document.getElementById('comp-filter-doctor');
    const selectedDocId = doctorFilter ? parseInt(doctorFilter.value) : 0;
    
    const list = window.doctorCompCalculated || [];
    const filtered = selectedDocId ? list.filter(c => c.doctor_id === selectedDocId) : list;
    
    if (filtered.length === 0) {
        container.innerHTML = '<tr><td colspan="6" style="padding: 20px; text-align: center; color: var(--text-secondary); font-size: 0.85rem;">Nessun compenso registrato.</td></tr>';
        return;
    }
    
    filtered.forEach(c => {
        const docName = c.doctor_name || `Medico ID ${c.doctor_id}`;
        const serviceText = c.service_name || 'Visita / Prestazione';
        const triggerText = c.event_type === 'erogato' ? 'Check-in' : (c.event_type === 'refertato' ? 'Firma Referto' : 'Fattura');
        const baseAmount = parseFloat(c.base_amount || 0).toFixed(2);
        const payout = parseFloat(c.calculated_amount || 0).toFixed(2);
        
        let statusBadge = '';
        if (c.status === 'pending') {
            statusBadge = '<span class="badge badge-warning" style="background-color: var(--amber-100, #fef3c7); color: var(--amber-800, #92400e); padding: 4px 8px; border-radius: 9999px; font-size: 0.75rem; font-weight: 500;">In sospeso</span>';
        } else {
            const dateStr = c.payout_date ? ` il ${c.payout_date}` : '';
            statusBadge = `<span class="badge badge-success" style="background-color: var(--emerald-100, #d1fae5); color: var(--emerald-800, #065f46); padding: 4px 8px; border-radius: 9999px; font-size: 0.75rem; font-weight: 500;">Liquidato${dateStr}</span>`;
        }
        
        container.innerHTML += `
            <tr style="border-bottom: 1px solid var(--border-color); font-size: 0.8rem;">
                <td style="padding: 10px; font-weight: 500; color: var(--text-primary);">${docName}</td>
                <td style="padding: 10px; color: var(--text-secondary);">${serviceText} ${c.invoice_number ? `<span style="font-size: 0.75rem; color: var(--primary);">(${c.invoice_number})</span>` : ''}</td>
                <td style="padding: 10px; color: var(--text-secondary);">${triggerText}</td>
                <td style="padding: 10px; color: var(--text-primary);">€ ${baseAmount}</td>
                <td style="padding: 10px; font-weight: 600; color: var(--primary);">€ ${payout}</td>
                <td style="padding: 10px;">${statusBadge}</td>
            </tr>
        `;
    });
};

window.saveCompConfig = function(event) {
    if (event) event.preventDefault();
    const doctorId = parseInt(document.getElementById('comp-config-doctor').value);
    if (!doctorId) {
        alert("Selezionare prima un medico specialista tramite la ricerca.");
        return;
    }
    const serviceVal = document.getElementById('comp-config-service').value;
    const serviceId = serviceVal ? parseInt(serviceVal) : null;
    const branch = document.getElementById('comp-config-branch').value.trim() || null;
    const patientType = document.getElementById('comp-config-patient-type').value || null;
    const triggerEvent = document.getElementById('comp-config-event').value;
    const compType = document.getElementById('comp-config-type').value;
    const val = parseFloat(document.getElementById('comp-config-value').value);
    
    if (isNaN(val)) {
        alert("Inserire un valore valido per il compenso.");
        return;
    }
    
    const payload = {
        doctor_id: doctorId,
        service_id: serviceId,
        branch: branch,
        patient_type: patientType,
        trigger_event: triggerEvent,
        compensation_type: compType,
        value: val
    };
    
    apiCall('/api/compensations-config-save', payload, (res) => {
        if (res && res.success) {
            alert("Regola di compenso salvata con successo!");
            // Reset search autocomplete fields and basic form
            document.getElementById('form-comp-config').reset();
            document.getElementById('comp-config-doctor').value = '';
            document.getElementById('comp-config-doctor-search').value = '';
            // Reload list
            window.loadDoctorCompensations();
        } else {
            alert("Errore nel salvataggio della regola: " + (res ? res.error : "Unknown error"));
        }
    });
};

window.deleteCompConfig = function(ruleId) {
    if (!confirm("Sei sicuro di voler eliminare questa regola di compenso?")) return;
    apiCall('/api/compensations-config-delete', { id: ruleId }, (res) => {
        if (res && res.success) {
            alert("Regola eliminata con successo!");
            window.loadDoctorCompensations();
        } else {
            alert("Errore nell'eliminazione della regola: " + (res ? res.error : "Unknown error"));
        }
    });
};

window.payDoctorCompensations = function() {
    const doctorFilter = document.getElementById('comp-filter-doctor');
    const selectedDocId = doctorFilter ? parseInt(doctorFilter.value) : 0;
    if (!selectedDocId) {
        alert("Selezionare un medico specifico per eseguire la liquidazione dei compensi.");
        return;
    }
    
    if (!confirm("Confermi la liquidazione di tutti i compensi in sospeso per il medico selezionato?")) return;
    
    apiCall('/api/compensations-payout', { doctor_id: selectedDocId }, (res) => {
        if (res && res.success) {
            alert("Compensi liquidati con successo!");
            window.loadDoctorCompensations();
        } else {
            alert("Errore durante la liquidazione: " + (res ? res.error : "Unknown error"));
        }
    });
};

window.renderSsnRecipes = function() {
    const tbody = document.getElementById('ssn-recipes-table-body');
    if (!tbody) return;
    
    tbody.innerHTML = '';
    
    const recipes = DB.get('ssn_recipes') || [];
    const patients = DB.get('patients') || [];
    
    // Sort descending by id
    const sortedRecipes = [...recipes].sort((a, b) => b.id - a.id);
    
    if (sortedRecipes.length === 0) {
        tbody.innerHTML = '<tr><td colspan="7" style="text-align: center; padding: 20px; color: var(--text-secondary);">Nessuna ricetta SSN trovata.</td></tr>';
        return;
    }
    
    sortedRecipes.forEach(recipe => {
        const patient = patients.find(p => p.id === recipe.patient_id);
        const patientName = patient ? `${patient.last_name.toUpperCase()} ${patient.first_name.toUpperCase()}` : `Paziente ID ${recipe.patient_id}`;
        
        const tr = document.createElement('tr');
        tr.style.borderBottom = '1px solid var(--border-color)';
        
        const ticketAmount = Number(recipe.ticket_amount) || 0;
        const refundAmount = Number(recipe.refund_amount) || 0;
        
        tr.innerHTML = `
            <td style="padding: 10px; font-weight: 600;">${recipe.nre || '--'}</td>
            <td style="padding: 10px;">${patientName}</td>
            <td style="padding: 10px;">${recipe.exemption_code || 'Nessuna'}</td>
            <td style="padding: 10px;">€ ${ticketAmount.toFixed(2)}</td>
            <td style="padding: 10px;">€ ${refundAmount.toFixed(2)}</td>
            <td style="padding: 10px;">${recipe.recipe_date || '--'}</td>
            <td style="padding: 10px; text-align: right;">
                <button class="btn btn-secondary btn-sm" onclick="window.openEditSsnRecipe(${recipe.id})" style="padding: 4px 8px; font-size: 0.8rem; margin-right: 5px;">
                    <i data-lucide="edit-2" style="width: 12px; height: 12px; vertical-align: middle; margin-right: 2px;"></i> Modifica
                </button>
                <button class="btn btn-danger btn-sm" onclick="window.deleteSsnRecipe(${recipe.id})" style="padding: 4px 8px; font-size: 0.8rem; background-color: var(--danger); border-color: var(--danger); color: white;">
                    <i data-lucide="trash-2" style="width: 12px; height: 12px; vertical-align: middle; margin-right: 2px;"></i> Elimina
                </button>
            </td>
        `;
        tbody.appendChild(tr);
    });
    if (window.lucide && typeof window.lucide.createIcons === 'function') {
        window.lucide.createIcons({ attrs: { class: 'lucide-icon' } });
    }
};

window.openEditSsnRecipe = function(recipeId) {
    const recipes = DB.get('ssn_recipes') || [];
    const recipe = recipes.find(r => r.id === parseInt(recipeId));
    if (!recipe) {
        alert("Ricetta non trovata.");
        return;
    }
    
    window.ssnRecipeContext = 'edit';
    window.editingSsnRecipeId = recipe.id;
    
    document.getElementById('recipe-nre').value = recipe.nre || "";
    document.getElementById('recipe-exemption').value = recipe.exemption_code || "";
    document.getElementById('recipe-diagnosis').value = recipe.diagnostic_question || "";
    document.getElementById('recipe-date').value = recipe.recipe_date || "";
    document.getElementById('recipe-doctor').value = recipe.prescribing_doctor || "";
    document.getElementById('recipe-priority').value = recipe.priority_code || "P";
    document.getElementById('recipe-city').value = recipe.city || "";
    document.getElementById('recipe-asl-code').value = recipe.asl_code || "";
    document.getElementById('recipe-fse-obscure').value = recipe.fse_obscure_code || "";
    document.getElementById('recipe-fse-oppose').checked = recipe.fse_opposed ? true : false;
    
    openModal('modal-ssn-recipe-details');
};

window.deleteSsnRecipe = function(recipeId) {
    if (!confirm("Sei sicuro di voler eliminare questa ricetta SSN? L'eliminazione non può essere annullata.")) return;
    DB.delete('ssn_recipes', recipeId);
    alert("Ricetta eliminata con successo!");
    if (typeof window.renderSsnRecipes === 'function') {
        window.renderSsnRecipes();
    }
};

// ============================================================================
// SSN EXEMPTIONS MANAGEMENT (GESTIONE ESENZIONI)
// ============================================================================

window.switchSsnSubTab = function(paneName) {
    const mainBtn = document.getElementById('sub-tab-ssn-main');
    const exemptionsBtn = document.getElementById('sub-tab-ssn-exemptions');
    const mainPane = document.getElementById('ssn-main-pane');
    const exemptionsPane = document.getElementById('ssn-exemptions-pane');

    if (paneName === 'main') {
        if (mainBtn) mainBtn.classList.add('active');
        if (exemptionsBtn) exemptionsBtn.classList.remove('active');
        if (mainPane) mainPane.style.display = 'block';
        if (exemptionsPane) exemptionsPane.style.display = 'none';
        if (typeof window.renderSsnRecipes === 'function') window.renderSsnRecipes();
    } else if (paneName === 'exemptions') {
        if (mainBtn) mainBtn.classList.remove('active');
        if (exemptionsBtn) exemptionsBtn.classList.add('active');
        if (mainPane) mainPane.style.display = 'none';
        if (exemptionsPane) exemptionsPane.style.display = 'block';
        if (typeof window.renderSsnExemptions === 'function') window.renderSsnExemptions();
    }
};

window.renderSsnExemptions = function() {
    const searchEl = document.getElementById('exemption-search');
    const searchQuery = searchEl ? searchEl.value.toLowerCase().trim() : '';
    
    const exemptions = DB.get('ssn_exemptions') || [];
    
    // Alphabetical sort by code
    const sortedExemptions = [...exemptions].sort((a, b) => {
        return (a.code || '').localeCompare(b.code || '', undefined, { sensitivity: 'base' });
    });
    
    const filtered = sortedExemptions.filter(ex => {
        const code = (ex.code || '').toLowerCase();
        const name = (ex.name || '').toLowerCase();
        return code.includes(searchQuery) || name.includes(searchQuery);
    });
    
    const paginated = window.setupTablePagination('exemptions-table', filtered, () => window.renderSsnExemptions());
    
    const tbody = document.getElementById('exemptions-table-body');
    if (!tbody) return;
    tbody.innerHTML = '';
    
    if (paginated.length === 0) {
        tbody.innerHTML = '<tr><td colspan="6" style="text-align: center; padding: 20px; color: var(--text-secondary);">Nessuna esenzione trovata.</td></tr>';
        return;
    }
    
    paginated.forEach(ex => {
        const tr = document.createElement('tr');
        tr.style.borderBottom = '1px solid var(--border-color)';
        
        const isExempt = parseFloat(ex.pct) >= 100.00;
        const tariffLabel = isExempt 
            ? `<span class="badge badge-success" style="background-color: #d1fae5; color: #065f46; padding: 4px 8px; border-radius: 4px; font-weight: 600; font-size: 0.75rem;">Esente 100%</span>`
            : `<span class="badge badge-warning" style="background-color: #fef3c7; color: #92400e; padding: 4px 8px; border-radius: 4px; font-weight: 600; font-size: 0.75rem;">Ticket (Paga)</span>`;
            
        const isActive = ex.active == 1;
        const statusLabel = isActive
            ? `<span class="badge badge-success" style="cursor: pointer; background-color: #d1fae5; color: #065f46; padding: 2px 6px; border-radius: 4px; font-size: 0.75rem;" onclick="window.toggleSsnExemptionActive(${ex.id})">Attivo</span>`
            : `<span class="badge badge-danger" style="cursor: pointer; background-color: #fee2e2; color: #991b1b; padding: 2px 6px; border-radius: 4px; font-size: 0.75rem;" onclick="window.toggleSsnExemptionActive(${ex.id})">Inattivo</span>`;

        tr.innerHTML = `
            <td style="padding: 10px; font-weight: 600; font-family: monospace;">${ex.code}</td>
            <td style="padding: 10px; font-size: 0.85rem;" title="${ex.name}">${ex.name}</td>
            <td style="padding: 10px;">${tariffLabel}</td>
            <td style="padding: 10px; font-size: 0.85rem;">${ex.type || 'Altro'}</td>
            <td style="padding: 10px;">${statusLabel}</td>
            <td style="padding: 10px; text-align: right; white-space: nowrap;">
                <button class="btn btn-secondary btn-sm" onclick="window.editSsnExemptionInline(${ex.id})" style="padding: 4px 8px; font-size: 0.8rem; margin-right: 5px;">
                    <i data-lucide="edit-2" style="width: 12px; height: 12px; vertical-align: middle; margin-right: 2px;"></i> Modifica
                </button>
                <button class="btn btn-danger btn-sm" onclick="window.deleteSsnExemption(${ex.id})" style="padding: 4px 8px; font-size: 0.8rem; background-color: var(--danger); border-color: var(--danger); color: white;">
                    <i data-lucide="trash-2" style="width: 12px; height: 12px; vertical-align: middle; margin-right: 2px;"></i> Elimina
                </button>
            </td>
        `;
        tbody.appendChild(tr);
    });
    
    if (window.lucide && typeof window.lucide.createIcons === 'function') {
        window.lucide.createIcons({ attrs: { class: 'lucide-icon' } });
    }
};

window.saveSsnExemption = function(e) {
    if (e) e.preventDefault();
    
    const idInput = document.getElementById('exemption-id');
    const codeInput = document.getElementById('exemption-code');
    const nameInput = document.getElementById('exemption-name');
    const tariffTypeSelect = document.getElementById('exemption-tariff-type');
    const typeSelect = document.getElementById('exemption-type');
    const activeCheckbox = document.getElementById('exemption-active');
    
    if (!codeInput || !nameInput || !tariffTypeSelect) return;
    
    const id = idInput.value ? parseInt(idInput.value) : null;
    const code = codeInput.value.trim().toUpperCase();
    const name = nameInput.value.trim();
    const pct = parseFloat(tariffTypeSelect.value);
    const type = typeSelect ? typeSelect.value : 'Altro';
    const active = activeCheckbox ? (activeCheckbox.checked ? 1 : 0) : 1;
    
    if (!code || !name) {
        alert("Inserire codice e descrizione dell'esenzione.");
        return;
    }
    
    const exemptions = DB.get('ssn_exemptions') || [];
    
    // Check duplicate
    const duplicate = exemptions.find(ex => ex.code.toUpperCase() === code && ex.id !== id);
    if (duplicate) {
        alert(`Errore: Esiste già un'esenzione con il codice ${code}.`);
        return;
    }
    
    const btnSave = document.getElementById('btn-exemption-save');
    const originalText = btnSave ? btnSave.innerText : 'Salva Esenzione';
    if (btnSave) {
        btnSave.disabled = true;
        btnSave.innerText = 'Salvataggio...';
    }
    
    let promise;
    if (id) {
        DB.update('ssn_exemptions', id, {
            code,
            name,
            pct,
            type,
            active
        });
        promise = DB.waitForSync();
    } else {
        const newItem = {
            code,
            name,
            pct,
            type,
            active,
            number_required: 0
        };
        DB.insert('ssn_exemptions', newItem);
        promise = DB.waitForSync();
    }
    
    promise.then(() => {
        alert("Esenzione salvata con successo!");
        window.resetExemptionForm();
        window.renderSsnExemptions();
    }).catch(err => {
        alert("Errore durante il salvataggio o la sincronizzazione: " + err.message);
    }).finally(() => {
        if (btnSave) {
            btnSave.disabled = false;
            btnSave.innerText = originalText;
        }
    });
};

window.resetExemptionForm = function() {
    const idInput = document.getElementById('exemption-id');
    const codeInput = document.getElementById('exemption-code');
    const nameInput = document.getElementById('exemption-name');
    const tariffTypeSelect = document.getElementById('exemption-tariff-type');
    const typeSelect = document.getElementById('exemption-type');
    const activeCheckbox = document.getElementById('exemption-active');
    const formTitle = document.getElementById('exemption-form-title');
    const btnCancel = document.getElementById('btn-exemption-cancel');
    
    if (idInput) idInput.value = '';
    if (codeInput) {
        codeInput.value = '';
        codeInput.removeAttribute('disabled');
    }
    if (nameInput) nameInput.value = '';
    if (tariffTypeSelect) tariffTypeSelect.value = '100.00';
    if (typeSelect) typeSelect.value = 'Patologia';
    if (activeCheckbox) activeCheckbox.checked = true;
    
    if (formTitle) formTitle.innerText = 'Aggiungi Nuova Esenzione';
    if (btnCancel) btnCancel.style.display = 'none';
};

window.editSsnExemptionInline = function(id) {
    const exemptions = DB.get('ssn_exemptions') || [];
    const ex = exemptions.find(item => item.id === parseInt(id));
    if (!ex) {
        alert("Esenzione non trovata.");
        return;
    }
    
    const idInput = document.getElementById('exemption-id');
    const codeInput = document.getElementById('exemption-code');
    const nameInput = document.getElementById('exemption-name');
    const tariffTypeSelect = document.getElementById('exemption-tariff-type');
    const typeSelect = document.getElementById('exemption-type');
    const activeCheckbox = document.getElementById('exemption-active');
    const formTitle = document.getElementById('exemption-form-title');
    const btnCancel = document.getElementById('btn-exemption-cancel');
    
    if (idInput) idInput.value = ex.id;
    if (codeInput) codeInput.value = ex.code;
    if (nameInput) nameInput.value = ex.name;
    
    if (tariffTypeSelect) {
        const pctVal = parseFloat(ex.pct);
        if (pctVal >= 100.00) {
            tariffTypeSelect.value = '100.00';
        } else {
            tariffTypeSelect.value = '0.00';
        }
    }
    
    if (typeSelect) {
        typeSelect.value = ex.type || 'Altro';
    }
    
    if (activeCheckbox) {
        activeCheckbox.checked = ex.active == 1;
    }
    
    if (formTitle) formTitle.innerText = 'Modifica Esenzione';
    if (btnCancel) btnCancel.style.display = 'block';
    
    const formCard = document.getElementById('form-ssn-exemption');
    if (formCard) {
        formCard.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
    }
};

window.toggleSsnExemptionActive = function(id) {
    const exemptions = DB.get('ssn_exemptions') || [];
    const ex = exemptions.find(item => item.id === parseInt(id));
    if (!ex) return;
    
    const newActive = ex.active == 1 ? 0 : 1;
    DB.update('ssn_exemptions', id, { active: newActive });
    
    DB.waitForSync().then(() => {
        const currentEditId = document.getElementById('exemption-id') ? document.getElementById('exemption-id').value : '';
        if (currentEditId && parseInt(currentEditId) === id) {
            const activeCheckbox = document.getElementById('exemption-active');
            if (activeCheckbox) activeCheckbox.checked = newActive === 1;
        }
        window.renderSsnExemptions();
    }).catch(err => {
        alert("Errore durante la sincronizzazione: " + err.message);
    });
};

window.deleteSsnExemption = function(id) {
    const exemptions = DB.get('ssn_exemptions') || [];
    const ex = exemptions.find(item => item.id === parseInt(id));
    if (!ex) return;
    
    if (!confirm(`Sei sicuro di voler eliminare l'esenzione ${ex.code} (${ex.name})? L'eliminazione non può essere annullata.`)) {
        return;
    }
    
    DB.delete('ssn_exemptions', id);
    
    DB.waitForSync().then(() => {
        alert("Esenzione eliminata con successo!");
        const currentEditId = document.getElementById('exemption-id') ? document.getElementById('exemption-id').value : '';
        if (currentEditId && parseInt(currentEditId) === id) {
            window.resetExemptionForm();
        }
        window.renderSsnExemptions();
    }).catch(err => {
        alert("Errore durante la sincronizzazione: " + err.message);
    });
};

