// --- helper function to check if a sample is already invoiced ---
function isSampleInvoiced(sam, allInvoices) {
    return allInvoices.some(inv => {
        if (inv.sample_id === sam.id) return true;
        if (inv.custom_rates && Array.isArray(inv.custom_rates.sample_ids)) {
            return inv.custom_rates.sample_ids.includes(sam.id);
        }
        return false;
    });
}

// --- Punti Prelievo CRUD (management) ---
window.renderLisCollectionPointsView = function() {
    const tbody = document.querySelector('#collection-points-table tbody');
    if (!tbody) return;
    tbody.innerHTML = '';

    const points = DB.get('lis_collection_points') || [];
    
    // Support pagination if setupTablePagination exists
    const paginated = window.setupTablePagination ? window.setupTablePagination('collection-points-table', points, () => window.renderLisCollectionPointsView()) : points;

    if (points.length === 0) {
        tbody.innerHTML = `<tr><td colspan="7" style="text-align: center;" class="text-muted">Nessun punto prelievo configurato</td></tr>`;
        return;
    }

    paginated.forEach(cp => {
        const tr = document.createElement('tr');
        
        let contactsHtml = `<div>${cp.address || ''}</div>`;
        if (cp.phone) contactsHtml += `<div style="font-size: 0.75rem; color: var(--text-secondary);"><i data-lucide="phone" style="width: 10px; height: 10px; display: inline-block;"></i> ${cp.phone}</div>`;
        contactsHtml += `<div style="font-size: 0.75rem; color: var(--text-secondary);"><i data-lucide="mail" style="width: 10px; height: 10px; display: inline-block;"></i> ${cp.email || ''}</div>`;

        let billingHtml = '';
        if (cp.invoice_separate == 1) {
            billingHtml = `<div><strong>Fattura Separata</strong></div>
                           <div style="font-size: 0.75rem; color: var(--text-secondary);">Prefisso: ${cp.invoice_prefix || ''}<br>Prossimo: ${cp.invoice_next_num || 1}</div>`;
        } else if (cp.billing_type === 'monthly_invoice') {
            billingHtml = `<div><strong>Fattura Cumulativa</strong></div>
                           <div style="font-size: 0.75rem; color: var(--text-secondary);">Sconto: ${cp.discount || 0}%</div>`;
        } else {
            billingHtml = `<div style="color: var(--text-secondary);">Diretta al Paziente</div>`;
        }

        let linkHtml = `<a href="portal_${cp.code}.html" target="_blank" class="text-primary font-semibold" style="display: inline-flex; align-items: center; gap: 4px;">
            <i data-lucide="external-link" style="width:14px; height:14px;"></i> Apri Portale
        </a>`;

        let actionsHtml = `
            <button class="btn btn-secondary btn-sm" onclick="window.editCollectionPoint(${cp.id})" style="margin-right: 5px;">
                <i data-lucide="edit" style="width:12px; height:12px; display:inline-block; margin-right:2px;"></i> Modifica
            </button>
            <button class="btn btn-danger btn-sm" onclick="window.deleteCollectionPoint(${cp.id})" style="margin-right: 5px;">
                <i data-lucide="trash-2" style="width:12px; height:12px; display:inline-block; margin-right:2px;"></i> Elimina
            </button>
        `;

        if (cp.billing_type === 'monthly_invoice') {
            actionsHtml += `
                <button class="btn btn-primary btn-sm" onclick="window.openCollectionPointBilling(${cp.id})" style="background-color: var(--success); border-color: var(--success); color: white;">
                    <i data-lucide="file-text" style="width:12px; height:12px; display:inline-block; margin-right:2px;"></i> Fatturazione
                </button>
            `;
        }

        tr.innerHTML = `
            <td><span class="badge badge-info" style="font-family: monospace;">${cp.code}</span></td>
            <td><strong>${cp.name}</strong></td>
            <td>${contactsHtml}</td>
            <td><code>${cp.username || ''}</code></td>
            <td>${billingHtml}</td>
            <td>${linkHtml}</td>
            <td><div style="display: flex; gap: 5px; align-items: center;">${actionsHtml}</div></td>
        `;
        tbody.appendChild(tr);
    });

    if (window.lucide) window.lucide.createIcons();
};

window.openAddCollectionPointModal = function() {
    const form = document.getElementById('form-collection-point');
    if (form) form.reset();
    document.getElementById('col-pt-id').value = '';
    document.getElementById('col-pt-invoice-fields').style.display = 'none';
    document.getElementById('collection-point-modal-title').innerText = "Nuovo Punto Prelievo";
    window.openModal('modal-hris-collection-point');
};

window.editCollectionPoint = function(id) {
    const points = DB.get('lis_collection_points') || [];
    const cp = points.find(p => p.id === parseInt(id));
    if (!cp) return;

    document.getElementById('col-pt-id').value = cp.id;
    document.getElementById('col-pt-code').value = cp.code || '';
    document.getElementById('col-pt-name').value = cp.name || '';
    document.getElementById('col-pt-address').value = cp.address || '';
    document.getElementById('col-pt-phone').value = cp.phone || '';
    document.getElementById('col-pt-email').value = cp.email || '';
    document.getElementById('col-pt-username').value = cp.username || '';
    document.getElementById('col-pt-password').value = cp.password || '';
    document.getElementById('col-pt-billing-type').value = cp.billing_type || 'direct';
    document.getElementById('col-pt-discount').value = cp.discount || 0;
    
    const sepCheck = document.getElementById('col-pt-invoice-separate');
    if (sepCheck) {
        sepCheck.checked = (cp.invoice_separate == 1);
        document.getElementById('col-pt-invoice-fields').style.display = sepCheck.checked ? 'grid' : 'none';
    }
    document.getElementById('col-pt-invoice-prefix').value = cp.invoice_prefix || '';
    document.getElementById('col-pt-invoice-next-num').value = cp.invoice_next_num || 1;

    document.getElementById('collection-point-modal-title').innerText = "Modifica Punto Prelievo";
    window.openModal('modal-hris-collection-point');
};

window.deleteCollectionPoint = async function(id) {
    if (!confirm("Sei sicuro di voler eliminare questo punto prelievo?")) return;
    const points = DB.get('lis_collection_points') || [];
    const filtered = points.filter(p => p.id !== parseInt(id));
    
    await DB.set('lis_collection_points', filtered);
    if (typeof window.populateDropdownsLIS === 'function') window.populateDropdownsLIS();
    window.renderLisCollectionPointsView();
};

window.saveCollectionPoint = async function(event) {
    if (event) event.preventDefault();
    const idVal = document.getElementById('col-pt-id').value;
    const code = document.getElementById('col-pt-code').value.trim();
    const name = document.getElementById('col-pt-name').value.trim();
    const address = document.getElementById('col-pt-address').value.trim();
    const phone = document.getElementById('col-pt-phone').value.trim();
    const email = document.getElementById('col-pt-email').value.trim();
    const username = document.getElementById('col-pt-username').value.trim();
    const password = document.getElementById('col-pt-password').value.trim();
    const billing_type = document.getElementById('col-pt-billing-type').value;
    const discount = parseFloat(document.getElementById('col-pt-discount').value || 0);
    const invoice_separate = document.getElementById('col-pt-invoice-separate').checked ? 1 : 0;
    const invoice_prefix = document.getElementById('col-pt-invoice-prefix').value.trim();
    const invoice_next_num = parseInt(document.getElementById('col-pt-invoice-next-num').value || 1, 10);

    const points = DB.get('lis_collection_points') || [];
    let cpObj = {};
    if (idVal) {
        const id = parseInt(idVal, 10);
        cpObj = points.find(p => p.id === id);
        if (cpObj) {
            cpObj.code = code;
            cpObj.name = name;
            cpObj.address = address;
            cpObj.phone = phone;
            cpObj.email = email;
            cpObj.username = username;
            cpObj.password = password;
            cpObj.billing_type = billing_type;
            cpObj.discount = discount;
            cpObj.invoice_separate = invoice_separate;
            cpObj.invoice_prefix = invoice_prefix;
            cpObj.invoice_next_num = invoice_next_num;
            cpObj.updated_at = new Date().toISOString();
        }
    } else {
        const maxId = points.reduce((max, p) => p.id > max ? p.id : max, 0);
        cpObj = {
            id: maxId + 1,
            code,
            name,
            address,
            phone,
            email,
            username,
            password,
            billing_type,
            discount,
            invoice_separate,
            invoice_prefix,
            invoice_next_num,
            created_at: new Date().toISOString(),
            updated_at: new Date().toISOString()
        };
        points.push(cpObj);
    }

    await DB.set('lis_collection_points', points);
    window.closeModal('modal-hris-collection-point');
    if (typeof window.populateDropdownsLIS === 'function') window.populateDropdownsLIS();
    window.renderLisCollectionPointsView();
};

// --- Check-in Provette / DDT Punti Prelievo ---
window.modalCheckinBarcodes = [];
window.activeCheckinDdtId = null;
window.activeCheckinScannedBarcodes = [];

window.openLisCheckinModal = function() {
    window.modalCheckinBarcodes = [];
    const inp = document.getElementById('lis-checkin-barcode-input');
    if (inp) inp.value = '';
    window.renderLisCheckinTable();
    window.openModal('modal-lis-checkin');
};

window.handleLisCheckinBarcodeKeydown = function(event) {
    if (event.key === 'Enter') {
        event.preventDefault();
        if (event.target.id === 'lis-checkin-barcode') {
            window.processScannedBarcodeManual();
        } else if (event.target.id === 'lis-checkin-barcode-input') {
            window.addBarcodeToCheckinList();
        }
    }
};

window.addBarcodeToCheckinList = function() {
    const inp = document.getElementById('lis-checkin-barcode-input');
    if (!inp) return;
    const barcode = inp.value.trim();
    if (!barcode) return;

    const samples = DB.get('lab_samples') || [];
    const sam = samples.find(s => s.barcode === barcode);
    if (!sam) {
        alert("Campione non trovato nel database!");
        return;
    }

    if (sam.status === 'non_prelevato' || sam.status === 'non_pervenuto') {
        alert(`Impossibile effettuare il check-in: il campione è stato segnato come '${sam.status.replace('_', ' ')}'`);
        return;
    }

    if (!window.modalCheckinBarcodes.includes(barcode)) {
        window.modalCheckinBarcodes.push(barcode);
    }
    inp.value = '';
    window.renderLisCheckinTable();
};

window.removeSampleFromCheckin = function(barcode) {
    window.modalCheckinBarcodes = window.modalCheckinBarcodes.filter(b => b !== barcode);
    window.renderLisCheckinTable();
};

window.renderLisCheckinTable = function() {
    const tbody = document.getElementById('lis-checkin-tbody');
    if (!tbody) return;
    tbody.innerHTML = '';

    const badge = document.getElementById('lis-checkin-count-badge');
    if (badge) badge.innerText = `${window.modalCheckinBarcodes.length} Campioni`;

    if (window.modalCheckinBarcodes.length === 0) {
        tbody.innerHTML = `<tr><td colspan="5" style="text-align: center;" class="text-muted">Nessuna provetta scansionata</td></tr>`;
        return;
    }

    const samples = DB.get('lab_samples') || [];
    const patients = DB.get('patients') || [];
    const points = DB.get('lis_collection_points') || [];
    const tests = DB.get('lab_tests') || [];
    const services = DB.get('medical_services') || [];

    window.modalCheckinBarcodes.forEach(barcode => {
        const sam = samples.find(s => s.barcode === barcode);
        if (!sam) return;

        const p = patients.find(pat => pat.id === sam.patient_id);
        const cp = points.find(pt => pt.id === sam.collection_point_id);
        const cpName = cp ? cp.name : 'Sede Centrale';

        const samTests = tests.filter(t => t.sample_id === sam.id);
        const testsStr = samTests.map(t => {
            const srv = services.find(s => s.id === t.service_id);
            return srv ? srv.name : t.test_name;
        }).join(', ');

        const tr = document.createElement('tr');
        tr.innerHTML = `
            <td><strong style="font-family: monospace;">${barcode}</strong></td>
            <td>${p ? `${p.last_name} ${p.first_name}` : 'N/D'}</td>
            <td>${cpName}</td>
            <td>${testsStr}</td>
            <td style="text-align: center;">
                <button class="btn btn-danger btn-sm" onclick="window.removeSampleFromCheckin('${barcode}')">
                    <i data-lucide="trash-2" style="width:12px; height:12px;"></i>
                </button>
            </td>
        `;
        tbody.appendChild(tr);
    });

    if (window.lucide) window.lucide.createIcons();
};

window.renderLisCheckinView = function() {
    const pendingTbody = document.querySelector('#lis-pending-ddt-table tbody');
    const receivedTbody = document.querySelector('#lis-received-ddt-table tbody');
    if (!pendingTbody || !receivedTbody) return;

    pendingTbody.innerHTML = '';
    receivedTbody.innerHTML = '';

    const ddts = DB.get('lis_ddt') || [];
    const points = DB.get('lis_collection_points') || [];

    const pendingDdts = ddts.filter(d => d.status === 'in viaggio');
    const receivedDdts = ddts.filter(d => d.status === 'arrivato in lab');

    if (pendingDdts.length === 0) {
        pendingTbody.innerHTML = `<tr><td colspan="5" style="text-align: center;" class="text-muted">Nessun DDT in arrivo</td></tr>`;
    } else {
        pendingDdts.forEach(d => {
            const cp = points.find(pt => pt.id === d.collection_point_id);
            const cpName = cp ? cp.name : 'Sede Centrale';
            const dateStr = new Date(d.shipped_at).toLocaleString('it-IT');
            const tubesCount = Array.isArray(d.samples_json) ? d.samples_json.length : 0;

            const tr = document.createElement('tr');
            tr.innerHTML = `
                <td><strong style="font-family: monospace;">${d.ddt_code}</strong></td>
                <td>${cpName}</td>
                <td>${dateStr}</td>
                <td><span class="badge badge-info">${tubesCount} provette</span></td>
                <td>
                    <button class="btn btn-primary btn-sm" onclick="window.startDdtCheckin(${d.id})">
                        <i data-lucide="check" style="width:12px; height:12px; display:inline-block; margin-right:2px;"></i> Avvia Check-in
                    </button>
                </td>
            `;
            pendingTbody.appendChild(tr);
        });
    }

    if (receivedDdts.length === 0) {
        receivedTbody.innerHTML = `<tr><td colspan="4" style="text-align: center;" class="text-muted">Nessun DDT in archivio</td></tr>`;
    } else {
        receivedDdts.forEach(d => {
            const cp = points.find(pt => pt.id === d.collection_point_id);
            const cpName = cp ? cp.name : 'Sede Centrale';
            const dateStr = new Date(d.received_at || d.updated_at).toLocaleString('it-IT');

            const tr = document.createElement('tr');
            tr.innerHTML = `
                <td><strong style="font-family: monospace;">${d.ddt_code}</strong></td>
                <td>${cpName}</td>
                <td>${dateStr}</td>
                <td><span class="badge badge-success">Ricevuto in Laboratorio</span></td>
            `;
            receivedTbody.appendChild(tr);
        });
    }

    if (window.lucide) window.lucide.createIcons();
};

window.startDdtCheckin = function(ddtId) {
    const ddts = DB.get('lis_ddt') || [];
    const ddt = ddts.find(d => d.id === ddtId);
    if (!ddt) return;

    window.activeCheckinDdtId = ddtId;
    window.activeCheckinScannedBarcodes = [];

    document.getElementById('lis-ddt-list-panel').style.display = 'none';
    document.getElementById('lis-checkin-active-panel').style.display = 'block';

    document.getElementById('lis-active-ddt-code').innerText = ddt.ddt_code;
    const cp = (DB.get('lis_collection_points') || []).find(pt => pt.id === ddt.collection_point_id);
    document.getElementById('lis-active-ddt-cp').innerText = cp ? cp.name : 'N/D';

    const barcodeInput = document.getElementById('lis-checkin-barcode');
    if (barcodeInput) {
        barcodeInput.value = '';
        barcodeInput.focus();
    }

    const feedback = document.getElementById('checkin-scan-feedback');
    if (feedback) feedback.style.display = 'none';

    window.renderActiveCheckinTable();
};

window.cancelActiveCheckin = function() {
    window.activeCheckinDdtId = null;
    window.activeCheckinScannedBarcodes = [];
    document.getElementById('lis-checkin-active-panel').style.display = 'none';
    document.getElementById('lis-ddt-list-panel').style.display = 'block';
    window.renderLisCheckinView();
};

window.toggleCheckinBarcode = function(barcode) {
    if (window.activeCheckinScannedBarcodes.includes(barcode)) {
        window.activeCheckinScannedBarcodes = window.activeCheckinScannedBarcodes.filter(b => b !== barcode);
    } else {
        window.activeCheckinScannedBarcodes.push(barcode);
    }
    window.renderActiveCheckinTable();
};

window.renderActiveCheckinTable = function() {
    const tbody = document.querySelector('#lis-checkin-samples-table tbody');
    if (!tbody) return;
    tbody.innerHTML = '';

    if (!window.activeCheckinDdtId) return;

    const ddts = DB.get('lis_ddt') || [];
    const ddt = ddts.find(d => d.id === window.activeCheckinDdtId);
    if (!ddt) return;

    const samples = DB.get('lab_samples') || [];
    const patients = DB.get('patients') || [];
    const tests = DB.get('lab_tests') || [];
    const services = DB.get('medical_services') || [];

    const barcodes = ddt.samples_json || [];

    barcodes.forEach(barcode => {
        const sam = samples.find(s => s.barcode === barcode);
        const p = sam ? patients.find(pat => pat.id === sam.patient_id) : null;
        const samTests = sam ? tests.filter(t => t.sample_id === sam.id) : [];
        const testsStr = samTests.map(t => {
            const srv = services.find(s => s.id === t.service_id);
            return srv ? srv.name : t.test_name;
        }).join(', ');

        const isScanned = window.activeCheckinScannedBarcodes.includes(barcode);

        const tr = document.createElement('tr');
        tr.innerHTML = `
            <td style="text-align: center;">
                <input type="checkbox" ${isScanned ? 'checked' : ''} onchange="window.toggleCheckinBarcode('${barcode}')">
            </td>
            <td><strong style="font-family: monospace;">${barcode}</strong></td>
            <td>${p ? `${p.last_name} ${p.first_name}` : 'N/D'}</td>
            <td>${sam ? window.getTubeBadgeHtml(sam.sample_type) : 'N/D'}</td>
            <td>${testsStr}</td>
        `;
        tbody.appendChild(tr);
    });
};

window.processScannedBarcodeManual = function() {
    const inputEl = document.getElementById('lis-checkin-barcode');
    if (!inputEl) return;
    const barcode = inputEl.value.trim();
    if (!barcode) return;

    const feedback = document.getElementById('checkin-scan-feedback');
    if (feedback) {
        feedback.style.display = 'block';
        feedback.className = '';
    }

    if (!window.activeCheckinDdtId) return;
    const ddts = DB.get('lis_ddt') || [];
    const ddt = ddts.find(d => d.id === window.activeCheckinDdtId);
    if (!ddt) return;

    const barcodes = ddt.samples_json || [];
    if (!barcodes.includes(barcode)) {
        if (feedback) {
            feedback.innerText = `Errore: Il barcode ${barcode} non appartiene a questo lotto DDT!`;
            feedback.style.color = 'var(--danger)';
        }
        return;
    }

    if (!window.activeCheckinScannedBarcodes.includes(barcode)) {
        window.activeCheckinScannedBarcodes.push(barcode);
    }

    if (feedback) {
        feedback.innerText = `Ok: Barcode ${barcode} accettato.`;
        feedback.style.color = 'var(--success)';
    }

    inputEl.value = '';
    inputEl.focus();
    window.renderActiveCheckinTable();
};

window.confirmLisCheckinBatch = async function() {
    const samples = DB.get('lab_samples') || [];
    const tests = DB.get('lab_tests') || [];

    if (window.activeCheckinDdtId) {
        // In-pane active DDT checkin
        if (!confirm("Confermare l'accettazione e l'arrivo in laboratorio delle provette selezionate per questo lotto DDT?")) return;

        const ddts = DB.get('lis_ddt') || [];
        const ddt = ddts.find(d => d.id === window.activeCheckinDdtId);
        if (!ddt) return;

        ddt.status = 'arrivato in lab';
        ddt.received_at = new Date().toISOString();
        ddt.received_by = 1;

        let count = 0;
        window.activeCheckinScannedBarcodes.forEach(barcode => {
            const sam = samples.find(s => s.barcode === barcode);
            if (sam) {
                sam.status = 'collected';
                sam.collected_at = new Date().toISOString();
                sam.collected_by = 1;
                
                const samTests = tests.filter(t => t.sample_id === sam.id);
                samTests.forEach(t => {
                    t.status = 'pending';
                });
                
                count++;
            }
        });

        await DB.set('lab_tests', tests);
        await DB.set('lab_samples', samples);
        await DB.set('lis_ddt', ddts);

        alert(`Check-in DDT completato! ${count} provette registrate in laboratorio.`);
        window.cancelActiveCheckin();
        if (typeof window.renderSamples === 'function') window.renderSamples();
    } else {
        // Modal batch check-in
        if (window.modalCheckinBarcodes.length === 0) {
            alert("Nessun campione scansionato!");
            return;
        }

        if (!confirm(`Registrare l'accettazione cumulativa per i ${window.modalCheckinBarcodes.length} campioni scansionati?`)) return;

        let count = 0;
        window.modalCheckinBarcodes.forEach(barcode => {
            const sam = samples.find(s => s.barcode === barcode);
            if (sam) {
                sam.status = 'collected';
                sam.collected_at = new Date().toISOString();
                sam.collected_by = 1;
                
                const samTests = tests.filter(t => t.sample_id === sam.id);
                samTests.forEach(t => {
                    t.status = 'pending';
                });
                
                count++;
            }
        });

        await DB.set('lab_tests', tests);
        await DB.set('lab_samples', samples);

        alert(`Accettazione completata con successo! Registrati ${count} campioni.`);
        window.closeModal('modal-lis-checkin');
        if (typeof window.renderSamples === 'function') window.renderSamples();
    }
};

// --- Cumulative Billing for Collection Points ---
window.openCollectionPointBilling = function(cpId) {
    const points = DB.get('lis_collection_points') || [];
    const cp = points.find(p => p.id === parseInt(cpId));
    if (!cp) return;

    document.getElementById('billing-cp-id').value = cp.id;
    document.getElementById('billing-cp-name').innerText = cp.name;
    document.getElementById('billing-cp-discount-label').innerText = `${cp.discount || 0}%`;

    const now = new Date();
    const y = now.getFullYear(), m = now.getMonth();
    const firstDay = new Date(y, m, 1).toISOString().split('T')[0];
    const lastDay = new Date(y, m + 1, 0).toISOString().split('T')[0];

    document.getElementById('cp-billing-date-from').value = firstDay;
    document.getElementById('cp-billing-date-to').value = lastDay;

    window.calculateCollectionPointBillingDetails();
    window.openModal('modal-collection-point-billing');
};

window.calculateCollectionPointBillingDetails = function() {
    const cpId = parseInt(document.getElementById('billing-cp-id').value);
    const dateFrom = document.getElementById('cp-billing-date-from').value;
    const dateTo = document.getElementById('cp-billing-date-to').value;

    const tbody = document.querySelector('#cp-billing-items-table tbody');
    if (!tbody) return;
    tbody.innerHTML = '';

    const points = DB.get('lis_collection_points') || [];
    const cp = points.find(p => p.id === cpId);
    if (!cp) return;

    const discountPct = parseFloat(cp.discount || 0);

    const samples = DB.get('lab_samples') || [];
    const patients = DB.get('patients') || [];
    const tests = DB.get('lab_tests') || [];
    const services = DB.get('medical_services') || [];
    const invoices = DB.get('invoices') || [];

    const filteredSamples = samples.filter(sam => {
        if (sam.collection_point_id !== cpId) return false;
        if (sam.status === 'rejected' || sam.status === 'suspended') return false;

        const date = new Date(sam.collected_at || sam.created_at);
        if (dateFrom) {
            const dFrom = new Date(dateFrom);
            dFrom.setHours(0,0,0,0);
            if (date < dFrom) return false;
        }
        if (dateTo) {
            const dTo = new Date(dateTo);
            dTo.setHours(23,59,59,999);
            if (date > dTo) return false;
        }

        return !isSampleInvoiced(sam, invoices);
    });

    let subtotalTotal = 0;
    let discountTotal = 0;
    let netTotal = 0;

    filteredSamples.forEach(sam => {
        const p = patients.find(pat => pat.id === sam.patient_id);
        const samTests = tests.filter(t => t.sample_id === sam.id);

        const uniqueServiceIds = [...new Set(samTests.map(t => t.service_id))];
        const serviceNames = uniqueServiceIds.map(sId => services.find(s => s.id === sId)?.name || 'Esame').join(', ');
        
        const sampleSubtotal = uniqueServiceIds.reduce((sum, sId) => {
            const srv = services.find(s => s.id === sId);
            return sum + (srv ? parseFloat(srv.price || 0) : 0);
        }, 0);

        const sampleDiscount = sampleSubtotal * (discountPct / 100);
        const sampleNet = sampleSubtotal - sampleDiscount;

        subtotalTotal += sampleSubtotal;
        discountTotal += sampleDiscount;
        netTotal += sampleNet;

        const dateStr = new Date(sam.collected_at || sam.created_at).toLocaleDateString('it-IT');

        const tr = document.createElement('tr');
        tr.innerHTML = `
            <td>${dateStr}</td>
            <td><strong style="font-family: monospace;">${sam.barcode}</strong></td>
            <td>${p ? `${p.last_name} ${p.first_name}` : 'N/D'}</td>
            <td>${serviceNames}</td>
            <td>€ ${sampleSubtotal.toFixed(2)}</td>
            <td>${discountPct}%</td>
            <td><strong>€ ${sampleNet.toFixed(2)}</strong></td>
        `;
        tbody.appendChild(tr);
    });

    document.getElementById('cp-billing-count-badge').innerText = `${filteredSamples.length} prestazioni`;
    document.getElementById('cp-billing-subtotal').innerText = `€ ${subtotalTotal.toFixed(2)}`;
    document.getElementById('cp-billing-discount-total').innerText = `€ ${discountTotal.toFixed(2)}`;
    document.getElementById('cp-billing-net-total').innerText = `€ ${netTotal.toFixed(2)}`;
};

window.emitCollectionPointCumulativeInvoice = async function() {
    const cpId = parseInt(document.getElementById('billing-cp-id').value);
    const dateFrom = document.getElementById('cp-billing-date-from').value;
    const dateTo = document.getElementById('cp-billing-date-to').value;

    const points = DB.get('lis_collection_points') || [];
    const cp = points.find(p => p.id === cpId);
    if (!cp) return;

    if (!confirm(`Emettere la fattura cumulativa fine mese per la sede ${cp.name} ed azzerare i conti del periodo selezionato?`)) return;

    const discountPct = parseFloat(cp.discount || 0);

    const samples = DB.get('lab_samples') || [];
    const tests = DB.get('lab_tests') || [];
    const services = DB.get('medical_services') || [];
    const invoices = DB.get('invoices') || [];

    const billedSamples = samples.filter(sam => {
        if (sam.collection_point_id !== cpId) return false;
        if (sam.status === 'rejected' || sam.status === 'suspended') return false;

        const date = new Date(sam.collected_at || sam.created_at);
        if (dateFrom) {
            const dFrom = new Date(dateFrom);
            dFrom.setHours(0,0,0,0);
            if (date < dFrom) return false;
        }
        if (dateTo) {
            const dTo = new Date(dateTo);
            dTo.setHours(23,59,59,999);
            if (date > dTo) return false;
        }

        return !isSampleInvoiced(sam, invoices);
    });

    if (billedSamples.length === 0) {
        alert("Nessun esame da fatturare nel periodo selezionato!");
        return;
    }

    let subtotalTotal = 0;
    let discountTotal = 0;
    let netTotal = 0;
    const billedSampleIds = [];

    billedSamples.forEach(sam => {
        billedSampleIds.push(sam.id);
        const samTests = tests.filter(t => t.sample_id === sam.id);
        const uniqueServiceIds = [...new Set(samTests.map(t => t.service_id))];
        const sampleSubtotal = uniqueServiceIds.reduce((sum, sId) => {
            const srv = services.find(s => s.id === sId);
            return sum + (srv ? parseFloat(srv.price || 0) : 0);
        }, 0);

        const sampleDiscount = sampleSubtotal * (discountPct / 100);
        const sampleNet = sampleSubtotal - sampleDiscount;

        subtotalTotal += sampleSubtotal;
        discountTotal += sampleDiscount;
        netTotal += sampleNet;
    });

    const invoiceNum = window.getNextInvoiceNumber(cpId);
    
    let stampDuty = 0;
    let finalTotal = netTotal;
    if (netTotal > 77.47) {
        stampDuty = 2.00;
        finalTotal = netTotal + 2.00;
    }

    const cumulativeInvoice = {
        invoice_number: invoiceNum,
        issue_date: new Date().toISOString().split('T')[0],
        subtotal: subtotalTotal,
        discount_value: discountPct,
        discount_type: 'percentage',
        discount_amount: discountTotal,
        price_list_id: 1,
        claim_id: null,
        insurance_covered_amount: 0,
        stamp_duty: stampDuty,
        amount_due: finalTotal,
        amount_paid: 0.0,
        payment_status: 'unpaid',
        payment_method: 'Bonifico',
        paid_at: null,
        is_insurance_invoice: false,
        collection_point_id: cpId,
        custom_rates: {
            sample_ids: billedSampleIds,
            notes: `Fattura cumulativa fine mese per ${billedSampleIds.length} prestazioni del punto prelievo ${cp.name} nel periodo ${dateFrom || 'Inizio'} - ${dateTo || 'Fine'}.`
        }
    };

    DB.insert('invoices', cumulativeInvoice);
    DB.logAudit(4, "CUMULATIVE_BILL_EMITTED", "invoices", null, { collection_point_id: cpId, invoice_number: invoiceNum, amount: finalTotal });

    await DB.waitForSync();
    window.closeModal('modal-collection-point-billing');
    
    alert(`Fattura cumulativa emessa con successo! Generato documento ${invoiceNum} per un totale di € ${finalTotal.toFixed(2)}.`);
    
    if (typeof window.renderLisCollectionPointsView === 'function') window.renderLisCollectionPointsView();
};


